{
  "name": "Tour লাগবে - Bus Seat Booking",
  "description": "A professional bus seat booking system for Tour লাগবে tour business featuring customized seat patterns, dynamic pricing calculations, and color-coded seat statuses based on passenger demographics.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Gender {
  MALE = 'Male',
  FEMALE = 'Female'
}

export enum Religion {
  MUSLIM = 'Muslim',
  HINDU = 'Hindu',
  BUDDHA = 'Buddha',
  CHRISTIAN = 'Christian',
  OTHERS = 'Others'
}

export enum BookingAgent {
  KAZI_SHETU = 'Kazi Shetu',
  SADEKUL_ISLAM = 'Sadekul Islam',
  AKRAMUL_HAQUE = 'Akramul Haque',
  MD_HANJELA = 'MD. Hanjela',
  KHURSED_ALAM = 'Khursed Alam',
  MASUD_RANA = 'Masud Rana'
}

export interface BookingInfo {
  name: string;
  phone: string;
  gender: Gender;
  religion: Religion;
  totalFees: number;
  discountPercentage: number;
  advanceAmount: number;
  dueAmount: number;
  bookedBy: BookingAgent;
}

export interface SeatData {
  id: string; // e.g., 'A1', 'K5'
  isBooked: boolean;
  bookingInfo?: BookingInfo;
}

import { SeatData } from './types';

export const BUSINESS_INFO = {
  name: "Tour লাগবে (Tour Lagbe)",
  address: "Kazi Genarel Store, Hindu Barir Mor, Borad Bazar, Gazipur",
  facebook: "https://www.facebook.com/tourlagbee",
  phonePrefix: "+880"
};

const rows = ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H', 'I', 'J'];
const lastRow = 'K';

const generateInitialSeats = (): SeatData[] => {
  const seats: SeatData[] = [];

  // Rows A to J: 4 seats each (1, 2, Aisle, 3, 4)
  rows.forEach(row => {
    for (let i = 1; i <= 4; i++) {
      seats.push({ id: `${row}${i}`, isBooked: false });
    }
  });

  // Row K: 5 seats (1 to 5)
  for (let i = 1; i <= 5; i++) {
    seats.push({ id: `${lastRow}${i}`, isBooked: false });
  }

  return seats;
};

export const INITIAL_SEATS = generateInitialSeats();

import React, { useState, useEffect, useCallback } from 'react';
import { BUSINESS_INFO, INITIAL_SEATS } from './constants';
import { SeatData, BookingInfo, Gender, Religion, BookingAgent } from './types';
import BusLayout from './components/BusLayout';
import BookingModal from './components/BookingModal';
import ConfirmationDialog from './components/ConfirmationDialog';

const App: React.FC = () => {
  const [seats, setSeats] = useState<SeatData[]>(() => {
    const saved = localStorage.getItem('tour_lagbe_seats');
    return saved ? JSON.parse(saved) : INITIAL_SEATS;
  });

  const [selectedSeatId, setSelectedSeatId] = useState<string | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [showConfirmDeselect, setShowConfirmDeselect] = useState(false);
  const [seatToDeselect, setSeatToDeselect] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem('tour_lagbe_seats', JSON.stringify(seats));
  }, [seats]);

  const handleSeatClick = useCallback((seatId: string) => {
    const seat = seats.find(s => s.id === seatId);
    if (seat?.isBooked) {
      setSeatToDeselect(seatId);
      setShowConfirmDeselect(true);
    } else {
      setSelectedSeatId(seatId);
      setShowBookingModal(true);
    }
  }, [seats]);

  const handleBookingSubmit = (info: BookingInfo) => {
    if (!selectedSeatId) return;

    setSeats(prev => prev.map(s => 
      s.id === selectedSeatId 
        ? { ...s, isBooked: true, bookingInfo: info } 
        : s
    ));
    setShowBookingModal(false);
    setSelectedSeatId(null);
  };

  const confirmDeselect = () => {
    if (seatToDeselect) {
      setSeats(prev => prev.map(s => 
        s.id === seatToDeselect 
          ? { ...s, isBooked: false, bookingInfo: undefined } 
          : s
      ));
    }
    setShowConfirmDeselect(false);
    setSeatToDeselect(null);
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header */}
      <header className="bg-indigo-700 text-white shadow-lg py-6 px-4">
        <div className="max-w-6xl mx-auto flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="text-center md:text-left">
            <h1 className="text-3xl font-extrabold flex items-center justify-center md:justify-start gap-2">
              <i className="fas fa-bus-alt"></i>
              {BUSINESS_INFO.name}
            </h1>
            <p className="text-indigo-100 text-sm mt-1">{BUSINESS_INFO.address}</p>
          </div>
          <div className="flex items-center gap-4">
            <a 
              href={BUSINESS_INFO.facebook} 
              target="_blank" 
              rel="noopener noreferrer"
              className="bg-white text-indigo-700 px-4 py-2 rounded-full font-semibold hover:bg-indigo-50 transition-colors flex items-center gap-2"
            >
              <i className="fab fa-facebook"></i>
              Facebook Page
            </a>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow max-w-6xl mx-auto w-full p-4 md:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Left: Bus View */}
        <div className="lg:col-span-7 bg-white rounded-3xl shadow-xl border border-gray-100 p-6 md:p-10">
          <div className="mb-8 flex flex-wrap justify-between items-end gap-4">
            <div>
              <h2 className="text-2xl font-bold text-gray-800">Seat Selection</h2>
              <p className="text-gray-500 text-sm">Select an available seat to start booking</p>
            </div>

            {/* Color Legend */}
            <div className="flex flex-wrap gap-4 text-xs font-medium text-gray-600">
              <div className="flex items-center gap-1.5">
                <div className="w-4 h-4 bg-green-500 rounded-sm"></div>
                <span>Available</span>
              </div>
              <div className="flex items-center gap-1.5">
                <div className="w-4 h-4 bg-red-500 rounded-sm"></div>
                <span>Booked (Male/Muslim)</span>
              </div>
              <div className="flex items-center gap-1.5">
                <div className="w-4 h-4 bg-pink-500 rounded-sm"></div>
                <span>Female</span>
              </div>
              <div className="flex items-center gap-1.5">
                <div className="w-4 h-4 bg-blue-500 rounded-sm"></div>
                <span>Non-Muslim</span>
              </div>
              <div className="flex items-center gap-1.5">
                <div className="w-4 h-4 bg-yellow-500 rounded-sm"></div>
                <span>Female Non-Muslim</span>
              </div>
            </div>
          </div>

          <BusLayout seats={seats} onSeatClick={handleSeatClick} />
        </div>

        {/* Right: Summary or Quick Stats */}
        <div className="lg:col-span-5 flex flex-col gap-6">
          <div className="bg-white rounded-3xl shadow-lg border border-gray-100 p-6">
            <h3 className="text-xl font-bold mb-4 text-gray-800">Booking Summary</h3>
            <div className="space-y-4">
              <div className="flex justify-between p-3 bg-gray-50 rounded-xl">
                <span className="text-gray-600">Total Capacity</span>
                <span className="font-bold">{seats.length} Seats</span>
              </div>
              <div className="flex justify-between p-3 bg-green-50 rounded-xl">
                <span className="text-green-700">Available</span>
                <span className="font-bold text-green-700">{seats.filter(s => !s.isBooked).length} Seats</span>
              </div>
              <div className="flex justify-between p-3 bg-red-50 rounded-xl">
                <span className="text-red-700">Booked</span>
                <span className="font-bold text-red-700">{seats.filter(s => s.isBooked).length} Seats</span>
              </div>
            </div>
          </div>

          <div className="bg-indigo-50 rounded-3xl p-6 border border-indigo-100">
            <h4 className="font-bold text-indigo-900 mb-2">Instructions</h4>
            <ul className="text-sm text-indigo-800 space-y-2 list-disc pl-4">
              <li>Click on a <span className="text-green-600 font-bold">Green</span> seat to enter booking details.</li>
              <li>Hover over a booked seat to see passenger info.</li>
              <li>Click on a booked seat to cancel or edit (confirmation required).</li>
              <li>Pricing updates automatically based on discount and advance amounts.</li>
            </ul>
          </div>
        </div>
      </main>

      {/* Footer */}
      <footer className="bg-gray-100 py-6 px-4 text-center text-gray-500 text-sm border-t border-gray-200">
        <p>&copy; {new Date().getFullYear()} {BUSINESS_INFO.name}. All rights reserved.</p>
        <p className="mt-1">Authorized Agency: {Object.values(BookingAgent).join(', ')}</p>
      </footer>

      {/* Modals */}
      {showBookingModal && (
        <BookingModal 
          seatId={selectedSeatId!} 
          onClose={() => {
            setShowBookingModal(false);
            setSelectedSeatId(null);
          }} 
          onSubmit={handleBookingSubmit}
        />
      )}

      {showConfirmDeselect && (
        <ConfirmationDialog 
          message="Are you sure you want to deselect this seat? All booking information will be lost."
          onConfirm={confirmDeselect}
          onCancel={() => {
            setShowConfirmDeselect(false);
            setSeatToDeselect(null);
          }}
        />
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { SeatData } from '../types';
import Seat from './Seat';

interface BusLayoutProps {
  seats: SeatData[];
  onSeatClick: (id: string) => void;
}

const BusLayout: React.FC<BusLayoutProps> = ({ seats, onSeatClick }) => {
  const rows = ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H', 'I', 'J'];
  const lastRow = 'K';

  return (
    <div className="relative mx-auto max-w-[400px] bg-gray-50 border-8 border-gray-800 rounded-t-[50px] rounded-b-[20px] p-6 pt-16 shadow-inner">
      {/* Driver Section */}
      <div className="absolute top-4 right-8 text-gray-400">
        <div className="w-10 h-10 border-4 border-gray-400 rounded-full flex items-center justify-center">
          <i className="fas fa-steering-wheel"></i>
        </div>
        <span className="text-[10px] uppercase font-bold tracking-widest mt-1 block">Driver</span>
      </div>

      <div className="space-y-4">
        {/* Rows A to J */}
        {rows.map((row) => {
          const rowSeats = seats.filter(s => s.id.startsWith(row));
          return (
            <div key={row} className="flex justify-between items-center">
              {/* Left Side (A1, A2) */}
              <div className="flex gap-3">
                {rowSeats.slice(0, 2).map(seat => (
                  <Seat key={seat.id} data={seat} onClick={() => onSeatClick(seat.id)} />
                ))}
              </div>

              {/* Aisle */}
              <div className="w-8 h-8 flex items-center justify-center text-[10px] font-bold text-gray-300">
                {row}
              </div>

              {/* Right Side (A3, A4) */}
              <div className="flex gap-3">
                {rowSeats.slice(2, 4).map(seat => (
                  <Seat key={seat.id} data={seat} onClick={() => onSeatClick(seat.id)} />
                ))}
              </div>
            </div>
          );
        })}

        {/* Last Row K (5 seats) */}
        <div className="flex justify-between gap-1 mt-6 border-t pt-4">
          {seats.filter(s => s.id.startsWith(lastRow)).map(seat => (
            <Seat key={seat.id} data={seat} onClick={() => onSeatClick(seat.id)} />
          ))}
        </div>
      </div>
    </div>
  );
};

export default BusLayout;

import React, { useState } from 'react';
import { SeatData, Gender, Religion } from '../types';

interface SeatProps {
  data: SeatData;
  onClick: () => void;
}

const Seat: React.FC<SeatProps> = ({ data, onClick }) => {
  const [isHovered, setIsHovered] = useState(false);

  const getSeatColor = () => {
    if (!data.isBooked) return 'bg-green-500 hover:bg-green-600';

    const info = data.bookingInfo!;
    const isFemale = info.gender === Gender.FEMALE;
    const isMuslim = info.religion === Religion.MUSLIM;

    if (isFemale && !isMuslim) return 'bg-yellow-500 hover:bg-yellow-600'; // Gold
    if (isFemale) return 'bg-pink-500 hover:bg-pink-600';
    if (!isMuslim) return 'bg-blue-500 hover:bg-blue-600';

    return 'bg-red-500 hover:bg-red-600'; // Male Muslim or Generic Booked
  };

  return (
    <div 
      className="relative"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <button
        onClick={onClick}
        className={`${getSeatColor()} w-10 h-10 md:w-11 md:h-11 rounded-lg flex items-center justify-center text-white text-xs font-bold transition-all shadow-md transform active:scale-95`}
        title={data.isBooked ? `Booked for ${data.bookingInfo?.name}` : `Seat ${data.id} is available`}
      >
        {data.id}
      </button>

      {/* Tooltip on Hover */}
      {isHovered && data.isBooked && data.bookingInfo && (
        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 z-50 w-48 bg-gray-900 text-white p-3 rounded-xl shadow-2xl text-xs seat-tooltip">
          <div className="font-bold text-indigo-300 border-b border-gray-700 pb-1 mb-1 flex justify-between">
            <span>Seat {data.id}</span>
            <span className="text-[10px] text-gray-400">Agent: {data.bookingInfo.bookedBy}</span>
          </div>
          <div className="space-y-1">
            <p><span className="text-gray-400">Name:</span> {data.bookingInfo.name}</p>
            <p><span className="text-gray-400">Phone:</span> +880{data.bookingInfo.phone}</p>
            <p><span className="text-gray-400">Gender:</span> {data.bookingInfo.gender}</p>
            <p><span className="text-gray-400">Religion:</span> {data.bookingInfo.religion}</p>
            <div className="pt-1 mt-1 border-t border-gray-700">
              <p className="flex justify-between"><span>Total:</span> <span>৳{data.bookingInfo.totalFees}</span></p>
              <p className="flex justify-between font-bold text-red-400"><span>Due:</span> <span>৳{data.bookingInfo.dueAmount}</span></p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Seat;

import React, { useState, useEffect } from 'react';
import { BookingInfo, Gender, Religion, BookingAgent } from '../types';
import { BUSINESS_INFO } from '../constants';

interface BookingModalProps {
  seatId: string;
  onClose: () => void;
  onSubmit: (info: BookingInfo) => void;
}

const BookingModal: React.FC<BookingModalProps> = ({ seatId, onClose, onSubmit }) => {
  const [formData, setFormData] = useState<Omit<BookingInfo, 'dueAmount'>>({
    name: '',
    phone: '',
    gender: Gender.MALE,
    religion: Religion.MUSLIM,
    totalFees: 0,
    discountPercentage: 0,
    advanceAmount: 0,
    bookedBy: BookingAgent.KAZI_SHETU
  });

  const [dueAmount, setDueAmount] = useState(0);

  useEffect(() => {
    // Logic: Due = (Total - Discount) - Advance
    // Note: The prompt's formula ({Total Amount - Discont } + Advence Amount= Due Amount) 
    // is interpreted as a typo for standard business logic.
    const discountedTotal = formData.totalFees * (1 - formData.discountPercentage / 100);
    const calculatedDue = discountedTotal - formData.advanceAmount;
    setDueAmount(calculatedDue);
  }, [formData.totalFees, formData.discountPercentage, formData.advanceAmount]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: (name === 'totalFees' || name === 'discountPercentage' || name === 'advanceAmount') 
        ? Number(value) 
        : value
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit({ ...formData, dueAmount });
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
      <div className="bg-white w-full max-w-lg rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
        <div className="bg-indigo-700 p-6 text-white flex justify-between items-center">
          <div>
            <h3 className="text-xl font-bold">Book Seat {seatId}</h3>
            <p className="text-indigo-200 text-xs">Enter passenger details to confirm booking</p>
          </div>
          <button 
            onClick={onClose}
            className="w-10 h-10 rounded-full bg-white/10 hover:bg-white/20 flex items-center justify-center transition-colors"
          >
            <i className="fas fa-times"></i>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4 max-h-[80vh] overflow-y-auto">
          {/* Row 1: Name */}
          <div>
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Passenger Name</label>
            <input 
              required
              type="text" 
              name="name" 
              value={formData.name}
              onChange={handleChange}
              placeholder="e.g. John Doe"
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
            />
          </div>

          {/* Row 2: Phone */}
          <div>
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Phone Number</label>
            <div className="relative">
              <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 font-medium">
                {BUSINESS_INFO.phonePrefix}
              </span>
              <input 
                required
                type="tel" 
                name="phone"
                value={formData.phone}
                onChange={handleChange}
                placeholder="01XXXXXXXXX"
                className="w-full pl-16 pr-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
              />
            </div>
          </div>

          {/* Row 3: Gender & Religion */}
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Gender</label>
              <select 
                name="gender"
                value={formData.gender}
                onChange={handleChange}
                className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                {Object.values(Gender).map(g => <option key={g} value={g}>{g}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Religion</label>
              <select 
                name="religion"
                value={formData.religion}
                onChange={handleChange}
                className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                {Object.values(Religion).map(r => <option key={r} value={r}>{r}</option>)}
              </select>
            </div>
          </div>

          {/* Row 4: Pricing */}
          <div className="grid grid-cols-2 gap-4 p-4 bg-gray-50 rounded-2xl border border-gray-100">
            <div>
              <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Total Fees (৳)</label>
              <input 
                required
                type="number" 
                name="totalFees"
                value={formData.totalFees || ''}
                onChange={handleChange}
                className="w-full px-3 py-2 rounded-lg border border-gray-200 text-sm"
              />
            </div>
            <div>
              <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Discount (%)</label>
              <input 
                type="number" 
                name="discountPercentage"
                value={formData.discountPercentage || ''}
                onChange={handleChange}
                className="w-full px-3 py-2 rounded-lg border border-gray-200 text-sm"
              />
            </div>
            <div>
              <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Advance (৳)</label>
              <input 
                type="number" 
                name="advanceAmount"
                value={formData.advanceAmount || ''}
                onChange={handleChange}
                className="w-full px-3 py-2 rounded-lg border border-gray-200 text-sm"
              />
            </div>
            <div className="flex flex-col justify-end">
              <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1">Due Amount</label>
              <div className="w-full px-3 py-2 rounded-lg bg-indigo-100 text-indigo-700 font-bold text-sm">
                ৳{dueAmount.toLocaleString()}
              </div>
            </div>
          </div>

          {/* Row 5: Agent */}
          <div>
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Booked By Agent</label>
            <select 
              name="bookedBy"
              value={formData.bookedBy}
              onChange={handleChange}
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 outline-none"
            >
              {Object.values(BookingAgent).map(a => <option key={a} value={a}>{a}</option>)}
            </select>
          </div>

          <button 
            type="submit"
            className="w-full py-4 bg-indigo-700 text-white rounded-2xl font-bold hover:bg-indigo-800 shadow-lg shadow-indigo-200 transition-all mt-4"
          >
            Confirm Booking
          </button>
        </form>
      </div>
    </div>
  );
};

export default BookingModal;

import React from 'react';

interface ConfirmationDialogProps {
  message: string;
  onConfirm: () => void;
  onCancel: () => void;
}

const ConfirmationDialog: React.FC<ConfirmationDialogProps> = ({ message, onConfirm, onCancel }) => {
  return (
    <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
      <div className="bg-white w-full max-w-sm rounded-3xl shadow-2xl p-6 text-center animate-in fade-in zoom-in duration-200">
        <div className="w-16 h-16 bg-red-100 text-red-600 rounded-full flex items-center justify-center mx-auto mb-4 text-2xl">
          <i className="fas fa-exclamation-triangle"></i>
        </div>
        <h3 className="text-xl font-bold text-gray-800 mb-2">Are you sure?</h3>
        <p className="text-gray-500 mb-6">{message}</p>
        <div className="flex gap-3">
          <button 
            onClick={onCancel}
            className="flex-1 py-3 border border-gray-200 text-gray-600 rounded-2xl font-bold hover:bg-gray-50 transition-colors"
          >
            Cancel
          </button>
          <button 
            onClick={onConfirm}
            className="flex-1 py-3 bg-red-600 text-white rounded-2xl font-bold hover:bg-red-700 shadow-lg shadow-red-100 transition-colors"
          >
            Confirm
          </button>
        </div>
      </div>
    </div>
  );
};

export default ConfirmationDialog;

export enum Gender {
  MALE = 'Male',
  FEMALE = 'Female',
  OTHERS = 'Others'
}

export enum Religion {
  MUSLIM = 'Muslim',
  HINDUISM = 'Hinduism',
  BUDDHISM = 'Buddhism',
  CHRISTIANITY = 'Christianity',
  OTHERS = 'Others'
}

export interface BookingInfo {
  id: string; // Unique booking ID
  name: string;
  mobile: string;
  address: string;
  gender: Gender;
  religion: Religion;
  tourName: string;
  tourFees: number;
  customerType?: string;
  customerTypeFees: number;
  discountAmount: number;
  advanceAmount: number;
  dueAmount: number;
  paymentStatus: 'Paid' | 'Partial' | 'Due';
  busNo: string;
  seatNo: string;
  bookedBy: string; // Booker Name
  bookerCode: string;
  bookingDate: string;
}

export interface SeatData {
  id: string; // e.g., 'A1'
  isBooked: boolean;
  bookingInfo?: BookingInfo;
}

export interface BusData {
  busId: string;
  seats: SeatData[];
}

export interface Tour {
  name: string;
  fee: number;
}

export interface Booker {
  code: string;
  name: string;
}

export interface CustomerType {
  type: string;
  fee: number;
}

