  motto: "আপনার বিশস্থ ভ্রমণ সঙ্গী",
  logo: "https://i.ibb.co/gb4jzgXj/Orange-and-Blue-Travel-Agency-Logo-1-1.png",
  address: "Kazi Genarel Store, Hindu Barir Mor, Borad Bazar, Gazipur",
  facebook: "https://www.facebook.com/tourlagbee",
  phonePrefix: "+880"
};

export const TOURS: Tour[] = [
  { name: "Sajek Valley", fee: 4500 },
  { name: "Cox's Bazar Relax", fee: 6500 },
  { name: "Sylhet Tea Garden", fee: 3500 },
  { name: "Saint Martin Relax", fee: 8500 },
  { name: "Sundarban Adventure", fee: 5500 }
];

export const BOOKERS: Booker[] = [
  { code: "KS101", name: "Kazi Shetu" },
  { code: "SI202", name: "Sadekul Islam" },
  { code: "AH303", name: "Akramul Haque" },
  { code: "MH404", name: "MD. Hanjela" },
  { code: "KA505", name: "Khursed Alam" },
  { code: "MR606", name: "Masud Rana" }
];

export const CUSTOMER_TYPES: CustomerType[] = [
  { type: "Standard", fee: 0 },
  { type: "Solo", fee: 1500 },
  { type: "Couple", fee: 0 }
];

const rows = ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H', 'I', 'J'];
const lastRow = 'K';

export const generateInitialSeats = (): SeatData[] => {
  const seats: SeatData[] = [];
  rows.forEach(row => {
    for (let i = 1; i <= 4; i++) {
      seats.push({ id: `${row}${i}`, isBooked: false });
    }
  });
  for (let i = 1; i <= 5; i++) {
    seats.push({ id: `${lastRow}${i}`, isBooked: false });
  }
  return seats;
};

import React, { useState, useEffect } from 'react';
import { BUSINESS_INFO, generateInitialSeats, BOOKERS } from './constants';
import { BusData, BookingInfo, SeatData } from './types';
import BusLayout from './components/BusLayout';
import BookingModal from './components/BookingModal';
import ConfirmationDialog from './components/ConfirmationDialog';
import Dashboard from './components/Dashboard';
import BookingLog from './components/BookingLog';
import EditData from './components/EditData';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'booking' | 'dashboard' | 'log' | 'edit'>('booking');
  const [selectedBusIndex, setSelectedBusIndex] = useState(0);
  const [buses, setBuses] = useState<BusData[]>(() => {
    const saved = localStorage.getItem('tour_lagbe_buses');
    if (saved) return JSON.parse(saved);
    return Array.from({ length: 10 }, (_, i) => ({
      busId: `Bus-${i + 1}`,
      seats: generateInitialSeats()
    }));
  });

  const [selectedSeatId, setSelectedSeatId] = useState<string | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [showConfirmDeselect, setShowConfirmDeselect] = useState(false);
  const [seatToDeselect, setSeatToDeselect] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem('tour_lagbe_buses', JSON.stringify(buses));
  }, [buses]);

  const handleSeatClick = (seatId: string) => {
    const seat = buses[selectedBusIndex].seats.find(s => s.id === seatId);
    if (seat?.isBooked) {
      setSeatToDeselect(seatId);
      setShowConfirmDeselect(true);
    } else {
      setSelectedSeatId(seatId);
      setShowBookingModal(true);
    }
  };

  const handleBookingSubmit = (info: BookingInfo) => {
    setBuses(prev => {
      const newBuses = [...prev];
      const bus = { ...newBuses[selectedBusIndex] };
      bus.seats = bus.seats.map(s => 
        s.id === selectedSeatId ? { ...s, isBooked: true, bookingInfo: info } : s
      );
      newBuses[selectedBusIndex] = bus;
      return newBuses;
    });
    setShowBookingModal(false);
    setSelectedSeatId(null);
  };

  const confirmDeselect = () => {
    if (seatToDeselect) {
      setBuses(prev => {
        const newBuses = [...prev];
        const bus = { ...newBuses[selectedBusIndex] };
        bus.seats = bus.seats.map(s => 
          s.id === seatToDeselect ? { ...s, isBooked: false, bookingInfo: undefined } : s
        );
        newBuses[selectedBusIndex] = bus;
        return newBuses;
      });
    }
    setShowConfirmDeselect(false);
    setSeatToDeselect(null);
  };

  const updateBooking = (updatedInfo: BookingInfo) => {
    setBuses(prev => {
      return prev.map(bus => ({
        ...bus,
        seats: bus.seats.map(seat => 
          seat.bookingInfo?.id === updatedInfo.id 
            ? { ...seat, bookingInfo: updatedInfo } 
            : seat
        )
      }));
    });
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row">
      {/* Sidebar Navigation */}
      <nav className="w-full md:w-64 bg-indigo-900 text-white flex flex-col shadow-2xl z-20">
        <div className="p-6 text-center border-b border-indigo-800">
          <img src={BUSINESS_INFO.logo} alt="Logo" className="w-24 mx-auto mb-2" />
          <h1 className="text-xl font-bold">{BUSINESS_INFO.name}</h1>
          <p className="text-[10px] text-indigo-300 uppercase tracking-tighter">{BUSINESS_INFO.motto}</p>
        </div>

        <div className="flex-grow py-4 space-y-1">
          <button 
            onClick={() => setActiveTab('dashboard')}
            className={`w-full flex items-center gap-3 px-6 py-3 text-sm font-medium transition-colors ${activeTab === 'dashboard' ? 'bg-indigo-700 text-white' : 'text-indigo-200 hover:bg-indigo-800'}`}
          >
            <i className="fas fa-chart-pie w-5"></i> Dashboard
          </button>
          <button 
            onClick={() => setActiveTab('booking')}
            className={`w-full flex items-center gap-3 px-6 py-3 text-sm font-medium transition-colors ${activeTab === 'booking' ? 'bg-indigo-700 text-white' : 'text-indigo-200 hover:bg-indigo-800'}`}
          >
            <i className="fas fa-bus w-5"></i> Seat Booking
          </button>
          <button 
            onClick={() => setActiveTab('log')}
            className={`w-full flex items-center gap-3 px-6 py-3 text-sm font-medium transition-colors ${activeTab === 'log' ? 'bg-indigo-700 text-white' : 'text-indigo-200 hover:bg-indigo-800'}`}
          >
            <i className="fas fa-list-ul w-5"></i> Booking Log
          </button>
          <button 
            onClick={() => setActiveTab('edit')}
            className={`w-full flex items-center gap-3 px-6 py-3 text-sm font-medium transition-colors ${activeTab === 'edit' ? 'bg-indigo-700 text-white' : 'text-indigo-200 hover:bg-indigo-800'}`}
          >
            <i className="fas fa-edit w-5"></i> Edit Data
          </button>
        </div>

        <div className="p-6 text-[10px] text-indigo-400 border-t border-indigo-800">
          {BUSINESS_INFO.address}
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-grow overflow-auto p-4 md:p-8">
        {activeTab === 'booking' && (
          <div className="max-w-5xl mx-auto animate-in fade-in duration-300">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
              <div>
                <h2 className="text-2xl font-bold text-gray-800">Bus Selection</h2>
                <p className="text-sm text-gray-500">Pick a bus to manage its seats</p>
              </div>
              <div className="flex items-center gap-3 bg-white p-2 rounded-xl shadow-sm border border-gray-100">
                <span className="text-sm font-bold text-indigo-700 ml-2">Select Bus:</span>
                <select 
                  value={selectedBusIndex} 
                  onChange={(e) => setSelectedBusIndex(Number(e.target.value))}
                  className="bg-gray-50 border-none text-sm font-bold rounded-lg focus:ring-0 p-2 cursor-pointer"
                >
                  {buses.map((bus, idx) => (
                    <option key={bus.busId} value={idx}>{bus.busId}</option>
                  ))}
                </select>
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
              <div className="lg:col-span-7 bg-white rounded-3xl shadow-xl p-8 border border-gray-100">
                <BusLayout seats={buses[selectedBusIndex].seats} onSeatClick={handleSeatClick} />
              </div>
              <div className="lg:col-span-5 space-y-6">
                 <div className="bg-white rounded-3xl p-6 shadow-lg border border-gray-100">
                    <h3 className="font-bold text-gray-800 mb-4 flex items-center gap-2">
                      <i className="fas fa-info-circle text-indigo-500"></i> Seat Legend
                    </h3>
                    <div className="grid grid-cols-2 gap-3 text-xs">
                       <div className="flex items-center gap-2"><div className="w-3 h-3 bg-green-500 rounded-full"></div> Available</div>
                       <div className="flex items-center gap-2"><div className="w-3 h-3 bg-red-500 rounded-full"></div> Male Booked</div>
                       <div className="flex items-center gap-2"><div className="w-3 h-3 bg-pink-500 rounded-full"></div> Female</div>
                       <div className="flex items-center gap-2"><div className="w-3 h-3 bg-blue-500 rounded-full"></div> Non-Muslim</div>
                       <div className="flex items-center gap-2"><div className="w-3 h-3 bg-yellow-500 rounded-full"></div> Non-Muslim Female</div>
                    </div>
                 </div>
                 <div className="bg-indigo-50 rounded-3xl p-6 border border-indigo-100">
                    <p className="text-xs text-indigo-800 leading-relaxed font-medium">
                      Total Seats Booked in {buses[selectedBusIndex].busId}: <span className="text-lg font-bold">{buses[selectedBusIndex].seats.filter(s => s.isBooked).length}</span>
                    </p>
                 </div>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'dashboard' && <Dashboard buses={buses} />}
        {activeTab === 'log' && <BookingLog buses={buses} />}
        {activeTab === 'edit' && <EditData buses={buses} onUpdate={updateBooking} />}
      </main>

      {showBookingModal && (
        <BookingModal 
          seatId={selectedSeatId!} 
          busNo={buses[selectedBusIndex].busId}
          onClose={() => { setShowBookingModal(false); setSelectedSeatId(null); }} 
          onSubmit={handleBookingSubmit}
        />
      )}

      {showConfirmDeselect && (
        <ConfirmationDialog 
          message="Are you sure you want to deselect this seat? All booking data will be removed."
          onConfirm={confirmDeselect}
          onCancel={() => { setShowConfirmDeselect(false); setSeatToDeselect(null); }}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { BookingInfo, Gender, Religion, Tour, CustomerType, Booker } from '../types';
import { BUSINESS_INFO, TOURS, CUSTOMER_TYPES, BOOKERS } from '../constants';

interface BookingModalProps {
  seatId: string;
  busNo: string;
  onClose: () => void;
  onSubmit: (info: BookingInfo) => void;
}

const BookingModal: React.FC<BookingModalProps> = ({ seatId, busNo, onClose, onSubmit }) => {
  const [formData, setFormData] = useState({
    name: '',
    mobile: '',
    address: '',
    gender: Gender.MALE,
    religion: Religion.MUSLIM,
    tourName: TOURS[0].name,
    customerType: 'Standard',
    discountAmount: 0,
    advanceAmount: 0,
    bookerCode: ''
  });

  const [tourFees, setTourFees] = useState(TOURS[0].fee);
  const [customerTypeFees, setCustomerTypeFees] = useState(0);
  const [dueAmount, setDueAmount] = useState(0);
  const [isRelaxTour, setIsRelaxTour] = useState(false);
  const [bookerName, setBookerName] = useState('');

  // Auto-calculations
  useEffect(() => {
    const tour = TOURS.find(t => t.name === formData.tourName);
    const fee = tour ? tour.fee : 0;
    setTourFees(fee);
    setIsRelaxTour(formData.tourName.toLowerCase().includes('relax'));

    const cType = CUSTOMER_TYPES.find(c => c.type === formData.customerType);
    const cFee = cType ? cType.fee : 0;
    setCustomerTypeFees(cFee);

    const booker = BOOKERS.find(b => b.code === formData.bookerCode);
    setBookerName(booker ? booker.name : '');

    const total = fee + cFee;
    const due = total - formData.discountAmount - formData.advanceAmount;
    setDueAmount(due);
  }, [formData]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleNumericChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: Number(value) }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!bookerName) {
      alert("Invalid Booker Code! Please enter a correct code from your agent list.");
      return;
    }

    const info: BookingInfo = {
      id: Math.random().toString(36).substr(2, 9).toUpperCase(),
      ...formData,
      tourFees,
      customerTypeFees,
      dueAmount,
      paymentStatus: dueAmount <= 0 ? 'Paid' : (formData.advanceAmount > 0 ? 'Partial' : 'Due'),
      busNo,
      seatNo: seatId,
      bookedBy: bookerName,
      bookingDate: new Date().toISOString()
    };
    onSubmit(info);
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm overflow-y-auto">
      <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl my-auto animate-in fade-in zoom-in duration-200 overflow-hidden">
        <div className="bg-orange-500 p-6 text-white flex justify-between items-center">
          <div>
            <h3 className="text-xl font-bold">Booking Seat {seatId} - {busNo}</h3>
            <p className="text-orange-100 text-xs uppercase font-bold tracking-widest">{BUSINESS_INFO.motto}</p>
          </div>
          <button onClick={onClose} className="w-10 h-10 rounded-full bg-white/20 hover:bg-white/30 transition-colors flex items-center justify-center">
             <i className="fas fa-times"></i>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 grid grid-cols-1 md:grid-cols-2 gap-6 max-h-[75vh] overflow-y-auto">
          {/* Passenger Info */}
          <div className="space-y-4">
            <h4 className="font-bold text-gray-400 text-[10px] uppercase border-b pb-2">Passenger Information</h4>
            <div>
              <label className="block text-xs font-bold text-gray-500 mb-1">Full Name</label>
              <input required name="name" value={formData.name} onChange={handleChange} className="w-full px-4 py-2 bg-gray-50 border rounded-xl focus:ring-2 focus:ring-orange-500 outline-none" placeholder="John Doe" />
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-500 mb-1">Mobile (+880)</label>
              <div className="relative">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">+880</span>
                <input required name="mobile" value={formData.mobile} onChange={handleChange} className="w-full pl-16 pr-4 py-2 bg-gray-50 border rounded-xl focus:ring-2 focus:ring-orange-500 outline-none" placeholder="17XXXXXXXX" />
              </div>
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-500 mb-1">Address</label>
              <textarea name="address" value={formData.address} onChange={handleChange} rows={2} className="w-full px-4 py-2 bg-gray-50 border rounded-xl focus:ring-2 focus:ring-orange-500 outline-none" placeholder="Complete Address" />
            </div>
            <div className="grid grid-cols-2 gap-3">
               <div>
                  <label className="block text-xs font-bold text-gray-500 mb-1">Gender</label>
                  <select name="gender" value={formData.gender} onChange={handleChange} className="w-full px-3 py-2 bg-gray-50 border rounded-xl outline-none">
                    {Object.values(Gender).map(g => <option key={g} value={g}>{g}</option>)}
                  </select>
               </div>
               <div>
                  <label className="block text-xs font-bold text-gray-500 mb-1">Religion</label>
                  <select name="religion" value={formData.religion} onChange={handleChange} className="w-full px-3 py-2 bg-gray-50 border rounded-xl outline-none">
                    {Object.values(Religion).map(r => <option key={r} value={r}>{r}</option>)}
                  </select>
               </div>
            </div>
          </div>

          {/* Tour & Fees Info */}
          <div className="space-y-4">
            <h4 className="font-bold text-gray-400 text-[10px] uppercase border-b pb-2">Tour & Financials</h4>
            <div>
              <label className="block text-xs font-bold text-gray-500 mb-1">Select Tour</label>
              <select name="tourName" value={formData.tourName} onChange={handleChange} className="w-full px-4 py-2 bg-gray-50 border rounded-xl font-bold text-indigo-700">
                {TOURS.map(t => <option key={t.name} value={t.name}>{t.name} (৳{t.fee})</option>)}
              </select>
            </div>

            {isRelaxTour && (
              <div className="animate-in slide-in-from-top-2 duration-300">
                <label className="block text-xs font-bold text-gray-500 mb-1">Customer Type (Relax Only)</label>
                <select name="customerType" value={formData.customerType} onChange={handleChange} className="w-full px-4 py-2 bg-indigo-50 border-indigo-200 border rounded-xl font-bold text-indigo-800">
                  {CUSTOMER_TYPES.map(c => <option key={c.type} value={c.type}>{c.type} {c.fee > 0 ? `(+৳${c.fee})` : ''}</option>)}
                </select>
              </div>
            )}

            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="block text-xs font-bold text-gray-500 mb-1">Discount (৳)</label>
                <input type="number" name="discountAmount" value={formData.discountAmount || ''} onChange={handleNumericChange} className="w-full px-4 py-2 bg-gray-50 border rounded-xl" />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-500 mb-1">Advance (৳)</label>
                <input type="number" name="advanceAmount" value={formData.advanceAmount || ''} onChange={handleNumericChange} className="w-full px-4 py-2 bg-gray-50 border rounded-xl" />
              </div>
            </div>

            <div className="p-4 bg-orange-50 border border-orange-100 rounded-2xl">
               <div className="flex justify-between text-sm mb-1"><span>Total Payable:</span> <span className="font-bold text-indigo-900">৳{(tourFees + customerTypeFees).toLocaleString()}</span></div>
               <div className="flex justify-between text-lg font-black pt-2 border-t border-orange-200 mt-2">
                 <span className="text-gray-600">DUE AMOUNT:</span>
                 <span className="text-red-600">৳{dueAmount.toLocaleString()}</span>
               </div>
            </div>

            <div>
              <label className="block text-xs font-bold text-gray-500 mb-1">Booker Code (Mandatory)</label>
              <div className="relative">
                <input required name="bookerCode" value={formData.bookerCode} onChange={handleChange} className={`w-full px-4 py-2 border rounded-xl focus:ring-2 outline-none ${bookerName ? 'border-green-300 focus:ring-green-400' : 'border-gray-200 focus:ring-orange-400'}`} placeholder="Agent Code" />
                {bookerName && <span className="absolute right-4 top-1/2 -translate-y-1/2 text-[10px] font-bold text-green-600 bg-green-50 px-2 py-1 rounded">By {bookerName}</span>}
              </div>
            </div>
          </div>

          <div className="md:col-span-2 pt-4">
            <button type="submit" className="w-full py-4 bg-orange-500 text-white rounded-2xl font-bold text-lg hover:bg-orange-600 shadow-xl shadow-orange-100 transition-all flex items-center justify-center gap-2">
              <i className="fas fa-check-circle"></i> Complete Entry
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default BookingModal;

import React from 'react';
import { BusData, BookingInfo } from '../types';

interface DashboardProps {
  buses: BusData[];
}

const Dashboard: React.FC<DashboardProps> = ({ buses }) => {
  const allBookings: BookingInfo[] = buses.flatMap(b => b.seats.filter(s => s.isBooked).map(s => s.bookingInfo!));

  const totalRevenue = allBookings.reduce((sum, b) => sum + (b.tourFees + b.customerTypeFees - b.discountAmount), 0);
  const totalAdvance = allBookings.reduce((sum, b) => sum + b.advanceAmount, 0);
  const totalDue = allBookings.reduce((sum, b) => sum + b.dueAmount, 0);

  const stats = [
    { label: 'Total Seats', value: buses.length * 45, icon: 'fa-chair', color: 'bg-blue-500' },
    { label: 'Total Bookings', value: allBookings.length, icon: 'fa-user-check', color: 'bg-green-500' },
    { label: 'Total Collected', value: `৳${totalAdvance.toLocaleString()}`, icon: 'fa-money-bill-wave', color: 'bg-orange-500' },
    { label: 'Outstanding Due', value: `৳${totalDue.toLocaleString()}`, icon: 'fa-exclamation-circle', color: 'bg-red-500' },
  ];

  return (
    <div className="space-y-8 animate-in slide-in-from-bottom-4 duration-500">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 flex items-center gap-5 hover:shadow-md transition-shadow">
            <div className={`${stat.color} w-14 h-14 rounded-2xl flex items-center justify-center text-white text-xl shadow-lg shadow-gray-100`}>
               <i className={`fas ${stat.icon}`}></i>
            </div>
            <div>
              <p className="text-xs font-bold text-gray-400 uppercase tracking-wider">{stat.label}</p>
              <h4 className="text-2xl font-black text-gray-800">{stat.value}</h4>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100">
          <h3 className="text-xl font-bold mb-6 flex items-center gap-2">
            <i className="fas fa-bus-alt text-indigo-500"></i> Bus-wise Occupancy
          </h3>
          <div className="space-y-4">
             {buses.map(bus => {
               const bookedCount = bus.seats.filter(s => s.isBooked).length;
               const percent = Math.round((bookedCount / bus.seats.length) * 100);
               return (
                 <div key={bus.busId}>
                    <div className="flex justify-between text-xs font-bold mb-1">
                      <span className="text-gray-600">{bus.busId}</span>
                      <span className="text-indigo-600">{bookedCount}/{bus.seats.length} ({percent}%)</span>
                    </div>
                    <div className="w-full bg-gray-100 h-2.5 rounded-full overflow-hidden">
                       <div className="bg-indigo-500 h-full transition-all duration-1000" style={{ width: `${percent}%` }}></div>
                    </div>
                 </div>
               )
             })}
          </div>
        </div>

        <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100 flex flex-col items-center justify-center text-center">
