import React, { useState } from 'react';
import { BusData, BookingInfo } from '../types';
import { BOOKERS } from '../constants';

interface EditDataProps {
  buses: BusData[];
  onUpdate: (info: BookingInfo) => void;
}

const EditData: React.FC<EditDataProps> = ({ buses, onUpdate }) => {
  const [accessCode, setAccessCode] = useState('');
  const [isUnlocked, setIsUnlocked] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [editingItem, setEditingItem] = useState<BookingInfo | null>(null);

  const handleUnlock = () => {
    if (BOOKERS.some(b => b.code === accessCode)) {
      setIsUnlocked(true);
    } else {
      alert("Unauthorized Booker Code!");
    }
  };

  const allBookings: BookingInfo[] = buses.flatMap(b => b.seats.filter(s => s.isBooked).map(s => s.bookingInfo!));
  const filtered = allBookings.filter(b => b.name.toLowerCase().includes(searchQuery.toLowerCase()) || b.mobile.includes(searchQuery));

  if (!isUnlocked) {
    return (
      <div className="max-w-md mx-auto mt-20 bg-white p-8 rounded-3xl shadow-2xl border text-center animate-in zoom-in duration-300">
        <div className="w-20 h-20 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center mx-auto mb-6 text-3xl shadow-inner">
          <i className="fas fa-lock"></i>
        </div>
        <h3 className="text-2xl font-black text-gray-800 mb-2">Editor Access</h3>
        <p className="text-sm text-gray-500 mb-8">Please verify your agent booker code to access the database management tools.</p>
        <div className="space-y-4">
           <input 
            type="text" 
            placeholder="Enter Booker Code" 
            className="w-full px-6 py-4 bg-gray-50 border rounded-2xl outline-none focus:ring-4 focus:ring-indigo-100 transition-all font-bold text-center"
            value={accessCode}
            onChange={(e) => setAccessCode(e.target.value.toUpperCase())}
          />
          <button onClick={handleUnlock} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100">
            Verify & Unlock
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="animate-in fade-in duration-500">
       <div className="bg-white rounded-3xl shadow-xl border overflow-hidden p-8 mb-8">
          <h2 className="text-2xl font-bold mb-6">Database Management</h2>
          <div className="relative">
            <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
            <input 
              className="w-full pl-12 pr-6 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-indigo-500" 
              placeholder="Search by name or mobile number..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>
       </div>

       <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filtered.map(booking => (
            <div key={booking.id} className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 hover:border-indigo-200 transition-all group">
               <div className="flex justify-between items-start mb-4">
                  <div>
                    <span className="text-[10px] font-black text-white bg-indigo-600 px-2 py-0.5 rounded-full uppercase mb-1 inline-block">{booking.busNo}</span>
                    <h4 className="font-bold text-gray-800">{booking.name}</h4>
                  </div>
                  <button 
                    onClick={() => {
                      const newAdvance = Number(prompt("Update Advance Amount (৳):", booking.advanceAmount.toString()));
                      if (!isNaN(newAdvance)) {
                        const total = booking.tourFees + (booking.customerTypeFees || 0);
                        const due = total - booking.discountAmount - newAdvance;
                        onUpdate({
                          ...booking, 
                          advanceAmount: newAdvance, 
                          dueAmount: due,
                          paymentStatus: due <= 0 ? 'Paid' : (newAdvance > 0 ? 'Partial' : 'Due')
                        });
                      }
                    }}
                    className="p-2 text-indigo-500 hover:bg-indigo-50 rounded-lg transition-colors"
                  >
                    <i className="fas fa-edit"></i>
                  </button>
               </div>
               <div className="space-y-1 text-xs text-gray-500 border-t pt-4">
                  <p className="flex justify-between"><span>Tour:</span> <span className="text-gray-800 font-medium">{booking.tourName}</span></p>
                  <p className="flex justify-between"><span>Mobile:</span> <span className="text-gray-800 font-medium">+880{booking.mobile}</span></p>
                  <p className="flex justify-between"><span>Due:</span> <span className="text-red-500 font-bold">৳{booking.dueAmount.toLocaleString()}</span></p>
               </div>
            </div>
          ))}
       </div>
    </div>
  );
};

export default EditData;

import React, { useState } from 'react';
import { SeatData, Gender, Religion } from '../types';

interface SeatProps {
  data: SeatData;
  onClick: () => void;
}

const Seat: React.FC<SeatProps> = ({ data, onClick }) => {
  const [isHovered, setIsHovered] = useState(false);

  const getSeatColor = () => {
    if (!data.isBooked) return 'bg-green-500 hover:bg-green-600';

    const info = data.bookingInfo!;
    const isFemale = info.gender === Gender.FEMALE;
    const isMuslim = info.religion === Religion.MUSLIM;

    if (isFemale && !isMuslim) return 'bg-yellow-500 hover:bg-yellow-600'; // Gold
    if (isFemale) return 'bg-pink-500 hover:bg-pink-600';
    if (!isMuslim) return 'bg-blue-500 hover:bg-blue-600';

    return 'bg-red-500 hover:bg-red-600'; // Default booked
  };

  return (
    <div 
      className="relative"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <button
        onClick={onClick}
        className={`${getSeatColor()} w-10 h-10 md:w-11 md:h-11 rounded-lg flex items-center justify-center text-white text-xs font-bold transition-all shadow-md transform active:scale-95`}
      >
        {data.id}
      </button>

      {isHovered && data.isBooked && data.bookingInfo && (
        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 z-50 w-56 bg-gray-900 text-white p-4 rounded-2xl shadow-2xl text-xs seat-tooltip border border-gray-700 animate-in fade-in slide-in-from-bottom-2">
          <div className="font-bold text-orange-400 border-b border-gray-700 pb-2 mb-2 flex justify-between items-center">
            <span>Seat {data.id}</span>
            <span className={`px-2 py-0.5 rounded text-[9px] font-black uppercase ${data.bookingInfo.paymentStatus === 'Paid' ? 'bg-green-500 text-white' : 'bg-red-500 text-white'}`}>
              {data.bookingInfo.paymentStatus}
            </span>
          </div>
          <div className="space-y-1.5">
            <p className="flex justify-between"><span className="text-gray-400">Name:</span> <span className="font-bold">{data.bookingInfo.name}</span></p>
            <p className="flex justify-between"><span className="text-gray-400">Tour:</span> <span className="text-indigo-300">{data.bookingInfo.tourName}</span></p>
            <p className="flex justify-between"><span className="text-gray-400">Mobile:</span> <span>+880{data.bookingInfo.mobile}</span></p>
            <div className="pt-2 mt-2 border-t border-gray-700 flex justify-between items-center">
              <span className="text-gray-400">Due Amount:</span>
              <span className="text-red-400 text-sm font-black">৳{data.bookingInfo.dueAmount.toLocaleString()}</span>
            </div>
            <p className="text-[9px] text-gray-500 text-right italic pt-1">Booked by {data.bookingInfo.bookedBy}</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default Seat;

import React, { useState, useEffect } from 'react';
import { BUSINESS_INFO, generateInitialSeats } from './constants';
import { BusData, BookingInfo, Tour, Booker, CustomerType } from './types';
import BusLayout from './components/BusLayout';
import BookingModal from './components/BookingModal';
import ConfirmationDialog from './components/ConfirmationDialog';
import Dashboard from './components/Dashboard';
import BookingLog from './components/BookingLog';
import EditData from './components/EditData';
import AdminPanel from './components/AdminPanel';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'booking' | 'dashboard' | 'log' | 'edit' | 'admin'>('booking');
  const [selectedBusIndex, setSelectedBusIndex] = useState(0);

  // Dynamic Configuration State (Persisted)
  const [tours, setTours] = useState<Tour[]>(() => {
    const saved = localStorage.getItem('tl_tours');
    return saved ? JSON.parse(saved) : [
      { name: "Sajek Valley", fee: 4500 },
      { name: "Cox's Bazar Relax", fee: 6500 }
    ];
  });

  const [bookers, setBookers] = useState<Booker[]>(() => {
    const saved = localStorage.getItem('tl_bookers');
    return saved ? JSON.parse(saved) : [
      { code: "KS101", name: "Kazi Shetu" },
      { code: "SI202", name: "Sadekul Islam" }
    ];
  });

  const [customerTypes, setCustomerTypes] = useState<CustomerType[]>(() => {
    const saved = localStorage.getItem('tl_customer_types');
    return saved ? JSON.parse(saved) : [
      { type: "Standard", fee: 0 },
      { type: "Solo", fee: 1500 }
    ];
  });

  const [buses, setBuses] = useState<BusData[]>(() => {
    const saved = localStorage.getItem('tour_lagbe_buses');
    if (saved) return JSON.parse(saved);
    return Array.from({ length: 10 }, (_, i) => ({
      busId: `Bus-${i + 1}`,
      seats: generateInitialSeats()
    }));
  });

  const [selectedSeatId, setSelectedSeatId] = useState<string | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [showConfirmDeselect, setShowConfirmDeselect] = useState(false);
  const [seatToDeselect, setSeatToDeselect] = useState<string | null>(null);
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);

  useEffect(() => {
    localStorage.setItem('tour_lagbe_buses', JSON.stringify(buses));
    localStorage.setItem('tl_tours', JSON.stringify(tours));
    localStorage.setItem('tl_bookers', JSON.stringify(bookers));
    localStorage.setItem('tl_customer_types', JSON.stringify(customerTypes));
  }, [buses, tours, bookers, customerTypes]);

  const handleSeatClick = (seatId: string) => {
    const seat = buses[selectedBusIndex].seats.find(s => s.id === seatId);
    if (seat?.isBooked) {
      setSeatToDeselect(seatId);
      setShowConfirmDeselect(true);
    } else {
      setSelectedSeatId(seatId);
      setShowBookingModal(true);
    }
  };

  const handleBookingSubmit = (info: BookingInfo) => {
    setBuses(prev => {
      const newBuses = [...prev];
      const bus = { ...newBuses[selectedBusIndex] };
      bus.seats = bus.seats.map(s => 
        s.id === selectedSeatId ? { ...s, isBooked: true, bookingInfo: info } : s
      );
      newBuses[selectedBusIndex] = bus;
      return newBuses;
    });
    setShowBookingModal(false);
    setSelectedSeatId(null);
  };

  const confirmDeselect = () => {
    if (seatToDeselect) {
      setBuses(prev => {
        const newBuses = [...prev];
        const bus = { ...newBuses[selectedBusIndex] };
        bus.seats = bus.seats.map(s => 
          s.id === seatToDeselect ? { ...s, isBooked: false, bookingInfo: undefined } : s
        );
        newBuses[selectedBusIndex] = bus;
        return newBuses;
      });
    }
    setShowConfirmDeselect(false);
    setSeatToDeselect(null);
  };

  const updateBooking = (updatedInfo: BookingInfo) => {
    setBuses(prev => prev.map(bus => ({
      ...bus,
      seats: bus.seats.map(seat => 
        seat.bookingInfo?.id === updatedInfo.id ? { ...seat, bookingInfo: updatedInfo } : seat
      )
    })));
  };

  const handleAdminAccess = () => {
    if (isAdminAuthenticated) {
      setActiveTab('admin');
      return;
    }
    const pass = prompt("Enter Admin Password:");
    if (pass === "@Rana&01625@") {
      setIsAdminAuthenticated(true);
      setActiveTab('admin');
    } else {
      alert("Incorrect Password!");
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row font-sans">
      {/* Sidebar Navigation */}
      <nav className="w-full md:w-72 bg-[#001D4A] text-white flex flex-col shadow-2xl z-20 shrink-0">
        <div className="p-8 text-center border-b border-white/10">
          <div className="relative inline-block mb-3">
            <img src={BUSINESS_INFO.logo} alt="Logo" className="w-24 drop-shadow-lg" />
            <div className="absolute -bottom-1 -right-1 w-4 h-4 bg-green-500 rounded-full border-2 border-[#001D4A]"></div>
          </div>
          <h1 className="text-2xl font-black text-white">{BUSINESS_INFO.name}</h1>
          <p className="text-[10px] text-orange-400 font-bold uppercase tracking-[0.2em] mt-1">{BUSINESS_INFO.motto}</p>
        </div>

        <div className="flex-grow py-6 space-y-1">
          {[
            { id: 'dashboard', icon: 'fa-chart-line', label: 'Overview Forecast' },
            { id: 'booking', icon: 'fa-ticket-alt', label: 'Seat Booking' },
            { id: 'log', icon: 'fa-clipboard-list', label: 'Response Sheet' },
            { id: 'edit', icon: 'fa-user-edit', label: 'Quick Editor' },
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`w-full flex items-center gap-4 px-8 py-4 text-sm font-semibold transition-all group ${activeTab === tab.id ? 'bg-orange-500 text-white shadow-lg' : 'text-white/70 hover:bg-white/5 hover:text-white'}`}
            >
              <i className={`fas ${tab.icon} w-6 text-center group-hover:scale-110 transition-transform`}></i>
              {tab.label}
            </button>
          ))}

          <div className="pt-8 px-4">
            <div className="border-t border-white/10 pt-4">
              <button 
                onClick={handleAdminAccess}
                className={`w-full flex items-center gap-4 px-6 py-4 text-sm font-bold rounded-2xl transition-all ${activeTab === 'admin' ? 'bg-white text-indigo-900' : 'bg-indigo-600/30 text-indigo-200 hover:bg-indigo-600/50'}`}
              >
                <i className="fas fa-user-shield"></i> Admin Control
              </button>
            </div>
          </div>
        </div>

        <div className="p-6 text-[10px] text-white/30 text-center border-t border-white/5">
          <p className="mb-1">{BUSINESS_INFO.address}</p>
          <p>© {new Date().getFullYear()} Tour লাগবে Official</p>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-grow overflow-auto p-6 md:p-10">
        {activeTab === 'booking' && (
          <div className="max-w-6xl mx-auto">
            <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center mb-10 gap-6">
              <div>
                <h2 className="text-3xl font-black text-[#001D4A]">Bus Inventory</h2>
                <div className="flex items-center gap-2 text-gray-400 text-sm mt-1">
                  <i className="fas fa-map-marker-alt text-orange-500"></i>
                  <span>Gazipur Junction • 10 Buses Active</span>
                </div>
              </div>

              <div className="flex items-center gap-4 bg-white p-3 rounded-2xl shadow-sm border border-gray-100">
                <div className="bg-indigo-50 p-2 rounded-xl">
                  <i className="fas fa-bus-alt text-indigo-600"></i>
                </div>
                <div className="pr-4">
                  <p className="text-[10px] font-black text-gray-400 uppercase">Current Fleet</p>
                  <select 
                    value={selectedBusIndex} 
                    onChange={(e) => setSelectedBusIndex(Number(e.target.value))}
                    className="bg-transparent border-none text-base font-black text-[#001D4A] focus:ring-0 p-0 cursor-pointer min-w-[120px]"
                  >
                    {buses.map((bus, idx) => (
                      <option key={bus.busId} value={idx}>{bus.busId} (Available: {bus.seats.filter(s => !s.isBooked).length})</option>
                    ))}
                  </select>
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
              <div className="lg:col-span-7">
                <div className="bg-white rounded-[40px] shadow-2xl p-10 border border-gray-100 relative overflow-hidden">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-50 rounded-bl-full -z-0 opacity-50"></div>
                  <BusLayout seats={buses[selectedBusIndex].seats} onSeatClick={handleSeatClick} />
                </div>
              </div>

              <div className="lg:col-span-5 space-y-8">
                <div className="bg-white rounded-[32px] p-8 shadow-xl border border-gray-100">
                  <h3 className="font-black text-[#001D4A] mb-6 flex items-center gap-3">
                    <div className="w-8 h-8 bg-orange-100 text-orange-600 rounded-lg flex items-center justify-center text-sm">
                      <i className="fas fa-swatchbook"></i>
                    </div>
                    Visual Legend
                  </h3>
                  <div className="space-y-4">
                    {[
                      { color: 'bg-green-500', label: 'Vacant Seat', desc: 'Ready for booking' },
                      { color: 'bg-red-500', label: 'Standard Booked', desc: 'Male / Regular' },
                      { color: 'bg-pink-500', label: 'Female Passenger', desc: 'Reserved status' },
                      { color: 'bg-blue-500', label: 'Special Preference', desc: 'Non-Muslim / General' },
                      { color: 'bg-yellow-500', label: 'Gold Class', desc: 'Non-Muslim Female' },
                    ].map((item, idx) => (
                      <div key={idx} className="flex items-center gap-4 group">
                        <div className={`${item.color} w-10 h-10 rounded-xl shadow-md transition-transform group-hover:scale-110`}></div>
                        <div>
                          <p className="text-sm font-bold text-gray-800">{item.label}</p>
                          <p className="text-[10px] text-gray-400 uppercase font-black tracking-widest">{item.desc}</p>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>

                <div className="bg-gradient-to-br from-indigo-900 to-[#001D4A] rounded-[32px] p-8 text-white shadow-2xl relative overflow-hidden">
                  <i className="fas fa-shield-alt absolute -right-4 -bottom-4 text-white/5 text-8xl rotate-12"></i>
                  <h4 className="text-xl font-black mb-4 flex items-center gap-2">
                    <i className="fas fa-lightbulb text-orange-400"></i>
                    Pro Tip
                  </h4>
                  <p className="text-sm text-indigo-100/80 leading-relaxed italic">
                    "Hover over any booked seat to see passenger summary, total fees, and due status instantly without clicking."
                  </p>
                  <div className="mt-6 flex gap-2">
                    <div className="px-3 py-1 bg-white/10 rounded-full text-[10px] font-bold">Safe Travels</div>
                    <div className="px-3 py-1 bg-white/10 rounded-full text-[10px] font-bold">Secure Booking</div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'dashboard' && <Dashboard buses={buses} />}
        {activeTab === 'log' && <BookingLog buses={buses} />}
        {activeTab === 'edit' && <EditData buses={buses} onUpdate={updateBooking} bookers={bookers} />}
        {activeTab === 'admin' && (
          <AdminPanel 
            tours={tours} setTours={setTours} 
            agents={bookers} setAgents={setBookers}
            customerTypes={customerTypes} setCustomerTypes={setCustomerTypes}
          />
        )}
      </main>

      {showBookingModal && (
        <BookingModal 
          seatId={selectedSeatId!} 
          busNo={buses[selectedBusIndex].busId}
          onClose={() => { setShowBookingModal(false); setSelectedSeatId(null); }} 
          onSubmit={handleBookingSubmit}
          tours={tours}
          bookers={bookers}
          customerTypes={customerTypes}
        />
      )}

      {showConfirmDeselect && (
        <ConfirmationDialog 
          message="Are you sure you want to cancel this booking? This will free up the seat and delete all passenger data."
          onConfirm={confirmDeselect}
          onCancel={() => { setShowConfirmDeselect(false); setSeatToDeselect(null); }}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Tour, Booker, CustomerType } from '../types';

interface AdminPanelProps {
  tours: Tour[];
  setTours: React.Dispatch<React.SetStateAction<Tour[]>>;
  agents: Booker[];
  setAgents: React.Dispatch<React.SetStateAction<Booker[]>>;
  customerTypes: CustomerType[];
  setCustomerTypes: React.Dispatch<React.SetStateAction<CustomerType[]>>;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  tours, setTours, 
  agents, setAgents, 
  customerTypes, setCustomerTypes 
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'tours' | 'agents' | 'types'>('tours');

  // Local states for new entries
  const [newTour, setNewTour] = useState({ name: '', fee: 0 });
  const [newAgent, setNewAgent] = useState({ code: '', name: '' });
  const [newType, setNewType] = useState({ type: '', fee: 0 });

  const addTour = () => {
    if (!newTour.name) return;
    setTours([...tours, newTour]);
    setNewTour({ name: '', fee: 0 });
  };

  const removeTour = (name: string) => {
    if (confirm("Delete this tour?")) {
      setTours(tours.filter(t => t.name !== name));
    }
  };

  const addAgent = () => {
    if (!newAgent.code || !newAgent.name) return;
    setAgents([...agents, newAgent]);
    setNewAgent({ code: '', name: '' });
  };

  const removeAgent = (code: string) => {
    if (confirm("Remove this agent?")) {
      setAgents(agents.filter(a => a.code !== code));
    }
  };

  const addType = () => {
    if (!newType.type) return;
    setCustomerTypes([...customerTypes, newType]);
    setNewType({ type: '', fee: 0 });
  };

  return (
    <div className="max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-5 duration-500">
      <div className="flex justify-between items-center mb-8">
        <h2 className="text-3xl font-black text-[#001D4A]">Admin Management</h2>
        <div className="bg-indigo-100 text-indigo-700 px-4 py-2 rounded-full text-xs font-black uppercase tracking-wider flex items-center gap-2">
          <i className="fas fa-lock"></i> Secure Access
        </div>
      </div>

      {/* Tabs */}
      <div className="flex bg-white p-2 rounded-2xl shadow-sm mb-8">
        {[
          { id: 'tours', label: 'Tours & Pricing', icon: 'fa-globe' },
          { id: 'agents', label: 'Agent Log', icon: 'fa-users-cog' },
          { id: 'types', label: 'Extra Types', icon: 'fa-tags' }
