import React, { useState, useEffect } from 'react';
import { BookingInfo, Gender, Religion, Tour, CustomerType, Booker } from '../types';
import { BUSINESS_INFO } from '../constants';

interface BookingModalProps {
  seatId: string;
  busNo: string;
  onClose: () => void;
  onSubmit: (info: BookingInfo) => void;
  tours: Tour[];
  bookers: Booker[];
  customerTypes: CustomerType[];
}

const BookingModal: React.FC<BookingModalProps> = ({ seatId, busNo, onClose, onSubmit, tours, bookers, customerTypes }) => {
  const [formData, setFormData] = useState({
    name: '',
    mobile: '',
    address: '',
    gender: Gender.MALE,
    religion: Religion.MUSLIM,
    tourName: tours.length > 0 ? tours[0].name : '',
    customerType: customerTypes.length > 0 ? customerTypes[0].type : '',
    discountAmount: 0,
    advanceAmount: 0,
    bookerCode: ''
  });

  const [tourFees, setTourFees] = useState(tours.length > 0 ? tours[0].fee : 0);
  const [customerTypeFees, setCustomerTypeFees] = useState(0);
  const [dueAmount, setDueAmount] = useState(0);
  const [isRelaxTour, setIsRelaxTour] = useState(false);
  const [bookerName, setBookerName] = useState('');

  useEffect(() => {
    const tour = tours.find(t => t.name === formData.tourName);
    const fee = tour ? tour.fee : 0;
    setTourFees(fee);
    setIsRelaxTour(formData.tourName.toLowerCase().includes('relax'));

    const cType = customerTypes.find(c => c.type === formData.customerType);
    const cFee = cType ? cType.fee : 0;
    setCustomerTypeFees(cFee);

    const booker = bookers.find(b => b.code === formData.bookerCode);
    setBookerName(booker ? booker.name : '');

    const total = fee + cFee;
    const due = total - formData.discountAmount - formData.advanceAmount;
    setDueAmount(due);
  }, [formData, tours, bookers, customerTypes]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleNumericChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: Number(value) }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!bookerName) {
      alert("Unauthorized Booker Code! System cannot verify this entry.");
      return;
    }

    const info: BookingInfo = {
      id: Math.random().toString(36).substr(2, 9).toUpperCase(),
      ...formData,
      tourFees,
      customerTypeFees,
      dueAmount,
      paymentStatus: dueAmount <= 0 ? 'Paid' : (formData.advanceAmount > 0 ? 'Partial' : 'Due'),
      busNo,
      seatNo: seatId,
      bookedBy: bookerName,
      bookingDate: new Date().toISOString()
    };
    onSubmit(info);
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-[#001D4A]/60 backdrop-blur-md overflow-y-auto">
      <div className="bg-white w-full max-w-2xl rounded-[40px] shadow-2xl my-auto animate-in fade-in zoom-in duration-300 overflow-hidden border border-white/20">
        <div className="bg-gradient-to-r from-orange-500 to-orange-600 p-8 text-white flex justify-between items-center relative overflow-hidden">
          <div className="relative z-10">
            <h3 className="text-2xl font-black">Book Seat {seatId} <span className="text-orange-200 text-sm opacity-60 ml-2">({busNo})</span></h3>
            <p className="text-orange-100 text-[10px] uppercase font-black tracking-widest mt-1">Official Terminal Entry</p>
          </div>
          <button onClick={onClose} className="w-12 h-12 rounded-2xl bg-white/20 hover:bg-white/30 transition-all flex items-center justify-center text-xl z-10">
             <i className="fas fa-times"></i>
          </button>
          <i className="fas fa-bus-alt absolute -right-6 -bottom-6 text-white/10 text-9xl"></i>
        </div>

        <form onSubmit={handleSubmit} className="p-10 grid grid-cols-1 md:grid-cols-2 gap-8 max-h-[70vh] overflow-y-auto">
          {/* Passenger Column */}
          <div className="space-y-5">
            <h4 className="font-black text-[#001D4A] text-xs uppercase tracking-wider flex items-center gap-2">
              <span className="w-2 h-2 bg-orange-500 rounded-full"></span> 
              Passenger Details
            </h4>

            <div className="space-y-1">
              <label className="text-[10px] font-black text-gray-400 uppercase">Full Legal Name</label>
              <input required name="name" value={formData.name} onChange={handleChange} className="w-full px-5 py-3 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-500 transition-all" placeholder="e.g. Arif Hossain" />
            </div>

            <div className="space-y-1">
              <label className="text-[10px] font-black text-gray-400 uppercase">Contact (+880)</label>
              <div className="relative">
                <span className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400 font-bold">+880</span>
                <input required name="mobile" value={formData.mobile} onChange={handleChange} className="w-full pl-16 pr-5 py-3 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-500" placeholder="1XXXXXXXXX" />
              </div>
            </div>

            <div className="space-y-1">
              <label className="text-[10px] font-black text-gray-400 uppercase">Current Address</label>
              <textarea name="address" value={formData.address} onChange={handleChange} rows={2} className="w-full px-5 py-3 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-500" placeholder="Street, Area, District" />
            </div>

            <div className="grid grid-cols-2 gap-4">
               <div className="space-y-1">
                  <label className="text-[10px] font-black text-gray-400 uppercase">Gender</label>
                  <select name="gender" value={formData.gender} onChange={handleChange} className="w-full px-4 py-3 bg-gray-50 border-none rounded-2xl">
                    {Object.values(Gender).map(g => <option key={g} value={g}>{g}</option>)}
                  </select>
               </div>
               <div className="space-y-1">
                  <label className="text-[10px] font-black text-gray-400 uppercase">Religion</label>
                  <select name="religion" value={formData.religion} onChange={handleChange} className="w-full px-4 py-3 bg-gray-50 border-none rounded-2xl">
                    {Object.values(Religion).map(r => <option key={r} value={r}>{r}</option>)}
                  </select>
               </div>
            </div>
          </div>

          {/* Tour Column */}
          <div className="space-y-5">
            <h4 className="font-black text-[#001D4A] text-xs uppercase tracking-wider flex items-center gap-2">
              <span className="w-2 h-2 bg-indigo-500 rounded-full"></span> 
              Tour Logistics
            </h4>

            <div className="space-y-1">
              <label className="text-[10px] font-black text-gray-400 uppercase">Active Tour Package</label>
              <select name="tourName" value={formData.tourName} onChange={handleChange} className="w-full px-5 py-3 bg-indigo-50 border-none rounded-2xl font-black text-indigo-700">
                {tours.map(t => <option key={t.name} value={t.name}>{t.name} (৳{t.fee.toLocaleString()})</option>)}
              </select>
            </div>

            {(isRelaxTour || customerTypes.length > 0) && (
              <div className="space-y-1 animate-in slide-in-from-top-2">
                <label className="text-[10px] font-black text-gray-400 uppercase">Accommodation / Type</label>
                <select name="customerType" value={formData.customerType} onChange={handleChange} className="w-full px-5 py-3 bg-gray-50 border-none rounded-2xl">
                  {customerTypes.map(c => <option key={c.type} value={c.type}>{c.type} {c.fee > 0 ? `(+৳${c.fee})` : ''}</option>)}
                </select>
              </div>
            )}

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase">Discount (৳)</label>
                <input type="number" name="discountAmount" value={formData.discountAmount || ''} onChange={handleNumericChange} className="w-full px-5 py-3 bg-gray-50 border-none rounded-2xl font-bold" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase">Advance (৳)</label>
                <input type="number" name="advanceAmount" value={formData.advanceAmount || ''} onChange={handleNumericChange} className="w-full px-5 py-3 bg-green-50 border-none rounded-2xl font-bold text-green-700" />
              </div>
            </div>

            <div className="p-6 bg-[#001D4A] rounded-[32px] text-white shadow-lg relative overflow-hidden">
               <div className="flex justify-between text-xs opacity-60 mb-2 font-bold uppercase tracking-widest">
                 <span>Total Balance</span>
                 <span>৳{(tourFees + customerTypeFees).toLocaleString()}</span>
               </div>
               <div className="flex justify-between items-center">
                 <span className="text-xs font-black text-orange-400 uppercase">Remaining Due</span>
                 <span className="text-2xl font-black">৳{dueAmount.toLocaleString()}</span>
               </div>
               <div className={`mt-3 text-[9px] font-black uppercase text-center py-1 rounded-full ${dueAmount <= 0 ? 'bg-green-500' : 'bg-red-500/50'}`}>
                 {dueAmount <= 0 ? 'Fully Cleared' : 'Payment Required'}
               </div>
            </div>

            <div className="space-y-1">
              <label className="text-[10px] font-black text-gray-400 uppercase">Authorized Booker Code</label>
              <div className="relative">
                <input required name="bookerCode" value={formData.bookerCode} onChange={handleChange} className={`w-full px-5 py-3 border-2 rounded-2xl focus:ring-0 outline-none uppercase font-mono tracking-widest ${bookerName ? 'border-green-400 bg-green-50 text-green-900' : 'border-gray-100 bg-gray-50'}`} placeholder="AGENT-ID" />
                {bookerName && (
                  <div className="absolute right-3 top-1/2 -translate-y-1/2 px-3 py-1 bg-green-500 text-white rounded-lg text-[9px] font-black animate-in fade-in zoom-in">
                    {bookerName}
                  </div>
                )}
              </div>
            </div>
          </div>

          <div className="md:col-span-2 pt-4 border-t">
            <button type="submit" className="w-full py-5 bg-orange-500 text-white rounded-2xl font-black text-xl hover:bg-orange-600 shadow-xl shadow-orange-100 transition-all hover:-translate-y-1 flex items-center justify-center gap-4 group">
              Confirm Passenger Seat
              <i className="fas fa-arrow-right group-hover:translate-x-2 transition-transform"></i>
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default BookingModal;

import React, { useState } from 'react';
import { BusData, BookingInfo, Booker } from '../types';

interface EditDataProps {
  buses: BusData[];
  onUpdate: (info: BookingInfo) => void;
  bookers: Booker[];
}

const EditData: React.FC<EditDataProps> = ({ buses, onUpdate, bookers }) => {
  const [accessCode, setAccessCode] = useState('');
  const [isUnlocked, setIsUnlocked] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  const handleUnlock = () => {
    if (bookers.some(b => b.code === accessCode)) {
      setIsUnlocked(true);
    } else {
      alert("Unauthorized Agent Code!");
    }
  };

  const allBookings: BookingInfo[] = buses.flatMap(b => b.seats.filter(s => s.isBooked).map(s => s.bookingInfo!));
  const filtered = allBookings.filter(b => b.name.toLowerCase().includes(searchQuery.toLowerCase()) || b.mobile.includes(searchQuery));

  if (!isUnlocked) {
    return (
      <div className="max-w-md mx-auto mt-20 bg-white p-10 rounded-[40px] shadow-2xl border text-center animate-in zoom-in duration-300">
        <div className="w-24 h-24 bg-indigo-50 text-indigo-600 rounded-[32px] flex items-center justify-center mx-auto mb-8 text-4xl shadow-inner border border-indigo-100">
          <i className="fas fa-user-lock"></i>
        </div>
        <h3 className="text-3xl font-black text-[#001D4A] mb-3">Agent Portal</h3>
        <p className="text-sm text-gray-500 mb-10 leading-relaxed">Enter your private agent identification code to unlock the quick editor tools.</p>
        <div className="space-y-4">
           <input 
            type="text" 
            placeholder="BOOKER-CODE" 
            className="w-full px-8 py-5 bg-gray-50 border-none rounded-2xl outline-none focus:ring-4 focus:ring-indigo-100 transition-all font-black text-center text-xl tracking-widest uppercase"
            value={accessCode}
            onChange={(e) => setAccessCode(e.target.value.toUpperCase())}
          />
          <button onClick={handleUnlock} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-lg hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100 active:scale-95">
            Verify Identity
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="animate-in fade-in duration-500 max-w-6xl mx-auto">
       <div className="bg-white rounded-[40px] shadow-2xl border-none p-10 mb-10 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-8 opacity-5">
            <i className="fas fa-search text-9xl"></i>
          </div>
          <h2 className="text-3xl font-black text-[#001D4A] mb-8">System Entry Editor</h2>
          <div className="relative group">
            <i className="fas fa-search absolute left-5 top-1/2 -translate-y-1/2 text-gray-300 group-focus-within:text-orange-500 transition-colors"></i>
            <input 
              className="w-full pl-14 pr-8 py-5 bg-gray-50 border-none rounded-3xl focus:ring-2 focus:ring-orange-500 transition-all text-lg font-bold" 
              placeholder="Filter by passenger name or mobile..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>
       </div>

       <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {filtered.length === 0 ? (
            <div className="col-span-full py-20 text-center text-gray-300 font-bold uppercase tracking-widest">
              No matching records found
            </div>
          ) : (
            filtered.map(booking => (
              <div key={booking.id} className="bg-white p-8 rounded-[32px] shadow-xl border border-transparent hover:border-orange-200 transition-all hover:shadow-2xl hover:-translate-y-2 group">
                 <div className="flex justify-between items-start mb-6">
                    <div>
                      <div className="flex items-center gap-2 mb-2">
                        <span className="text-[9px] font-black text-white bg-indigo-600 px-2.5 py-1 rounded-full uppercase">{booking.busNo}</span>
                        <span className="text-[9px] font-black text-indigo-600 bg-indigo-50 px-2.5 py-1 rounded-full uppercase">Seat {booking.seatNo}</span>
                      </div>
                      <h4 className="font-black text-[#001D4A] text-xl">{booking.name}</h4>
                    </div>
                    <button 
                      onClick={() => {
                        const newAdvance = Number(prompt("Update Payment Received (৳):", booking.advanceAmount.toString()));
                        if (!isNaN(newAdvance)) {
                          const total = booking.tourFees + (booking.customerTypeFees || 0);
                          const due = total - booking.discountAmount - newAdvance;
                          onUpdate({
                            ...booking, 
                            advanceAmount: newAdvance, 
                            dueAmount: due,
                            paymentStatus: due <= 0 ? 'Paid' : (newAdvance > 0 ? 'Partial' : 'Due')
                          });
                        }
                      }}
                      className="w-12 h-12 flex items-center justify-center bg-gray-50 text-indigo-500 rounded-2xl hover:bg-orange-500 hover:text-white transition-all shadow-sm"
                    >
                      <i className="fas fa-pen"></i>
                    </button>
                 </div>
                 <div className="space-y-3 pt-6 border-t border-gray-50">
                    <div className="flex justify-between items-center text-xs">
                       <span className="text-gray-400 font-bold uppercase">Package</span>
                       <span className="text-gray-800 font-black">{booking.tourName}</span>
                    </div>
                    <div className="flex justify-between items-center text-xs">
                       <span className="text-gray-400 font-bold uppercase">Contact</span>
                       <span className="text-gray-800 font-black">+880{booking.mobile}</span>
                    </div>
                    <div className="flex justify-between items-center bg-red-50 p-3 rounded-xl mt-2">
                       <span className="text-red-400 font-black uppercase text-[10px]">Due Balance</span>
                       <span className="text-red-600 font-black text-lg">৳{booking.dueAmount.toLocaleString()}</span>
                    </div>
                 </div>
                 <div className="mt-4 text-[9px] text-gray-300 text-right uppercase font-black tracking-tighter">
                   Logged By {booking.bookedBy}
                 </div>
              </div>
            ))
          )}
       </div>
    </div>
  );
};

