      <div className="absolute top-0 left-0 w-full h-1 bg-[#001D4A] opacity-10"></div>
      <div className="absolute top-12 left-1/2 -translate-x-1/2 w-32 h-2 bg-gray-100 rounded-full"></div>

      {/* Driver Section */}
      <div className="absolute top-6 right-10 text-[#001D4A]">
        <div className="w-12 h-12 border-4 border-[#001D4A] rounded-2xl flex items-center justify-center bg-gray-50 shadow-inner">
          <i className="fas fa-dharmachakra text-xl animate-spin-slow"></i>
        </div>
        <span className="text-[9px] uppercase font-black tracking-[0.2em] mt-2 block text-center opacity-40">Pilot</span>
      </div>

      <div className="space-y-5 relative z-10">
        {/* Rows A to J */}
        {rows.map((row) => {
          const rowSeats = seats.filter(s => s.id.startsWith(row));
          return (
            <div key={row} className="flex justify-between items-center group">
              {/* Left Side (A1, A2) */}
              <div className="flex gap-4">
                {rowSeats.slice(0, 2).map(seat => (
                  <Seat key={seat.id} data={seat} onClick={() => onSeatClick(seat.id)} />
                ))}
              </div>

              {/* Aisle - Center Indicator */}
              <div className="w-10 h-10 flex items-center justify-center">
                <div className="w-6 h-6 rounded-full bg-gray-50 text-[10px] font-black text-gray-300 flex items-center justify-center border border-gray-100">
                  {row}
                </div>
              </div>

              {/* Right Side (A3, A4) */}
              <div className="flex gap-4">
                {rowSeats.slice(2, 4).map(seat => (
                  <Seat key={seat.id} data={seat} onClick={() => onSeatClick(seat.id)} />
                ))}
              </div>
            </div>
          );
        })}

        {/* Back Bench - Row K (5 seats) */}
        <div className="pt-8 mt-4 border-t-2 border-dashed border-gray-100">
           <div className="flex justify-between gap-1.5 px-1">
            {seats.filter(s => s.id.startsWith(lastRow)).map(seat => (
              <Seat key={seat.id} data={seat} onClick={() => onSeatClick(seat.id)} />
            ))}
          </div>
          <div className="text-center mt-3 text-[8px] font-black text-gray-200 uppercase tracking-widest">Back Bench Priority</div>
        </div>
      </div>

      {/* Floor Pattern */}
      <div className="absolute inset-0 pointer-events-none opacity-[0.03]" style={{backgroundImage: 'radial-gradient(#000 1px, transparent 0)', backgroundSize: '16px 16px'}}></div>
    </div>
  );
};

export default BusLayout;

import React, { useState } from 'react';
import { SeatData, Gender, Religion } from '../types';

interface SeatProps {
  data: SeatData;
  onClick: () => void;
}

const Seat: React.FC<SeatProps> = ({ data, onClick }) => {
  const [isHovered, setIsHovered] = useState(false);

  const getSeatColor = () => {
    if (!data.isBooked) return 'bg-green-500 hover:bg-green-600 shadow-green-200';

    const info = data.bookingInfo!;
    const isFemale = info.gender === Gender.FEMALE;
    const isMuslim = info.religion === Religion.MUSLIM;

    if (isFemale && !isMuslim) return 'bg-yellow-500 hover:bg-yellow-600 shadow-yellow-200'; // Gold
    if (isFemale) return 'bg-pink-500 hover:bg-pink-600 shadow-pink-200';
    if (!isMuslim) return 'bg-blue-500 hover:bg-blue-600 shadow-blue-200';

    return 'bg-red-500 hover:bg-red-600 shadow-red-200'; // Default booked
  };

  return (
    <div 
      className="relative"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <button
        onClick={onClick}
        className={`${getSeatColor()} w-11 h-11 md:w-12 md:h-12 rounded-2xl flex items-center justify-center text-white text-[11px] font-black transition-all shadow-lg transform active:scale-90 hover:-translate-y-1`}
      >
        {data.id}
      </button>

      {isHovered && data.isBooked && data.bookingInfo && (
        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-4 z-50 w-64 bg-white text-gray-800 p-0 rounded-[28px] shadow-2xl border border-gray-100 animate-in fade-in slide-in-from-bottom-3 duration-200 overflow-hidden">
          <div className="bg-[#001D4A] p-4 flex justify-between items-center">
             <span className="text-white font-black text-xs">Seat {data.id} Summary</span>
             <span className={`px-2.5 py-1 rounded-full text-[9px] font-black uppercase ${data.bookingInfo.paymentStatus === 'Paid' ? 'bg-green-500 text-white' : 'bg-orange-500 text-white'}`}>
              {data.bookingInfo.paymentStatus}
            </span>
          </div>
          <div className="p-5 space-y-2">
            <div className="flex justify-between items-end border-b pb-2">
               <div>
                  <p className="text-[10px] text-gray-400 font-bold uppercase">Passenger</p>
                  <p className="text-sm font-black text-[#001D4A]">{data.bookingInfo.name}</p>
               </div>
               <div className="text-right">
                  <p className="text-[10px] text-gray-400 font-bold uppercase">Tour</p>
                  <p className="text-[10px] font-bold text-indigo-600">{data.bookingInfo.tourName}</p>
               </div>
            </div>

            <div className="space-y-1.5 pt-2">
              <p className="flex justify-between text-[10px]"><span className="text-gray-400">Mobile</span> <span className="font-bold">+880{data.bookingInfo.mobile}</span></p>
              <p className="flex justify-between text-[10px]"><span className="text-gray-400">Agent</span> <span className="font-bold text-indigo-400">{data.bookingInfo.bookedBy}</span></p>
            </div>

            <div className="mt-3 pt-3 border-t border-dashed flex justify-between items-center">
              <span className="text-[10px] font-black text-gray-400 uppercase">Outstanding</span>
              <span className="text-lg font-black text-red-500">৳{data.bookingInfo.dueAmount.toLocaleString()}</span>
            </div>
          </div>
          <div className="bg-gray-50 px-4 py-2 text-center text-[8px] font-black text-gray-300 uppercase tracking-[0.2em]">
            Digital Receipt Verified
          </div>
        </div>
      )}
    </div>
  );
};

export default Seat;

import React, { useState, useEffect } from 'react';
import { BUSINESS_INFO, generateInitialSeats } from './constants';
import { BusData, BookingInfo, Tour, Booker, CustomerType } from './types';
import BusLayout from './components/BusLayout';
import BookingModal from './components/BookingModal';
import ConfirmationDialog from './components/ConfirmationDialog';
import Dashboard from './components/Dashboard';
import BookingLog from './components/BookingLog';
import EditData from './components/EditData';
import AdminPanel from './components/AdminPanel';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'booking' | 'dashboard' | 'log' | 'edit' | 'admin'>('booking');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);

  // Dynamic Configuration State (Persisted)
  const [tours, setTours] = useState<Tour[]>(() => {
    const saved = localStorage.getItem('tl_tours');
    return saved ? JSON.parse(saved) : [
      { name: "Sajek Valley", fee: 4500 },
      { name: "Cox's Bazar Relax", fee: 6500 }
    ];
  });

  const [bookers, setBookers] = useState<Booker[]>(() => {
    const saved = localStorage.getItem('tl_bookers');
    return saved ? JSON.parse(saved) : [
      { code: "KS101", name: "Kazi Shetu" },
      { code: "SI202", name: "Sadekul Islam" }
    ];
  });

  const [customerTypes, setCustomerTypes] = useState<CustomerType[]>(() => {
    const saved = localStorage.getItem('tl_customer_types');
    return saved ? JSON.parse(saved) : [
      { type: "Standard", fee: 0 },
      { type: "Solo", fee: 1500 }
    ];
  });

  // Map tours to bus data. Each tour name represents a "Bus".
  const [buses, setBuses] = useState<BusData[]>(() => {
    const saved = localStorage.getItem('tour_lagbe_buses');
    if (saved) return JSON.parse(saved);
    // Initial sync with default tours
    return [
      { name: "Sajek Valley", fee: 4500 },
      { name: "Cox's Bazar Relax", fee: 6500 }
    ].map(t => ({
      busId: t.name,
      seats: generateInitialSeats()
    }));
  });

  const [selectedBusIndex, setSelectedBusIndex] = useState(0);
  const [selectedSeatId, setSelectedSeatId] = useState<string | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [showConfirmDeselect, setShowConfirmDeselect] = useState(false);
  const [seatToDeselect, setSeatToDeselect] = useState<string | null>(null);

  // Sync buses with tours when tours change
  useEffect(() => {
    setBuses(prevBuses => {
      return tours.map(tour => {
        const existingBus = prevBuses.find(b => b.busId === tour.name);
        return existingBus || { busId: tour.name, seats: generateInitialSeats() };
      });
    });
  }, [tours]);

  useEffect(() => {
    localStorage.setItem('tour_lagbe_buses', JSON.stringify(buses));
    localStorage.setItem('tl_tours', JSON.stringify(tours));
    localStorage.setItem('tl_bookers', JSON.stringify(bookers));
    localStorage.setItem('tl_customer_types', JSON.stringify(customerTypes));
  }, [buses, tours, bookers, customerTypes]);

  const handleSeatClick = (seatId: string) => {
    if (selectedBusIndex >= buses.length) return;
    const seat = buses[selectedBusIndex].seats.find(s => s.id === seatId);
    if (seat?.isBooked) {
      setSeatToDeselect(seatId);
      setShowConfirmDeselect(true);
    } else {
      setSelectedSeatId(seatId);
      setShowBookingModal(true);
    }
  };

  const handleBookingSubmit = (info: BookingInfo) => {
    setBuses(prev => {
      const newBuses = [...prev];
      const bus = { ...newBuses[selectedBusIndex] };
      bus.seats = bus.seats.map(s => 
        s.id === selectedSeatId ? { ...s, isBooked: true, bookingInfo: info } : s
      );
      newBuses[selectedBusIndex] = bus;
      return newBuses;
    });
    setShowBookingModal(false);
    setSelectedSeatId(null);
  };

  const confirmDeselect = () => {
    if (seatToDeselect) {
      setBuses(prev => {
        const newBuses = [...prev];
        const bus = { ...newBuses[selectedBusIndex] };
        bus.seats = bus.seats.map(s => 
          s.id === seatToDeselect ? { ...s, isBooked: false, bookingInfo: undefined } : s
        );
        newBuses[selectedBusIndex] = bus;
        return newBuses;
      });
    }
    setShowConfirmDeselect(false);
    setSeatToDeselect(null);
  };

  const updateBooking = (updatedInfo: BookingInfo) => {
    setBuses(prev => prev.map(bus => ({
      ...bus,
      seats: bus.seats.map(seat => 
        seat.bookingInfo?.id === updatedInfo.id ? { ...seat, bookingInfo: updatedInfo } : seat
      )
    })));
  };

  const handleAdminTabClick = () => {
    if (isAdminAuthenticated) {
      setActiveTab('admin');
    } else {
      const pass = prompt("Enter Admin Password:");
      if (pass === "@Rana&01625@") {
        setIsAdminAuthenticated(true);
        setActiveTab('admin');
      } else {
        alert("Incorrect Password!");
      }
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row font-sans overflow-hidden">
      {/* Sidebar Navigation */}
      <nav className={`fixed md:relative h-full transition-all duration-300 ease-in-out bg-[#001D4A] text-white flex flex-col shadow-2xl z-[60] shrink-0 
        ${isSidebarOpen ? 'w-72 translate-x-0' : 'w-0 -translate-x-full md:w-20 md:translate-x-0 overflow-hidden'}`}>

        <div className={`p-8 text-center border-b border-white/10 ${!isSidebarOpen && 'md:p-4'}`}>
          <div className="relative inline-block mb-3">
            <img src={BUSINESS_INFO.logo} alt="Logo" className={`${isSidebarOpen ? 'w-24' : 'w-10'} transition-all drop-shadow-lg mx-auto`} />
          </div>
          {isSidebarOpen && (
            <>
              <h1 className="text-2xl font-black text-white">{BUSINESS_INFO.name}</h1>
              <p className="text-[10px] text-orange-400 font-bold uppercase tracking-[0.2em] mt-1">{BUSINESS_INFO.motto}</p>
            </>
          )}
        </div>

        <div className="flex-grow py-6 space-y-1 overflow-y-auto">
          {[
            { id: 'dashboard', icon: 'fa-chart-line', label: 'Dashboard' },
            { id: 'booking', icon: 'fa-ticket-alt', label: 'Seat Booking' },
            { id: 'log', icon: 'fa-clipboard-list', label: 'Booking Log' },
            { id: 'edit', icon: 'fa-user-edit', label: 'Editor' },
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`w-full flex items-center gap-4 px-8 py-4 text-sm font-semibold transition-all group ${activeTab === tab.id ? 'bg-orange-500 text-white shadow-lg' : 'text-white/70 hover:bg-white/5 hover:text-white'} ${!isSidebarOpen && 'md:px-0 md:justify-center'}`}
            >
              <i className={`fas ${tab.icon} w-6 text-center group-hover:scale-110 transition-transform`}></i>
              {isSidebarOpen && <span>{tab.label}</span>}
            </button>
          ))}

          <div className={`pt-8 ${isSidebarOpen ? 'px-4' : 'px-1'}`}>
            <div className="border-t border-white/10 pt-4">
              <button 
                onClick={handleAdminTabClick}
                className={`w-full flex items-center gap-4 py-4 text-sm font-bold rounded-2xl transition-all ${activeTab === 'admin' ? 'bg-white text-indigo-900' : 'bg-indigo-600/30 text-indigo-200 hover:bg-indigo-600/50'} ${isSidebarOpen ? 'px-6' : 'justify-center'}`}
              >
                <i className="fas fa-user-shield"></i>
                {isSidebarOpen && <span>Admin Control</span>}
              </button>
            </div>
          </div>
        </div>

        {isSidebarOpen && (
          <div className="p-6 text-[10px] text-white/30 text-center border-t border-white/5">
            <p className="mb-1">{BUSINESS_INFO.address}</p>
            <p>© {new Date().getFullYear()} Tour লাগবে Official</p>
          </div>
        )}
      </nav>

      {/* Main Content Area */}
      <main className="flex-grow h-screen overflow-auto relative">
        {/* Toggle Button */}
        <button 
          onClick={() => setIsSidebarOpen(!isSidebarOpen)}
          className="fixed top-4 left-4 md:absolute md:top-6 md:left-6 z-[70] bg-[#001D4A] text-white w-10 h-10 rounded-xl flex items-center justify-center shadow-lg hover:bg-orange-500 transition-colors"
        >
          <i className={`fas ${isSidebarOpen ? 'fa-angle-left' : 'fa-bars'}`}></i>
        </button>

        <div className="p-6 md:p-10 pt-20 md:pt-10">
          {activeTab === 'booking' && (
            <div className="max-w-6xl mx-auto">
              <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center mb-10 gap-6">
                <div className="md:pl-12">
                  <h2 className="text-3xl font-black text-[#001D4A]">Tour Selection</h2>
                  <div className="flex items-center gap-2 text-gray-400 text-sm mt-1">
                    <i className="fas fa-bus-alt text-orange-500"></i>
                    <span>Select an active tour to manage seats</span>
                  </div>
                </div>

                <div className="flex items-center gap-4 bg-white p-3 rounded-2xl shadow-sm border border-gray-100">
                  <div className="bg-indigo-50 p-2 rounded-xl">
                    <i className="fas fa-map-marked-alt text-indigo-600"></i>
                  </div>
                  <div className="pr-4">
                    <p className="text-[10px] font-black text-gray-400 uppercase">Active Tour</p>
                    <select 
                      value={selectedBusIndex} 
                      onChange={(e) => setSelectedBusIndex(Number(e.target.value))}
                      className="bg-transparent border-none text-base font-black text-[#001D4A] focus:ring-0 p-0 cursor-pointer min-w-[150px]"
                    >
                      {buses.map((bus, idx) => (
                        <option key={bus.busId} value={idx}>{bus.busId}</option>
                      ))}
                    </select>
                  </div>
                </div>
              </div>

              {buses.length > 0 ? (
                <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                  <div className="lg:col-span-7">
                    <div className="bg-white rounded-[40px] shadow-2xl p-10 border border-gray-100 relative overflow-hidden">
                      <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-50 rounded-bl-full -z-0 opacity-50"></div>
                      <BusLayout seats={buses[selectedBusIndex].seats} onSeatClick={handleSeatClick} />
                    </div>
                  </div>

                  <div className="lg:col-span-5 space-y-8">
                    <div className="bg-white rounded-[32px] p-8 shadow-xl border border-gray-100">
                      <h3 className="font-black text-[#001D4A] mb-6 flex items-center gap-3">
                        <div className="w-8 h-8 bg-orange-100 text-orange-600 rounded-lg flex items-center justify-center text-sm">
                          <i className="fas fa-swatchbook"></i>
                        </div>
                        Visual Legend
                      </h3>
                      <div className="space-y-4">
                        {[
                          { color: 'bg-green-500', label: 'Vacant Seat', desc: 'Ready for booking' },
                          { color: 'bg-red-500', label: 'Standard Booked', desc: 'Male / Regular' },
                          { color: 'bg-pink-500', label: 'Female Passenger', desc: 'Reserved status' },
                          { color: 'bg-blue-500', label: 'Special Preference', desc: 'Non-Muslim / General' },
                          { color: 'bg-yellow-500', label: 'Gold Class', desc: 'Non-Muslim Female' },
                        ].map((item, idx) => (
                          <div key={idx} className="flex items-center gap-4 group">
                            <div className={`${item.color} w-10 h-10 rounded-xl shadow-md transition-transform group-hover:scale-110`}></div>
                            <div>
                              <p className="text-sm font-bold text-gray-800">{item.label}</p>
                              <p className="text-[10px] text-gray-400 uppercase font-black tracking-widest">{item.desc}</p>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>

                    <div className="bg-gradient-to-br from-indigo-900 to-[#001D4A] rounded-[32px] p-8 text-white shadow-2xl relative overflow-hidden">
                      <i className="fas fa-shield-alt absolute -right-4 -bottom-4 text-white/5 text-8xl rotate-12"></i>
                      <h4 className="text-xl font-black mb-4 flex items-center gap-2">
                        <i className="fas fa-lightbulb text-orange-400"></i>
                        Pro Tip
                      </h4>
                      <p className="text-sm text-indigo-100/80 leading-relaxed italic">
                        "Selecting a tour automatically loads its unique bus seat layout. All bookings are tour-specific."
                      </p>
                    </div>
                  </div>
                </div>
              ) : (
                <div className="bg-white p-20 rounded-[40px] text-center shadow-xl border border-gray-100">
                   <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-6 text-gray-200">
                      <i className="fas fa-bus-alt text-4xl"></i>
                   </div>
                   <h3 className="text-2xl font-black text-gray-400">No Tours Active</h3>
                   <p className="text-gray-400 mt-2">Go to Admin Control to add your first tour package.</p>
                </div>
              )}
            </div>
          )}

          {activeTab === 'dashboard' && <Dashboard buses={buses} />}
          {activeTab === 'log' && <BookingLog buses={buses} />}
          {activeTab === 'edit' && <EditData buses={buses} onUpdate={updateBooking} bookers={bookers} />}
          {activeTab === 'admin' && (
            <AdminPanel 
              tours={tours} setTours={setTours} 
              agents={bookers} setAgents={setBookers}
              customerTypes={customerTypes} setCustomerTypes={setCustomerTypes}
            />
          )}
        </div>
      </main>

      {showBookingModal && selectedBusIndex < buses.length && (
        <BookingModal 
          seatId={selectedSeatId!} 
          busNo={buses[selectedBusIndex].busId}
          onClose={() => { setShowBookingModal(false); setSelectedSeatId(null); }} 
          onSubmit={handleBookingSubmit}
          tours={tours}
          bookers={bookers}
          customerTypes={customerTypes}
        />
      )}

      {showConfirmDeselect && (
        <ConfirmationDialog 
          message="Are you sure you want to cancel this booking? This will free up the seat and delete all passenger data."
          onConfirm={confirmDeselect}
          onCancel={() => { setShowConfirmDeselect(false); setSeatToDeselect(null); }}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Tour, Booker, CustomerType } from '../types';

interface AdminPanelProps {
  tours: Tour[];
  setTours: React.Dispatch<React.SetStateAction<Tour[]>>;
  agents: Booker[];
  setAgents: React.Dispatch<React.SetStateAction<Booker[]>>;
  customerTypes: CustomerType[];
  setCustomerTypes: React.Dispatch<React.SetStateAction<CustomerType[]>>;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  tours, setTours, 
  agents, setAgents, 
  customerTypes, setCustomerTypes 
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'tours' | 'agents' | 'types'>('tours');

  // Local states for new entries
  const [newTour, setNewTour] = useState({ name: '', fee: 0 });
  const [newAgent, setNewAgent] = useState({ code: '', name: '' });
  const [newType, setNewType] = useState({ type: '', fee: 0 });

  const addTour = () => {
    if (!newTour.name.trim()) {
      alert("Please enter a tour name.");
      return;
    }
    if (tours.some(t => t.name.toLowerCase() === newTour.name.trim().toLowerCase())) {
      alert("A tour with this name already exists.");
      return;
    }
    setTours([...tours, { name: newTour.name.trim(), fee: newTour.fee }]);
    setNewTour({ name: '', fee: 0 });
  };

  const removeTour = (name: string) => {
    if (confirm(`Delete the tour "${name}"? This will also remove all its seat booking data.`)) {
      setTours(tours.filter(t => t.name !== name));
    }
  };

  const addAgent = () => {
    if (!newAgent.code.trim() || !newAgent.name.trim()) return;
    setAgents([...agents, { code: newAgent.code.trim().toUpperCase(), name: newAgent.name.trim() }]);
    setNewAgent({ code: '', name: '' });
  };

  const removeAgent = (code: string) => {
    if (confirm(`Remove agent with code ${code}?`)) {
      setAgents(agents.filter(a => a.code !== code));
    }
  };

  const addType = () => {
    if (!newType.type.trim()) return;
    setCustomerTypes([...customerTypes, { type: newType.type.trim(), fee: newType.fee }]);
    setNewType({ type: '', fee: 0 });
  };

  return (
    <div className="max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-5 duration-500">
      <div className="flex justify-between items-center mb-8">
        <h2 className="text-3xl font-black text-[#001D4A]">Admin Management</h2>
        <div className="bg-indigo-100 text-indigo-700 px-4 py-2 rounded-full text-xs font-black uppercase tracking-wider flex items-center gap-2">
          <i className="fas fa-lock"></i> Master Access
        </div>
      </div>

      {/* Tabs */}
      <div className="flex bg-white p-2 rounded-2xl shadow-sm mb-8">
        {[
          { id: 'tours', label: 'Tour Packages', icon: 'fa-globe' },
          { id: 'agents', label: 'Agent Log', icon: 'fa-users-cog' },
          { id: 'types', label: 'Pricing Tiers', icon: 'fa-tags' }
        ].map(tab => (
          <button 
            key={tab.id}
            onClick={() => setActiveSubTab(tab.id as any)}
            className={`flex-1 py-3 rounded-xl font-bold text-sm transition-all flex items-center justify-center gap-2 ${activeSubTab === tab.id ? 'bg-[#001D4A] text-white shadow-lg' : 'text-gray-400 hover:text-[#001D4A]'}`}
          >
            <i className={`fas ${tab.icon}`}></i> {tab.label}
          </button>
        ))}
      </div>

      {/* Tour Management */}
      {activeSubTab === 'tours' && (
        <div className="space-y-6">
          <div className="bg-white p-8 rounded-3xl shadow-xl border border-indigo-50">
            <h3 className="text-lg font-bold mb-4 flex items-center gap-2"><i className="fas fa-plus-circle text-orange-500"></i> Register New Tour</h3>
            <p className="text-xs text-gray-500 mb-6">Every tour name automatically creates a corresponding bus seat inventory in the main booking section.</p>
