            </div>
          </div>

          <div className="bg-white rounded-3xl shadow-xl border overflow-hidden">
            <table className="w-full text-left">
              <thead className="bg-gray-50 text-[10px] font-black uppercase text-gray-400 tracking-widest">
                <tr>
                  <th className="px-6 py-4">Tour Name / Bus ID</th>
                  <th className="px-6 py-4">Standard Fee</th>
                  <th className="px-6 py-4 text-right">Delete</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {tours.length > 0 ? tours.map(t => (
                  <tr key={t.name} className="group hover:bg-gray-50 transition-colors">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 bg-indigo-50 rounded-lg flex items-center justify-center text-indigo-500">
                           <i className="fas fa-route"></i>
                        </div>
                        <span className="font-bold text-gray-800">{t.name}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-indigo-600 font-bold">৳{t.fee.toLocaleString()}</td>
                    <td className="px-6 py-4 text-right">
                      <button onClick={() => removeTour(t.name)} className="text-red-400 hover:text-red-600 p-2 transition-colors">
                        <i className="fas fa-trash-alt"></i>
                      </button>
                    </td>
                  </tr>
                )) : (
                  <tr>
                    <td colSpan={3} className="px-6 py-12 text-center text-gray-300 italic">No tours defined yet.</td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Agent Management */}
      {activeSubTab === 'agents' && (
        <div className="space-y-6">
          <div className="bg-white p-8 rounded-3xl shadow-xl border">
            <h3 className="text-lg font-bold mb-4">Register New Agent</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 items-end">
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1">Booker Code</label>
                <input 
                  className="w-full px-4 py-2 bg-gray-50 border rounded-xl uppercase font-mono"
                  placeholder="e.g. AZ007"
                  value={newAgent.code}
                  onChange={(e) => setNewAgent({...newAgent, code: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1">Agent Full Name</label>
                <input 
                  className="w-full px-4 py-2 bg-gray-50 border rounded-xl"
                  placeholder="Agent Name"
                  value={newAgent.name}
                  onChange={(e) => setNewAgent({...newAgent, name: e.target.value})}
                />
              </div>
              <button onClick={addAgent} className="bg-indigo-600 text-white font-bold py-2 rounded-xl hover:bg-indigo-700 shadow-lg shadow-indigo-100">
                Confirm Agent
              </button>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {agents.map(a => (
              <div key={a.code} className="bg-white p-6 rounded-2xl shadow-md border border-gray-100 flex justify-between items-center hover:shadow-lg transition-shadow">
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 bg-indigo-50 text-indigo-500 rounded-full flex items-center justify-center font-black">
                    {a.name.charAt(0)}
                  </div>
                  <div>
                    <div className="text-[10px] font-black text-indigo-500 bg-indigo-50 px-2 py-0.5 rounded-full inline-block mb-1">{a.code}</div>
                    <p className="font-bold text-gray-800">{a.name}</p>
                  </div>
                </div>
                <button onClick={() => removeAgent(a.code)} className="text-gray-200 hover:text-red-500 p-2 transition-colors">
                  <i className="fas fa-user-minus"></i>
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Extra Type Management */}
      {activeSubTab === 'types' && (
        <div className="space-y-6">
          <div className="bg-white p-8 rounded-3xl shadow-xl border">
            <h3 className="text-lg font-bold mb-4">Pricing Tiers (Solo/Extra)</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 items-end">
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1">Tier Name</label>
                <input className="w-full px-4 py-2 bg-gray-50 border rounded-xl" placeholder="e.g. Premium Bed" value={newType.type} onChange={e => setNewType({...newType, type: e.target.value})} />
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1">Surcharge (৳)</label>
                <input type="number" className="w-full px-4 py-2 bg-gray-50 border rounded-xl" placeholder="Extra Cost" value={newType.fee || ''} onChange={e => setNewType({...newType, fee: Number(e.target.value)})} />
              </div>
              <button onClick={addType} className="bg-blue-600 text-white font-bold py-2 rounded-xl hover:bg-blue-700">Add to System</button>
            </div>
          </div>

          <div className="bg-white rounded-3xl p-6 shadow-xl border border-gray-50">
             <div className="space-y-3">
               {customerTypes.map((c, i) => (
                 <div key={i} className="flex justify-between items-center p-5 bg-gray-50 rounded-2xl border border-gray-100 group">
                    <div>
                      <span className="font-black text-gray-800">{c.type}</span>
                      <p className="text-[10px] text-gray-400 uppercase font-bold">Additional Category</p>
                    </div>
                    <div className="flex items-center gap-6">
                      <span className="text-indigo-600 font-black text-lg">+৳{c.fee.toLocaleString()}</span>
                      <button onClick={() => setCustomerTypes(customerTypes.filter((_, idx) => idx !== i))} className="text-gray-300 hover:text-red-500 transition-colors">
                        <i className="fas fa-trash"></i>
                      </button>
                    </div>
                 </div>
               ))}
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect } from 'react';
import { BUSINESS_INFO, generateInitialSeats } from './constants';
import { BusData, BookingInfo, Tour, Booker, CustomerType } from './types';
import BusLayout from './components/BusLayout';
import BookingModal from './components/BookingModal';
import ConfirmationDialog from './components/ConfirmationDialog';
import Dashboard from './components/Dashboard';
import BookingLog from './components/BookingLog';
import EditData from './components/EditData';
import AdminPanel from './components/AdminPanel';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'booking' | 'dashboard' | 'log' | 'edit' | 'admin'>('booking');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false); // Default closed on mobile
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);
  const [adminPasswordInput, setAdminPasswordInput] = useState('');
  const [showAdminLogin, setShowAdminLogin] = useState(false);

  // Dynamic Configuration State (Persisted)
  const [tours, setTours] = useState<Tour[]>(() => {
    const saved = localStorage.getItem('tl_tours');
    return saved ? JSON.parse(saved) : [
      { name: "Sajek Valley", fee: 4500 },
      { name: "Cox's Bazar Relax", fee: 6500 }
    ];
  });

  const [bookers, setBookers] = useState<Booker[]>(() => {
    const saved = localStorage.getItem('tl_bookers');
    return saved ? JSON.parse(saved) : [
      { code: "KS101", name: "Kazi Shetu" },
      { code: "SI202", name: "Sadekul Islam" }
    ];
  });

  const [customerTypes, setCustomerTypes] = useState<CustomerType[]>(() => {
    const saved = localStorage.getItem('tl_customer_types');
    return saved ? JSON.parse(saved) : [
      { type: "Standard", fee: 0 },
      { type: "Solo", fee: 1500 }
    ];
  });

  const [buses, setBuses] = useState<BusData[]>(() => {
    const saved = localStorage.getItem('tour_lagbe_buses');
    if (saved) return JSON.parse(saved);
    return [
      { name: "Sajek Valley", fee: 4500 },
      { name: "Cox's Bazar Relax", fee: 6500 }
    ].map(t => ({
      busId: t.name,
      seats: generateInitialSeats()
    }));
  });

  const [selectedBusIndex, setSelectedBusIndex] = useState(0);
  const [selectedSeatId, setSelectedSeatId] = useState<string | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [showConfirmDeselect, setShowConfirmDeselect] = useState(false);
  const [seatToDeselect, setSeatToDeselect] = useState<string | null>(null);

  useEffect(() => {
    setBuses(prevBuses => {
      const newBusList = tours.map(tour => {
        const existingBus = prevBuses.find(b => b.busId === tour.name);
        return existingBus || { busId: tour.name, seats: generateInitialSeats() };
      });
      // Filter out buses that no longer have a tour
      return newBusList.filter(b => tours.some(t => t.name === b.busId));
    });
  }, [tours]);

  useEffect(() => {
    localStorage.setItem('tour_lagbe_buses', JSON.stringify(buses));
    localStorage.setItem('tl_tours', JSON.stringify(tours));
    localStorage.setItem('tl_bookers', JSON.stringify(bookers));
    localStorage.setItem('tl_customer_types', JSON.stringify(customerTypes));
  }, [buses, tours, bookers, customerTypes]);

  const handleSeatClick = (seatId: string) => {
    if (selectedBusIndex >= buses.length) return;
    const seat = buses[selectedBusIndex].seats.find(s => s.id === seatId);
    if (seat?.isBooked) {
      setSeatToDeselect(seatId);
      setShowConfirmDeselect(true);
    } else {
      setSelectedSeatId(seatId);
      setShowBookingModal(true);
    }
  };

  const handleBookingSubmit = (info: BookingInfo) => {
    setBuses(prev => {
      const newBuses = [...prev];
      const bus = { ...newBuses[selectedBusIndex] };
      bus.seats = bus.seats.map(s => 
        s.id === selectedSeatId ? { ...s, isBooked: true, bookingInfo: info } : s
      );
      newBuses[selectedBusIndex] = bus;
      return newBuses;
    });
    setShowBookingModal(false);
    setSelectedSeatId(null);
  };

  const confirmDeselect = () => {
    if (seatToDeselect) {
      setBuses(prev => {
        const newBuses = [...prev];
        const bus = { ...newBuses[selectedBusIndex] };
        bus.seats = bus.seats.map(s => 
          s.id === seatToDeselect ? { ...s, isBooked: false, bookingInfo: undefined } : s
        );
        newBuses[selectedBusIndex] = bus;
        return newBuses;
      });
    }
    setShowConfirmDeselect(false);
    setSeatToDeselect(null);
  };

  const updateBooking = (updatedInfo: BookingInfo) => {
    setBuses(prev => prev.map(bus => ({
      ...bus,
      seats: bus.seats.map(seat => 
        seat.bookingInfo?.id === updatedInfo.id ? { ...seat, bookingInfo: updatedInfo } : seat
      )
    })));
  };

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPasswordInput === "@Rana&01625@") {
      setIsAdminAuthenticated(true);
      setShowAdminLogin(false);
      setActiveTab('admin');
      setAdminPasswordInput('');
    } else {
      alert("Incorrect Admin Password!");
    }
  };

  const openAdminTab = () => {
    if (isAdminAuthenticated) {
      setActiveTab('admin');
      setIsSidebarOpen(false);
    } else {
      setShowAdminLogin(true);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row font-sans overflow-hidden relative">
      {/* Sidebar Overlay for Mobile */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-[55] md:hidden"
          onClick={() => setIsSidebarOpen(false)}
        ></div>
      )}

      {/* Sidebar Navigation */}
      <nav className={`fixed md:sticky top-0 h-full transition-all duration-300 ease-in-out bg-[#001D4A] text-white flex flex-col shadow-2xl z-[60] shrink-0 
        ${isSidebarOpen ? 'w-72 translate-x-0' : 'w-72 -translate-x-full md:w-20 md:translate-x-0'}`}>

        <div className={`p-8 text-center border-b border-white/10 ${!isSidebarOpen && 'md:p-4'}`}>
          <div className="relative inline-block mb-3">
            <img src={BUSINESS_INFO.logo} alt="Logo" className={`${isSidebarOpen ? 'w-24' : 'w-10'} transition-all drop-shadow-lg mx-auto`} />
          </div>
          {isSidebarOpen && (
            <>
              <h1 className="text-2xl font-black text-white">{BUSINESS_INFO.name}</h1>
              <p className="text-[10px] text-orange-400 font-bold uppercase tracking-[0.2em] mt-1">{BUSINESS_INFO.motto}</p>
            </>
          )}
        </div>

        <div className="flex-grow py-6 space-y-1 overflow-y-auto">
          {[
            { id: 'dashboard', icon: 'fa-chart-line', label: 'Dashboard' },
            { id: 'booking', icon: 'fa-ticket-alt', label: 'Seat Booking' },
            { id: 'log', icon: 'fa-clipboard-list', label: 'Booking Log' },
            { id: 'edit', icon: 'fa-user-edit', label: 'Editor' },
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => { setActiveTab(tab.id as any); setIsSidebarOpen(false); }}
              className={`w-full flex items-center gap-4 px-8 py-4 text-sm font-semibold transition-all group ${activeTab === tab.id ? 'bg-orange-500 text-white shadow-lg' : 'text-white/70 hover:bg-white/5 hover:text-white'} ${!isSidebarOpen && 'md:px-0 md:justify-center'}`}
            >
              <i className={`fas ${tab.icon} w-6 text-center group-hover:scale-110 transition-transform`}></i>
              {isSidebarOpen && <span>{tab.label}</span>}
            </button>
          ))}

          <div className={`pt-8 ${isSidebarOpen ? 'px-4' : 'px-1'}`}>
            <div className="border-t border-white/10 pt-4">
              <button 
                onClick={openAdminTab}
                className={`w-full flex items-center gap-4 py-4 text-sm font-bold rounded-2xl transition-all ${activeTab === 'admin' ? 'bg-white text-[#001D4A]' : 'bg-indigo-600/30 text-indigo-200 hover:bg-indigo-600/50'} ${isSidebarOpen ? 'px-6' : 'justify-center'}`}
              >
                <i className="fas fa-user-shield"></i>
                {isSidebarOpen && <span>Admin Control</span>}
              </button>
            </div>
          </div>
        </div>

        {isSidebarOpen && (
          <div className="p-6 text-[10px] text-white/30 text-center border-t border-white/5">
            <p className="mb-1">{BUSINESS_INFO.address}</p>
            <p>© {new Date().getFullYear()} Tour লাগবে Official</p>
          </div>
        )}
      </nav>

      {/* Main Content Area */}
      <main className="flex-grow h-screen overflow-auto relative flex flex-col">
        {/* Mobile Header Bar */}
        <header className="sticky top-0 left-0 w-full bg-[#001D4A] text-white p-4 flex items-center justify-between z-50 md:hidden">
          <button onClick={() => setIsSidebarOpen(true)} className="w-10 h-10 flex items-center justify-center bg-white/10 rounded-xl">
            <i className="fas fa-bars"></i>
          </button>
          <div className="flex items-center gap-2">
            <img src={BUSINESS_INFO.logo} alt="Logo" className="h-8" />
            <span className="font-black text-sm">{BUSINESS_INFO.name}</span>
          </div>
          <div className="w-10"></div> {/* Spacer for symmetry */}
        </header>

        {/* Floating Sidebar Toggle for Desktop */}
        <button 
          onClick={() => setIsSidebarOpen(!isSidebarOpen)}
          className="hidden md:flex absolute top-6 left-6 z-[70] bg-[#001D4A] text-white w-10 h-10 rounded-xl items-center justify-center shadow-lg hover:bg-orange-500 transition-colors"
        >
          <i className={`fas ${isSidebarOpen ? 'fa-angle-left' : 'fa-angle-right'}`}></i>
        </button>

        <div className="p-4 md:p-10 flex-grow">
          {activeTab === 'booking' && (
            <div className="max-w-6xl mx-auto md:pl-12">
              <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center mb-8 gap-6">
                <div>
                  <h2 className="text-2xl md:text-3xl font-black text-[#001D4A]">Tour Selection</h2>
                  <div className="flex items-center gap-2 text-gray-400 text-xs md:text-sm mt-1">
                    <i className="fas fa-bus-alt text-orange-500"></i>
                    <span>Pick an active tour for seat entry</span>
                  </div>
                </div>

                <div className="w-full lg:w-auto flex items-center gap-4 bg-white p-3 rounded-2xl shadow-sm border border-gray-100">
                  <div className="bg-indigo-50 p-2 rounded-xl shrink-0">
                    <i className="fas fa-map-marked-alt text-indigo-600"></i>
                  </div>
                  <div className="flex-grow">
                    <p className="text-[10px] font-black text-gray-400 uppercase">Current Fleet</p>
                    <select 
                      value={selectedBusIndex} 
                      onChange={(e) => setSelectedBusIndex(Number(e.target.value))}
                      className="w-full bg-transparent border-none text-sm md:text-base font-black text-[#001D4A] focus:ring-0 p-0 cursor-pointer min-w-[150px]"
                    >
                      {buses.map((bus, idx) => (
                        <option key={bus.busId} value={idx}>{bus.busId}</option>
                      ))}
                    </select>
                  </div>
                </div>
              </div>

              {buses.length > 0 ? (
                <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 lg:gap-10">
                  {/* Bus Layout - Scrollable on mobile if needed */}
                  <div className="lg:col-span-7 overflow-x-auto pb-4">
                    <div className="min-w-[320px] bg-white rounded-[30px] md:rounded-[40px] shadow-2xl p-6 md:p-10 border border-gray-100 relative">
                      <BusLayout seats={buses[selectedBusIndex].seats} onSeatClick={handleSeatClick} />
                    </div>
                  </div>

                  {/* Sidebar Info */}
                  <div className="lg:col-span-5 space-y-6">
                    <div className="bg-white rounded-[24px] md:rounded-[32px] p-6 md:p-8 shadow-xl border border-gray-100">
                      <h3 className="font-black text-[#001D4A] mb-6 flex items-center gap-3">
                        <div className="w-8 h-8 bg-orange-100 text-orange-600 rounded-lg flex items-center justify-center text-sm">
                          <i className="fas fa-swatchbook"></i>
                        </div>
                        Seat Legend
                      </h3>
                      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-1 gap-3">
                        {[
                          { color: 'bg-green-500', label: 'Vacant', desc: 'Available' },
                          { color: 'bg-red-500', label: 'Standard', desc: 'Male Booked' },
                          { color: 'bg-pink-500', label: 'Female', desc: 'Reserved' },
                          { color: 'bg-blue-500', label: 'Non-Muslim', desc: 'Special' },
                          { color: 'bg-yellow-500', label: 'Gold', desc: 'Female Non-Muslim' },
                        ].map((item, idx) => (
                          <div key={idx} className="flex items-center gap-3">
                            <div className={`${item.color} w-8 h-8 md:w-10 md:h-10 rounded-xl shadow-md shrink-0`}></div>
                            <div>
                              <p className="text-xs md:text-sm font-bold text-gray-800 leading-none">{item.label}</p>
                              <p className="text-[9px] text-gray-400 uppercase font-black tracking-widest">{item.desc}</p>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>

                    <div className="bg-gradient-to-br from-indigo-900 to-[#001D4A] rounded-[24px] md:rounded-[32px] p-6 md:p-8 text-white shadow-2xl">
                      <h4 className="text-lg md:text-xl font-black mb-4 flex items-center gap-2">
                        <i className="fas fa-lightbulb text-orange-400"></i>
                        Pro Tip
                      </h4>
                      <p className="text-xs md:text-sm text-indigo-100/80 leading-relaxed italic">
                        "Each tour manages its own independent bus seating. Changes in admin tours directly sync with the booking fleet."
                      </p>
                    </div>
                  </div>
                </div>
              ) : (
                <div className="bg-white p-12 md:p-20 rounded-[30px] md:rounded-[40px] text-center shadow-xl border border-gray-100">
                   <div className="w-16 h-16 md:w-20 md:h-20 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-6 text-gray-200">
                      <i className="fas fa-bus-alt text-3xl md:text-4xl"></i>
                   </div>
                   <h3 className="text-xl md:text-2xl font-black text-gray-400">No Active Tours</h3>
                   <p className="text-gray-400 mt-2 text-sm">Please register tours in Admin Control to begin booking.</p>
                </div>
              )}
            </div>
          )}

          {activeTab === 'dashboard' && <Dashboard buses={buses} />}
          {activeTab === 'log' && <BookingLog buses={buses} />}
          {activeTab === 'edit' && <EditData buses={buses} onUpdate={updateBooking} bookers={bookers} />}
          {activeTab === 'admin' && (
            <AdminPanel 
              tours={tours} setTours={setTours} 
              agents={bookers} setAgents={setBookers}
              customerTypes={customerTypes} setCustomerTypes={setCustomerTypes}
            />
          )}
        </div>
      </main>

      {/* Admin Login Modal */}
      {showAdminLogin && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-[#001D4A]/90 backdrop-blur-md">
           <div className="bg-white w-full max-w-sm rounded-[32px] p-8 shadow-2xl animate-in zoom-in duration-300">
              <div className="text-center mb-6">
                <div className="w-16 h-16 bg-orange-100 text-orange-600 rounded-2xl flex items-center justify-center mx-auto mb-4 text-2xl">
                  <i className="fas fa-user-shield"></i>
                </div>
                <h3 className="text-2xl font-black text-[#001D4A]">Admin Login</h3>
                <p className="text-sm text-gray-400">Enter secure access key</p>
              </div>
              <form onSubmit={handleAdminLogin} className="space-y-4">
                <input 
                  autoFocus
                  type="password"
                  placeholder="Password"
                  value={adminPasswordInput}
                  onChange={(e) => setAdminPasswordInput(e.target.value)}
                  className="w-full px-5 py-4 bg-gray-50 border rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold text-center"
                />
                <div className="flex gap-3 pt-2">
                  <button type="button" onClick={() => setShowAdminLogin(false)} className="flex-1 py-4 text-gray-500 font-bold hover:bg-gray-50 rounded-2xl">Cancel</button>
                  <button type="submit" className="flex-1 py-4 bg-orange-500 text-white rounded-2xl font-black shadow-lg shadow-orange-100">Verify</button>
                </div>
              </form>
           </div>
        </div>
      )}

      {showBookingModal && selectedBusIndex < buses.length && (
        <BookingModal 
          seatId={selectedSeatId!} 
          busNo={buses[selectedBusIndex].busId}
          onClose={() => { setShowBookingModal(false); setSelectedSeatId(null); }} 
          onSubmit={handleBookingSubmit}
          tours={tours}
          bookers={bookers}
          customerTypes={customerTypes}
        />
      )}

      {showConfirmDeselect && (
        <ConfirmationDialog 
          message="Are you sure you want to cancel this booking? This will free up the seat and delete all passenger data."
          onConfirm={confirmDeselect}
          onCancel={() => { setShowConfirmDeselect(false); setSeatToDeselect(null); }}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Tour, Booker, CustomerType } from '../types';

interface AdminPanelProps {
  tours: Tour[];
  setTours: React.Dispatch<React.SetStateAction<Tour[]>>;
  agents: Booker[];
  setAgents: React.Dispatch<React.SetStateAction<Booker[]>>;
  customerTypes: CustomerType[];
  setCustomerTypes: React.Dispatch<React.SetStateAction<CustomerType[]>>;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  tours, setTours, 
  agents, setAgents, 
  customerTypes, setCustomerTypes 
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'tours' | 'agents' | 'types'>('tours');

  // Local states for new entries
  const [newTour, setNewTour] = useState({ name: '', fee: 0 });
  const [newAgent, setNewAgent] = useState({ code: '', name: '' });
  const [newType, setNewType] = useState({ type: '', fee: 0 });

  const addTour = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTour.name.trim()) {
      alert("Please enter a tour name.");
      return;
    }
    if (tours.some(t => t.name.toLowerCase() === newTour.name.trim().toLowerCase())) {
      alert("A tour with this name already exists.");
      return;
    }
    setTours([...tours, { name: newTour.name.trim(), fee: newTour.fee }]);
    setNewTour({ name: '', fee: 0 });
  };

  const removeTour = (name: string) => {
    if (confirm(`Delete the tour "${name}"? This will also remove all its seat booking data.`)) {
      setTours(tours.filter(t => t.name !== name));
    }
  };

  const addAgent = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAgent.code.trim() || !newAgent.name.trim()) return;
    if (agents.some(a => a.code.toUpperCase() === newAgent.code.trim().toUpperCase())) {
      alert("An agent with this code already exists.");
      return;
    }
    setAgents([...agents, { code: newAgent.code.trim().toUpperCase(), name: newAgent.name.trim() }]);
    setNewAgent({ code: '', name: '' });
  };

  const removeAgent = (code: string) => {
    if (confirm(`Remove agent with code ${code}?`)) {
      setAgents(agents.filter(a => a.code !== code));
    }
  };

  const addType = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newType.type.trim()) return;
    setCustomerTypes([...customerTypes, { type: newType.type.trim(), fee: newType.fee }]);
    setNewType({ type: '', fee: 0 });
  };

  const removeType = (index: number) => {
    if (confirm("Remove this pricing tier?")) {
      setCustomerTypes(customerTypes.filter((_, idx) => idx !== index));
    }
  };

  return (
    <div className="max-w-4xl mx-auto md:pl-12 animate-in fade-in slide-in-from-bottom-5 duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <h2 className="text-2xl md:text-3xl font-black text-[#001D4A]">Admin Management</h2>
        <div className="bg-indigo-100 text-indigo-700 px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-wider flex items-center gap-2">
          <i className="fas fa-lock"></i> Master Access
        </div>
      </div>

      {/* Responsive Tabs */}
      <div className="flex overflow-x-auto no-scrollbar bg-white p-2 rounded-2xl shadow-sm mb-8 gap-1">
        {[
          { id: 'tours', label: 'Tours', icon: 'fa-globe' },
          { id: 'agents', label: 'Agents', icon: 'fa-users-cog' },
          { id: 'types', label: 'Pricing', icon: 'fa-tags' }
        ].map(tab => (
          <button 
            key={tab.id}
            onClick={() => setActiveSubTab(tab.id as any)}
            className={`flex-1 min-w-[100px] py-3 rounded-xl font-bold text-xs transition-all flex items-center justify-center gap-2 ${activeSubTab === tab.id ? 'bg-[#001D4A] text-white shadow-lg' : 'text-gray-400 hover:text-[#001D4A] hover:bg-gray-50'}`}
          >
            <i className={`fas ${tab.icon}`}></i> {tab.label}
          </button>
        ))}
      </div>

      {/* Tour Management */}
      {activeSubTab === 'tours' && (
        <div className="space-y-6">
          <div className="bg-white p-6 md:p-8 rounded-[24px] md:rounded-[32px] shadow-xl border border-indigo-50">
            <h3 className="text-lg font-bold mb-2 flex items-center gap-2 text-[#001D4A]">
              <i className="fas fa-plus-circle text-orange-500"></i> Register New Tour
            </h3>
            <p className="text-[10px] md:text-xs text-gray-500 mb-6 font-medium">Adding a tour name automatically generates a bus layout for that tour.</p>
            <form onSubmit={addTour} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 items-end">
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1">Destination Name</label>
                <input 
                  required
                  className="w-full px-4 py-3 bg-gray-50 border-none rounded-xl focus:ring-2 focus:ring-orange-500"
                  placeholder="e.g. Bandarbans Special"
                  value={newTour.name}
                  onChange={(e) => setNewTour({...newTour, name: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1">Standard Budget (৳)</label>
                <input 
                  required
                  type="number"
                  className="w-full px-4 py-3 bg-gray-50 border-none rounded-xl focus:ring-2 focus:ring-orange-500"
                  value={newTour.fee || ''}
                  onChange={(e) => setNewTour({...newTour, fee: Number(e.target.value)})}
                />
              </div>
              <button type="submit" className="w-full bg-orange-500 text-white font-black py-3 rounded-xl hover:bg-orange-600 transition-colors shadow-lg shadow-orange-100">
                Launch Tour
              </button>
            </form>
          </div>

          <div className="bg-white rounded-[24px] md:rounded-[32px] shadow-xl border overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-gray-50 text-[10px] font-black uppercase text-gray-400 tracking-widest border-b">
                  <tr>
                    <th className="px-6 py-4">Tour Identity</th>
                    <th className="px-6 py-4">Pricing</th>
                    <th className="px-6 py-4 text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                  {tours.length > 0 ? tours.map(t => (
                    <tr key={t.name} className="hover:bg-gray-50/50 transition-colors">
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-3">
                          <div className="w-8 h-8 md:w-10 md:h-10 bg-indigo-50 text-indigo-500 rounded-xl flex items-center justify-center">
                             <i className="fas fa-route"></i>
                          </div>
                          <span className="font-bold text-gray-800 text-sm md:text-base">{t.name}</span>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-indigo-600 font-black text-sm md:text-base">৳{t.fee.toLocaleString()}</td>
                      <td className="px-6 py-4 text-right">
                        <button onClick={() => removeTour(t.name)} className="text-gray-300 hover:text-red-600 p-2 transition-colors">
                          <i className="fas fa-trash-alt"></i>
                        </button>
                      </td>
                    </tr>
                  )) : (
                    <tr>
                      <td colSpan={3} className="px-6 py-20 text-center text-gray-400 italic font-medium">No tour records available.</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {/* Agent Management */}
      {activeSubTab === 'agents' && (
        <div className="space-y-6">
          <div className="bg-white p-6 md:p-8 rounded-[24px] md:rounded-[32px] shadow-xl border border-indigo-50">
            <h3 className="text-lg font-bold mb-6 text-[#001D4A]">Create Agent Entry</h3>
            <form onSubmit={addAgent} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 items-end">
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1">Booker ID Code</label>
                <input 
                  required
                  className="w-full px-4 py-3 bg-gray-50 border-none rounded-xl focus:ring-2 focus:ring-indigo-500 uppercase font-mono tracking-widest"
                  placeholder="e.g. AGT-101"
                  value={newAgent.code}
                  onChange={(e) => setNewAgent({...newAgent, code: e.target.value.toUpperCase()})}
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1">Agent Full Name</label>
                <input 
                  required
                  className="w-full px-4 py-3 bg-gray-50 border-none rounded-xl focus:ring-2 focus:ring-indigo-500"
                  placeholder="Full Legal Name"
                  value={newAgent.name}
                  onChange={(e) => setNewAgent({...newAgent, name: e.target.value})}
                />
              </div>
              <button type="submit" className="w-full bg-indigo-600 text-white font-black py-3 rounded-xl hover:bg-indigo-700 shadow-lg shadow-indigo-100">
                Register Agent
              </button>
            </form>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            {agents.map(a => (
              <div key={a.code} className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100 flex justify-between items-center group hover:border-indigo-200 transition-all">
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 bg-indigo-50 text-indigo-500 rounded-full flex items-center justify-center font-black">
                    {a.name.charAt(0)}
                  </div>
                  <div>
                    <div className="text-[9px] font-black text-indigo-500 bg-indigo-100/50 px-2 py-0.5 rounded-full inline-block mb-0.5">{a.code}</div>
                    <p className="font-bold text-gray-800 text-sm">{a.name}</p>
                  </div>
                </div>
                <button onClick={() => removeAgent(a.code)} className="text-gray-200 hover:text-red-500 p-2 transition-colors">
                  <i className="fas fa-user-minus"></i>
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Extra Type Management */}
      {activeSubTab === 'types' && (
        <div className="space-y-6">
          <div className="bg-white p-6 md:p-8 rounded-[24px] md:rounded-[32px] shadow-xl border">
            <h3 className="text-lg font-bold mb-6 text-[#001D4A]">Manage Pricing Categories</h3>
            <form onSubmit={addType} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 items-end">
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1">Tier Category</label>
                <input required className="w-full px-4 py-3 bg-gray-50 border-none rounded-xl" placeholder="e.g. Deluxe Cabin" value={newType.type} onChange={e => setNewType({...newType, type: e.target.value})} />
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1">Additional Cost (৳)</label>
                <input required type="number" className="w-full px-4 py-3 bg-gray-50 border-none rounded-xl" placeholder="Extra Fee" value={newType.fee || ''} onChange={e => setNewType({...newType, fee: Number(e.target.value)})} />
              </div>
              <button type="submit" className="w-full bg-blue-600 text-white font-black py-3 rounded-xl hover:bg-blue-700">Add Tier</button>
            </form>
          </div>

          <div className="grid grid-cols-1 gap-3">
             {customerTypes.map((c, i) => (
               <div key={i} className="flex justify-between items-center p-5 bg-white rounded-2xl border border-gray-100 shadow-sm hover:border-blue-200 transition-all">
                  <div>
                    <span className="font-black text-gray-800 text-sm">{c.type}</span>
                    <p className="text-[9px] text-gray-400 uppercase font-black tracking-tighter">Surcharge Category</p>
