              <div className="p-6 bg-[#001D4A] rounded-[28px] text-white shadow-xl relative overflow-hidden">
                 <div className="flex justify-between text-[10px] opacity-50 mb-1 font-bold uppercase">
                   <span>Gross Total</span>
                   <span>৳{(tourFees + customerTypeFees).toLocaleString()}</span>
