                  <input required name="bookerCode" value={formData.bookerCode} onChange={handleChange} className={`w-full px-5 py-3 md:py-4 border-2 rounded-2xl focus:ring-0 outline-none uppercase font-mono text-sm tracking-widest ${bookerName ? 'border-green-400 bg-green-50 text-green-900' : 'border-gray-100 bg-gray-50'}`} placeholder="CODE-123" />
