import React, { useState, useEffect } from 'react';
import { BUSINESS_INFO, generateInitialSeats } from './constants';
import { BusData, BookingInfo, Tour, Booker, CustomerType } from './types';
import BusLayout from './components/BusLayout';
import BookingModal from './components/BookingModal';
import ConfirmationDialog from './components/ConfirmationDialog';
import Dashboard from './components/Dashboard';
import BookingLog from './components/BookingLog';
import EditData from './components/EditData';
import AdminPanel from './components/AdminPanel';
import SeatDetailModal from './components/SeatDetailModal';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'booking' | 'dashboard' | 'log' | 'edit' | 'admin'>('booking');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);
  const [adminPasswordInput, setAdminPasswordInput] = useState('');
  const [showAdminLogin, setShowAdminLogin] = useState(false);

  const [tours, setTours] = useState<Tour[]>(() => {
    const saved = localStorage.getItem('tl_tours');
    return saved ? JSON.parse(saved) : [
      { name: "Sajek Valley", fee: 4500 },
      { name: "Cox's Bazar Relax", fee: 6500 }
    ];
  });

  const [bookers, setBookers] = useState<Booker[]>(() => {
    const saved = localStorage.getItem('tl_bookers');
    return saved ? JSON.parse(saved) : [
      { code: "KS101", name: "Kazi Shetu" },
      { code: "SI202", name: "Sadekul Islam" }
    ];
  });

  const [customerTypes, setCustomerTypes] = useState<CustomerType[]>(() => {
    const saved = localStorage.getItem('tl_customer_types');
    return saved ? JSON.parse(saved) : [
      { type: "Standard", fee: 0 },
      { type: "Solo", fee: 1500 }
    ];
  });

  const [buses, setBuses] = useState<BusData[]>(() => {
    const saved = localStorage.getItem('tour_lagbe_buses');
    if (saved) return JSON.parse(saved);
    return [
      { name: "Sajek Valley", fee: 4500 },
      { name: "Cox's Bazar Relax", fee: 6500 }
    ].map(t => ({
      busId: t.name,
      seats: generateInitialSeats()
    }));
  });

  const [selectedBusIndex, setSelectedBusIndex] = useState(0);
  const [selectedSeatId, setSelectedSeatId] = useState<string | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [editingInfo, setEditingInfo] = useState<BookingInfo | null>(null);

  const [showConfirmDeselect, setShowConfirmDeselect] = useState(false);
  const [seatToDeselect, setSeatToDeselect] = useState<string | null>(null);

  useEffect(() => {
    setBuses(prevBuses => {
      const newBusList = tours.map(tour => {
        const existingBus = prevBuses.find(b => b.busId === tour.name);
        return existingBus || { busId: tour.name, seats: generateInitialSeats() };
      });
      return newBusList.filter(b => tours.some(t => t.name === b.busId));
    });
  }, [tours]);

  useEffect(() => {
    localStorage.setItem('tour_lagbe_buses', JSON.stringify(buses));
    localStorage.setItem('tl_tours', JSON.stringify(tours));
    localStorage.setItem('tl_bookers', JSON.stringify(bookers));
    localStorage.setItem('tl_customer_types', JSON.stringify(customerTypes));
  }, [buses, tours, bookers, customerTypes]);

  const handleSeatClick = (seatId: string) => {
    if (selectedBusIndex >= buses.length) return;
    const seat = buses[selectedBusIndex].seats.find(s => s.id === seatId);
    setSelectedSeatId(seatId);
    if (seat?.isBooked && seat.bookingInfo) {
      setEditingInfo(seat.bookingInfo);
      setShowDetailModal(true);
    } else {
      setShowBookingModal(true);
    }
  };

  const handleBookingSubmit = (info: BookingInfo) => {
    setBuses(prev => {
      const newBuses = [...prev];
      const busIndex = newBuses.findIndex(b => b.busId === (editingInfo ? editingInfo.busNo : buses[selectedBusIndex].busId));
      if (busIndex === -1) return prev;

      const bus = { ...newBuses[busIndex] };
      const targetSeatId = editingInfo ? editingInfo.seatNo : selectedSeatId;

      bus.seats = bus.seats.map(s => 
        s.id === targetSeatId ? { ...s, isBooked: true, bookingInfo: info } : s
      );
      newBuses[busIndex] = bus;
      return newBuses;
    });
    setShowBookingModal(false);
    setShowDetailModal(false);
    setSelectedSeatId(null);
    setEditingInfo(null);
  };

  const triggerCancelBooking = () => {
    if (editingInfo) {
      setSeatToDeselect(editingInfo.seatNo);
      setShowConfirmDeselect(true);
      setShowDetailModal(false);
    }
  };

  const confirmDeselect = () => {
    if (seatToDeselect && editingInfo) {
      setBuses(prev => {
        const newBuses = [...prev];
        const busIndex = newBuses.findIndex(b => b.busId === editingInfo.busNo);
        if (busIndex === -1) return prev;

        const bus = { ...newBuses[busIndex] };
        bus.seats = bus.seats.map(s => 
          s.id === seatToDeselect ? { ...s, isBooked: false, bookingInfo: undefined } : s
        );
        newBuses[busIndex] = bus;
        return newBuses;
      });
    }
    setShowConfirmDeselect(false);
    setSeatToDeselect(null);
    setEditingInfo(null);
  };

  const handleEditSeatRequest = () => {
    const code = prompt("Enter Agent Booker Code to Edit:");
    if (code && bookers.some(b => b.code.toUpperCase() === code.toUpperCase())) {
      setShowDetailModal(false);
      setShowBookingModal(true);
    } else if (code) {
      alert("Unauthorized Agent Code!");
    }
  };

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPasswordInput === "@Rana&01625@") {
      setIsAdminAuthenticated(true);
      setShowAdminLogin(false);
      setActiveTab('admin');
      setAdminPasswordInput('');
    } else {
      alert("Incorrect Admin Password!");
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row font-sans overflow-hidden relative">
      {isSidebarOpen && (
        <div className="fixed inset-0 bg-black/50 z-[55] md:hidden" onClick={() => setIsSidebarOpen(false)}></div>
      )}

      <nav className={`fixed md:sticky top-0 h-full transition-all duration-300 ease-in-out bg-[#001D4A] text-white flex flex-col shadow-2xl z-[60] shrink-0 
        ${isSidebarOpen ? 'w-72 translate-x-0' : 'w-72 -translate-x-full md:w-20 md:translate-x-0'}`}>

        <div className={`p-8 text-center border-b border-white/10 ${!isSidebarOpen && 'md:p-4'}`}>
          <img src={BUSINESS_INFO.logo} alt="Logo" className={`${isSidebarOpen ? 'w-24' : 'w-10'} transition-all drop-shadow-lg mx-auto mb-2`} />
          {isSidebarOpen && <h1 className="text-2xl font-black text-white">{BUSINESS_INFO.name}</h1>}
        </div>

        <div className="flex-grow py-6 space-y-1 overflow-y-auto">
          {[
            { id: 'dashboard', icon: 'fa-chart-line', label: 'Dashboard' },
            { id: 'booking', icon: 'fa-ticket-alt', label: 'Seat Booking' },
            { id: 'log', icon: 'fa-clipboard-list', label: 'Booking Log' },
            { id: 'edit', icon: 'fa-user-edit', label: 'Editor' },
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => { setActiveTab(tab.id as any); setIsSidebarOpen(false); }}
              className={`w-full flex items-center gap-4 px-8 py-4 text-sm font-semibold transition-all group ${activeTab === tab.id ? 'bg-orange-500 text-white shadow-lg' : 'text-white/70 hover:bg-white/5 hover:text-white'} ${!isSidebarOpen && 'md:px-0 md:justify-center'}`}
            >
              <i className={`fas ${tab.icon} w-6 text-center transition-transform group-hover:scale-110`}></i>
              {isSidebarOpen && <span>{tab.label}</span>}
            </button>
          ))}
          <div className={`pt-8 ${isSidebarOpen ? 'px-4' : 'px-1'}`}>
            <div className="border-t border-white/10 pt-4">
              <button onClick={() => setShowAdminLogin(true)} className={`w-full flex items-center gap-4 py-4 text-sm font-bold rounded-2xl transition-all ${activeTab === 'admin' ? 'bg-white text-[#001D4A]' : 'bg-indigo-600/30 text-indigo-200 hover:bg-indigo-600/50'} ${isSidebarOpen ? 'px-6' : 'justify-center'}`}>
                <i className="fas fa-user-shield"></i>
                {isSidebarOpen && <span>Admin Control</span>}
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="flex-grow h-screen overflow-auto relative flex flex-col">
        <header className="sticky top-0 left-0 w-full bg-[#001D4A] text-white p-4 flex items-center justify-between z-50 md:hidden">
          <button onClick={() => setIsSidebarOpen(true)} className="w-10 h-10 flex items-center justify-center bg-white/10 rounded-xl">
            <i className="fas fa-bars"></i>
          </button>
          <img src={BUSINESS_INFO.logo} alt="Logo" className="h-8" />
          <div className="w-10"></div>
        </header>

        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="hidden md:flex absolute top-6 left-6 z-[70] bg-[#001D4A] text-white w-10 h-10 rounded-xl items-center justify-center shadow-lg hover:bg-orange-500 transition-colors">
          <i className={`fas ${isSidebarOpen ? 'fa-angle-left' : 'fa-angle-right'}`}></i>
        </button>

        <div className="p-4 md:p-10 flex-grow">
          {activeTab === 'booking' && (
            <div className="max-w-6xl mx-auto md:pl-12">
               <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center mb-10 gap-6">
                <div>
                  <h2 className="text-3xl font-black text-[#001D4A]">Seat Booking</h2>
                  <p className="text-sm text-gray-400">Select a seat to book or view details.</p>
                </div>
                <select 
                  value={selectedBusIndex} 
                  onChange={(e) => setSelectedBusIndex(Number(e.target.value))}
                  className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 font-black text-[#001D4A] outline-none min-w-[200px]"
                >
                  {buses.map((bus, idx) => <option key={bus.busId} value={idx}>{bus.busId}</option>)}
                </select>
              </div>
              <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                <div className="lg:col-span-7 overflow-x-auto pb-4">
                  <div className="min-w-[320px] bg-white rounded-[40px] shadow-2xl p-6 md:p-10 border border-gray-100">
                    <BusLayout seats={buses[selectedBusIndex]?.seats || []} onSeatClick={handleSeatClick} />
                  </div>
                </div>
                <div className="lg:col-span-5 space-y-6">
                  <div className="bg-white rounded-[32px] p-8 shadow-xl border border-gray-100">
                    <h3 className="font-black text-[#001D4A] mb-6 flex items-center gap-3">Visual Status</h3>
                    <div className="grid grid-cols-2 lg:grid-cols-1 gap-4">
                      {[{c:'bg-green-500',l:'Vacant'},{c:'bg-red-500',l:'Male'},{c:'bg-pink-500',l:'Female'},{c:'bg-blue-500',l:'Special'},{c:'bg-yellow-500',l:'Gold'}].map((item,i)=>(
                        <div key={i} className="flex items-center gap-4"><div className={`${item.c} w-10 h-10 rounded-xl`}></div><span className="text-sm font-bold text-gray-700">{item.l}</span></div>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'dashboard' && <Dashboard buses={buses} />}
          {activeTab === 'log' && <BookingLog buses={buses} />}
          {activeTab === 'edit' && <EditData buses={buses} onUpdate={updateBooking} bookers={bookers} />}
          {activeTab === 'admin' && isAdminAuthenticated && (
            <AdminPanel tours={tours} setTours={setTours} agents={bookers} setAgents={setBookers} customerTypes={customerTypes} setCustomerTypes={setCustomerTypes} />
          )}
        </div>
      </main>

      {showAdminLogin && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-[#001D4A]/90 backdrop-blur-md">
           <div className="bg-white w-full max-w-sm rounded-[32px] p-8 shadow-2xl animate-in zoom-in duration-300">
              <h3 className="text-2xl font-black text-[#001D4A] mb-2 text-center">Admin Access</h3>
              <p className="text-sm text-gray-400 text-center mb-6">Enter secure password</p>
              <form onSubmit={handleAdminLogin} className="space-y-4">
                <input autoFocus type="password" placeholder="Password" value={adminPasswordInput} onChange={(e) => setAdminPasswordInput(e.target.value)} className="w-full px-5 py-4 bg-gray-50 border rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold text-center" />
                <div className="flex gap-3">
                  <button type="button" onClick={() => setShowAdminLogin(false)} className="flex-1 py-4 text-gray-500 font-bold hover:bg-gray-50 rounded-2xl">Cancel</button>
                  <button type="submit" className="flex-1 py-4 bg-orange-500 text-white rounded-2xl font-black shadow-lg">Login</button>
                </div>
              </form>
           </div>
        </div>
      )}

      {showBookingModal && (
        <BookingModal 
          seatId={selectedSeatId!} 
          busNo={editingInfo ? editingInfo.busNo : buses[selectedBusIndex].busId}
          onClose={() => { setShowBookingModal(false); setSelectedSeatId(null); setEditingInfo(null); }} 
          onSubmit={handleBookingSubmit}
          tours={tours}
          bookers={bookers}
          customerTypes={customerTypes}
          existingData={editingInfo || undefined}
        />
      )}

      {showDetailModal && editingInfo && (
        <SeatDetailModal 
          info={editingInfo} 
          onClose={() => { setShowDetailModal(false); setEditingInfo(null); }} 
          onEdit={handleEditSeatRequest}
          onCancel={triggerCancelBooking}
        />
      )}

      {showConfirmDeselect && (
        <ConfirmationDialog message="Are you sure you want to cancel this booking?" onConfirm={confirmDeselect} onCancel={() => setShowConfirmDeselect(false)} />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { BookingInfo, Gender, Religion, Tour, CustomerType, Booker } from '../types';
import { BUSINESS_INFO } from '../constants';

interface BookingModalProps {
  seatId: string;
  busNo: string;
  onClose: () => void;
  onSubmit: (info: BookingInfo) => void;
  tours: Tour[];
  bookers: Booker[];
  customerTypes: CustomerType[];
  existingData?: BookingInfo;
}

const BookingModal: React.FC<BookingModalProps> = ({ seatId, busNo, onClose, onSubmit, tours, bookers, customerTypes, existingData }) => {
  const [formData, setFormData] = useState({
    name: existingData?.name || '',
    mobile: existingData?.mobile || '',
    address: existingData?.address || '',
    gender: existingData?.gender || Gender.MALE,
    religion: existingData?.religion || Religion.MUSLIM,
    tourName: existingData?.tourName || busNo,
    customerType: existingData?.customerType || (customerTypes.length > 0 ? customerTypes[0].type : ''),
    discountAmount: existingData?.discountAmount || 0,
    advanceAmount: existingData?.advanceAmount || 0,
    bookerCode: existingData?.bookerCode || ''
  });

  const [tourFees, setTourFees] = useState(0);
  const [customerTypeFees, setCustomerTypeFees] = useState(0);
  const [dueAmount, setDueAmount] = useState(0);
  const [isRelaxTour, setIsRelaxTour] = useState(false);
  const [bookerName, setBookerName] = useState('');

  useEffect(() => {
    const tour = tours.find(t => t.name === formData.tourName);
    const fee = tour ? tour.fee : 0;
    setTourFees(fee);
    setIsRelaxTour(formData.tourName.toLowerCase().includes('relax'));

    const cType = customerTypes.find(c => c.type === formData.customerType);
    const cFee = cType ? cType.fee : 0;
    setCustomerTypeFees(cFee);

    const booker = bookers.find(b => b.code.toUpperCase() === formData.bookerCode.toUpperCase());
    setBookerName(booker ? booker.name : '');

    const total = fee + cFee;
    const due = total - formData.discountAmount - formData.advanceAmount;
    setDueAmount(due);
  }, [formData, tours, bookers, customerTypes]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleNumericChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: Number(value) }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!bookerName) {
      alert("Invalid Agent Code! A verified booker code is required.");
      return;
    }

    const info: BookingInfo = {
      id: existingData?.id || Math.random().toString(36).substr(2, 9).toUpperCase(),
      ...formData,
      tourFees,
      customerTypeFees,
      dueAmount,
      paymentStatus: dueAmount <= 0 ? 'Paid' : (formData.advanceAmount > 0 ? 'Partial' : 'Due'),
      busNo: formData.tourName,
      seatNo: seatId,
      bookedBy: bookerName,
      bookingDate: existingData?.bookingDate || new Date().toISOString()
    };
    onSubmit(info);
  };

  return (
    <div className="fixed inset-0 z-[130] flex items-center justify-center p-2 md:p-4 bg-[#001D4A]/80 backdrop-blur-md overflow-y-auto">
      <div className="bg-white w-full max-w-2xl rounded-[30px] md:rounded-[40px] shadow-2xl my-auto animate-in fade-in zoom-in duration-300 border border-white/20 flex flex-col max-h-[95vh] overflow-hidden">
        <div className="bg-gradient-to-r from-orange-500 to-orange-600 p-6 md:p-8 text-white flex justify-between items-center relative shrink-0">
          <div>
            <h3 className="text-xl md:text-2xl font-black">{existingData ? 'Edit' : 'Book'} Seat {seatId}</h3>
            <p className="text-orange-100 text-[10px] uppercase font-black tracking-widest mt-1">{busNo} Terminal</p>
          </div>
          <button onClick={onClose} className="w-10 h-10 md:w-12 md:h-12 rounded-2xl bg-white/20 hover:bg-white/30 flex items-center justify-center text-xl"><i className="fas fa-times"></i></button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 md:p-10 overflow-y-auto custom-scrollbar">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-5">
              <h4 className="font-black text-[#001D4A] text-xs uppercase tracking-wider flex items-center gap-2">Passenger Information</h4>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase">Legal Name</label>
                <input required name="name" value={formData.name} onChange={handleChange} className="w-full px-5 py-3 md:py-4 bg-gray-50 border-none rounded-2xl text-sm" placeholder="e.g. Arif Hossain" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase">Mobile (+880)</label>
                <div className="relative">
                  <span className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400 font-bold text-sm">+880</span>
                  <input required name="mobile" value={formData.mobile} onChange={handleChange} className="w-full pl-16 pr-5 py-3 md:py-4 bg-gray-50 border-none rounded-2xl text-sm" placeholder="1XXXXXXXXX" />
                </div>
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase">Home Address</label>
                <textarea name="address" value={formData.address} onChange={handleChange} rows={2} className="w-full px-5 py-3 bg-gray-50 border-none rounded-2xl text-sm" placeholder="Detailed Address" />
              </div>
              <div className="grid grid-cols-2 gap-3">
                 <div className="space-y-1"><label className="text-[10px] font-black text-gray-400 uppercase">Gender</label><select name="gender" value={formData.gender} onChange={handleChange} className="w-full px-4 py-3 bg-gray-50 border-none rounded-2xl text-xs font-bold">{Object.values(Gender).map(g => <option key={g} value={g}>{g}</option>)}</select></div>
                 <div className="space-y-1"><label className="text-[10px] font-black text-gray-400 uppercase">Religion</label><select name="religion" value={formData.religion} onChange={handleChange} className="w-full px-4 py-3 bg-gray-50 border-none rounded-2xl text-xs font-bold">{Object.values(Religion).map(r => <option key={r} value={r}>{r}</option>)}</select></div>
              </div>
            </div>

            <div className="space-y-5">
              <h4 className="font-black text-[#001D4A] text-xs uppercase tracking-wider flex items-center gap-2">Tour & Billing</h4>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase">Tour Name</label>
                <select name="tourName" value={formData.tourName} onChange={handleChange} className="w-full px-5 py-3 md:py-4 bg-indigo-50 border-none rounded-2xl font-black text-indigo-700 text-sm">{tours.map(t => <option key={t.name} value={t.name}>{t.name}</option>)}</select>
              </div>
              {(isRelaxTour || customerTypes.length > 0) && (
                <div className="space-y-1"><label className="text-[10px] font-black text-gray-400 uppercase">Extra Category</label><select name="customerType" value={formData.customerType} onChange={handleChange} className="w-full px-5 py-3 bg-gray-50 border-none rounded-2xl text-sm font-bold">{customerTypes.map(c => <option key={c.type} value={c.type}>{c.type} (+৳{c.fee})</option>)}</select></div>
              )}
              <div className="grid grid-cols-2 gap-3">
                <div className="space-y-1"><label className="text-[10px] font-black text-gray-400 uppercase">Discount</label><input type="number" name="discountAmount" value={formData.discountAmount || ''} onChange={handleNumericChange} className="w-full px-5 py-3 bg-gray-50 border-none rounded-2xl font-bold text-sm" /></div>
                <div className="space-y-1"><label className="text-[10px] font-black text-gray-400 uppercase">Advance</label><input type="number" name="advanceAmount" value={formData.advanceAmount || ''} onChange={handleNumericChange} className="w-full px-5 py-3 bg-green-50 border-none rounded-2xl font-bold text-green-700 text-sm" /></div>
              </div>
              <div className="p-6 bg-[#001D4A] rounded-[28px] text-white shadow-xl relative overflow-hidden">
                 <div className="flex justify-between items-center"><span className="text-[10px] font-black text-orange-400 uppercase">Due Balance</span><span className="text-xl md:text-2xl font-black">৳{dueAmount.toLocaleString()}</span></div>
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase">Agent Verification Code</label>
                <div className="relative">
                  <input required name="bookerCode" value={formData.bookerCode} onChange={handleChange} className={`w-full px-5 py-3 md:py-4 border-2 rounded-2xl focus:ring-0 outline-none font-mono text-sm uppercase ${bookerName ? 'border-green-400 bg-green-50' : 'border-gray-100 bg-gray-50'}`} placeholder="CODE-123" />
                  {bookerName && <div className="absolute right-3 top-1/2 -translate-y-1/2 px-2 py-1 bg-green-500 text-white rounded-lg text-[8px] font-black uppercase">{bookerName}</div>}
                </div>
              </div>
            </div>
          </div>
          <div className="pt-8 mt-4 border-t sticky bottom-0 bg-white">
            <button type="submit" className="w-full py-4 md:py-5 bg-orange-500 text-white rounded-2xl font-black text-lg md:text-xl shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3">Confirm Entry <i className="fas fa-check-circle"></i></button>
          </div>
        </form>
      </div>
    </div>
  );
};

