              </div>
              <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                <div className="lg:col-span-7 overflow-x-auto pb-4">
                  <div className="min-w-[320px] bg-white rounded-[40px] shadow-2xl p-6 md:p-10 border border-gray-100">
                    <BusLayout seats={buses[selectedBusIndex]?.seats || []} onSeatClick={handleSeatClick} />
                  </div>
                </div>
                <div className="lg:col-span-5 space-y-6">
                  <div className="bg-white rounded-[32px] p-8 shadow-xl border border-gray-100">
                    <h3 className="font-black text-[#001D4A] mb-6 flex items-center gap-3">Visual Key</h3>
                    <div className="grid grid-cols-2 lg:grid-cols-1 gap-4">
                      {[{c:'bg-green-500',l:'Vacant'},{c:'bg-red-500',l:'Male'},{c:'bg-pink-500',l:'Female'},{c:'bg-blue-500',l:'Special'},{c:'bg-yellow-500',l:'Gold'}].map((item,i)=>(
                        <div key={i} className="flex items-center gap-4"><div className={`${item.c} w-10 h-10 rounded-xl`}></div><span className="text-sm font-bold text-gray-700">{item.l}</span></div>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'dashboard' && <Dashboard buses={buses} />}
          {activeTab === 'log' && <BookingLog buses={buses} />}
          {activeTab === 'edit' && <EditData buses={buses} onUpdate={updateBooking} onDelete={triggerCancelBooking} onEdit={handleEditSeatRequest} bookers={bookers} />}
          {activeTab === 'admin' && isAdminAuthenticated && (
            <AdminPanel 
              tours={tours} setTours={updateToursMaster} 
              agents={bookers} setAgents={setBookers} 
              customerTypes={customerTypes} setCustomerTypes={setCustomerTypes} 
            />
          )}
        </div>
      </main>

      {showAdminLogin && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-[#001D4A]/90 backdrop-blur-md">
           <div className="bg-white w-full max-w-sm rounded-[32px] p-8 shadow-2xl animate-in zoom-in duration-300">
              <h3 className="text-2xl font-black text-[#001D4A] mb-2 text-center">Admin Access</h3>
              <p className="text-sm text-gray-400 text-center mb-6">Enter secure password</p>
              <form onSubmit={handleAdminLogin} className="space-y-4">
                <input autoFocus type="password" placeholder="Password" value={adminPasswordInput} onChange={(e) => setAdminPasswordInput(e.target.value)} className="w-full px-5 py-4 bg-gray-50 border rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold text-center" />
                <div className="flex gap-3">
                  <button type="button" onClick={() => setShowAdminLogin(false)} className="flex-1 py-4 text-gray-500 font-bold hover:bg-gray-50 rounded-2xl">Cancel</button>
                  <button type="submit" className="flex-1 py-4 bg-orange-500 text-white rounded-2xl font-black shadow-lg">Login</button>
                </div>
              </form>
           </div>
        </div>
      )}

      {showBookingModal && (
        <BookingModal 
          seatId={selectedSeatId!} 
          busNo={editingInfo ? editingInfo.busNo : (buses[selectedBusIndex]?.busId || '')}
          onClose={() => { setShowBookingModal(false); setSelectedSeatId(null); setEditingInfo(null); }} 
          onSubmit={handleBookingSubmit}
          tours={tours}
          bookers={bookers}
          customerTypes={customerTypes}
          existingData={editingInfo || undefined}
        />
      )}

      {showDetailModal && editingInfo && (
        <SeatDetailModal 
          info={editingInfo} 
          onClose={() => { setShowDetailModal(false); setEditingInfo(null); }} 
          onEdit={() => handleEditSeatRequest(editingInfo)}
          onCancel={() => triggerCancelBooking(editingInfo.busNo, editingInfo.seatNo)}
        />
      )}

      {showConfirmDeselect && (
        <ConfirmationDialog message="Are you sure you want to cancel this booking? This action is irreversible." onConfirm={confirmDeselect} onCancel={() => setShowConfirmDeselect(false)} />
      )}
    </div>
  );
};

export default App;

import React, { useRef } from 'react';
import { BookingInfo } from '../types';
import { BUSINESS_INFO } from '../constants';

interface SeatDetailModalProps {
  info: BookingInfo;
  onClose: () => void;
  onEdit: () => void;
  onCancel: () => void;
  onUpdate?: (updatedInfo: BookingInfo) => void;
}

const SeatDetailModal: React.FC<SeatDetailModalProps> = ({ info, onClose, onEdit, onCancel, onUpdate }) => {
  const ticketRef = useRef<HTMLDivElement>(null);

  // Generate QR Code URL based on booking info
  const qrData = `ID:${info.id}|Seat:${info.seatNo}|Name:${info.name}|Tour:${info.tourName}`;
  const qrCodeUrl = `https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=${encodeURIComponent(qrData)}`;

  const handlePayDue = () => {
    const code = prompt("Security Check: Enter the original Agent Booker Code to settle this balance:");
    if (code && code.toUpperCase() === info.bookerCode.toUpperCase()) {
      if (onUpdate) {
        const updatedInfo: BookingInfo = {
          ...info,
          advanceAmount: info.advanceAmount + info.dueAmount,
          dueAmount: 0,
          paymentStatus: 'Paid'
        };
        onUpdate(updatedInfo);
        alert("Balance settled successfully!");
      }
    } else if (code) {
      alert("Verification Failed: Unauthorized Agent Code. Only the original booker can settle this balance.");
    }
  };

  const printTicket = () => {
    const printContent = ticketRef.current;
    const windowPrint = window.open('', '', 'left=0,top=0,width=800,height=900,toolbar=0,scrollbars=0,status=0');
    if (windowPrint && printContent) {
      windowPrint.document.write(`
        <html>
          <head>
            <title>Ticket - ${info.name}</title>
            <script src="https://cdn.tailwindcss.com"></script>
            <link href="https://fonts.googleapis.com/css2?family=Hind+Siliguri:wght@400;700&display=swap" rel="stylesheet">
            <style>
              body { font-family: 'Hind Siliguri', sans-serif; }
              @media print {
                .no-print { display: none; }
                .ticket-container { border: 2px dashed #ccc; padding: 20px; border-radius: 20px; }
              }
            </style>
          </head>
          <body onload="window.print();window.close()">
            <div class="p-10 ticket-container">
              ${printContent.innerHTML}
            </div>
          </body>
        </html>
      `);
      windowPrint.document.close();
      windowPrint.focus();
    }
  };

  return (
    <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-[#001D4A]/80 backdrop-blur-md overflow-y-auto">
      <div className="bg-white w-full max-w-xl rounded-[40px] shadow-2xl my-auto animate-in zoom-in duration-300 overflow-hidden border border-white/20">

        <div className="p-6 md:p-8">
           <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-black text-white bg-indigo-600 px-3 py-1 rounded-full uppercase mb-2 inline-block tracking-widest">Booking Record</span>
                <h3 className="text-2xl md:text-3xl font-black text-[#001D4A]">{info.name}</h3>
              </div>
              <button onClick={onClose} className="w-10 h-10 bg-gray-100 rounded-full flex items-center justify-center hover:bg-red-50 hover:text-red-500 transition-colors">
                <i className="fas fa-times"></i>
              </button>
           </div>

           {/* Ticket Design */}
           <div ref={ticketRef} className="bg-white border-2 border-dashed border-gray-200 rounded-[32px] p-6 mb-8 relative overflow-hidden shadow-inner">
              <div className="absolute -left-4 top-1/2 -translate-y-1/2 w-8 h-8 bg-gray-50 rounded-full border-r-2 border-dashed border-gray-200"></div>
              <div className="absolute -right-4 top-1/2 -translate-y-1/2 w-8 h-8 bg-gray-50 rounded-full border-l-2 border-dashed border-gray-200"></div>

              <div className="flex justify-between items-start mb-6">
                 <div>
                    <img src={BUSINESS_INFO.logo} alt="Logo" className="h-10 mb-2" />
                    <p className="text-[8px] font-black text-gray-400 uppercase tracking-widest">{BUSINESS_INFO.address}</p>
                 </div>
                 <div className="text-right">
                    <div className="bg-[#001D4A] text-white px-3 py-1 rounded-lg inline-block mb-1">
                      <p className="text-[10px] font-black uppercase tracking-tighter">Seat: {info.seatNo}</p>
                    </div>
                    <p className="text-[9px] font-bold text-gray-400">ID: {info.id}</p>
                 </div>
              </div>

              <div className="flex flex-col md:flex-row gap-6 border-y border-dashed border-gray-200 py-6 mb-6">
                 <div className="flex-grow grid grid-cols-2 gap-4">
                    <div>
                        <p className="text-[9px] font-black text-gray-400 uppercase mb-0.5">Passenger</p>
                        <p className="text-sm font-black text-[#001D4A]">{info.name}</p>
                    </div>
                    <div>
                        <p className="text-[9px] font-black text-gray-400 uppercase mb-0.5">Tour</p>
                        <p className="text-sm font-black text-[#001D4A] truncate">{info.tourName}</p>
                    </div>
                    <div>
                        <p className="text-[9px] font-black text-gray-400 uppercase mb-0.5">Contact</p>
                        <p className="text-sm font-bold text-gray-700">+880{info.mobile}</p>
                    </div>
                    <div>
                        <p className="text-[9px] font-black text-gray-400 uppercase mb-0.5">Status</p>
                        <p className={`text-sm font-black uppercase tracking-widest ${info.paymentStatus === 'Paid' ? 'text-green-600' : 'text-orange-500'}`}>{info.paymentStatus}</p>
                    </div>
                 </div>

                 {/* QR Code Section */}
                 <div className="flex justify-center items-center bg-gray-50 p-2 rounded-2xl border border-gray-100 shrink-0">
                    <img src={qrCodeUrl} alt="QR Code" className="w-24 h-24 md:w-28 md:h-28" />
                 </div>
              </div>

              <div className="flex justify-between items-end">
                 <div>
                    <p className="text-[9px] font-black text-gray-400 uppercase">Booked By</p>
                    <p className="text-xs font-bold text-gray-800">{info.bookedBy} ({info.bookerCode})</p>
                 </div>
                 <div className="text-right">
                    {info.dueAmount > 0 ? (
                      <div>
                        <p className="text-[9px] font-black text-red-400 uppercase">Outstanding Due</p>
                        <p className="text-xl font-black text-red-600">৳{info.dueAmount.toLocaleString()}</p>
                      </div>
                    ) : (
                      <div className="flex items-center gap-2 text-green-600">
                        <i className="fas fa-check-circle"></i>
                        <span className="text-xs font-black uppercase tracking-widest">Fully Paid</span>
                      </div>
                    )}
                 </div>
              </div>
           </div>

           {/* Action Controls */}
           <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <button 
                onClick={printTicket}
                className="py-4 bg-[#001D4A] text-white rounded-2xl font-black text-sm hover:bg-indigo-700 shadow-xl shadow-indigo-100 flex items-center justify-center gap-2"
              >
                <i className="fas fa-print"></i> Print Ticket
              </button>

              {info.dueAmount > 0 ? (
                <button 
                  onClick={handlePayDue}
                  className="py-4 bg-green-600 text-white rounded-2xl font-black text-sm hover:bg-green-700 shadow-xl shadow-green-100 flex items-center justify-center gap-2"
                >
                  <i className="fas fa-money-bill-wave"></i> Pay Due (৳{info.dueAmount})
                </button>
              ) : (
                <button 
                  disabled
                  className="py-4 bg-gray-100 text-gray-400 rounded-2xl font-black text-sm cursor-not-allowed flex items-center justify-center gap-2"
                >
                  <i className="fas fa-check-double"></i> Paid
                </button>
              )}

              <button 
                onClick={onEdit}
                className="py-4 bg-blue-50 text-blue-600 rounded-2xl font-black text-sm hover:bg-blue-100 flex items-center justify-center gap-2"
              >
                <i className="fas fa-user-edit"></i> Full Edit
              </button>
              <button 
                onClick={onCancel}
                className="py-4 bg-red-50 text-red-600 rounded-2xl font-black text-sm hover:bg-red-100 flex items-center justify-center gap-2"
              >
                <i className="fas fa-trash-alt"></i> Cancel Booking
              </button>
           </div>
        </div>
      </div>
    </div>
  );
};

export default SeatDetailModal;

import React, { useState, useEffect } from 'react';
import { BUSINESS_INFO, generateInitialSeats } from './constants';
import { BusData, BookingInfo, Tour, Booker, CustomerType } from './types';
import BusLayout from './components/BusLayout';
import BookingModal from './components/BookingModal';
import ConfirmationDialog from './components/ConfirmationDialog';
import Dashboard from './components/Dashboard';
import BookingLog from './components/BookingLog';
import EditData from './components/EditData';
import AdminPanel from './components/AdminPanel';
import SeatDetailModal from './components/SeatDetailModal';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'booking' | 'dashboard' | 'log' | 'edit' | 'admin'>('booking');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);
  const [adminPasswordInput, setAdminPasswordInput] = useState('');
  const [showAdminLogin, setShowAdminLogin] = useState(false);

  const [selectedBusIndex, setSelectedBusIndex] = useState(0);
  const [selectedSeatId, setSelectedSeatId] = useState<string | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [showConfirmDeselect, setShowConfirmDeselect] = useState(false);
  const [editingInfo, setEditingInfo] = useState<BookingInfo | null>(null);
  const [seatToDeselect, setSeatToDeselect] = useState<{ busId: string, seatId: string } | null>(null);

  const [tours, setTours] = useState<Tour[]>(() => {
    const saved = localStorage.getItem('tl_tours');
    return saved ? JSON.parse(saved) : [
      { name: "Sajek Valley", fee: 4500 },
      { name: "Cox's Bazar Relax", fee: 6500 }
    ];
  });

  const [bookers, setBookers] = useState<Booker[]>(() => {
    const saved = localStorage.getItem('tl_bookers');
    return saved ? JSON.parse(saved) : [
      { code: "KS101", name: "Kazi Shetu" },
      { code: "SI202", name: "Sadekul Islam" }
    ];
  });

  const [customerTypes, setCustomerTypes] = useState<CustomerType[]>(() => {
    const saved = localStorage.getItem('tl_customer_types');
    return saved ? JSON.parse(saved) : [
      { type: "Standard", fee: 0 },
      { type: "Solo", fee: 1500 }
    ];
  });

  const [buses, setBuses] = useState<BusData[]>(() => {
    const saved = localStorage.getItem('tour_lagbe_buses');
    if (saved) return JSON.parse(saved);
    return tours.map(t => ({
      busId: t.name,
      seats: generateInitialSeats()
    }));
  });

  const updateToursMaster = (newTours: Tour[]) => {
    setBuses(prevBuses => {
      return newTours.map(tour => {
        const existingBus = prevBuses.find(b => b.busId === tour.name);
        return existingBus || { busId: tour.name, seats: generateInitialSeats() };
      });
    });
    setTours(newTours);
  };

  useEffect(() => {
    localStorage.setItem('tour_lagbe_buses', JSON.stringify(buses));
    localStorage.setItem('tl_tours', JSON.stringify(tours));
    localStorage.setItem('tl_bookers', JSON.stringify(bookers));
    localStorage.setItem('tl_customer_types', JSON.stringify(customerTypes));
  }, [buses, tours, bookers, customerTypes]);

  const handleSeatClick = (seatId: string) => {
    if (selectedBusIndex >= buses.length) return;
    const seat = buses[selectedBusIndex].seats.find(s => s.id === seatId);
    setSelectedSeatId(seatId);
    if (seat?.isBooked && seat.bookingInfo) {
      setEditingInfo(seat.bookingInfo);
      setShowDetailModal(true);
    } else {
      setShowBookingModal(true);
    }
  };

  const handleBookingSubmit = (info: BookingInfo) => {
    setBuses(prev => {
      return prev.map(bus => {
        if (bus.busId !== info.busNo) return bus;
        return {
          ...bus,
          seats: bus.seats.map(s => 
            s.id === info.seatNo ? { ...s, isBooked: true, bookingInfo: info } : s
          )
        };
      });
    });
    setShowBookingModal(false);
    setShowDetailModal(false);
    setSelectedSeatId(null);
    setEditingInfo(null);
  };

  const triggerCancelBooking = (busId: string, seatId: string) => {
    setSeatToDeselect({ busId, seatId });
    setShowConfirmDeselect(true);
    setShowDetailModal(false);
  };

  const confirmDeselect = () => {
    if (seatToDeselect) {
      setBuses(prev => {
        return prev.map(bus => {
          if (bus.busId !== seatToDeselect.busId) return bus;
          return {
            ...bus,
            seats: bus.seats.map(s => 
              s.id === seatToDeselect.seatId ? { ...s, isBooked: false, bookingInfo: undefined } : s
            )
          };
        });
      });
    }
    setShowConfirmDeselect(false);
    setSeatToDeselect(null);
    setEditingInfo(null);
  };

  const handleEditSeatRequest = (info: BookingInfo) => {
    const code = prompt("Security Check: Enter Agent Booker Code to enable full edit access:");
    if (code && bookers.some(b => b.code.toUpperCase() === code.toUpperCase())) {
      setEditingInfo(info);
      setSelectedSeatId(info.seatNo);
      setShowDetailModal(false);
      setShowBookingModal(true);
    } else if (code) {
      alert("Unauthorized Agent Code!");
    }
  };

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPasswordInput === "@Rana&01625@") {
      setIsAdminAuthenticated(true);
      setShowAdminLogin(false);
      setActiveTab('admin');
      setAdminPasswordInput('');
    } else {
      alert("Incorrect Admin Password!");
    }
  };

  const updateBooking = (updatedInfo: BookingInfo) => {
    handleBookingSubmit(updatedInfo);
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row font-sans overflow-hidden relative">
      {isSidebarOpen && (
        <div className="fixed inset-0 bg-black/50 z-[55] md:hidden" onClick={() => setIsSidebarOpen(false)}></div>
      )}

      <nav className={`fixed md:sticky top-0 h-full transition-all duration-300 ease-in-out bg-[#001D4A] text-white flex flex-col shadow-2xl z-[60] shrink-0 
        ${isSidebarOpen ? 'w-72 translate-x-0' : 'w-72 -translate-x-full md:w-20 md:translate-x-0'}`}>

        <div className={`p-8 text-center border-b border-white/10 ${!isSidebarOpen && 'md:p-4'}`}>
          <img src={BUSINESS_INFO.logo} alt="Logo" className={`${isSidebarOpen ? 'w-24' : 'w-10'} transition-all drop-shadow-lg mx-auto mb-2`} />
          {isSidebarOpen && <h1 className="text-2xl font-black text-white">{BUSINESS_INFO.name}</h1>}
        </div>

        <div className="flex-grow py-6 space-y-1 overflow-y-auto">
          {[
            { id: 'dashboard', icon: 'fa-chart-line', label: 'Dashboard' },
            { id: 'booking', icon: 'fa-ticket-alt', label: 'Seat Booking' },
            { id: 'log', icon: 'fa-clipboard-list', label: 'Response Section' },
            { id: 'edit', icon: 'fa-user-edit', label: 'Editor' },
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => { setActiveTab(tab.id as any); setIsSidebarOpen(false); }}
              className={`w-full flex items-center gap-4 px-8 py-4 text-sm font-semibold transition-all group ${activeTab === tab.id ? 'bg-orange-500 text-white shadow-lg' : 'text-white/70 hover:bg-white/5 hover:text-white'} ${!isSidebarOpen && 'md:px-0 md:justify-center'}`}
            >
              <i className={`fas ${tab.icon} w-6 text-center transition-transform group-hover:scale-110`}></i>
              {isSidebarOpen && <span>{tab.label}</span>}
            </button>
          ))}
          <div className={`pt-8 ${isSidebarOpen ? 'px-4' : 'px-1'}`}>
            <div className="border-t border-white/10 pt-4">
              <button onClick={() => setShowAdminLogin(true)} className={`w-full flex items-center gap-4 py-4 text-sm font-bold rounded-2xl transition-all ${activeTab === 'admin' ? 'bg-white text-[#001D4A]' : 'bg-indigo-600/30 text-indigo-200 hover:bg-indigo-600/50'} ${isSidebarOpen ? 'px-6' : 'justify-center'}`}>
                <i className="fas fa-user-shield"></i>
                {isSidebarOpen && <span>Admin Control</span>}
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="flex-grow h-screen overflow-auto relative flex flex-col">
        <header className="sticky top-0 left-0 w-full bg-[#001D4A] text-white p-4 flex items-center justify-between z-50 md:hidden">
          <button onClick={() => setIsSidebarOpen(true)} className="w-10 h-10 flex items-center justify-center bg-white/10 rounded-xl">
            <i className="fas fa-bars"></i>
          </button>
          <div className="flex items-center gap-2">
            <img src={BUSINESS_INFO.logo} alt="Logo" className="h-8" />
            <span className="font-bold text-xs uppercase tracking-tighter">{BUSINESS_INFO.name}</span>
          </div>
          <div className="w-10"></div>
        </header>

        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="hidden md:flex absolute top-6 left-6 z-[70] bg-[#001D4A] text-white w-10 h-10 rounded-xl items-center justify-center shadow-lg hover:bg-orange-500 transition-colors">
          <i className={`fas ${isSidebarOpen ? 'fa-angle-left' : 'fa-angle-right'}`}></i>
        </button>

        <div className="p-4 md:p-10 flex-grow">
          {activeTab === 'booking' && (
            <div className="max-w-6xl mx-auto md:pl-12">
               <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center mb-10 gap-6">
                <div>
                  <h2 className="text-3xl font-black text-[#001D4A]">Seat Booking</h2>
                  <p className="text-sm text-gray-400">Manage seating for your tour fleet.</p>
                </div>
                <div className="flex items-center gap-4 bg-white p-2 rounded-2xl border shadow-sm">
                  <span className="text-[10px] font-black uppercase text-gray-400 pl-2">Selected Tour:</span>
                  <select 
                    value={selectedBusIndex} 
                    onChange={(e) => setSelectedBusIndex(Number(e.target.value))}
                    className="bg-transparent font-black text-[#001D4A] outline-none min-w-[150px] p-2"
                  >
                    {buses.map((bus, idx) => <option key={bus.busId} value={idx}>{bus.busId}</option>)}
                  </select>
                </div>
              </div>
              <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                <div className="lg:col-span-7 overflow-x-auto pb-4">
                  <div className="min-w-[320px] bg-white rounded-[40px] shadow-2xl p-6 md:p-10 border border-gray-100">
                    <BusLayout seats={buses[selectedBusIndex]?.seats || []} onSeatClick={handleSeatClick} />
                  </div>
                </div>
                <div className="lg:col-span-5 space-y-6">
                  <div className="bg-white rounded-[32px] p-8 shadow-xl border border-gray-100">
                    <h3 className="font-black text-[#001D4A] mb-6 flex items-center gap-3">Visual Key</h3>
                    <div className="grid grid-cols-2 lg:grid-cols-1 gap-4">
                      {[{c:'bg-green-500',l:'Vacant'},{c:'bg-red-500',l:'Male'},{c:'bg-pink-500',l:'Female'},{c:'bg-blue-500',l:'Special'},{c:'bg-yellow-500',l:'Gold'}].map((item,i)=>(
                        <div key={i} className="flex items-center gap-4"><div className={`${item.c} w-10 h-10 rounded-xl`}></div><span className="text-sm font-bold text-gray-700">{item.l}</span></div>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'dashboard' && <Dashboard buses={buses} />}
          {activeTab === 'log' && <BookingLog buses={buses} />}
          {activeTab === 'edit' && <EditData buses={buses} onUpdate={updateBooking} onDelete={triggerCancelBooking} onEdit={handleEditSeatRequest} bookers={bookers} />}
          {activeTab === 'admin' && isAdminAuthenticated && (
            <AdminPanel 
              tours={tours} setTours={updateToursMaster} 
              agents={bookers} setAgents={setBookers} 
              customerTypes={customerTypes} setCustomerTypes={setCustomerTypes} 
            />
          )}
        </div>
      </main>

      {showAdminLogin && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-[#001D4A]/90 backdrop-blur-md">
           <div className="bg-white w-full max-w-sm rounded-[32px] p-8 shadow-2xl animate-in zoom-in duration-300">
              <h3 className="text-2xl font-black text-[#001D4A] mb-2 text-center">Admin Access</h3>
              <p className="text-sm text-gray-400 text-center mb-6">Enter secure password</p>
              <form onSubmit={handleAdminLogin} className="space-y-4">
                <input autoFocus type="password" placeholder="Password" value={adminPasswordInput} onChange={(e) => setAdminPasswordInput(e.target.value)} className="w-full px-5 py-4 bg-gray-50 border rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold text-center" />
                <div className="flex gap-3">
                  <button type="button" onClick={() => setShowAdminLogin(false)} className="flex-1 py-4 text-gray-500 font-bold hover:bg-gray-50 rounded-2xl">Cancel</button>
                  <button type="submit" className="flex-1 py-4 bg-orange-500 text-white rounded-2xl font-black shadow-lg">Login</button>
                </div>
              </form>
           </div>
        </div>
      )}

      {showBookingModal && (
        <BookingModal 
          seatId={selectedSeatId!} 
          busNo={editingInfo ? editingInfo.busNo : (buses[selectedBusIndex]?.busId || '')}
          onClose={() => { setShowBookingModal(false); setSelectedSeatId(null); setEditingInfo(null); }} 
          onSubmit={handleBookingSubmit}
          tours={tours}
          bookers={bookers}
          customerTypes={customerTypes}
          existingData={editingInfo || undefined}
        />
      )}

      {showDetailModal && editingInfo && (
        <SeatDetailModal 
          info={editingInfo} 
          onClose={() => { setShowDetailModal(false); setEditingInfo(null); }} 
          onEdit={() => handleEditSeatRequest(editingInfo)}
          onCancel={() => triggerCancelBooking(editingInfo.busNo, editingInfo.seatNo)}
          onUpdate={updateBooking}
        />
      )}

      {showConfirmDeselect && (
        <ConfirmationDialog message="Are you sure you want to cancel this booking? This action is irreversible." onConfirm={confirmDeselect} onCancel={() => setShowConfirmDeselect(false)} />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { BusData, BookingInfo, Booker } from '../types';

interface EditDataProps {
  buses: BusData[];
  onUpdate: (info: BookingInfo) => void;
  onDelete: (busId: string, seatId: string) => void;
  onEdit: (info: BookingInfo) => void;
  bookers: Booker[];
}

const EditData: React.FC<EditDataProps> = ({ buses, onUpdate, onDelete, onEdit, bookers }) => {
  const [accessCode, setAccessCode] = useState('');
  const [isUnlocked, setIsUnlocked] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  const handleUnlock = () => {
    if (bookers.some(b => b.code.toUpperCase() === accessCode.toUpperCase())) {
      setIsUnlocked(true);
    } else {
      alert("Unauthorized Agent Code!");
    }
  };

  const allBookings: BookingInfo[] = buses.flatMap(b => b.seats.filter(s => s.isBooked).map(s => s.bookingInfo!));
  const filtered = allBookings.filter(b => 
    b.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    b.mobile.includes(searchQuery) ||
    b.seatNo.toLowerCase().includes(searchQuery.toLowerCase())
  );

  if (!isUnlocked) {
    return (
      <div className="max-w-md mx-auto mt-20 bg-white p-10 rounded-[40px] shadow-2xl border text-center animate-in zoom-in duration-300">
        <div className="w-24 h-24 bg-indigo-50 text-indigo-600 rounded-[32px] flex items-center justify-center mx-auto mb-8 text-4xl shadow-inner border border-indigo-100">
          <i className="fas fa-user-lock"></i>
        </div>
        <h3 className="text-3xl font-black text-[#001D4A] mb-3">Agent Portal</h3>
        <p className="text-sm text-gray-500 mb-10 leading-relaxed">Enter your agent code to modify existing booking entries.</p>
        <div className="space-y-4">
           <input 
            type="text" 
            placeholder="AGENT-CODE" 
            className="w-full px-8 py-5 bg-gray-50 border-none rounded-2xl outline-none focus:ring-4 focus:ring-indigo-100 transition-all font-black text-center text-xl tracking-widest uppercase"
            value={accessCode}
            onChange={(e) => setAccessCode(e.target.value.toUpperCase())}
          />
          <button onClick={handleUnlock} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-lg hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100 active:scale-95">
            Unlock Editor
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="animate-in fade-in duration-500 max-w-6xl mx-auto md:pl-12">
       <div className="bg-white rounded-[40px] shadow-2xl border-none p-8 md:p-10 mb-10 relative overflow-hidden">
          <h2 className="text-3xl font-black text-[#001D4A] mb-8">System Entry Editor</h2>
          <div className="relative group">
            <i className="fas fa-search absolute left-5 top-1/2 -translate-y-1/2 text-gray-300 group-focus-within:text-orange-500 transition-colors"></i>
            <input 
              className="w-full pl-14 pr-8 py-5 bg-gray-50 border-none rounded-3xl focus:ring-2 focus:ring-orange-500 transition-all text-lg font-bold" 
              placeholder="Filter by name, mobile, or seat..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>
       </div>

       <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-8">
          {filtered.length === 0 ? (
            <div className="col-span-full py-20 text-center text-gray-300 font-bold uppercase tracking-widest">
              No matching records found
            </div>
          ) : (
            filtered.map(booking => (
              <div key={booking.id} className="bg-white p-6 md:p-8 rounded-[32px] shadow-xl border border-transparent hover:border-indigo-100 transition-all group">
                 <div className="flex justify-between items-start mb-6">
                    <div>
                      <div className="flex items-center gap-2 mb-2">
                        <span className="text-[9px] font-black text-white bg-indigo-600 px-2.5 py-1 rounded-full uppercase">{booking.busNo}</span>
                        <span className="text-[9px] font-black text-indigo-600 bg-indigo-50 px-2.5 py-1 rounded-full uppercase">Seat {booking.seatNo}</span>
                      </div>
                      <h4 className="font-black text-[#001D4A] text-xl truncate max-w-[150px]">{booking.name}</h4>
                    </div>
                    <div className="flex gap-2">
                      <button 
                        onClick={() => onEdit(booking)}
                        className="w-10 h-10 flex items-center justify-center bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all shadow-sm"
                        title="Full Edit"
                      >
                        <i className="fas fa-edit"></i>
                      </button>
                      <button 
                        onClick={() => onDelete(booking.busNo, booking.seatNo)}
                        className="w-10 h-10 flex items-center justify-center bg-red-50 text-red-500 rounded-xl hover:bg-red-600 hover:text-white transition-all shadow-sm"
                        title="Delete Entry"
                      >
                        <i className="fas fa-trash-alt"></i>
                      </button>
                    </div>
                 </div>
                 <div className="space-y-3 pt-6 border-t border-gray-50">
                    <div className="flex justify-between items-center text-xs">
                       <span className="text-gray-400 font-bold uppercase">Contact</span>
                       <span className="text-gray-800 font-black">+880{booking.mobile}</span>
                    </div>
                    <div className="flex justify-between items-center bg-indigo-50 p-3 rounded-xl mt-2">
                       <span className="text-indigo-400 font-black uppercase text-[10px]">Total Paid</span>
                       <span className="text-indigo-700 font-black text-lg">৳{booking.advanceAmount.toLocaleString()}</span>
                    </div>
                    <div className="flex justify-between items-center bg-red-50 p-3 rounded-xl">
                       <span className="text-red-400 font-black uppercase text-[10px]">Due Balance</span>
                       <span className="text-red-600 font-black text-lg">৳{booking.dueAmount.toLocaleString()}</span>
                    </div>
                 </div>
                 <div className="mt-4 flex justify-between items-center">
                   <span className="text-[9px] text-gray-300 uppercase font-black tracking-tighter">Agent: {booking.bookedBy}</span>
                   <button 
                    onClick={() => {
                      const code = prompt("Security Check: Enter Agent Booker Code to settle this balance:");
                      if (code && code.toUpperCase() === booking.bookerCode.toUpperCase()) {
                        const newAdvance = Number(prompt("Update Payment (Current: ৳" + booking.advanceAmount + ")", (booking.advanceAmount + booking.dueAmount).toString()));
                        if (!isNaN(newAdvance) && newAdvance >= 0) {
                          const total = booking.tourFees + (booking.customerTypeFees || 0);
                          const due = total - booking.discountAmount - newAdvance;
                          onUpdate({
                            ...booking, 
                            advanceAmount: newAdvance, 
                            dueAmount: due,
                            paymentStatus: due <= 0 ? 'Paid' : (newAdvance > 0 ? 'Partial' : 'Due')
                          });
                        }
                      } else if (code) {
                        alert("Unauthorized: Only the original booker can settle this payment.");
                      }
                    }}
                    className="text-[10px] font-black text-indigo-600 hover:text-orange-500 transition-colors uppercase underline"
                   >
                     Quick Pay
                   </button>
                 </div>
              </div>
            ))
          )}
       </div>
    </div>
  );
};

export default EditData;

import React, { useState, useEffect } from 'react';
import { BUSINESS_INFO, generateInitialSeats } from './constants';
import { BusData, BookingInfo, Tour, Booker, CustomerType } from './types';
import BusLayout from './components/BusLayout';
import BookingModal from './components/BookingModal';
import ConfirmationDialog from './components/ConfirmationDialog';
import Dashboard from './components/Dashboard';
import BookingLog from './components/BookingLog';
import EditData from './components/EditData';
import AdminPanel from './components/AdminPanel';
import SeatDetailModal from './components/SeatDetailModal';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'booking' | 'dashboard' | 'log' | 'edit' | 'admin'>('booking');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);
  const [adminPasswordInput, setAdminPasswordInput] = useState('');
  const [showAdminLogin, setShowAdminLogin] = useState(false);

  const [selectedBusIndex, setSelectedBusIndex] = useState(0);
  const [selectedSeatId, setSelectedSeatId] = useState<string | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [showConfirmDeselect, setShowConfirmDeselect] = useState(false);
  const [editingInfo, setEditingInfo] = useState<BookingInfo | null>(null);
  const [seatToDeselect, setSeatToDeselect] = useState<{ busId: string, seatId: string } | null>(null);

  const [tours, setTours] = useState<Tour[]>(() => {
    const saved = localStorage.getItem('tl_tours');
    return saved ? JSON.parse(saved) : [
      { name: "Sajek Valley", fee: 4500 },
      { name: "Cox's Bazar Relax", fee: 6500 }
    ];
  });

  const [bookers, setBookers] = useState<Booker[]>(() => {
    const saved = localStorage.getItem('tl_bookers');
    return saved ? JSON.parse(saved) : [
      { code: "KS101", name: "Kazi Shetu" },
      { code: "SI202", name: "Sadekul Islam" }
    ];
  });

  const [customerTypes, setCustomerTypes] = useState<CustomerType[]>(() => {
    const saved = localStorage.getItem('tl_customer_types');
    return saved ? JSON.parse(saved) : [
      { type: "Standard", fee: 0 },
      { type: "Solo", fee: 1500 }
    ];
  });

  const [buses, setBuses] = useState<BusData[]>(() => {
    const saved = localStorage.getItem('tour_lagbe_buses');
    if (saved) return JSON.parse(saved);
    return tours.map(t => ({
      busId: t.name,
      seats: generateInitialSeats()
    }));
  });

  // Track renames in AdminPanel to avoid data loss
  const updateToursMaster = (newTours: Tour[], renameMap?: { oldName: string, newName: string }) => {
    setBuses(prevBuses => {
      let updatedBuses = [...prevBuses];

      // Handle Renames
      if (renameMap) {
        updatedBuses = updatedBuses.map(b => {
          if (b.busId === renameMap.oldName) {
            return {
              ...b,
              busId: renameMap.newName,
              seats: b.seats.map(s => s.isBooked ? {
                ...s,
                bookingInfo: s.bookingInfo ? { ...s.bookingInfo, busNo: renameMap.newName, tourName: renameMap.newName } : undefined
              } : s)
            };
          }
          return b;
        });
      }

      // Handle additions/deletions
      return newTours.map(tour => {
        const existingBus = updatedBuses.find(b => b.busId === tour.name);
        return existingBus || { busId: tour.name, seats: generateInitialSeats() };
      });
    });
    setTours(newTours);
  };

  useEffect(() => {
    localStorage.setItem('tour_lagbe_buses', JSON.stringify(buses));
    localStorage.setItem('tl_tours', JSON.stringify(tours));
    localStorage.setItem('tl_bookers', JSON.stringify(bookers));
    localStorage.setItem('tl_customer_types', JSON.stringify(customerTypes));
  }, [buses, tours, bookers, customerTypes]);

  const handleSeatClick = (seatId: string) => {
    if (selectedBusIndex >= buses.length) return;
    const seat = buses[selectedBusIndex].seats.find(s => s.id === seatId);
    setSelectedSeatId(seatId);
    if (seat?.isBooked && seat.bookingInfo) {
      setEditingInfo(seat.bookingInfo);
      setShowDetailModal(true);
    } else {
      setShowBookingModal(true);
    }
  };

  const handleBookingSubmit = (info: BookingInfo) => {
    setBuses(prev => {
      // If we are editing and changed the tour, we must remove from old tour first
      let intermediate = prev;
      if (editingInfo && editingInfo.busNo !== info.busNo) {
        intermediate = intermediate.map(bus => {
          if (bus.busId !== editingInfo.busNo) return bus;
          return {
            ...bus,
            seats: bus.seats.map(s => s.id === editingInfo.seatNo ? { ...s, isBooked: false, bookingInfo: undefined } : s)
          };
        });
      }

      return intermediate.map(bus => {
        if (bus.busId !== info.busNo) return bus;
        return {
          ...bus,
          seats: bus.seats.map(s => 
            s.id === info.seatNo ? { ...s, isBooked: true, bookingInfo: info } : s
          )
        };
      });
    });
    setShowBookingModal(false);
    setShowDetailModal(false);
    setSelectedSeatId(null);
    setEditingInfo(null);
  };

  const triggerCancelBooking = (busId: string, seatId: string) => {
    setSeatToDeselect({ busId, seatId });
    setShowConfirmDeselect(true);
    setShowDetailModal(false);
  };

  const confirmDeselect = () => {
    if (seatToDeselect) {
      setBuses(prev => {
        return prev.map(bus => {
          if (bus.busId !== seatToDeselect.busId) return bus;
          return {
            ...bus,
            seats: bus.seats.map(s => 
              s.id === seatToDeselect.seatId ? { ...s, isBooked: false, bookingInfo: undefined } : s
            )
          };
        });
      });
    }
    setShowConfirmDeselect(false);
    setSeatToDeselect(null);
    setEditingInfo(null);
  };

  const handleEditSeatRequest = (info: BookingInfo) => {
    const code = prompt("Security Check: Enter Agent Booker Code to enable full edit access:");
    if (code && bookers.some(b => b.code.toUpperCase() === code.toUpperCase())) {
      setEditingInfo(info);
      setSelectedSeatId(info.seatNo);
      setShowDetailModal(false);
      setShowBookingModal(true);
    } else if (code) {
      alert("Unauthorized Agent Code!");
    }
  };

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPasswordInput === "@Rana&01625@") {
      setIsAdminAuthenticated(true);
      setShowAdminLogin(false);
      setActiveTab('admin');
      setAdminPasswordInput('');
    } else {
      alert("Incorrect Admin Password!");
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row font-sans overflow-hidden relative">
      {isSidebarOpen && (
        <div className="fixed inset-0 bg-black/50 z-[55] md:hidden" onClick={() => setIsSidebarOpen(false)}></div>
      )}

      <nav className={`fixed md:sticky top-0 h-full transition-all duration-300 ease-in-out bg-[#001D4A] text-white flex flex-col shadow-2xl z-[60] shrink-0 
        ${isSidebarOpen ? 'w-72 translate-x-0' : 'w-72 -translate-x-full md:w-20 md:translate-x-0'}`}>

        <div className={`p-8 text-center border-b border-white/10 ${!isSidebarOpen && 'md:p-4'}`}>
          <img src={BUSINESS_INFO.logo} alt="Logo" className={`${isSidebarOpen ? 'w-24' : 'w-10'} transition-all drop-shadow-lg mx-auto mb-2`} />
          {isSidebarOpen && <h1 className="text-2xl font-black text-white">{BUSINESS_INFO.name}</h1>}
        </div>

        <div className="flex-grow py-6 space-y-1 overflow-y-auto">
          {[
            { id: 'dashboard', icon: 'fa-chart-line', label: 'Dashboard' },
            { id: 'booking', icon: 'fa-ticket-alt', label: 'Seat Booking' },
            { id: 'log', icon: 'fa-clipboard-list', label: 'Response Section' },
            { id: 'edit', icon: 'fa-user-edit', label: 'Editor' },
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => { setActiveTab(tab.id as any); setIsSidebarOpen(false); }}
              className={`w-full flex items-center gap-4 px-8 py-4 text-sm font-semibold transition-all group ${activeTab === tab.id ? 'bg-orange-500 text-white shadow-lg' : 'text-white/70 hover:bg-white/5 hover:text-white'} ${!isSidebarOpen && 'md:px-0 md:justify-center'}`}
            >
              <i className={`fas ${tab.icon} w-6 text-center transition-transform group-hover:scale-110`}></i>
              {isSidebarOpen && <span>{tab.label}</span>}
            </button>
          ))}
          <div className={`pt-8 ${isSidebarOpen ? 'px-4' : 'px-1'}`}>
            <div className="border-t border-white/10 pt-4">
              <button onClick={() => setShowAdminLogin(true)} className={`w-full flex items-center gap-4 py-4 text-sm font-bold rounded-2xl transition-all ${activeTab === 'admin' ? 'bg-white text-[#001D4A]' : 'bg-indigo-600/30 text-indigo-200 hover:bg-indigo-600/50'} ${isSidebarOpen ? 'px-6' : 'justify-center'}`}>
                <i className="fas fa-user-shield"></i>
                {isSidebarOpen && <span>Admin Control</span>}
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="flex-grow h-screen overflow-auto relative flex flex-col">
        <header className="sticky top-0 left-0 w-full bg-[#001D4A] text-white p-4 flex items-center justify-between z-50 md:hidden">
          <button onClick={() => setIsSidebarOpen(true)} className="w-10 h-10 flex items-center justify-center bg-white/10 rounded-xl">
            <i className="fas fa-bars"></i>
          </button>
          <div className="flex items-center gap-2">
            <img src={BUSINESS_INFO.logo} alt="Logo" className="h-8" />
            <span className="font-bold text-xs uppercase tracking-tighter">{BUSINESS_INFO.name}</span>
          </div>
          <div className="w-10"></div>
        </header>

        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="hidden md:flex absolute top-6 left-6 z-[70] bg-[#001D4A] text-white w-10 h-10 rounded-xl items-center justify-center shadow-lg hover:bg-orange-500 transition-colors">
          <i className={`fas ${isSidebarOpen ? 'fa-angle-left' : 'fa-angle-right'}`}></i>
        </button>

        <div className="p-4 md:p-10 flex-grow">
          {activeTab === 'booking' && (
            <div className="max-w-6xl mx-auto md:pl-12">
               <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center mb-10 gap-6">
                <div>
                  <h2 className="text-3xl font-black text-[#001D4A]">Seat Booking</h2>
                  <p className="text-sm text-gray-400">Manage seating for your tour fleet.</p>
                </div>
                <div className="flex items-center gap-4 bg-white p-2 rounded-2xl border shadow-sm">
                  <span className="text-[10px] font-black uppercase text-gray-400 pl-2">Selected Tour:</span>
                  <select 
                    value={selectedBusIndex} 
                    onChange={(e) => setSelectedBusIndex(Number(e.target.value))}
                    className="bg-transparent font-black text-[#001D4A] outline-none min-w-[150px] p-2"
                  >
                    {buses.map((bus, idx) => <option key={bus.busId} value={idx}>{bus.busId}</option>)}
                  </select>
                </div>
              </div>
              <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                <div className="lg:col-span-7 overflow-x-auto pb-4">
                  <div className="min-w-[320px] bg-white rounded-[40px] shadow-2xl p-6 md:p-10 border border-gray-100">
                    <BusLayout seats={buses[selectedBusIndex]?.seats || []} onSeatClick={handleSeatClick} />
                  </div>
                </div>
                <div className="lg:col-span-5 space-y-6">
                  <div className="bg-white rounded-[32px] p-8 shadow-xl border border-gray-100">
                    <h3 className="font-black text-[#001D4A] mb-6 flex items-center gap-3">Visual Key</h3>
                    <div className="grid grid-cols-2 lg:grid-cols-1 gap-4">
                      {[{c:'bg-green-500',l:'Vacant'},{c:'bg-red-500',l:'Male'},{c:'bg-pink-500',l:'Female'},{c:'bg-blue-500',l:'Special'},{c:'bg-yellow-500',l:'Gold'}].map((item,i)=>(
                        <div key={i} className="flex items-center gap-4"><div className={`${item.c} w-10 h-10 rounded-xl`}></div><span className="text-sm font-bold text-gray-700">{item.l}</span></div>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'dashboard' && <Dashboard buses={buses} />}
          {activeTab === 'log' && <BookingLog buses={buses} />}
          {activeTab === 'edit' && <EditData buses={buses} onUpdate={handleBookingSubmit} onDelete={triggerCancelBooking} onEdit={handleEditSeatRequest} bookers={bookers} />}
          {activeTab === 'admin' && isAdminAuthenticated && (
            <AdminPanel 
              tours={tours} setTours={updateToursMaster} 
              agents={bookers} setAgents={setBookers} 
              customerTypes={customerTypes} setCustomerTypes={setCustomerTypes} 
            />
          )}
        </div>
      </main>

      {showAdminLogin && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-[#001D4A]/90 backdrop-blur-md">
           <div className="bg-white w-full max-w-sm rounded-[32px] p-8 shadow-2xl animate-in zoom-in duration-300">
              <h3 className="text-2xl font-black text-[#001D4A] mb-2 text-center">Admin Access</h3>
              <p className="text-sm text-gray-400 text-center mb-6">Enter secure password</p>
              <form onSubmit={handleAdminLogin} className="space-y-4">
                <input autoFocus type="password" placeholder="Password" value={adminPasswordInput} onChange={(e) => setAdminPasswordInput(e.target.value)} className="w-full px-5 py-4 bg-gray-50 border rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold text-center" />
                <div className="flex gap-3">
                  <button type="button" onClick={() => setShowAdminLogin(false)} className="flex-1 py-4 text-gray-500 font-bold hover:bg-gray-50 rounded-2xl">Cancel</button>
                  <button type="submit" className="flex-1 py-4 bg-orange-500 text-white rounded-2xl font-black shadow-lg">Login</button>
                </div>
              </form>
           </div>
        </div>
      )}

      {showBookingModal && (
        <BookingModal 
          seatId={selectedSeatId!} 
          busNo={editingInfo ? editingInfo.busNo : (buses[selectedBusIndex]?.busId || '')}
          onClose={() => { setShowBookingModal(false); setSelectedSeatId(null); setEditingInfo(null); }} 
          onSubmit={handleBookingSubmit}
          tours={tours}
          bookers={bookers}
          customerTypes={customerTypes}
          existingData={editingInfo || undefined}
        />
      )}

      {showDetailModal && editingInfo && (
        <SeatDetailModal 
          info={editingInfo} 
          onClose={() => { setShowDetailModal(false); setEditingInfo(null); }} 
          onEdit={() => handleEditSeatRequest(editingInfo)}
          onCancel={() => triggerCancelBooking(editingInfo.busNo, editingInfo.seatNo)}
          onUpdate={handleBookingSubmit}
        />
      )}

      {showConfirmDeselect && (
        <ConfirmationDialog message="Are you sure you want to cancel this booking? This action is irreversible." onConfirm={confirmDeselect} onCancel={() => setShowConfirmDeselect(false)} />
      )}
    </div>
  );
};

