              Cancel
            </button>
            <button 
              type="submit" 
              className="flex-1 py-4 bg-[#001D4A] text-white rounded-2xl font-black shadow-lg hover:bg-indigo-700 transition-all active:scale-95"
            >
              Verify
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

