import React, { useState, useMemo } from 'react';
import { Tour, Booker, CustomerType, BusData, BookingInfo } from '../types';
import { BUSINESS_INFO } from '../constants';

interface AdminPanelProps {
  tours: Tour[];
  setTours: (tours: Tour[]) => void;
  agents: Booker[];
  setAgents: (agents: Booker[]) => void;
  customerTypes: CustomerType[];
  setCustomerTypes: (types: CustomerType[]) => void;
  buses: BusData[];
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  tours, setTours, 
  agents, setAgents, 
  customerTypes, setCustomerTypes,
  buses
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'tours' | 'agents' | 'types' | 'print'>('tours');

  const [newTour, setNewTour] = useState({ name: '', fee: 0 });
  const [newAgent, setNewAgent] = useState({ code: '', name: '' });
  const [newType, setNewType] = useState({ type: '', fee: 0 });

  const [editTourIndex, setEditTourIndex] = useState<number | null>(null);
  const [editTourData, setEditTourData] = useState<Tour | null>(null);

  const [editAgentIndex, setEditAgentIndex] = useState<number | null>(null);
  const [editAgentData, setEditAgentData] = useState<Booker | null>(null);

  const [editTypeIndex, setEditTypeIndex] = useState<number | null>(null);
  const [editTypeData, setEditTypeData] = useState<CustomerType | null>(null);

  const [selectedForPrint, setSelectedForPrint] = useState<string[]>([]);
  const allBookings: BookingInfo[] = useMemo(() => 
    buses.flatMap(b => b.seats.filter(s => s.isBooked).map(s => s.bookingInfo!)),
    [buses]
  );

  const addTour = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTour.name.trim()) return;
    const updated = [...tours, { name: newTour.name.trim(), fee: newTour.fee }];
    setTours(updated);
    setNewTour({ name: '', fee: 0 });
  };

  const saveTourEdit = () => {
    if (editTourIndex !== null && editTourData) {
      const updated = [...tours];
      updated[editTourIndex] = editTourData;
      setTours(updated);
      setEditTourIndex(null);
    }
  };

  const removeTour = (name: string) => {
    if (confirm(`Delete tour "${name}"?`)) {
      setTours(tours.filter(t => t.name !== name));
    }
  };

  const addAgent = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAgent.code.trim() || !newAgent.name.trim()) return;
    const updated = [...agents, { code: newAgent.code.trim().toUpperCase(), name: newAgent.name.trim() }];
    setAgents(updated);
    setNewAgent({ code: '', name: '' });
  };

  const saveAgentEdit = () => {
    if (editAgentIndex !== null && editAgentData) {
      const updated = [...agents];
      updated[editAgentIndex] = editAgentData;
      setAgents(updated);
      setEditAgentIndex(null);
    }
  };

  const removeAgent = (code: string) => {
    if (confirm(`Remove agent ${code}?`)) {
      setAgents(agents.filter(a => a.code !== code));
    }
  };

  const addType = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newType.type.trim()) return;
    const updated = [...customerTypes, { type: newType.type.trim(), fee: newType.fee }];
    setCustomerTypes(updated);
    setNewType({ type: '', fee: 0 });
  };

  const saveTypeEdit = () => {
    if (editTypeIndex !== null && editTypeData) {
      const updated = [...customerTypes];
      updated[editTypeIndex] = editTypeData;
      setCustomerTypes(updated);
      setEditTypeIndex(null);
    }
  };

  const removeType = (index: number) => {
    if (confirm("Remove this category?")) {
      setCustomerTypes(customerTypes.filter((_, idx) => idx !== index));
    }
  };

  const handlePrintBatch = () => {
    if (selectedForPrint.length === 0) return;
    const printWindow = window.open('', '_blank');
    if (!printWindow) return;
    const bookingsToPrint = allBookings.filter(b => selectedForPrint.includes(b.id));
    const htmlContent = `<html><head><title>Tickets</title><script src="https://cdn.tailwindcss.com"></script></head><body onload="window.print()">
      <div class="grid grid-cols-2 gap-4 p-8">
        ${bookingsToPrint.map(info => `
          <div class="border p-4 rounded-xl text-xs">
            <h1 class="font-black text-lg">${info.name}</h1>
            <p>Seat: ${info.seatNo} | Tour: ${info.tourName}</p>
            <p>Agent: ${info.bookedBy}</p>
            <p class="font-black text-red-600">Due: ৳${info.dueAmount}</p>
          </div>
        `).join('')}
      </div></body></html>`;
    printWindow.document.write(htmlContent);
    printWindow.document.close();
  };

  return (
    <div className="max-w-4xl mx-auto md:pl-12 pb-20">
      <div className="flex justify-between items-center mb-10">
        <h2 className="text-3xl font-black text-[#001D4A]">Master Settings</h2>
      </div>

      <div className="flex bg-white p-2 rounded-2xl shadow-sm mb-10 gap-2 border flex-wrap">
        {['tours', 'agents', 'types', 'print'].map(tab => (
          <button key={tab} onClick={() => setActiveSubTab(tab as any)} className={`flex-1 min-w-[100px] py-4 rounded-xl font-black text-xs transition-all uppercase ${activeSubTab === tab ? 'bg-[#001D4A] text-white' : 'text-gray-400 hover:bg-gray-50'}`}>
            {tab}
          </button>
        ))}
      </div>

      {activeSubTab === 'tours' && (
        <div className="space-y-8">
          <form onSubmit={addTour} className="bg-white p-8 rounded-[32px] shadow-xl border flex flex-col md:flex-row gap-4 items-end">
            <div className="flex-1 space-y-1 w-full"><label className="text-[10px] font-black uppercase text-gray-400">New Tour Name</label><input required className="w-full px-5 py-4 bg-gray-50 border-none rounded-2xl font-bold" value={newTour.name} onChange={e => setNewTour({...newTour, name: e.target.value})} /></div>
            <div className="w-full md:w-48 space-y-1"><label className="text-[10px] font-black uppercase text-gray-400">Base Fee</label><input required type="number" className="w-full px-5 py-4 bg-gray-50 border-none rounded-2xl font-bold" value={newTour.fee || ''} onChange={e => setNewTour({...newTour, fee: Number(e.target.value)})} /></div>
            <button type="submit" className="px-10 py-4 bg-orange-500 text-white rounded-2xl font-black shadow-lg">Add</button>
          </form>
          <div className="bg-white rounded-[32px] shadow-xl border overflow-hidden"><table className="w-full">
            <thead className="bg-gray-50 border-b"><tr className="text-[10px] font-black uppercase text-gray-400 tracking-widest"><th className="px-8 py-4 text-left">Tour Identity</th><th className="px-8 py-4 text-left">Base Fee</th><th className="px-8 py-4 text-right">Control</th></tr></thead>
            <tbody className="divide-y divide-gray-100">{tours.map((t, i) => (
              <tr key={i} className="hover:bg-gray-50/50">
                <td className="px-8 py-4">{editTourIndex === i ? <input className="px-3 py-2 border rounded-lg w-full" value={editTourData?.name} onChange={e => setEditTourData({...editTourData!, name: e.target.value})} /> : <span className="font-black text-gray-800">{t.name}</span>}</td>
                <td className="px-8 py-4">{editTourIndex === i ? <input type="number" className="px-3 py-2 border rounded-lg w-full" value={editTourData?.fee} onChange={e => setEditTourData({...editTourData!, fee: Number(e.target.value)})} /> : <span className="font-bold text-indigo-600">৳{t.fee.toLocaleString()}</span>}</td>
                <td className="px-8 py-4 text-right space-x-2">{editTourIndex === i ? <button onClick={saveTourEdit} className="text-green-600 font-black">SAVE</button> : <><button onClick={() => {setEditTourIndex(i); setEditTourData(t);}} className="text-blue-500 mr-4"><i className="fas fa-pen"></i></button><button onClick={() => removeTour(t.name)} className="text-red-400"><i className="fas fa-trash-alt"></i></button></>}</td>
              </tr>
            ))}</tbody>
          </table></div>
        </div>
      )}

      {activeSubTab === 'agents' && (
        <div className="space-y-8">
          <form onSubmit={addAgent} className="bg-white p-8 rounded-[32px] shadow-xl border flex flex-col md:flex-row gap-4 items-end">
            <div className="w-full md:w-48 space-y-1"><label className="text-[10px] font-black uppercase text-gray-400">Agent ID</label><input required className="w-full px-5 py-4 bg-gray-50 border-none rounded-2xl font-black uppercase" value={newAgent.code} onChange={e => setNewAgent({...newAgent, code: e.target.value.toUpperCase()})} /></div>
            <div className="flex-1 space-y-1 w-full"><label className="text-[10px] font-black uppercase text-gray-400">Full Name</label><input required className="w-full px-5 py-4 bg-gray-50 border-none rounded-2xl font-bold" value={newAgent.name} onChange={e => setNewAgent({...newAgent, name: e.target.value})} /></div>
            <button type="submit" className="px-10 py-4 bg-indigo-600 text-white rounded-2xl font-black">Add Agent</button>
          </form>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">{agents.map((a, i) => (
            <div key={i} className="p-6 rounded-[24px] border bg-white flex justify-between items-center">
              <div><span className="text-[10px] font-black text-indigo-500 bg-indigo-100 px-2 py-0.5 rounded-full block w-fit mb-1">{a.code}</span><p className="font-bold text-gray-800">{a.name}</p></div>
              <button onClick={() => removeAgent(a.code)} className="text-red-400"><i className="fas fa-trash-alt"></i></button>
            </div>
          ))}</div>
        </div>
      )}

      {activeSubTab === 'types' && (
        <div className="space-y-8">
          <form onSubmit={addType} className="bg-white p-8 rounded-[32px] shadow-xl border flex flex-col md:flex-row gap-4 items-end">
            <div className="flex-1 space-y-1 w-full"><label className="text-[10px] font-black uppercase text-gray-400">Category Name</label><input required className="w-full px-5 py-4 bg-gray-50 border-none rounded-2xl font-bold" value={newType.type} onChange={e => setNewType({...newType, type: e.target.value})} /></div>
            <div className="w-full md:w-48 space-y-1"><label className="text-[10px] font-black uppercase text-gray-400">Surcharge</label><input required type="number" className="w-full px-5 py-4 bg-gray-50 border-none rounded-2xl font-bold" value={newType.fee || ''} onChange={e => setNewType({...newType, fee: Number(e.target.value)})} /></div>
            <button type="submit" className="px-10 py-4 bg-blue-600 text-white rounded-2xl font-black">Add</button>
          </form>
          <div className="space-y-4">{customerTypes.map((c, i) => (
            <div key={i} className="p-6 rounded-[24px] border bg-white flex justify-between items-center">
              <div><p className="font-black text-gray-800 text-lg">{c.type}</p></div>
              <div className="flex items-center gap-6"><span className="text-blue-600 font-black text-xl">৳{c.fee}</span><button onClick={() => removeType(i)} className="text-red-400"><i className="fas fa-trash-alt"></i></button></div>
            </div>
          ))}</div>
        </div>
      )}

      {activeSubTab === 'print' && (
        <div className="space-y-6">
          <div className="flex justify-between items-center bg-white p-6 rounded-[32px] shadow-xl border">
            <div><h3 className="font-black text-[#001D4A]">Batch Print</h3></div>
            <button onClick={handlePrintBatch} className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-black text-sm">Print ({selectedForPrint.length})</button>
          </div>
          <div className="bg-white rounded-[32px] shadow-xl border overflow-hidden"><table className="w-full text-left text-sm whitespace-nowrap">
            <thead className="bg-gray-50 border-b"><tr className="text-[10px] font-black uppercase text-gray-400 tracking-widest"><th className="px-6 py-4 w-10">Select</th><th className="px-6 py-4">Passenger</th><th className="px-6 py-4">Status</th></tr></thead>
            <tbody className="divide-y divide-gray-100">{allBookings.map((b) => (
              <tr key={b.id} className={`hover:bg-indigo-50 cursor-pointer ${selectedForPrint.includes(b.id) ? 'bg-indigo-50' : ''}`} onClick={() => setSelectedForPrint(prev => prev.includes(b.id) ? prev.filter(p => p !== b.id) : [...prev, b.id])}>
                <td className="px-6 py-4"><div className={`w-5 h-5 rounded border ${selectedForPrint.includes(b.id) ? 'bg-indigo-600' : 'bg-white'}`}></div></td>
                <td className="px-6 py-4 font-bold">{b.name} (Seat ${b.seatNo})</td>
                <td className="px-6 py-4 uppercase font-black text-[10px]">${b.paymentStatus}</td>
              </tr>
            ))}</tbody>
          </table></div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useCallback } from 'react';
import { BUSINESS_INFO, generateInitialSeats, TOURS, BOOKERS, CUSTOMER_TYPES } from './constants';
import { BusData, BookingInfo, Tour, Booker, CustomerType } from './types';
import BusLayout from './components/BusLayout';
import BookingModal from './components/BookingModal';
import ConfirmationDialog from './components/ConfirmationDialog';
import Dashboard from './components/Dashboard';
import BookingLog from './components/BookingLog';
import EditData from './components/EditData';
import AdminPanel from './components/AdminPanel';
import SeatDetailModal from './components/SeatDetailModal';
import SecurityModal from './components/SecurityModal';
import { supabase } from './supabase';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'booking' | 'dashboard' | 'log' | 'edit' | 'admin'>('booking');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);
  const [adminPasswordInput, setAdminPasswordInput] = useState('');
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  const [selectedBusIndex, setSelectedBusIndex] = useState(0);
  const [selectedSeatId, setSelectedSeatId] = useState<string | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [showConfirmDeselect, setShowConfirmDeselect] = useState(false);
  const [editingInfo, setEditingInfo] = useState<BookingInfo | null>(null);
  const [seatToDeselect, setSeatToDeselect] = useState<{ busId: string, seatId: string } | null>(null);

  const [securityModal, setSecurityModal] = useState<{
    isOpen: boolean;
    targetInfo: BookingInfo;
    action: 'edit' | 'delete';
  } | null>(null);

  const [tours, setTours] = useState<Tour[]>([]);
  const [bookers, setBookers] = useState<Booker[]>([]);
  const [customerTypes, setCustomerTypes] = useState<CustomerType[]>([]);
  const [buses, setBuses] = useState<BusData[]>([]);

  const fetchData = useCallback(async () => {
    try {
      const [toursRes, bookersRes, typesRes, bookingsRes] = await Promise.all([
        supabase.from('tl_tours').select('*').order('name'),
        supabase.from('tl_agents').select('*').order('name'),
        supabase.from('tl_customer_types').select('*').order('type'),
        supabase.from('tl_bookings').select('*')
      ]);

      if (toursRes.error) console.error("Tours Error:", toursRes.error);
      if (bookersRes.error) console.error("Agents Error:", bookersRes.error);

      const fetchedTours = toursRes.data || [];
      const fetchedBookers = bookersRes.data || [];
      const fetchedTypes = typesRes.data || [];
      const fetchedBookings: any[] = bookingsRes.data || [];

      const mappedBookings: BookingInfo[] = fetchedBookings.map(b => ({
        id: b.id,
        name: b.name,
        mobile: b.mobile,
        address: b.address,
        gender: b.gender,
        religion: b.religion,
        tourName: b.tour_name,
        tourFees: b.tour_fees,
        customerType: b.customer_type,
        customerTypeFees: b.customer_type_fees,
        discountAmount: b.discount_amount,
        advanceAmount: b.advance_amount,
        dueAmount: b.due_amount,
        paymentStatus: b.payment_status,
        busNo: b.bus_no,
        seatNo: b.seat_no,
        bookedBy: b.booked_by,
        bookerCode: b.booker_code,
        bookingDate: b.booking_date
      }));

      setTours(fetchedTours);
      setBookers(fetchedBookers);
      setCustomerTypes(fetchedTypes);

      const busLayouts = fetchedTours.map(t => {
        const seats = generateInitialSeats();
        mappedBookings.forEach(booking => {
          if (booking.busNo === t.name) {
            const seatIdx = seats.findIndex(s => s.id === booking.seatNo);
            if (seatIdx !== -1) {
              seats[seatIdx] = { ...seats[seatIdx], isBooked: true, bookingInfo: booking };
            }
          }
        });
        return { busId: t.name, seats };
      });
      setBuses(busLayouts);
    } catch (error) {
      console.error("Critical Cloud Fetch Error:", error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
    const channel = supabase.channel('tl_realtime_v2')
      .on('postgres_changes', { event: '*', schema: 'public' }, () => {
        fetchData();
      })
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, [fetchData]);

  const handleBookingSubmit = async (info: BookingInfo) => {
    try {
      const { error } = await supabase.from('tl_bookings').upsert({
        id: info.id,
        name: info.name,
        mobile: info.mobile,
        address: info.address,
        gender: info.gender,
        religion: info.religion,
        tour_name: info.tourName,
        tour_fees: info.tourFees,
        customer_type: info.customerType,
        customer_type_fees: info.customerTypeFees,
        discount_amount: info.discountAmount,
        advance_amount: info.advanceAmount,
        due_amount: info.dueAmount,
        payment_status: info.paymentStatus,
        bus_no: info.busNo,
        seat_no: info.seatNo,
        booked_by: info.bookedBy,
        booker_code: info.bookerCode,
        booking_date: info.bookingDate
      });
      if (error) throw error;
      fetchData();
    } catch (error) {
      alert("Booking failed. Please check your cloud connection.");
    }
    setShowBookingModal(false);
    setShowDetailModal(false);
    setSelectedSeatId(null);
    setEditingInfo(null);
  };

  const confirmDeselect = async () => {
    if (seatToDeselect) {
      const bus = buses.find(b => b.busId === seatToDeselect.busId);
      const seat = bus?.seats.find(s => s.id === seatToDeselect.seatId);
      if (seat?.bookingInfo) {
        try {
          const { error } = await supabase.from('tl_bookings').delete().eq('id', seat.bookingInfo.id);
          if (error) throw error;
          fetchData();
        } catch (error) {
          alert("Cancellation failed.");
        }
      }
    }
    setShowConfirmDeselect(false);
    setSeatToDeselect(null);
  };

  const syncAdminTours = async (newTours: Tour[]) => {
    try {
      await supabase.from('tl_tours').delete().neq('name', '___'); 
      if (newTours.length > 0) {
        const { error } = await supabase.from('tl_tours').insert(newTours);
        if (error) throw error;
      }
      fetchData();
    } catch (e) { alert("Failed to sync tours."); }
  };

  const syncAdminAgents = async (newAgents: Booker[]) => {
    try {
      await supabase.from('tl_agents').delete().neq('code', '___');
      if (newAgents.length > 0) {
        const { error } = await supabase.from('tl_agents').insert(newAgents);
        if (error) throw error;
      }
      fetchData();
    } catch (e) { alert("Failed to sync agents."); }
  };

  const syncAdminTypes = async (newTypes: CustomerType[]) => {
    try {
      await supabase.from('tl_customer_types').delete().neq('type', '___');
      if (newTypes.length > 0) {
        const { error } = await supabase.from('tl_customer_types').insert(newTypes);
        if (error) throw error;
      }
      fetchData();
    } catch (e) { alert("Failed to sync categories."); }
  };

  const seedDatabase = async () => {
    if (confirm("This will populate your cloud database with default tours and agents. Continue?")) {
      setIsLoading(true);
      try {
        await Promise.all([
          supabase.from('tl_tours').insert(TOURS),
          supabase.from('tl_agents').insert(BOOKERS),
          supabase.from('tl_customer_types').insert(CUSTOMER_TYPES)
        ]);
        await fetchData();
        alert("Cloud Initialized Successfully!");
      } catch (e) {
        alert("Initialization failed. Check if tables exist.");
      } finally {
        setIsLoading(false);
      }
    }
  };

  const handleSeatClick = (seatId: string) => {
    if (buses.length === 0) return;
    const bus = buses[selectedBusIndex];
    if (!bus) return;
    const seat = bus.seats.find(s => s.id === seatId);
    setSelectedSeatId(seatId);
    if (seat?.isBooked && seat.bookingInfo) {
      setEditingInfo(seat.bookingInfo);
      setShowDetailModal(true);
    } else {
      setShowBookingModal(true);
    }
  };

  const handleEditSeatRequest = (info: BookingInfo) => {
    setShowDetailModal(false);
    setSecurityModal({ isOpen: true, targetInfo: info, action: 'edit' });
  };

  const triggerCancelBooking = (busId: string, seatId: string) => {
    const bus = buses.find(b => b.busId === busId);
    const seat = bus?.seats.find(s => s.id === seatId);
    if (seat?.bookingInfo) {
      setShowDetailModal(false);
      setSecurityModal({ isOpen: true, targetInfo: seat.bookingInfo, action: 'delete' });
    }
  };

  const handleSecurityVerify = (code: string) => {
    if (!securityModal) return;
    if (code.toUpperCase() === securityModal.targetInfo.bookerCode.toUpperCase()) {
      const { action, targetInfo } = securityModal;
      setSecurityModal(null);
      if (action === 'edit') {
        setEditingInfo(targetInfo);
        setSelectedSeatId(targetInfo.seatNo);
        setShowBookingModal(true);
      } else if (action === 'delete') {
        setSeatToDeselect({ busId: targetInfo.busNo, seatId: targetInfo.seatNo });
        setShowConfirmDeselect(true);
      }
    } else {
      alert("Unauthorized Agent Code!");
    }
  };

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPasswordInput === "@Rana&01625@") {
      setIsAdminAuthenticated(true);
      setShowAdminLogin(false);
      setActiveTab('admin');
      setAdminPasswordInput('');
    } else {
      alert("Incorrect Admin Password!");
    }
  };

  if (isLoading) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-[#001D4A] text-white">
        <img src={BUSINESS_INFO.logo} className="w-32 animate-pulse mb-8" />
        <div className="flex flex-col items-center gap-4">
          <div className="flex gap-2">
            <div className="w-3 h-3 bg-orange-500 rounded-full animate-bounce"></div>
            <div className="w-3 h-3 bg-orange-500 rounded-full animate-bounce delay-75"></div>
            <div className="w-3 h-3 bg-orange-500 rounded-full animate-bounce delay-150"></div>
          </div>
          <p className="text-[10px] font-black uppercase tracking-widest opacity-40">Syncing with Tour লাগবে Cloud...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row font-sans overflow-hidden relative">
      {isSidebarOpen && <div className="fixed inset-0 bg-black/50 z-[55] md:hidden" onClick={() => setIsSidebarOpen(false)}></div>}
      <nav className={`fixed md:sticky top-0 h-full transition-all duration-300 ease-in-out bg-[#001D4A] text-white flex flex-col shadow-2xl z-[60] shrink-0 ${isSidebarOpen ? 'w-72 translate-x-0' : 'w-72 -translate-x-full md:w-20 md:translate-x-0'}`}>
        <div className={`p-8 text-center border-b border-white/10 ${!isSidebarOpen && 'md:p-4'}`}>
          <img src={BUSINESS_INFO.logo} alt="Logo" className={`${isSidebarOpen ? 'w-24' : 'w-10'} transition-all mx-auto mb-2`} />
          {isSidebarOpen && <h1 className="text-2xl font-black text-white">{BUSINESS_INFO.name}</h1>}
        </div>
        <div className="flex-grow py-6 space-y-1 overflow-y-auto">
          {[
            { id: 'dashboard', icon: 'fa-chart-line', label: 'Dashboard' },
            { id: 'booking', icon: 'fa-ticket-alt', label: 'Seat Booking' },
            { id: 'log', icon: 'fa-clipboard-list', label: 'Response Section' },
            { id: 'edit', icon: 'fa-user-edit', label: 'Editor' },
          ].map(tab => (
            <button key={tab.id} onClick={() => { setActiveTab(tab.id as any); setIsSidebarOpen(false); }} className={`w-full flex items-center gap-4 px-8 py-4 text-sm font-semibold transition-all group ${activeTab === tab.id ? 'bg-orange-500 text-white shadow-lg' : 'text-white/70 hover:bg-white/5 hover:text-white'} ${!isSidebarOpen && 'md:px-0 md:justify-center'}`}>
              <i className={`fas ${tab.icon} w-6 text-center transition-transform group-hover:scale-110`}></i>
              {isSidebarOpen && <span>{tab.label}</span>}
            </button>
          ))}
          <div className={`pt-8 ${isSidebarOpen ? 'px-4' : 'px-1'}`}>
            <div className="border-t border-white/10 pt-4">
              <button onClick={() => setShowAdminLogin(true)} className={`w-full flex items-center gap-4 py-4 text-sm font-bold rounded-2xl transition-all ${activeTab === 'admin' ? 'bg-white text-[#001D4A]' : 'bg-indigo-600/30 text-indigo-200 hover:bg-indigo-600/50'} ${isSidebarOpen ? 'px-6' : 'justify-center'}`}>
                <i className="fas fa-user-shield"></i>
                {isSidebarOpen && <span>Admin Control</span>}
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="flex-grow h-screen overflow-auto relative flex flex-col">
        <header className="sticky top-0 left-0 w-full bg-[#001D4A] text-white p-4 flex items-center justify-between z-50 md:hidden">
          <button onClick={() => setIsSidebarOpen(true)} className="w-10 h-10 flex items-center justify-center bg-white/10 rounded-xl"><i className="fas fa-bars"></i></button>
          <div className="flex items-center gap-2"><img src={BUSINESS_INFO.logo} className="h-8" /><span className="font-bold text-xs uppercase tracking-tighter">{BUSINESS_INFO.name}</span></div>
          <div className="w-10"></div>
        </header>

        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="hidden md:flex absolute top-6 left-6 z-[70] bg-[#001D4A] text-white w-10 h-10 rounded-xl items-center justify-center shadow-lg hover:bg-orange-500 transition-colors">
          <i className={`fas ${isSidebarOpen ? 'fa-angle-left' : 'fa-angle-right'}`}></i>
        </button>

        <div className="p-4 md:p-10 flex-grow">
          {activeTab === 'booking' && (
            <div className="max-w-6xl mx-auto md:pl-12">
               <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center mb-10 gap-6">
                <div>
                  <h2 className="text-3xl font-black text-[#001D4A]">Seat Booking</h2>
                  <p className="text-sm text-gray-400">Cloud synchronized terminals.</p>
                </div>
                {buses.length > 0 && (
                  <div className="flex items-center gap-4 bg-white p-2 rounded-2xl border shadow-sm">
                    <span className="text-[10px] font-black uppercase text-gray-400 pl-2">Selected Tour:</span>
