              <tr key={i} className="hover:bg-gray-50/50">
                <td className="px-8 py-4">{editTourIndex === i ? <input className="px-3 py-2 border rounded-lg w-full" value={editTourData?.name} onChange={e => setEditTourData({...editTourData!, name: e.target.value})} /> : <span className="font-black text-gray-800">{t.name}</span>}</td>
                <td className="px-8 py-4">{editTourIndex === i ? <input type="number" className="px-3 py-2 border rounded-lg w-full" value={editTourData?.fee} onChange={e => setEditTourData({...editTourData!, fee: Number(e.target.value)})} /> : <span className="font-bold text-indigo-600">৳{t.fee.toLocaleString()}</span>}</td>
                <td className="px-8 py-4 text-right space-x-2">{editTourIndex === i ? <button onClick={saveTourEdit} className="text-green-600 font-black">SAVE</button> : <><button onClick={() => {setEditTourIndex(i); setEditTourData(t);}} className="text-blue-500 mr-4"><i className="fas fa-pen"></i></button><button onClick={() => removeTour(t.name)} className="text-red-400"><i className="fas fa-trash-alt"></i></button></>}</td>
              </tr>
            )) : <tr><td colSpan={3} className="px-8 py-10 text-center text-gray-400 italic">No tours defined in cloud database.</td></tr>}</tbody>
          </table></div>
        </div>
      )}

      {activeSubTab === 'agents' && (
        <div className="space-y-8 animate-in fade-in duration-300">
