                <td className="px-6 py-4"><div className={`w-6 h-6 rounded-lg border-2 transition-all flex items-center justify-center ${selectedForPrint.includes(b.id) ? 'bg-indigo-600 border-indigo-600' : 'bg-white border-gray-200'}`}>{selectedForPrint.includes(b.id) && <i className="fas fa-check text-[10px] text-white"></i>}</div></td>
                <td className="px-6 py-4 font-black text-gray-800">{b.name} <span className="text-[10px] text-gray-400 font-bold block">Seat {b.seatNo}</span></td>
                <td className="px-6 py-4"><span className="text-indigo-600 font-black text-xs">{b.tourName}</span></td>
                <td className="px-6 py-4 uppercase font-black text-[10px]"><span className={`${b.paymentStatus === 'Paid' ? 'text-green-600' : 'text-orange-500'}`}>{b.paymentStatus}</span></td>
              </tr>
            )) : <tr><td colSpan={4} className="px-6 py-10 text-center text-gray-400 italic">No bookings found across any fleet.</td></tr>}</tbody>
          </table></div>
        </div>
      )}
    </div>
  );
};

