            </div>
          </div>
          <div className="bg-white rounded-[32px] shadow-xl border overflow-hidden">
            <table className="w-full text-left text-sm whitespace-nowrap">
              <thead className="bg-gray-50 border-b"><tr className="text-[10px] font-black uppercase text-gray-400 tracking-widest"><th className="px-6 py-4 w-10">Select</th><th className="px-6 py-4">Passenger Info</th><th className="px-6 py-4">Tour Identity</th><th className="px-6 py-4">Status</th></tr></thead>
              <tbody className="divide-y divide-gray-100">{allBookings.length > 0 ? allBookings.map((b) => (
                <tr key={b.id} className={`hover:bg-indigo-50/50 cursor-pointer transition-colors ${selectedForPrint.includes(b.id) ? 'bg-indigo-50' : ''}`} onClick={() => setSelectedForPrint(prev => prev.includes(b.id) ? prev.filter(p => p !== b.id) : [...prev, b.id])}>
                  <td className="px-6 py-4">
                    <div className={`w-6 h-6 rounded-lg border-2 transition-all flex items-center justify-center ${selectedForPrint.includes(b.id) ? 'bg-indigo-600 border-indigo-600' : 'bg-white border-gray-200'}`}>
                      {selectedForPrint.includes(b.id) && <i className="fas fa-check text-[10px] text-white"></i>}
                    </div>
                  </td>
                  <td className="px-6 py-4 font-black text-gray-800">
                    {b.name} 
                    <span className="text-[10px] text-indigo-600 font-black block">Seat ${b.seatNo}</span>
                  </td>
                  <td className="px-6 py-4"><span className="text-gray-500 font-bold text-xs">{b.tourName}</span></td>
                  <td className="px-6 py-4 uppercase font-black text-[10px]"><span className={`${b.paymentStatus === 'Paid' ? 'text-green-600' : 'text-orange-500'}`}>{b.paymentStatus}</span></td>
                </tr>
              )) : <tr><td colSpan={4} className="px-6 py-10 text-center text-gray-400 italic">No bookings found in fleet.</td></tr>}</tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useRef } from 'react';
import { BookingInfo } from '../types';
import { BUSINESS_INFO } from '../constants';

interface SeatDetailModalProps {
  info: BookingInfo;
  onClose: () => void;
  onEdit: () => void;
  onCancel: () => void;
  onUpdate?: (updatedInfo: BookingInfo) => void;
}

const SeatDetailModal: React.FC<SeatDetailModalProps> = ({ info, onClose, onEdit, onCancel, onUpdate }) => {
  const ticketRef = useRef<HTMLDivElement>(null);

  // Generate QR Code URL based on booking info
  const qrData = `ID:${info.id}|Seat:${info.seatNo}|Name:${info.name}|Tour:${info.tourName}`;
  const qrCodeUrl = `https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=${encodeURIComponent(qrData)}`;

  const handlePayDue = () => {
    const code = prompt("Security Check: Enter the original Agent Booker Code to settle this balance:");
    if (code && code.toUpperCase() === info.bookerCode.toUpperCase()) {
      if (onUpdate) {
        const updatedInfo: BookingInfo = {
          ...info,
          advanceAmount: info.advanceAmount + info.dueAmount,
          dueAmount: 0,
          paymentStatus: 'Paid'
        };
        onUpdate(updatedInfo);
        alert("Balance settled successfully!");
      }
    } else if (code) {
      alert("Verification Failed: Unauthorized Agent Code.");
    }
  };

  const printTicket = () => {
    const printContent = ticketRef.current;
    if (!printContent) return;

    const windowPrint = window.open('', '', 'left=0,top=0,width=900,height=1000,toolbar=0,scrollbars=0,status=0');
    if (windowPrint) {
      windowPrint.document.write(`
        <html>
          <head>
            <title>Ticket - ${info.name}</title>
            <script src="https://cdn.tailwindcss.com"></script>
            <link href="https://fonts.googleapis.com/css2?family=Hind+Siliguri:wght@400;700&family=Inter:wght@400;700;900&display=swap" rel="stylesheet">
            <style>
              body { font-family: 'Inter', 'Hind Siliguri', sans-serif; background: white; margin: 0; padding: 20px; }
              .ticket-print-wrap { width: 100%; max-width: 600px; margin: 0 auto; }
              @media print {
                .no-print { display: none; }
                body { padding: 0; }
              }
            </style>
          </head>
          <body>
            <div class="ticket-print-wrap">
              ${printContent.innerHTML}
            </div>
            <script>
              // Wait for Tailwind CDN and Fonts to settle
              window.onload = () => {
                setTimeout(() => {
                  window.print();
                  window.close();
                }, 500);
              };
            </script>
          </body>
        </html>
      `);
      windowPrint.document.close();
    }
  };

  return (
    <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-[#001D4A]/80 backdrop-blur-md overflow-y-auto">
      <div className="bg-white w-full max-w-xl rounded-[40px] shadow-2xl my-auto animate-in zoom-in duration-300 overflow-hidden border border-white/20">

        <div className="p-8">
           <div className="flex justify-between items-start mb-6">
              <div>
                <span className="text-[10px] font-black text-white bg-indigo-600 px-4 py-1 rounded-full uppercase mb-3 inline-block tracking-widest shadow-lg shadow-indigo-100">Booking Record</span>
                <h3 className="text-4xl md:text-5xl font-black text-[#001D4A] tracking-tighter">{info.name}</h3>
              </div>
              <button onClick={onClose} className="w-12 h-12 bg-gray-50 rounded-full flex items-center justify-center hover:bg-red-50 hover:text-red-500 transition-all text-gray-400">
                <i className="fas fa-times text-xl"></i>
              </button>
           </div>

           {/* Ticket Design - Matches Screenshot Layout */}
           <div ref={ticketRef} className="bg-white border-2 border-dashed border-gray-200 rounded-[40px] p-8 mb-10 relative overflow-hidden shadow-inner">
              {/* Card Cutouts */}
              <div className="absolute -left-5 top-1/2 -translate-y-1/2 w-10 h-10 bg-[#f9fafb] md:bg-white rounded-full border-r-2 border-dashed border-gray-200 z-10"></div>
              <div className="absolute -right-5 top-1/2 -translate-y-1/2 w-10 h-10 bg-[#f9fafb] md:bg-white rounded-full border-l-2 border-dashed border-gray-200 z-10"></div>

              <div className="flex justify-between items-start mb-8">
                 <div>
                    <img src={BUSINESS_INFO.logo} alt="Logo" className="h-12 mb-3" />
                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest max-w-[280px] leading-relaxed">
                      {BUSINESS_INFO.address}
                    </p>
                 </div>
                 <div className="text-right">
                    <div className="bg-[#001D4A] text-white px-5 py-2 rounded-xl inline-block mb-1 shadow-lg shadow-indigo-100">
                      <p className="text-[10px] font-black uppercase tracking-widest">Seat: {info.seatNo}</p>
                    </div>
                    <p className="text-[10px] font-black text-gray-300 tracking-widest mt-1">ID: {info.id}</p>
                 </div>
              </div>

              <div className="border-t border-dashed border-gray-100 my-8"></div>

              <div className="flex flex-col md:flex-row gap-8 items-center">
                 <div className="flex-grow grid grid-cols-2 gap-y-8 gap-x-4 w-full">
                    <div>
                        <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Passenger</p>
                        <p className="text-lg font-black text-[#001D4A] leading-none">{info.name}</p>
                    </div>
                    <div>
                        <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Tour</p>
                        <p className="text-lg font-black text-[#001D4A] leading-none truncate">{info.tourName}</p>
                    </div>
                    <div>
                        <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Contact</p>
