              </button>

              {info.dueAmount > 0 ? (
                <button 
                  onClick={handlePayDue}
                  className="py-5 bg-[#10a342] text-white rounded-[24px] font-black text-base hover:bg-green-700 shadow-xl shadow-green-100 flex items-center justify-center gap-3 transition-all active:scale-95"
                >
                  <i className="fas fa-money-bill-wave text-lg"></i> Pay Due (৳{info.dueAmount})
                </button>
              ) : (
                <button 
                  disabled
                  className="py-5 bg-gray-100 text-gray-400 rounded-[24px] font-black text-base cursor-not-allowed flex items-center justify-center gap-3"
                >
                  <i className="fas fa-check-double text-lg"></i> Paid In Full
                </button>
              )}

              <button 
                onClick={onEdit}
                className="py-5 bg-[#eef5ff] text-blue-600 rounded-[24px] font-black text-base hover:bg-blue-100 flex items-center justify-center gap-3 transition-all active:scale-95"
              >
                <i className="fas fa-user-edit text-lg"></i> Full Edit
              </button>
              <button 
                onClick={onCancel}
                className="py-5 bg-[#fff1f1] text-red-600 rounded-[24px] font-black text-base hover:bg-red-100 flex items-center justify-center gap-3 transition-all active:scale-95"
              >
                <i className="fas fa-trash-alt text-lg"></i> Cancel Booking
              </button>
           </div>
        </div>
      </div>
    </div>
  );
};

