          <form onSubmit={addAgent} className="bg-white p-8 rounded-[32px] shadow-xl border flex flex-col md:flex-row gap-4 items-end">
            <div className="w-full md:w-48 space-y-1"><label className="text-[10px] font-black uppercase text-gray-400">Agent ID</label><input required className="w-full px-5 py-4 bg-gray-50 border-none rounded-2xl font-black uppercase" value={newAgent.code} onChange={e => setNewAgent({...newAgent, code: e.target.value.toUpperCase()})} /></div>
            <div className="flex-1 space-y-1 w-full"><label className="text-[10px] font-black uppercase text-gray-400">Full Name</label><input required className="w-full px-5 py-4 bg-gray-50 border-none rounded-2xl font-bold" value={newAgent.name} onChange={e => setNewAgent({...newAgent, name: e.target.value})} /></div>
            <button type="submit" className="px-10 py-4 bg-indigo-600 text-white rounded-2xl font-black">Add Agent</button>
          </form>
          <div className="bg-white rounded-[32px] shadow-xl border overflow-hidden">
            <table className="w-full">
              <thead className="bg-gray-50 border-b"><tr className="text-[10px] font-black uppercase text-gray-400 tracking-widest"><th className="px-8 py-4 text-left">Code</th><th className="px-8 py-4 text-left">Agent Name</th><th className="px-8 py-4 text-right">Control</th></tr></thead>
              <tbody className="divide-y divide-gray-100">{agents.map((a, i) => (
                <tr key={i} className="hover:bg-gray-50/50">
                  <td className="px-8 py-4">{editAgentIndex === i ? <input className="px-3 py-2 border rounded-lg w-full font-black uppercase" value={editAgentData?.code} onChange={e => setEditAgentData({...editAgentData!, code: e.target.value.toUpperCase()})} /> : <span className="font-black text-indigo-600 bg-indigo-50 px-2 py-1 rounded">{a.code}</span>}</td>
                  <td className="px-8 py-4">{editAgentIndex === i ? <input className="px-3 py-2 border rounded-lg w-full font-bold" value={editAgentData?.name} onChange={e => setEditAgentData({...editAgentData!, name: e.target.value})} /> : <span className="font-bold text-gray-800">{a.name}</span>}</td>
                  <td className="px-8 py-4 text-right space-x-2">
                    {editAgentIndex === i ? (
                      <button onClick={saveAgentEdit} className="text-green-600 font-black px-3 py-1 rounded">SAVE</button>
                    ) : (
                      <>
                        <button onClick={() => {setEditAgentIndex(i); setEditAgentData(a);}} className="text-blue-500 p-2 hover:bg-blue-50 rounded"><i className="fas fa-pen"></i></button>
                        <button onClick={() => removeAgent(a.code)} className="text-red-400 p-2 hover:bg-red-50 rounded"><i className="fas fa-trash-alt"></i></button>
                      </>
                    )}
                  </td>
                </tr>
              ))}</tbody>
            </table>
          </div>
        </div>
      )}

      {activeSubTab === 'types' && (
        <div className="space-y-8 animate-in fade-in duration-300">
          <form onSubmit={addType} className="bg-white p-8 rounded-[32px] shadow-xl border flex flex-col md:flex-row gap-4 items-end">
            <div className="flex-1 space-y-1 w-full"><label className="text-[10px] font-black uppercase text-gray-400">Category Name</label><input required className="w-full px-5 py-4 bg-gray-50 border-none rounded-2xl font-bold" value={newType.type} onChange={e => setNewType({...newType, type: e.target.value})} /></div>
            <div className="w-full md:w-48 space-y-1"><label className="text-[10px] font-black uppercase text-gray-400">Surcharge</label><input required type="number" className="w-full px-5 py-4 bg-gray-50 border-none rounded-2xl font-bold" value={newType.fee || ''} onChange={e => setNewType({...newType, fee: Number(e.target.value)})} /></div>
            <button type="submit" className="px-10 py-4 bg-blue-600 text-white rounded-2xl font-black">Add Category</button>
          </form>
          <div className="bg-white rounded-[32px] shadow-xl border overflow-hidden">
            <table className="w-full">
              <thead className="bg-gray-50 border-b"><tr className="text-[10px] font-black uppercase text-gray-400 tracking-widest"><th className="px-8 py-4 text-left">Category</th><th className="px-8 py-4 text-left">Surcharge</th><th className="px-8 py-4 text-right">Control</th></tr></thead>
              <tbody className="divide-y divide-gray-100">{customerTypes.map((c, i) => (
                <tr key={i} className="hover:bg-gray-50/50">
                  <td className="px-8 py-4">{editTypeIndex === i ? <input className="px-3 py-2 border rounded-lg w-full font-black" value={editTypeData?.type} onChange={e => setEditTypeData({...editTypeData!, type: e.target.value})} /> : <span className="font-black text-gray-800">{c.type}</span>}</td>
                  <td className="px-8 py-4">{editTypeIndex === i ? <input type="number" className="px-3 py-2 border rounded-lg w-full font-bold" value={editTypeData?.fee} onChange={e => setEditTypeData({...editTypeData!, fee: Number(e.target.value)})} /> : <span className="font-bold text-blue-600">৳{c.fee}</span>}</td>
                  <td className="px-8 py-4 text-right space-x-2">
                    {editTypeIndex === i ? (
                      <button onClick={saveTypeEdit} className="text-green-600 font-black px-3 py-1 rounded">SAVE</button>
                    ) : (
                      <>
                        <button onClick={() => {setEditTypeIndex(i); setEditTypeData(c);}} className="text-blue-500 p-2 hover:bg-blue-50 rounded"><i className="fas fa-pen"></i></button>
                        <button onClick={() => removeType(i)} className="text-red-400 p-2 hover:bg-red-50 rounded"><i className="fas fa-trash-alt"></i></button>
                      </>
                    )}
                  </td>
                </tr>
              ))}</tbody>
            </table>
          </div>
        </div>
      )}

      {activeSubTab === 'print' && (
        <div className="space-y-6 animate-in fade-in duration-300">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center bg-white p-6 rounded-[32px] shadow-xl border gap-4">
            <div>
              <h3 className="font-black text-[#001D4A]">Batch Print Tickets</h3>
              <p className="text-xs text-gray-400">Layout optimized for 8 tickets per page.</p>
            </div>
            <div className="flex gap-2 w-full md:w-auto">
              <button onClick={() => setSelectedForPrint(allBookings.map(b => b.id))} className="px-4 py-4 bg-gray-100 text-gray-600 rounded-2xl font-black text-xs uppercase">Select All</button>
              <button onClick={handlePrintBatch} className="flex-grow md:flex-none px-10 py-4 bg-indigo-600 text-white rounded-2xl font-black text-sm shadow-xl hover:bg-indigo-700 active:scale-95 transition-all">Print Selected (${selectedForPrint.length})</button>
            </div>
          </div>
          <div className="bg-white rounded-[32px] shadow-xl border overflow-hidden">
            <table className="w-full text-left text-sm whitespace-nowrap">
              <thead className="bg-gray-50 border-b"><tr className="text-[10px] font-black uppercase text-gray-400 tracking-widest"><th className="px-6 py-4 w-10">Select</th><th className="px-6 py-4">Passenger Info</th><th className="px-6 py-4">Tour Identity</th><th className="px-6 py-4">Status</th></tr></thead>
              <tbody className="divide-y divide-gray-100">{allBookings.length > 0 ? allBookings.map((b) => (
                <tr key={b.id} className={`hover:bg-indigo-50/50 cursor-pointer transition-colors ${selectedForPrint.includes(b.id) ? 'bg-indigo-50' : ''}`} onClick={() => setSelectedForPrint(prev => prev.includes(b.id) ? prev.filter(p => p !== b.id) : [...prev, b.id])}>
                  <td className="px-6 py-4">
                    <div className={`w-6 h-6 rounded-lg border-2 transition-all flex items-center justify-center ${selectedForPrint.includes(b.id) ? 'bg-indigo-600 border-indigo-600' : 'bg-white border-gray-200'}`}>
                      {selectedForPrint.includes(b.id) && <i className="fas fa-check text-[10px] text-white"></i>}
                    </div>
                  </td>
                  <td className="px-6 py-4 font-black text-gray-800">
                    {b.name} 
                    <span className="text-[10px] text-indigo-600 font-black block uppercase tracking-widest">Seat: ${b.seatNo}</span>
                  </td>
                  <td className="px-6 py-4"><span className="text-gray-500 font-bold text-xs">{b.tourName}</span></td>
                  <td className="px-6 py-4 uppercase font-black text-[10px]"><span className={`${b.paymentStatus === 'Paid' ? 'text-green-600' : 'text-orange-500'}`}>{b.paymentStatus}</span></td>
                </tr>
              )) : <tr><td colSpan={4} className="px-6 py-10 text-center text-gray-400 italic">No bookings found in fleet.</td></tr>}</tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useCallback } from 'react';
import { BUSINESS_INFO, generateInitialSeats, TOURS, BOOKERS, CUSTOMER_TYPES } from './constants';
import { BusData, BookingInfo, Tour, Booker, CustomerType } from './types';
import BusLayout from './components/BusLayout';
import BookingModal from './components/BookingModal';
import ConfirmationDialog from './components/ConfirmationDialog';
import Dashboard from './components/Dashboard';
import BookingLog from './components/BookingLog';
import EditData from './components/EditData';
import AdminPanel from './components/AdminPanel';
import SeatDetailModal from './components/SeatDetailModal';
import SecurityModal from './components/SecurityModal';
import { supabase } from './supabase';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'booking' | 'dashboard' | 'log' | 'edit' | 'admin'>('booking');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);
  const [adminPasswordInput, setAdminPasswordInput] = useState('');
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  const [selectedBusIndex, setSelectedBusIndex] = useState(0);
  const [selectedSeatId, setSelectedSeatId] = useState<string | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [showConfirmDeselect, setShowConfirmDeselect] = useState(false);
  const [editingInfo, setEditingInfo] = useState<BookingInfo | null>(null);
  const [seatToDeselect, setSeatToDeselect] = useState<{ busId: string, seatId: string } | null>(null);

  const [securityModal, setSecurityModal] = useState<{
    isOpen: boolean;
    targetInfo: BookingInfo;
    action: 'edit' | 'delete';
  } | null>(null);

  const [tours, setTours] = useState<Tour[]>([]);
  const [bookers, setBookers] = useState<Booker[]>([]);
  const [customerTypes, setCustomerTypes] = useState<CustomerType[]>([]);
  const [buses, setBuses] = useState<BusData[]>([]);

  const fetchData = useCallback(async () => {
    try {
      const [toursRes, bookersRes, typesRes, bookingsRes] = await Promise.all([
        supabase.from('tl_tours').select('*').order('name'),
        supabase.from('tl_agents').select('*').order('name'),
        supabase.from('tl_customer_types').select('*').order('type'),
        supabase.from('tl_bookings').select('*')
      ]);

      const fetchedTours = toursRes.data || [];
      const fetchedBookers = bookersRes.data || [];
      const fetchedTypes = typesRes.data || [];
      const fetchedBookings: any[] = bookingsRes.data || [];

      const mappedBookings: BookingInfo[] = fetchedBookings.map(b => ({
        id: b.id,
        name: b.name,
        mobile: b.mobile,
        address: b.address,
        gender: b.gender,
        religion: b.religion,
        tourName: b.tour_name,
        tourFees: b.tour_fees,
        customerType: b.customer_type,
        customerTypeFees: b.customer_type_fees,
        discount_amount: b.discount_amount,
        advanceAmount: b.advance_amount,
        dueAmount: b.due_amount,
        paymentStatus: b.payment_status,
        busNo: b.bus_no,
        seatNo: b.seat_no,
        bookedBy: b.booked_by,
        bookerCode: b.booker_code,
        bookingDate: b.booking_date
      }));

      setTours(fetchedTours);
      setBookers(fetchedBookers);
      setCustomerTypes(fetchedTypes);

      const busLayouts = fetchedTours.map(t => {
        const seats = generateInitialSeats();
        mappedBookings.forEach(booking => {
          if (booking.busNo === t.name) {
            const seatIdx = seats.findIndex(s => s.id === booking.seatNo);
            if (seatIdx !== -1) {
              seats[seatIdx] = { ...seats[seatIdx], isBooked: true, bookingInfo: booking };
            }
          }
        });
        return { busId: t.name, seats };
      });
      setBuses(busLayouts);
    } catch (error) {
      console.error("Fetch Error:", error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
    const channel = supabase.channel('tl_realtime_v2')
      .on('postgres_changes', { event: '*', schema: 'public' }, () => {
        fetchData();
      })
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, [fetchData]);

  const handleBookingSubmit = async (info: BookingInfo) => {
    try {
      const { error } = await supabase.from('tl_bookings').upsert({
        id: info.id,
        name: info.name,
        mobile: info.mobile,
        address: info.address,
        gender: info.gender,
        religion: info.religion,
        tour_name: info.tourName,
        tour_fees: info.tourFees,
        customer_type: info.customerType,
        customer_type_fees: info.customerTypeFees,
        discount_amount: info.discountAmount,
        advance_amount: info.advanceAmount,
        due_amount: info.dueAmount,
        payment_status: info.paymentStatus,
        bus_no: info.busNo,
        seat_no: info.seatNo,
        booked_by: info.bookedBy,
        booker_code: info.bookerCode,
        booking_date: info.bookingDate
      });
      if (error) throw error;
      fetchData();
    } catch (error) {
      alert("Sync failed.");
    }
    setShowBookingModal(false);
    setShowDetailModal(false);
  };

  const confirmDeselect = async () => {
    if (seatToDeselect) {
      const bus = buses.find(b => b.busId === seatToDeselect.busId);
      const seat = bus?.seats.find(s => s.id === seatToDeselect.seatId);
      if (seat?.bookingInfo) {
        try {
          await supabase.from('tl_bookings').delete().eq('id', seat.bookingInfo.id);
          fetchData();
        } catch (error) {
          alert("Cancel failed.");
        }
      }
    }
    setShowConfirmDeselect(false);
  };

  const syncAdminTours = async (newTours: Tour[]) => {
    await supabase.from('tl_tours').delete().neq('name', '___'); 
    if (newTours.length > 0) await supabase.from('tl_tours').insert(newTours);
    fetchData();
  };

  const syncAdminAgents = async (newAgents: Booker[]) => {
    await supabase.from('tl_agents').delete().neq('code', '___');
    if (newAgents.length > 0) await supabase.from('tl_agents').insert(newAgents);
    fetchData();
  };

  const syncAdminTypes = async (newTypes: CustomerType[]) => {
    await supabase.from('tl_customer_types').delete().neq('type', '___');
    if (newTypes.length > 0) await supabase.from('tl_customer_types').insert(newTypes);
    fetchData();
  };

  const seedDatabase = async () => {
    if (confirm("Seed database?")) {
      setIsLoading(true);
      await Promise.all([
        supabase.from('tl_tours').insert(TOURS),
        supabase.from('tl_agents').insert(BOOKERS),
        supabase.from('tl_customer_types').insert(CUSTOMER_TYPES)
      ]);
      await fetchData();
      setIsLoading(false);
    }
  };

  const handleSeatClick = (seatId: string) => {
    const bus = buses[selectedBusIndex];
    if (!bus) return;
    const seat = bus.seats.find(s => s.id === seatId);
    setSelectedSeatId(seatId);
    if (seat?.isBooked && seat.bookingInfo) {
      setEditingInfo(seat.bookingInfo);
      setShowDetailModal(true);
    } else {
      setShowBookingModal(true);
    }
  };

  const handleEditSeatRequest = (info: BookingInfo) => {
    setShowDetailModal(false);
    setSecurityModal({ isOpen: true, targetInfo: info, action: 'edit' });
  };

  const triggerCancelBooking = (busId: string, seatId: string) => {
    const bus = buses.find(b => b.busId === busId);
    const seat = bus?.seats.find(s => s.id === seatId);
    if (seat?.bookingInfo) {
      setShowDetailModal(false);
      setSecurityModal({ isOpen: true, targetInfo: seat.bookingInfo, action: 'delete' });
    }
  };

  const handleSecurityVerify = (code: string) => {
    if (!securityModal) return;
    if (code.toUpperCase() === securityModal.targetInfo.bookerCode.toUpperCase()) {
      const { action, targetInfo } = securityModal;
      setSecurityModal(null);
      if (action === 'edit') {
        setEditingInfo(targetInfo);
        setSelectedSeatId(targetInfo.seatNo);
        setShowBookingModal(true);
      } else if (action === 'delete') {
        setSeatToDeselect({ busId: targetInfo.busNo, seatId: targetInfo.seatNo });
        setShowConfirmDeselect(true);
      }
    } else {
      alert("Invalid Code!");
    }
  };

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPasswordInput === "@Rana&01625@") {
      setIsAdminAuthenticated(true);
      setShowAdminLogin(false);
      setActiveTab('admin');
    } else {
      alert("Access Denied!");
    }
  };

  if (isLoading) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-[#001D4A] text-white">
        <img src={BUSINESS_INFO.logo} className="w-24 animate-pulse mb-8" />
        <div className="flex gap-2">
          <div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce"></div>
          <div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
          <div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
        </div>
      </div>
    );
  }

  const navItems = [
    { id: 'dashboard', icon: 'fa-chart-line', label: 'Dashboard' },
    { id: 'booking', icon: 'fa-bus', label: 'Seats' },
    { id: 'log', icon: 'fa-clipboard-list', label: 'Log' },
    { id: 'edit', icon: 'fa-user-pen', label: 'Editor' },
  ];

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row font-sans overflow-hidden">
      {/* Redesigned Sidebar - Matches Screenshot */}
      <nav className="fixed md:sticky top-0 h-screen w-20 md:w-24 bg-[#001D4A] flex flex-col items-center justify-between py-8 shadow-2xl z-50 shrink-0 border-r border-white/5">
        <div className="flex flex-col items-center w-full">
          <img src={BUSINESS_INFO.logo} alt="Logo" className="w-12 md:w-14 mb-12 hover:scale-105 transition-transform" />

          <div className="flex flex-col w-full">
            {navItems.map(item => (
              <button 
                key={item.id} 
                onClick={() => setActiveTab(item.id as any)} 
                className={`w-full py-6 flex flex-col items-center transition-all relative ${activeTab === item.id ? 'bg-orange-500 text-white' : 'text-white/40 hover:text-white hover:bg-white/5'}`}
              >
                <i className={`fas ${item.icon} text-xl md:text-2xl`}></i>
                {activeTab === item.id && <div className="absolute left-0 top-0 bottom-0 w-1 bg-white/20"></div>}
              </button>
            ))}
          </div>
        </div>

        {/* Admin Control Section at Bottom */}
        <div className="w-full flex flex-col items-center pb-4 px-2">
          <div className="w-full h-[1px] bg-white/10 mb-8"></div>
          <button 
            onClick={() => setShowAdminLogin(true)} 
            className={`w-14 h-14 md:w-16 md:h-16 flex items-center justify-center rounded-[20px] transition-all ${activeTab === 'admin' ? 'bg-orange-500 text-white' : 'bg-white/5 text-white/40 hover:bg-white/10 hover:text-white'}`}
          >
            <i className="fas fa-user-shield text-xl md:text-2xl"></i>
          </button>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-grow h-screen overflow-auto bg-gray-50/50">
        <div className="p-4 md:p-10">
          {activeTab === 'booking' && (
            <div className="max-w-6xl mx-auto">
               <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-6">
                <div>
                  <h2 className="text-4xl font-black text-[#001D4A] tracking-tighter">Fleet Terminal</h2>
                  <p className="text-xs text-gray-400 font-bold uppercase tracking-widest mt-1">Live Cloud Access Enabled</p>
                </div>
                {buses.length > 0 && (
                  <div className="flex items-center gap-4 bg-white p-3 rounded-3xl border shadow-xl">
                    <span className="text-[10px] font-black uppercase text-gray-300 pl-3">Route:</span>
                    <select value={selectedBusIndex} onChange={(e) => setSelectedBusIndex(Number(e.target.value))} className="bg-transparent font-black text-[#001D4A] outline-none min-w-[180px] text-sm pr-4">
                      {buses.map((bus, idx) => <option key={bus.busId} value={idx}>{bus.busId}</option>)}
                    </select>
                  </div>
                )}
              </div>

              {buses.length > 0 ? (
                <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
                  <div className="lg:col-span-7 flex justify-center">
                    <BusLayout seats={buses[selectedBusIndex]?.seats || []} onSeatClick={handleSeatClick} />
                  </div>
                  <div className="lg:col-span-5 space-y-8">
                    <div className="bg-white rounded-[40px] p-10 shadow-xl border border-gray-100">
                      <h3 className="font-black text-[#001D4A] mb-8 flex items-center gap-3 uppercase tracking-tighter text-sm">Visual Dashboard</h3>
                      <div className="grid grid-cols-1 gap-5">
                        {[{c:'bg-green-500',l:'Vacant'},{c:'bg-red-500',l:'Male (Muslim)'},{c:'bg-pink-500',l:'Female (Muslim)'},{c:'bg-blue-500',l:'Male (Non-Muslim)'},{c:'bg-yellow-500',l:'Female (Non-Muslim)'}].map((item,i)=>(
                          <div key={i} className="flex items-center gap-5 group">
                            <div className={`${item.c} w-12 h-12 rounded-2xl shadow-lg transition-transform group-hover:scale-110`}></div>
                            <span className="text-xs font-black text-gray-600 uppercase tracking-widest">{item.l}</span>
                          </div>
                        ))}
                      </div>
                    </div>
                  </div>
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center py-32 bg-white rounded-[60px] border-4 border-dashed border-gray-100">
                  <div className="w-24 h-24 bg-gray-50 rounded-full flex items-center justify-center text-gray-200 text-5xl mb-8"><i className="fas fa-bus-simple"></i></div>
                  <h3 className="text-2xl font-black text-gray-400 uppercase">Fleet Empty</h3>
                  <button onClick={() => setShowAdminLogin(true)} className="mt-8 px-10 py-4 bg-[#001D4A] text-white rounded-3xl font-black shadow-2xl hover:bg-orange-500 transition-all">Initialize Admin</button>
                </div>
              )}
            </div>
          )}

          {activeTab === 'dashboard' && <Dashboard buses={buses} />}
          {activeTab === 'log' && <BookingLog buses={buses} />}
          {activeTab === 'edit' && <EditData buses={buses} onUpdate={handleBookingSubmit} onDelete={triggerCancelBooking} onEdit={handleEditSeatRequest} bookers={bookers} />}
          {activeTab === 'admin' && isAdminAuthenticated && (
            <AdminPanel 
              tours={tours} setTours={syncAdminTours} 
              agents={bookers} setAgents={syncAdminAgents} 
              customerTypes={customerTypes} setCustomerTypes={syncAdminTypes} 
              buses={buses}
              onSeed={seedDatabase}
            />
          )}
        </div>
      </main>

      {showAdminLogin && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-[#001D4A]/90 backdrop-blur-md">
           <div className="bg-white w-full max-w-sm rounded-[40px] p-10 shadow-2xl animate-in zoom-in duration-300">
