import React, { useRef } from 'react';
import { BookingInfo } from '../types';
import { BUSINESS_INFO } from '../constants';

interface SeatDetailModalProps {
  info: BookingInfo;
  onClose: () => void;
  onEdit: () => void;
  onCancel: () => void;
  onUpdate?: (updatedInfo: BookingInfo) => void;
}

const SeatDetailModal: React.FC<SeatDetailModalProps> = ({ info, onClose, onEdit, onCancel, onUpdate }) => {
  const ticketRef = useRef<HTMLDivElement>(null);

  // Generate QR Code URL based on booking info
  const qrData = `ID:${info.id}|Seat:${info.seatNo}|Name:${info.name}|Tour:${info.tourName}`;
  const qrCodeUrl = `https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=${encodeURIComponent(qrData)}`;

  const handlePayDue = () => {
    const code = prompt(`SECURITY VERIFICATION\n\nPlease enter the Agent Code (${info.bookerCode}) to authorize payment:`);
    if (code && code.toUpperCase() === info.bookerCode.toUpperCase()) {
      const amountStr = prompt(`Current Due: ৳${info.dueAmount}\n\nEnter the payment amount to settle:`, info.dueAmount.toString());
      const amount = Number(amountStr);

      if (amountStr && !isNaN(amount) && amount > 0) {
        if (amount > info.dueAmount) {
          alert("Error: Payment amount cannot exceed the remaining due.");
          return;
        }

        if (onUpdate) {
          const newAdvance = info.advanceAmount + amount;
          const newDue = info.dueAmount - amount;
          const updatedInfo: BookingInfo = {
            ...info,
            advanceAmount: newAdvance,
            dueAmount: newDue,
            paymentStatus: newDue <= 0 ? 'Paid' : 'Partial'
          };
          onUpdate(updatedInfo);
          alert(`Success! ৳${amount} has been settled. New due: ৳${newDue}`);
        }
      } else if (amountStr) {
        alert("Error: Invalid payment amount.");
      }
    } else if (code) {
      alert("Verification Failed: Unauthorized Agent Code.");
    }
  };

  const handleShareTicket = async () => {
    const totalAmount = info.tourFees + (info.customerTypeFees || 0);
    const message = `
