  // Generate QR Code URL based on booking info
  const qrData = `ID:${info.id}|Seat:${info.seatNo}|Name:${info.name}|Tour:${info.tourName}`;
  const qrCodeUrl = `https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=${encodeURIComponent(qrData)}`;

  const handleProcessPayment = async (amount: number) => {
    if (onUpdate) {
      const newAdvance = info.advanceAmount + amount;
      const newDue = info.dueAmount - amount;
      const updatedInfo: BookingInfo = {
        ...info,
        advanceAmount: newAdvance,
        dueAmount: newDue,
        paymentStatus: newDue <= 0 ? 'Paid' : 'Partial'
      };

      try {
        await onUpdate(updatedInfo);
        setShowPaymentModal(false);
      } catch (error) {
        console.error("Update failed:", error);
        alert("Could not process payment. Please try again.");
      }
    }
  };

  const handleShareTicket = async () => {
    const totalAmount = info.tourFees + (info.customerTypeFees || 0);
    const message = `
🎫 *${BUSINESS_INFO.name} - Official Ticket*
---------------------------------------
👤 *Passenger:* ${info.name}
📍 *Tour:* ${info.tourName}
💺 *Seat Number:* ${info.seatNo}
📞 *Contact:* +880${info.mobile}

💰 *Ticket Price:* ৳${totalAmount.toLocaleString()}
💵 *Advance Paid:* ৳${info.advanceAmount.toLocaleString()}
🔴 *Due Balance:* ৳${info.dueAmount.toLocaleString()}
✅ *Status:* ${info.paymentStatus}

🆔 *Booking ID:* ${info.id}
📝 *Booked By:* ${info.bookedBy}
📅 *Date:* ${new Date(info.bookingDate).toLocaleDateString()}
---------------------------------------
*Thank you for choosing ${BUSINESS_INFO.name}!*
📍 ${BUSINESS_INFO.address}
`.trim();

    if (navigator.share) {
      try {
        await navigator.share({
          title: `Ticket for ${info.name}`,
          text: message,
        });
      } catch (err) {
        console.error("Share failed:", err);
      }
    } else {
      try {
        await navigator.clipboard.writeText(message);
        alert("Ticket details copied to clipboard!");
      } catch (err) {
        alert("Could not share ticket.");
      }
    }
  };

  const printTicket = () => {
    const printContent = ticketRef.current;
    if (!printContent) return;

    const windowPrint = window.open('', '', 'left=0,top=0,width=900,height=1000,toolbar=0,scrollbars=0,status=0');
    if (windowPrint) {
      windowPrint.document.write(`
        <html>
          <head>
            <title>Ticket - ${info.name}</title>
            <script src="https://cdn.tailwindcss.com"></script>
            <link href="https://fonts.googleapis.com/css2?family=Hind+Siliguri:wght@400;700&family=Inter:wght@400;700;900&display=swap" rel="stylesheet">
            <style>
              body { font-family: 'Inter', 'Hind Siliguri', sans-serif; background: white; margin: 0; padding: 20px; }
              .ticket-print-wrap { width: 100%; max-width: 600px; margin: 0 auto; }
            </style>
          </head>
          <body>
            <div class="ticket-print-wrap">
              ${printContent.innerHTML}
            </div>
            <script>
              window.onload = () => {
                setTimeout(() => {
                  window.print();
                  window.close();
                }, 500);
              };
            </script>
          </body>
        </html>
      `);
      windowPrint.document.close();
    }
  };

  return (
    <>
      <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-[#001D4A]/80 backdrop-blur-md overflow-y-auto">
        <div className="bg-white w-full max-w-xl rounded-[40px] shadow-2xl my-auto animate-in zoom-in duration-300 overflow-hidden border border-white/20">

          <div className="p-4 md:p-8">
             <div className="flex justify-between items-start mb-6 px-2">
                <div>
                  <span className="text-[10px] font-black text-white bg-indigo-600 px-4 py-1 rounded-full uppercase mb-3 inline-block tracking-widest shadow-lg">Cloud Registry</span>
                  <h3 className="text-3xl md:text-5xl font-black text-[#001D4A] tracking-tighter leading-none truncate max-w-[300px]">{info.name}</h3>
                </div>
                <button onClick={onClose} className="w-10 h-10 md:w-12 md:h-12 bg-gray-50 rounded-full flex items-center justify-center hover:bg-gray-100 transition-all text-gray-400 active:scale-90">
                  <i className="fas fa-times text-xl"></i>
                </button>
             </div>

             {/* Ticket Design */}
             <div ref={ticketRef} className="bg-white border-2 border-dashed border-gray-200 rounded-[30px] md:rounded-[40px] p-6 md:p-8 mb-8 relative overflow-hidden shadow-sm">
                <div className="absolute -left-5 top-1/2 -translate-y-1/2 w-10 h-10 bg-white rounded-full border-r-2 border-dashed border-gray-200 z-10"></div>
                <div className="absolute -right-5 top-1/2 -translate-y-1/2 w-10 h-10 bg-white rounded-full border-l-2 border-dashed border-gray-200 z-10"></div>

                <div className="flex justify-between items-start mb-8">
                   <div>
                      <img src={BUSINESS_INFO.logo} alt="Logo" className="h-10 md:h-12 mb-3" />
                      <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest max-w-[200px] leading-relaxed">
                        {BUSINESS_INFO.address}
                      </p>
                   </div>
                   <div className="text-right">
                      <div className="bg-[#001D4A] text-white px-5 py-2 md:px-6 md:py-3 rounded-2xl flex flex-col items-center shadow-xl shadow-indigo-100/50">
                        <span className="text-[8px] md:text-[10px] font-black uppercase tracking-[0.2em] opacity-60">Seat</span>
                        <span className="text-2xl md:text-4xl font-black leading-none">{info.seatNo}</span>
                      </div>
                   </div>
                </div>

                <div className="flex flex-col md:flex-row gap-6 md:gap-8 items-center border-t border-dashed border-gray-100 pt-6">
                   <div className="flex-grow grid grid-cols-2 gap-y-6 md:gap-y-8 gap-x-4 w-full text-left">
                      <div>
                          <p className="text-[9px] md:text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Route</p>
                          <p className="text-sm md:text-base font-black text-[#001D4A] truncate">{info.tourName}</p>
                      </div>
                      <div>
                          <p className="text-[9px] md:text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Contact</p>
                          <p className="text-sm md:text-base font-black text-gray-700">+880{info.mobile}</p>
                      </div>
                      <div>
                          <p className="text-[9px] md:text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Advanced</p>
                          <p className="text-sm md:text-base font-black text-green-600">৳{info.advanceAmount.toLocaleString()}</p>
                      </div>
                      <div>
                          <p className="text-[9px] md:text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Status</p>
                          <p className={`text-sm md:text-base font-black uppercase tracking-widest ${info.paymentStatus === 'Paid' ? 'text-green-600' : 'text-orange-500'}`}>
                            {info.paymentStatus}
                          </p>
                      </div>
                   </div>

                   <div className="shrink-0 flex flex-col items-center">
                      <img src={qrCodeUrl} alt="QR" className="w-24 h-24 md:w-28 md:h-28" />
                      <p className="text-[8px] font-black text-gray-300 uppercase mt-2 tracking-tighter">ID: {info.id}</p>
                   </div>
                </div>

                <div className="border-t border-dashed border-gray-100 my-6 pt-6 flex justify-between items-end">
                   <div className="text-left">
                      <p className="text-[9px] md:text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Agent Details</p>
                      <p className="text-[12px] md:text-sm font-black text-gray-800 uppercase leading-none">{info.bookedBy} ({info.bookerCode})</p>
                   </div>
                   <div className="text-right">
                      {info.dueAmount > 0 && (
                        <div>
                          <p className="text-[9px] md:text-[10px] font-black text-red-400 uppercase tracking-widest mb-1">Remaining Due</p>
                          <p className="text-2xl md:text-3xl font-black text-red-600 leading-none">৳{info.dueAmount.toLocaleString()}</p>
                        </div>
                      )}
                   </div>
                </div>
             </div>

             {/* High-Performance Action Grid */}
             <div className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <button 
                    onClick={printTicket}
                    className="py-4 md:py-5 bg-[#312e81] text-white rounded-[32px] md:rounded-[40px] font-black text-sm md:text-base hover:bg-indigo-900 shadow-xl shadow-indigo-100 flex items-center justify-center gap-2 transition-all active:scale-95"
                  >
                    <i className="fas fa-print"></i> Print
                  </button>

                  <button 
                    onClick={handleShareTicket}
                    className="py-4 md:py-5 bg-[#10a342] text-white rounded-[32px] md:rounded-[40px] font-black text-sm md:text-base hover:bg-green-700 shadow-xl shadow-green-100 flex items-center justify-center gap-2 transition-all active:scale-95"
                  >
                    <i className="fas fa-share-nodes"></i> Share
                  </button>

                  <button 
                    onClick={onEdit}
                    className="py-4 md:py-5 bg-[#eef5ff] text-[#3b82f6] rounded-[32px] md:rounded-[40px] font-black text-sm md:text-base hover:bg-blue-100 flex items-center justify-center gap-2 transition-all active:scale-95"
                  >
                    <i className="fas fa-user-edit"></i> Edit
                  </button>

                  <button 
                    onClick={() => setShowPaymentModal(true)}
                    disabled={info.dueAmount <= 0}
                    className={`py-4 md:py-5 rounded-[32px] md:rounded-[40px] font-black text-sm md:text-base flex items-center justify-center gap-2 transition-all active:scale-95 shadow-xl ${info.dueAmount > 0 ? 'bg-[#ff7a1a] text-white hover:bg-orange-600 shadow-orange-100' : 'bg-gray-100 text-gray-300 cursor-not-allowed shadow-none'}`}
                  >
                    <i className="fas fa-money-bill-wave"></i> Due Pay ৳{info.dueAmount}
                  </button>
                </div>

                <button 
                  onClick={onCancel}
                  className="w-full py-4 bg-[#fff1f1] text-red-500 rounded-[32px] md:rounded-[40px] font-black text-xs uppercase tracking-widest hover:bg-red-100 transition-all active:scale-95 flex items-center justify-center gap-2"
                >
                  <i className="fas fa-trash-alt"></i> Cancel Booking Permanently
                </button>
             </div>
          </div>
        </div>
      </div>

      {showPaymentModal && (
        <PaymentModal 
          info={info} 
          onClose={() => setShowPaymentModal(false)} 
          onConfirm={handleProcessPayment} 
        />
      )}
    </>
  );
};

export default SeatDetailModal;

export enum Gender {
  MALE = 'Male',
  FEMALE = 'Female',
  OTHERS = 'Others'
}

export enum Religion {
  MUSLIM = 'Muslim',
  HINDUISM = 'Hinduism',
  BUDDHISM = 'Buddhism',
  CHRISTIANITY = 'Christianity',
  OTHERS = 'Others'
}

export interface BookingInfo {
  id: string; // Unique booking ID
  name: string;
  mobile: string;
  address: string;
  gender: Gender;
  religion: Religion;
  tourName: string;
  tourFees: number;
  customerType?: string;
  customerTypeFees: number;
  discountAmount: number;
  advanceAmount: number;
  dueAmount: number;
  paymentStatus: 'Paid' | 'Partial' | 'Due';
  busNo: string;
  seatNo: string;
  bookedBy: string; // Booker Name
  bookerCode: string;
  bookingDate: string;
}

export interface Expense {
  id: string;
  category: string;
  amount: number;
  description: string;
  date: string;
  recordedBy: string;
}

export interface SeatData {
  id: string; // e.g., 'A1'
  isBooked: boolean;
  bookingInfo?: BookingInfo;
}

export interface BusData {
  busId: string;
  seats: SeatData[];
}

export interface Tour {
  name: string;
  fee: number;
}

export interface Booker {
  code: string;
  name: string;
}

export interface CustomerType {
  type: string;
  fee: number;
}

import React, { useState, useEffect, useCallback } from 'react';
import { BUSINESS_INFO, generateInitialSeats, TOURS, BOOKERS, CUSTOMER_TYPES } from './constants';
import { BusData, BookingInfo, Tour, Booker, CustomerType, Expense } from './types';
import BusLayout from './components/BusLayout';
import BookingModal from './components/BookingModal';
import ConfirmationDialog from './components/ConfirmationDialog';
import Dashboard from './components/Dashboard';
import BookingLog from './components/BookingLog';
import EditData from './components/EditData';
import AdminPanel from './components/AdminPanel';
import SeatDetailModal from './components/SeatDetailModal';
import SecurityModal from './components/SecurityModal';
import ExpenseTracker from './components/ExpenseTracker';
import RevenueReport from './components/RevenueReport';
import { supabase } from './supabase';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'booking' | 'dashboard' | 'log' | 'edit' | 'admin' | 'expenses' | 'revenue'>('booking');
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);
  const [adminPasswordInput, setAdminPasswordInput] = useState('');
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  const [selectedBusIndex, setSelectedBusIndex] = useState(0);
  const [selectedSeatId, setSelectedSeatId] = useState<string | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [showConfirmDeselect, setShowConfirmDeselect] = useState(false);
  const [editingInfo, setEditingInfo] = useState<BookingInfo | null>(null);
  const [seatToDeselect, setSeatToDeselect] = useState<{ busId: string, seatId: string } | null>(null);

  const [securityModal, setSecurityModal] = useState<{
    isOpen: boolean;
    targetInfo: BookingInfo;
    action: 'edit' | 'delete';
  } | null>(null);

  const [tours, setTours] = useState<Tour[]>([]);
  const [bookers, setBookers] = useState<Booker[]>([]);
  const [customerTypes, setCustomerTypes] = useState<CustomerType[]>([]);
  const [buses, setBuses] = useState<BusData[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);

  const fetchData = useCallback(async () => {
    try {
      const [toursRes, bookersRes, typesRes, bookingsRes, expensesRes] = await Promise.all([
        supabase.from('tl_tours').select('*').order('name'),
        supabase.from('tl_agents').select('*').order('name'),
        supabase.from('tl_customer_types').select('*').order('type'),
        supabase.from('tl_bookings').select('*'),
        supabase.from('tl_expenses').select('*').order('date', { ascending: false })
      ]);

      const fetchedTours = toursRes.data || [];
      const fetchedBookers = bookersRes.data || [];
      const fetchedTypes = typesRes.data || [];
      const fetchedBookings: any[] = bookingsRes.data || [];
      const fetchedExpenses: any[] = expensesRes.data || [];

      const mappedBookings: BookingInfo[] = fetchedBookings.map(b => ({
        id: b.id,
        name: b.name,
        mobile: b.mobile,
        address: b.address,
        gender: b.gender,
        religion: b.religion,
        tourName: b.tour_name,
        tourFees: b.tour_fees,
        customerType: b.customer_type,
        customerTypeFees: b.customer_type_fees,
        discountAmount: b.discount_amount,
        advanceAmount: b.advance_amount,
        dueAmount: b.due_amount,
        paymentStatus: b.payment_status,
        busNo: b.bus_no,
        seatNo: b.seat_no,
        bookedBy: b.booked_by,
        bookerCode: b.booker_code,
        bookingDate: b.booking_date
      }));

      setTours(fetchedTours);
      setBookers(fetchedBookers);
      setCustomerTypes(fetchedTypes);
      setExpenses(fetchedExpenses);

      const busLayouts = fetchedTours.map(t => {
        const seats = generateInitialSeats();
        mappedBookings.forEach(booking => {
          if (booking.busNo === t.name) {
            const seatIdx = seats.findIndex(s => s.id === booking.seatNo);
            if (seatIdx !== -1) {
              seats[seatIdx] = { ...seats[seatIdx], isBooked: true, bookingInfo: booking };
            }
          }
        });
        return { busId: t.name, seats };
      });
      setBuses(busLayouts);
    } catch (error) {
      console.error("Fetch Error:", error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
    const channel = supabase.channel('tl_realtime_v4')
      .on('postgres_changes', { event: '*', schema: 'public' }, () => {
        fetchData();
      })
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, [fetchData]);

  const handleBookingSubmit = async (info: BookingInfo) => {
    try {
      const { error } = await supabase.from('tl_bookings').upsert({
        id: info.id,
        name: info.name,
        mobile: info.mobile,
        address: info.address,
        gender: info.gender,
        religion: info.religion,
        tour_name: info.tourName,
        tour_fees: info.tourFees,
        customer_type: info.customerType,
        customer_type_fees: info.customerTypeFees,
        discount_amount: info.discountAmount,
        advance_amount: info.advanceAmount,
        due_amount: info.dueAmount,
        payment_status: info.paymentStatus,
        bus_no: info.busNo,
        seat_no: info.seatNo,
        booked_by: info.bookedBy,
        booker_code: info.bookerCode,
        booking_date: info.bookingDate
      });
      if (error) throw error;
      fetchData();
    } catch (error) {
      alert("Sync failed.");
    }
    setShowBookingModal(false);
    setShowDetailModal(false);
  };

  const handleExpenseSubmit = async (expense: Expense) => {
    try {
      const { error } = await supabase.from('tl_expenses').upsert(expense);
      if (error) throw error;
      fetchData();
    } catch (error) {
      alert("Expense sync failed.");
    }
  };

  const handleDeleteExpense = async (id: string) => {
    if (!confirm("Delete this expense permanently?")) return;
    try {
      await supabase.from('tl_expenses').delete().eq('id', id);
      fetchData();
    } catch (error) {
      alert("Delete failed.");
    }
  };

  const confirmDeselect = async () => {
    if (seatToDeselect) {
      const bus = buses.find(b => b.busId === seatToDeselect.busId);
      const seat = bus?.seats.find(s => s.id === seatToDeselect.seatId);
      if (seat?.bookingInfo) {
        try {
          await supabase.from('tl_bookings').delete().eq('id', seat.bookingInfo.id);
          fetchData();
        } catch (error) {
          alert("Cancel failed.");
        }
      }
    }
    setShowConfirmDeselect(false);
  };

  const syncAdminTours = async (newTours: Tour[]) => {
    await supabase.from('tl_tours').delete().neq('name', '___'); 
    if (newTours.length > 0) await supabase.from('tl_tours').insert(newTours);
    fetchData();
  };

  const syncAdminAgents = async (newAgents: Booker[]) => {
    await supabase.from('tl_agents').delete().neq('code', '___');
    if (newAgents.length > 0) await supabase.from('tl_agents').insert(newAgents);
    fetchData();
  };

  const syncAdminTypes = async (newTypes: CustomerType[]) => {
    await supabase.from('tl_customer_types').delete().neq('type', '___');
    if (newTypes.length > 0) await supabase.from('tl_customer_types').insert(newTypes);
    fetchData();
  };

  const seedDatabase = async () => {
    if (confirm("Seed database?")) {
      setIsLoading(true);
      await Promise.all([
        supabase.from('tl_tours').insert(TOURS),
        supabase.from('tl_agents').insert(BOOKERS),
        supabase.from('tl_customer_types').insert(CUSTOMER_TYPES)
      ]);
      await fetchData();
      setIsLoading(false);
    }
  };

  const handleSeatClick = (seatId: string) => {
    const bus = buses[selectedBusIndex];
    if (!bus) return;
    const seat = bus.seats.find(s => s.id === seatId);
    setSelectedSeatId(seatId);
    if (seat?.isBooked && seat.bookingInfo) {
      setEditingInfo(seat.bookingInfo);
      setShowDetailModal(true);
    } else {
      setShowBookingModal(true);
    }
  };

  const handleEditSeatRequest = (info: BookingInfo) => {
    setShowDetailModal(false);
    setSecurityModal({ isOpen: true, targetInfo: info, action: 'edit' });
  };

  const triggerCancelBooking = (busId: string, seatId: string) => {
    const bus = buses.find(b => b.busId === busId);
    const seat = bus?.seats.find(s => s.id === seatId);
    if (seat?.bookingInfo) {
      setShowDetailModal(false);
      setSecurityModal({ isOpen: true, targetInfo: seat.bookingInfo, action: 'delete' });
    }
  };

  const handleSecurityVerify = (code: string) => {
    if (!securityModal) return;
    if (code.toUpperCase() === securityModal.targetInfo.bookerCode.toUpperCase()) {
      const { action, targetInfo } = securityModal;
      setSecurityModal(null);
      if (action === 'edit') {
        setEditingInfo(targetInfo);
        setSelectedSeatId(targetInfo.seatNo);
        setShowBookingModal(true);
      } else if (action === 'delete') {
        setSeatToDeselect({ busId: targetInfo.busNo, seatId: targetInfo.seatNo });
        setShowConfirmDeselect(true);
      }
    } else {
      alert("Invalid Code!");
    }
  };

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPasswordInput === "@Rana&01625@") {
      setIsAdminAuthenticated(true);
      setShowAdminLogin(false);
      setActiveTab('admin');
    } else {
      alert("Access Denied!");
    }
  };

  if (isLoading) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-[#001D4A] text-white">
        <img src={BUSINESS_INFO.logo} className="w-24 animate-pulse mb-8" />
        <div className="flex gap-2">
          <div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce"></div>
          <div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
          <div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
        </div>
      </div>
    );
  }

  const navItems = [
    { id: 'dashboard', icon: 'fa-chart-line', label: 'Stats' },
    { id: 'booking', icon: 'fa-bus', label: 'Seats' },
    { id: 'revenue', icon: 'fa-sack-dollar', label: 'Revenue' },
    { id: 'expenses', icon: 'fa-file-invoice-dollar', label: 'Costs' },
    { id: 'log', icon: 'fa-clipboard-list', label: 'Log' },
    { id: 'edit', icon: 'fa-user-pen', label: 'Edit' },
  ];

  return (
    <div className="min-h-screen bg-gray-50 font-sans relative overflow-x-hidden">

      {/* Desktop Sidebar (Left) */}
      <nav className="hidden md:flex fixed top-0 left-0 bottom-0 w-24 bg-[#001D4A] flex-col items-center justify-between py-8 shadow-2xl z-50 border-r border-white/5">
        <div className="flex flex-col items-center w-full">
          <img src={BUSINESS_INFO.logo} alt="Logo" className="w-14 mb-12 hover:scale-105 transition-transform cursor-pointer" onClick={() => setActiveTab('booking')} />
          <div className="flex flex-col w-full">
            {navItems.map(item => (
              <button 
                key={item.id} 
                onClick={() => setActiveTab(item.id as any)} 
                className={`w-full py-5 flex flex-col items-center justify-center transition-all relative ${activeTab === item.id ? 'bg-orange-500 text-white' : 'text-white/40 hover:text-white hover:bg-white/5'}`}
              >
                <i className={`fas ${item.icon} text-xl mb-1`}></i>
                <span className="text-[9px] font-black uppercase tracking-widest text-center px-1 leading-none">{item.label}</span>
