    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='tl_expenses' AND column_name='agent_code') THEN
        ALTER TABLE tl_expenses ADD COLUMN agent_code TEXT;
    END IF;
END $$;

