Run this complete script in your Supabase **SQL Editor**:

```sql
-- 1. CLEAN START: Remove existing tables
DROP TABLE IF EXISTS tl_bookings CASCADE;
DROP TABLE IF EXISTS tl_expenses CASCADE;
DROP TABLE IF EXISTS tl_customer_types CASCADE;
DROP TABLE IF EXISTS tl_agents CASCADE;
DROP TABLE IF EXISTS tl_tours CASCADE;

-- 2. CORE DATA TABLES
CREATE TABLE tl_tours (
  name text PRIMARY KEY,
  fee int8 NOT NULL
);

CREATE TABLE tl_agents (
  code text PRIMARY KEY,
  name text NOT NULL
);

CREATE TABLE tl_customer_types (
  type text PRIMARY KEY,
  fee int8 NOT NULL
);

-- 3. BOOKING TABLE (Includes Agent/Booker Code)
CREATE TABLE tl_bookings (
  id text PRIMARY KEY,
  name text,
  mobile text,
  address text,
  gender text,
  religion text,
  tour_name text,
  tour_fees int8,
  customer_type text,
  customer_type_fees int8,
  discount_amount int8,
  advance_amount int8,
  due_amount int8,
  payment_status text,
  bus_no text,
  seat_no text,
  booked_by text,
  booker_code text, -- Tracks the Agent ID
  booking_date timestamptz DEFAULT now()
);

-- 4. EXPENSES TABLE (Includes Agent Code for Authorization)
CREATE TABLE tl_expenses (
  id text PRIMARY KEY,
  category text NOT NULL,
  amount numeric NOT NULL,
  description text,
  date date NOT NULL DEFAULT CURRENT_DATE,
  recorded_by text,
  agent_code text -- Tracks which Agent recorded the cost
);

-- 5. ENABLE REALTIME SYNC
-- This makes sure that when any agent makes a change, everyone sees it instantly.
-- Note: If you get an error that 'supabase_realtime' publication already exists, 
-- you can use 'ALTER PUBLICATION' instead of 'CREATE'.
BEGIN;
  DROP PUBLICATION IF EXISTS supabase_realtime;
  CREATE PUBLICATION supabase_realtime FOR TABLE 
    tl_bookings, 
    tl_expenses, 
    tl_tours, 
    tl_agents, 
    tl_customer_types;
COMMIT;

