          <div className="bg-white p-8 rounded-[40px] shadow-xl border border-gray-100">
             <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-8">
                <div>
                   <h3 className="text-2xl font-black text-[#001D4A] tracking-tighter">Food Token Generator</h3>
                   <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mt-1">4x6 Grid Optimized (24 tokens per page)</p>
                </div>
                <button onClick={handlePrintFoodTokens} className="w-full md:w-auto px-10 py-5 bg-orange-500 text-white rounded-2xl font-black shadow-xl hover:bg-orange-600 transition-all active:scale-95 flex items-center justify-center gap-3">
                   <i className="fas fa-print"></i> Generate Tokens ({selectedForPrint.length})
