             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-8">
                <div className="space-y-1">
                   <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-2">Meal Type</label>
                   <div className="flex bg-gray-50 p-2 rounded-2xl gap-2">
                      {['Breakfast', 'Lunch', 'Dinner'].map(type => (
                         <button 
                            key={type}
                            onClick={() => setFoodType(type as any)}
                            className={`flex-1 py-3 rounded-xl font-black text-xs uppercase transition-all ${foodType === type ? 'bg-[#001D4A] text-white shadow-lg' : 'text-gray-400 hover:bg-white'}`}
                         >
                            {type}
                         </button>
                      ))}
                   </div>
                </div>
                <div className="space-y-1">
                   <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-2">Serving Time</label>
                   <input 
                      type="text" 
                      value={foodTime}
                      onChange={e => setFoodTime(e.target.value)}
