             </div>

             <div className="bg-white rounded-[32px] border overflow-hidden">
                <div className="flex justify-between items-center p-4 bg-gray-50 border-b">
                   <span className="text-[10px] font-black uppercase text-gray-400">Recipient List</span>
                   <button onClick={() => setSelectedForPrint(allBookings.map(b => b.id))} className="text-[10px] font-black text-indigo-600 uppercase underline">Select All Passengers</button>
