                  <i className="fas fa-filter absolute right-3 top-1/2 -translate-y-1/2 text-indigo-300 pointer-events-none text-[10px]"></i>
               </div>
             </div>

             <div className="space-y-4 max-h-[500px] overflow-y-auto no-scrollbar pr-2">
