    buses.flatMap(b => b.seats.filter(s => s.isBooked).map(s => s.bookingInfo!)),
    [buses]
  );

  const filteredBookings = useMemo(() => {
    return allBookings.filter(b => {
      const matchesTour = filterTour === '' || b.tourName === filterTour;
      const matchesBooker = filterBooker === '' || b.bookedBy.toLowerCase().includes(filterBooker.toLowerCase()) || b.bookerCode.toLowerCase().includes(filterBooker.toLowerCase());
      const matchesDate = filterDate === '' || b.bookingDate.startsWith(filterDate);
      return matchesTour && matchesBooker && matchesDate;
    });
  }, [allBookings, filterTour, filterBooker, filterDate]);

  const uniqueTours = useMemo(() => Array.from(new Set(allBookings.map(b => b.tourName))), [allBookings]);

  const downloadCSV = () => {
    const headers = ['Seat', 'Name', 'Mobile', 'Tour', 'Total Fees', 'Advance', 'Due', 'Status', 'Booked By', 'Booker ID', 'Date'];
    const rows = filteredBookings.map(b => [
      `${b.busNo}-${b.seatNo}`,
      b.name,
      `+880${b.mobile}`,
      b.tourName,
      b.tourFees + b.customerTypeFees,
      b.advanceAmount,
      b.dueAmount,
      b.paymentStatus,
      b.bookedBy,
      b.bookerCode,
      new Date(b.bookingDate).toLocaleDateString()
    ]);

    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `TourLagbe_Report_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-4 animate-in fade-in duration-300">
      <div className="bg-white rounded-[32px] shadow-sm border border-gray-100 p-6 md:p-8">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
          <div>
            <h2 className="text-2xl font-black text-[#001D4A] tracking-tighter uppercase">Response Sheet</h2>
            <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Entries: {filteredBookings.length}</p>
          </div>
          <button 
            onClick={downloadCSV}
            className="w-full md:w-auto bg-[#001D4A] text-white px-6 py-4 rounded-2xl text-xs font-black uppercase shadow-lg hover:bg-orange-500 transition-all flex items-center justify-center gap-2 active:scale-95"
          >
            <i className="fas fa-file-csv text-base"></i> Export Data
          </button>
        </div>

        {/* Filters */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <select 
            value={filterTour}
            onChange={(e) => setFilterTour(e.target.value)}
            className="w-full bg-gray-50 border-none rounded-2xl px-5 py-4 text-xs font-black text-[#001D4A] outline-none appearance-none"
          >
            <option value="">All Tours</option>
            {uniqueTours.map(t => <option key={t} value={t}>{t}</option>)}
          </select>
          <input 
            type="text"
            placeholder="Search Agent / ID"
            value={filterBooker}
            onChange={(e) => setFilterBooker(e.target.value)}
            className="w-full bg-gray-50 border-none rounded-2xl px-5 py-4 text-xs font-black outline-none placeholder:text-gray-300 uppercase"
          />
          <input 
            type="date"
            value={filterDate}
            onChange={(e) => setFilterDate(e.target.value)}
            className="w-full bg-gray-50 border-none rounded-2xl px-5 py-4 text-xs font-black outline-none"
          />
        </div>
      </div>

      {/* Mobile Card List / Desktop Table */}
      <div className="md:bg-white md:rounded-[32px] md:shadow-sm md:border md:border-gray-100 md:overflow-hidden">
        {/* Desktop View Table */}
        <div className="hidden md:block overflow-x-auto">
          <table className="w-full text-left text-sm whitespace-nowrap">
            <thead>
              <tr className="bg-gray-100 text-gray-500 font-black uppercase text-[10px] tracking-widest">
                <th className="px-6 py-4">Seat</th>
                <th className="px-6 py-4">Passenger</th>
                <th className="px-6 py-4">Tour Info</th>
                <th className="px-6 py-4">Finance</th>
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4">Agent</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filteredBookings.map((b) => (
                <tr key={b.id} className="hover:bg-indigo-50/30 transition-colors">
                  <td className="px-6 py-4 font-black text-indigo-600">{b.seatNo}</td>
                  <td className="px-6 py-4">
                    <p className="font-bold text-gray-800">{b.name}</p>
                    <p className="text-[10px] text-gray-400 font-bold uppercase">+880{b.mobile}</p>
                  </td>
                  <td className="px-6 py-4 font-black text-gray-700">{b.tourName}</td>
                  <td className="px-6 py-4">
                    <p className="font-black text-gray-800">৳{(b.tourFees + b.customerTypeFees).toLocaleString()}</p>
                    <p className="text-[10px] text-red-500 font-black">DUE: ৳{b.dueAmount.toLocaleString()}</p>
                  </td>
                  <td className="px-6 py-4">
                    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${b.paymentStatus === 'Paid' ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'}`}>
                      {b.paymentStatus}
                    </span>
                  </td>
                  <td className="px-6 py-4 font-black text-gray-800">{b.bookedBy}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* Mobile View Card List */}
        <div className="md:hidden space-y-3">
          {filteredBookings.length === 0 ? (
            <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-gray-200">
              <p className="text-gray-400 font-black uppercase text-xs">No records found</p>
            </div>
          ) : (
            filteredBookings.map((b) => (
              <div key={b.id} className="bg-white p-5 rounded-3xl shadow-sm border border-gray-100">
                <div className="flex justify-between items-start mb-4">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-[#001D4A] rounded-xl flex items-center justify-center text-white font-black text-sm">{b.seatNo}</div>
                    <div>
                      <p className="font-black text-[#001D4A] leading-none">{b.name}</p>
                      <p className="text-[9px] text-gray-400 font-bold uppercase mt-1 tracking-tight">+880{b.mobile}</p>
                    </div>
                  </div>
                  <span className={`px-2 py-1 rounded-lg text-[8px] font-black uppercase tracking-widest ${b.paymentStatus === 'Paid' ? 'bg-green-50 text-green-600' : 'bg-orange-50 text-orange-600'}`}>
                    {b.paymentStatus}
                  </span>
                </div>
                <div className="grid grid-cols-2 gap-4 border-t border-gray-50 pt-4">
                  <div>
                    <p className="text-[8px] font-black text-gray-400 uppercase tracking-widest mb-0.5">Tour Identity</p>
                    <p className="text-[10px] font-black text-gray-700 truncate">{b.tourName}</p>
                  </div>
                  <div className="text-right">
                    <p className="text-[8px] font-black text-gray-400 uppercase tracking-widest mb-0.5">Financials</p>
                    <p className="text-[10px] font-black text-gray-900 leading-none">৳{(b.tourFees + b.customerTypeFees).toLocaleString()}</p>
                    <p className="text-[9px] font-black text-red-500 mt-0.5">DUE: ৳{b.dueAmount}</p>
                  </div>
                  <div>
                    <p className="text-[8px] font-black text-gray-400 uppercase tracking-widest mb-0.5">Booking Agent</p>
                    <p className="text-[10px] font-black text-indigo-600 uppercase">{b.bookedBy}</p>
                  </div>
                  <div className="text-right">
                    <p className="text-[8px] font-black text-gray-400 uppercase tracking-widest mb-0.5">Date Entered</p>
                    <p className="text-[10px] font-black text-gray-500">{new Date(b.bookingDate).toLocaleDateString()}</p>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

export default BookingLog;

import React, { useState, useEffect, useCallback } from 'react';
import { BUSINESS_INFO, generateInitialSeats, TOURS, BOOKERS, CUSTOMER_TYPES } from './constants';
import { BusData, BookingInfo, Tour, Booker, CustomerType, Expense } from './types';
import BusLayout from './components/BusLayout';
import BookingModal from './components/BookingModal';
import ConfirmationDialog from './components/ConfirmationDialog';
import Dashboard from './components/Dashboard';
import BookingLog from './components/BookingLog';
import EditData from './components/EditData';
import AdminPanel from './components/AdminPanel';
import SeatDetailModal from './components/SeatDetailModal';
import SecurityModal from './components/SecurityModal';
import ExpenseTracker from './components/ExpenseTracker';
import RevenueReport from './components/RevenueReport';
import { supabase } from './supabase';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'booking' | 'dashboard' | 'log' | 'edit' | 'admin' | 'expenses' | 'revenue'>('booking');
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(() => {
    return sessionStorage.getItem('tl_auth_admin') === 'true';
  });
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminPasswordInput, setAdminPasswordInput] = useState('');
  const [isLoading, setIsLoading] = useState(true);

  const [authenticatedAgent, setAuthenticatedAgent] = useState<Booker | null>(() => {
    const saved = sessionStorage.getItem('tl_auth_agent');
    return saved ? JSON.parse(saved) : null;
  });
  const [entryCodeInput, setEntryCodeInput] = useState('');

  const [selectedBusIndex, setSelectedBusIndex] = useState(0);
  const [selectedSeatId, setSelectedSeatId] = useState<string | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [showConfirmDeselect, setShowConfirmDeselect] = useState(false);
  const [editingInfo, setEditingInfo] = useState<BookingInfo | null>(null);
  const [seatToDeselect, setSeatToDeselect] = useState<{ busId: string, seatId: string } | null>(null);

  const [securityModal, setSecurityModal] = useState<{
    isOpen: boolean;
    targetInfo: BookingInfo;
    action: 'edit' | 'delete';
  } | null>(null);

  const [tours, setTours] = useState<Tour[]>([]);
  const [bookers, setBookers] = useState<Booker[]>([]);
  const [customerTypes, setCustomerTypes] = useState<CustomerType[]>([]);
  const [buses, setBuses] = useState<BusData[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);

  const fetchData = useCallback(async () => {
    try {
      const [toursRes, bookersRes, typesRes, bookingsRes, expensesRes] = await Promise.all([
        supabase.from('tl_tours').select('*').order('name'),
        supabase.from('tl_agents').select('*').order('name'),
        supabase.from('tl_customer_types').select('*').order('type'),
        supabase.from('tl_bookings').select('*'),
        supabase.from('tl_expenses').select('*').order('date', { ascending: false })
      ]);

      const fetchedTours = toursRes.data || [];
      const fetchedBookers = bookersRes.data || [];
      const fetchedTypes = typesRes.data || [];
      const fetchedBookings: any[] = bookingsRes.data || [];
      const fetchedExpenses: any[] = expensesRes.data || [];

      const mappedBookings: BookingInfo[] = fetchedBookings.map(b => ({
        id: b.id,
        name: b.name,
        mobile: b.mobile,
        address: b.address,
        gender: b.gender,
        religion: b.religion,
        tourName: b.tour_name,
        tourFees: b.tour_fees,
        customerType: b.customer_type,
        customerTypeFees: b.customer_type_fees,
        discountAmount: b.discount_amount,
        advanceAmount: b.advance_amount,
        dueAmount: b.due_amount,
        paymentStatus: b.payment_status,
        busNo: b.bus_no,
        seatNo: b.seat_no,
        bookedBy: b.booked_by,
        bookerCode: b.booker_code,
        bookingDate: b.booking_date
      }));

      const mappedExpenses: Expense[] = fetchedExpenses.map(e => ({
        id: e.id,
        category: e.category,
        amount: e.amount,
        description: e.description,
        date: e.date,
        recordedBy: e.recorded_by,
        agentCode: e.agent_code || 'ADMIN',
        tourName: e.tour_name
      }));

      setTours(fetchedTours);
      setBookers(fetchedBookers);
      setCustomerTypes(fetchedTypes);
      setExpenses(mappedExpenses);

      const busLayouts = fetchedTours.map(t => {
        const seats = generateInitialSeats();
        mappedBookings.forEach(booking => {
          if (booking.busNo === t.name) {
            const seatIdx = seats.findIndex(s => s.id === booking.seatNo);
            if (seatIdx !== -1) {
              seats[seatIdx] = { ...seats[seatIdx], isBooked: true, bookingInfo: booking };
            }
          }
        });
        return { busId: t.name, seats };
      });
      setBuses(busLayouts);
    } catch (error) {
      console.error("Fetch Error:", error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
    const channel = supabase.channel('tl_realtime_v4')
      .on('postgres_changes', { event: '*', schema: 'public' }, () => {
        fetchData();
      })
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, [fetchData]);

  const handleBookingSubmit = async (info: BookingInfo) => {
    try {
      const { error } = await supabase.from('tl_bookings').upsert({
        id: info.id,
        name: info.name,
        mobile: info.mobile,
        address: info.address,
        gender: info.gender,
        religion: info.religion,
        tour_name: info.tourName,
        tour_fees: info.tourFees,
        customer_type: info.customer_type,
        customer_type_fees: info.customer_type_fees,
        discount_amount: info.discount_amount,
        advance_amount: info.advance_amount,
        due_amount: info.due_amount,
        payment_status: info.payment_status,
        bus_no: info.busNo,
        seat_no: info.seatNo,
        booked_by: info.bookedBy,
        booker_code: info.bookerCode,
        booking_date: info.bookingDate
      });
      if (error) throw error;
      fetchData();
    } catch (error) {
      alert("Sync failed.");
    }
    setShowBookingModal(false);
    setShowDetailModal(false);
  };

  const handleExpenseSubmit = async (expense: Expense) => {
    try {
      const { error } = await supabase.from('tl_expenses').upsert({
        id: expense.id,
        category: expense.category,
        amount: expense.amount,
        description: expense.description,
        date: expense.date,
        recorded_by: expense.recordedBy,
        agent_code: expense.agentCode,
        tour_name: expense.tourName
      });
      if (error) throw error;
      fetchData();
    } catch (error) {
      alert("Expense sync failed.");
    }
  };

  const handleDeleteExpense = async (id: string) => {
    if (!confirm("Delete this expense permanently?")) return;
    try {
      await supabase.from('tl_expenses').delete().eq('id', id);
      fetchData();
    } catch (error) {
      alert("Delete failed.");
    }
  };

  const confirmDeselect = async () => {
    if (seatToDeselect) {
      const bus = buses.find(b => b.busId === seatToDeselect.busId);
      const seat = bus?.seats.find(s => s.id === seatToDeselect.seatId);
      if (seat?.bookingInfo) {
        try {
          await supabase.from('tl_bookings').delete().eq('id', seat.bookingInfo.id);
          fetchData();
        } catch (error) {
          alert("Cancel failed.");
        }
      }
    }
    setShowConfirmDeselect(false);
  };

  const syncAdminTours = async (newTours: Tour[]) => {
    await supabase.from('tl_tours').delete().neq('name', '___'); 
    if (newTours.length > 0) await supabase.from('tl_tours').insert(newTours);
    fetchData();
  };

  const syncAdminAgents = async (newAgents: Booker[]) => {
    await supabase.from('tl_agents').delete().neq('code', '___');
    if (newAgents.length > 0) await supabase.from('tl_agents').insert(newAgents);
    fetchData();
  };

  const syncAdminTypes = async (newTypes: CustomerType[]) => {
    await supabase.from('tl_customer_types').delete().neq('type', '___');
    if (newTypes.length > 0) await supabase.from('tl_customer_types').insert(newTypes);
    fetchData();
  };

  const handleTourDeleteCascading = async (tourName: string) => {
    if (!confirm(`Warning: Deleting "${tourName}" will permanently remove all associated bookings and expenses. Proceed?`)) return;
    setIsLoading(true);
    try {
      await Promise.all([
        supabase.from('tl_tours').delete().eq('name', tourName),
        supabase.from('tl_bookings').delete().eq('bus_no', tourName),
        supabase.from('tl_expenses').delete().eq('tour_name', tourName)
      ]);
      await fetchData();
    } catch (error) {
      alert("Cascading delete failed.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleMasterReset = async () => {
    if (!confirm("CRITICAL WARNING: Irreversible delete of ALL data. Proceed?")) return;
    setIsLoading(true);
    try {
      await Promise.all([
        supabase.from('tl_bookings').delete().neq('id', '___'),
        supabase.from('tl_expenses').delete().neq('id', '___'),
        supabase.from('tl_tours').delete().neq('name', '___'),
        supabase.from('tl_agents').delete().neq('code', '___'),
        supabase.from('tl_customer_types').delete().neq('type', '___')
      ]);
      await fetchData();
      alert("All data wiped.");
    } catch (error) {
      alert("Master reset failed.");
    } finally {
      setIsLoading(false);
    }
  };

  const seedDatabase = async () => {
    if (confirm("Seed database?")) {
      setIsLoading(true);
      await Promise.all([
        supabase.from('tl_tours').insert(TOURS),
        supabase.from('tl_agents').insert(BOOKERS),
        supabase.from('tl_customer_types').insert(CUSTOMER_TYPES)
      ]);
      await fetchData();
      setIsLoading(false);
    }
  };

  const handleSeatClick = (seatId: string) => {
    const bus = buses[selectedBusIndex];
    if (!bus) return;
    const seat = bus.seats.find(s => s.id === seatId);
    setSelectedSeatId(seatId);
    if (seat?.isBooked && seat.bookingInfo) {
      setEditingInfo(seat.bookingInfo);
      setShowDetailModal(true);
    } else {
      setShowBookingModal(true);
    }
  };

  const handleEditSeatRequest = (info: BookingInfo) => {
    setShowDetailModal(false);
    if (isAdminAuthenticated) {
      setEditingInfo(info);
      setSelectedSeatId(info.seatNo);
      setShowBookingModal(true);
    } else {
      setSecurityModal({ isOpen: true, targetInfo: info, action: 'edit' });
    }
  };

  const triggerCancelBooking = (busId: string, seatId: string) => {
    const bus = buses.find(b => b.busId === busId);
    const seat = bus?.seats.find(s => s.id === seatId);
    if (seat?.bookingInfo) {
      setShowDetailModal(false);
      if (isAdminAuthenticated) {
        setSeatToDeselect({ busId, seatId });
        setShowConfirmDeselect(true);
      } else {
        setSecurityModal({ isOpen: true, targetInfo: seat.bookingInfo, action: 'delete' });
      }
    }
  };

  const handleSecurityVerify = (code: string) => {
    if (!securityModal) return;
    if (code.toUpperCase() === securityModal.targetInfo.bookerCode.toUpperCase()) {
      const { action, targetInfo } = securityModal;
      setSecurityModal(null);
      if (action === 'edit') {
        setEditingInfo(targetInfo);
        setSelectedSeatId(targetInfo.seatNo);
        setShowBookingModal(true);
      } else if (action === 'delete') {
        setSeatToDeselect({ busId: targetInfo.busNo, seatId: targetInfo.seatNo });
        setShowConfirmDeselect(true);
      }
    } else {
      alert("Invalid Code!");
    }
  };

  const handleEntryLogin = (e: React.FormEvent) => {
