    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-[#001D4A] text-white">
        <img src={BUSINESS_INFO.logo} className="w-24 animate-pulse mb-8" />
        <div className="flex gap-2"><div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce"></div><div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div><div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div></div>
      </div>
    );
  }

  if (!authenticatedAgent) {
    return (
      <div className="min-h-screen w-full flex items-center justify-center bg-[#001D4A] p-6">
        <div className="w-full max-w-sm z-10 animate-in fade-in zoom-in duration-500">
           <div className="bg-white/5 backdrop-blur-3xl p-8 rounded-[40px] border border-white/10 shadow-2xl">
              <div className="flex flex-col items-center mb-10">
                <div className="bg-white p-5 rounded-3xl shadow-xl mb-6"><img src={BUSINESS_INFO.logo} alt="Logo" className="w-16" /></div>
                <h1 className="text-2xl font-black text-white tracking-tighter text-center uppercase">{BUSINESS_INFO.name}</h1>
                <p className="text-white/40 text-[9px] font-black uppercase tracking-[0.3em] mt-2">Booker Access Portal</p>
              </div>
              <form onSubmit={handleEntryLogin} className="space-y-4">
                 <input autoFocus type="password" placeholder="ENTER CODE" value={entryCodeInput} onChange={(e) => setEntryCodeInput(e.target.value)} className="w-full bg-white/10 border border-white/10 px-6 py-5 rounded-2xl text-white font-black text-xl tracking-widest uppercase placeholder:text-white/20 focus:outline-none focus:ring-2 focus:ring-orange-500 text-center" />
                 <button type="submit" className="w-full py-5 bg-orange-500 text-white rounded-2xl font-black text-lg shadow-xl active:scale-95 transition-all">Unlock Terminal</button>
              </form>
           </div>
        </div>
      </div>
    );
  }

  const navItems = [
    { id: 'dashboard', icon: 'fa-chart-line', label: 'Stats' },
    { id: 'booking', icon: 'fa-bus', label: 'Seats' },
    { id: 'revenue', icon: 'fa-sack-dollar', label: 'Fin' },
    { id: 'expenses', icon: 'fa-file-invoice-dollar', label: 'Cost' },
    { id: 'log', icon: 'fa-clipboard-list', label: 'Log' }
  ];

  const handleAdminClick = () => { if (isAdminAuthenticated) setActiveTab('admin'); else setShowAdminLogin(true); };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row pb-[80px] md:pb-0 mobile-safe-bottom">
      {/* Side Nav for Desktop */}
      <nav className="hidden md:flex fixed top-0 left-0 bottom-0 w-24 bg-[#001D4A] flex-col items-center justify-between py-8 shadow-2xl z-50">
        <div className="flex flex-col items-center w-full">
          <img src={BUSINESS_INFO.logo} alt="Logo" className="w-14 mb-12" />
          {navItems.map(item => (
            <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`w-full py-5 flex flex-col items-center transition-all ${activeTab === item.id ? 'bg-orange-500 text-white shadow-lg' : 'text-white/40 hover:text-white'}`}>
              <i className={`fas ${item.icon} text-xl mb-1`}></i>
              <span className="text-[9px] font-black uppercase">{item.label}</span>
            </button>
          ))}
        </div>
        <div className="flex flex-col items-center gap-6">
          <button onClick={handleAdminClick} className={`w-14 h-14 flex items-center justify-center rounded-2xl transition-all ${activeTab === 'admin' ? 'bg-orange-500 text-white' : 'bg-white/5 text-white/40'}`}><i className="fas fa-user-shield text-xl"></i></button>
          <button onClick={handleLogout} className="w-14 h-14 flex items-center justify-center rounded-2xl bg-red-500/10 text-red-500"><i className="fas fa-power-off text-xl"></i></button>
        </div>
      </nav>

      {/* Bottom Nav for Mobile */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 h-[75px] bg-[#001D4A] flex items-center justify-around z-50 border-t border-white/5 shadow-[0_-10px_30px_rgba(0,0,0,0.3)] px-2">
        {navItems.map(item => (
          <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`flex-1 flex flex-col items-center justify-center gap-1 transition-all py-2 rounded-2xl ${activeTab === item.id ? 'bg-orange-500 text-white shadow-lg' : 'text-white/30'}`}>
            <i className={`fas ${item.icon} text-lg`}></i>
            <span className="text-[7px] font-black uppercase tracking-tight">{item.label}</span>
          </button>
        ))}
        <button onClick={handleAdminClick} className={`flex-1 flex flex-col items-center justify-center gap-1 py-2 rounded-2xl ${activeTab === 'admin' ? 'bg-orange-500 text-white shadow-lg' : 'text-white/30'}`}><i className="fas fa-user-shield text-lg"></i><span className="text-[7px] font-black uppercase tracking-tight">Admin</span></button>
      </nav>

      {/* Main Content Area */}
      <main className="flex-grow md:ml-24 p-4 md:p-10">
        <header className="flex justify-between items-center mb-6 md:mb-10">
            <div className="flex items-center gap-3">
               <div className="md:hidden w-10 h-10 bg-white p-2 rounded-xl shadow-sm"><img src={BUSINESS_INFO.logo} className="w-full" /></div>
               <div>
                  <h2 className="text-xl md:text-3xl font-black text-[#001D4A] uppercase tracking-tighter">{activeTab.replace('booking', 'Seats')}</h2>
                  <p className="text-[8px] md:text-[10px] font-black text-gray-400 uppercase tracking-widest">Agent: {authenticatedAgent.name}</p>
               </div>
            </div>
            <button onClick={handleLogout} className="md:hidden w-10 h-10 rounded-xl bg-red-50 text-red-500 flex items-center justify-center"><i className="fas fa-power-off"></i></button>
        </header>

        <div className="max-w-7xl mx-auto">
          {activeTab === 'booking' && (
            <div className="animate-in fade-in duration-500 space-y-6">
               {buses.length > 0 && (
                  <div className="bg-white p-4 rounded-3xl shadow-sm border border-gray-100 flex items-center gap-3">
                    <i className="fas fa-map-marked-alt text-orange-500 ml-2"></i>
                    <select value={selectedBusIndex} onChange={(e) => setSelectedBusIndex(Number(e.target.value))} className="bg-transparent font-black text-[#001D4A] outline-none w-full text-xs uppercase tracking-widest cursor-pointer">
                      {buses.map((bus, idx) => <option key={bus.busId} value={idx}>{bus.busId}</option>)}
                    </select>
                  </div>
               )}
               {buses.length > 0 ? (
                 <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start pb-10">
                    <div className="lg:col-span-7 flex justify-center"><BusLayout seats={buses[selectedBusIndex]?.seats || []} onSeatClick={handleSeatClick} /></div>
                    <div className="hidden lg:block lg:col-span-5 space-y-6">
                       <div className="bg-white rounded-[40px] p-8 shadow-sm border border-gray-100">
                         <h3 className="font-black text-[#001D4A] uppercase text-xs tracking-widest mb-6 border-b pb-4">Legend</h3>
                         <div className="space-y-4">
                           {[{c:'bg-green-500',l:'Vacant'}, {c:'bg-red-500',l:'Male (Muslim)'}, {c:'bg-pink-500',l:'Female (Muslim)'}, {c:'bg-blue-500',l:'Male (Others)'}, {c:'bg-yellow-500',l:'Female (Others)'}].map((item,i)=>(
                             <div key={i} className="flex items-center gap-4">
                               <div className={`${item.c} w-10 h-10 rounded-xl`}></div>
                               <p className="text-[10px] font-black text-gray-800 uppercase tracking-widest">{item.l}</p>
                             </div>
                           ))}
                         </div>
                       </div>
                    </div>
                 </div>
               ) : <div className="text-center py-20 bg-white rounded-[40px] border border-dashed border-gray-200"><p className="text-gray-400 font-black uppercase text-xs">Fleet Terminal Offline</p></div>}
            </div>
          )}
          {activeTab === 'dashboard' && <Dashboard buses={buses} expenses={expenses} />}
          {activeTab === 'log' && <BookingLog buses={buses} bookers={bookers} />}
          {activeTab === 'expenses' && <ExpenseTracker expenses={expenses} onSubmit={handleExpenseSubmit} onDelete={handleDeleteExpense} bookers={bookers} initialAgentCode={authenticatedAgent?.code} tours={tours} />}
          {activeTab === 'revenue' && <RevenueReport buses={buses} expenses={expenses} tours={tours} />}
          {activeTab === 'edit' && <EditData buses={buses} onUpdate={handleBookingSubmit} onDelete={triggerCancelBooking} onEdit={handleEditSeatRequest} bookers={bookers} />}
          {activeTab === 'admin' && isAdminAuthenticated && <AdminPanel tours={tours} setTours={syncAdminTours} agents={bookers} setAgents={syncAdminAgents} customerTypes={customerTypes} setCustomerTypes={syncAdminTypes} buses={buses} onSeed={seedDatabase} onDeleteTourCascading={handleTourDeleteCascading} onMasterReset={handleMasterReset} />}
        </div>
      </main>

      {showAdminLogin && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 bg-[#001D4A]/90 backdrop-blur-xl">
           <div className="bg-white w-full max-w-sm rounded-[40px] p-8 animate-in zoom-in duration-300 shadow-2xl">
              <h3 className="text-xl font-black text-[#001D4A] mb-8 text-center uppercase tracking-widest">Master Unlock</h3>
              <form onSubmit={handleAdminAuth} className="space-y-4">
                <input autoFocus type="password" placeholder="PASSWORD" value={adminPasswordInput} onChange={(e) => setAdminPasswordInput(e.target.value)} className="w-full px-6 py-5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-500 text-center font-black text-xl tracking-widest outline-none" />
                <div className="flex gap-4">
                  <button type="button" onClick={() => setShowAdminLogin(false)} className="flex-1 py-4 text-gray-400 font-black text-xs uppercase">Cancel</button>
                  <button type="submit" className="flex-1 py-4 bg-orange-500 text-white rounded-2xl font-black shadow-lg">Enter</button>
                </div>
              </form>
           </div>
        </div>
      )}

      {securityModal?.isOpen && <SecurityModal info={securityModal.targetInfo} action={securityModal.action} onClose={() => setSecurityModal(null)} onVerify={handleSecurityVerify} />}
      {showBookingModal && <BookingModal seatId={selectedSeatId!} busNo={editingInfo ? editingInfo.busNo : (buses[selectedBusIndex]?.busId || '')} onClose={() => { setShowBookingModal(false); setEditingInfo(null); }} onSubmit={handleBookingSubmit} tours={tours} bookers={bookers} customerTypes={customerTypes} existingData={editingInfo || undefined} />}
      {showDetailModal && editingInfo && <SeatDetailModal info={editingInfo} onClose={() => { setShowDetailModal(false); setEditingInfo(null); }} onEdit={() => handleEditSeatRequest(editingInfo)} onCancel={() => triggerCancelBooking(editingInfo.busNo, editingInfo.seatNo)} onUpdate={handleBookingSubmit} isAdmin={isAdminAuthenticated} />}
      {showConfirmDeselect && <ConfirmationDialog message="Permanently cancel this booking?" onConfirm={confirmDeselect} onCancel={() => setShowConfirmDeselect(false)} />}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { BUSINESS_INFO, generateInitialSeats, TOURS, BOOKERS, CUSTOMER_TYPES } from './constants';
import { BusData, BookingInfo, Tour, Booker, CustomerType, Expense } from './types';
import BusLayout from './components/BusLayout';
import BookingModal from './components/BookingModal';
import ConfirmationDialog from './components/ConfirmationDialog';
import Dashboard from './components/Dashboard';
import BookingLog from './components/BookingLog';
import EditData from './components/EditData';
import AdminPanel from './components/AdminPanel';
import SeatDetailModal from './components/SeatDetailModal';
import SecurityModal from './components/SecurityModal';
import ExpenseTracker from './components/ExpenseTracker';
import RevenueReport from './components/RevenueReport';
import { supabase } from './supabase';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'booking' | 'dashboard' | 'log' | 'edit' | 'admin' | 'expenses' | 'revenue'>('booking');
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(() => {
    return sessionStorage.getItem('tl_auth_admin') === 'true';
  });
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminPasswordInput, setAdminPasswordInput] = useState('');
  const [isLoading, setIsLoading] = useState(true);

  const [authenticatedAgent, setAuthenticatedAgent] = useState<Booker | null>(() => {
    const saved = sessionStorage.getItem('tl_auth_agent');
    return saved ? JSON.parse(saved) : null;
  });
  const [entryCodeInput, setEntryCodeInput] = useState('');

  const [selectedBusIndex, setSelectedBusIndex] = useState(0);
  const [selectedSeatId, setSelectedSeatId] = useState<string | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [showConfirmDeselect, setShowConfirmDeselect] = useState(false);
  const [editingInfo, setEditingInfo] = useState<BookingInfo | null>(null);
  const [seatToDeselect, setSeatToDeselect] = useState<{ busId: string, seatId: string } | null>(null);

  const [securityModal, setSecurityModal] = useState<{
    isOpen: boolean;
    targetInfo: BookingInfo;
    action: 'edit' | 'delete';
  } | null>(null);

  const [tours, setTours] = useState<Tour[]>([]);
  const [bookers, setBookers] = useState<Booker[]>([]);
  const [customerTypes, setCustomerTypes] = useState<CustomerType[]>([]);
  const [buses, setBuses] = useState<BusData[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);

  const fetchData = useCallback(async () => {
    try {
      const [toursRes, bookersRes, typesRes, bookingsRes, expensesRes] = await Promise.all([
        supabase.from('tl_tours').select('*').order('name'),
        supabase.from('tl_agents').select('*').order('name'),
        supabase.from('tl_customer_types').select('*').order('type'),
        supabase.from('tl_bookings').select('*'),
        supabase.from('tl_expenses').select('*').order('date', { ascending: false })
      ]);

      const fetchedTours = toursRes.data || [];
      const fetchedBookers = bookersRes.data || [];
      const fetchedTypes = typesRes.data || [];
      const fetchedBookings: any[] = bookingsRes.data || [];
      const fetchedExpenses: any[] = expensesRes.data || [];

      const mappedBookings: BookingInfo[] = fetchedBookings.map(b => ({
        id: b.id,
        name: b.name,
        mobile: b.mobile,
        address: b.address,
        gender: b.gender,
        religion: b.religion,
        tourName: b.tour_name,
        tourFees: b.tour_fees,
        customerType: b.customer_type,
        customerTypeFees: b.customer_type_fees,
        discountAmount: b.discount_amount,
        advanceAmount: b.advance_amount,
        dueAmount: b.due_amount,
        paymentStatus: b.payment_status,
        busNo: b.bus_no,
        seatNo: b.seat_no,
        bookedBy: b.booked_by,
        bookerCode: b.booker_code,
        bookingDate: b.booking_date
      }));

      setTours(fetchedTours);
      setBookers(fetchedBookers);
      setCustomerTypes(fetchedTypes);
      setExpenses(mappedExpenses.map(e => ({
        id: e.id,
        category: e.category,
        amount: e.amount,
        description: e.description,
        date: e.date,
        recordedBy: e.recorded_by,
        agentCode: e.agent_code || 'ADMIN',
        tourName: e.tour_name
      })));

      const busLayouts = fetchedTours.map(t => {
        const seats = generateInitialSeats();
        mappedBookings.forEach(booking => {
          if (booking.busNo === t.name) {
            const seatIdx = seats.findIndex(s => s.id === booking.seatNo);
            if (seatIdx !== -1) {
              seats[seatIdx] = { ...seats[seatIdx], isBooked: true, bookingInfo: booking };
            }
          }
        });
        return { busId: t.name, seats };
      });
      setBuses(busLayouts);
    } catch (error) {
      console.error("Fetch Error:", error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
    const channel = supabase.channel('tl_realtime_v4')
      .on('postgres_changes', { event: '*', schema: 'public' }, () => {
        fetchData();
      })
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, [fetchData]);

  const handleBookingSubmit = async (info: BookingInfo) => {
    try {
      const { error } = await supabase.from('tl_bookings').upsert({
        id: info.id,
        name: info.name,
        mobile: info.mobile,
        address: info.address,
        gender: info.gender,
        religion: info.religion,
        tour_name: info.tourName,
        tour_fees: info.tourFees,
        customer_type: info.customerType,
        customer_type_fees: info.customerTypeFees,
        discount_amount: info.discountAmount,
        advance_amount: info.advanceAmount,
        due_amount: info.dueAmount,
        payment_status: info.paymentStatus,
        bus_no: info.busNo,
        seat_no: info.seatNo,
        booked_by: info.bookedBy,
        booker_code: info.bookerCode,
        booking_date: info.bookingDate
      });
      if (error) throw error;
      fetchData();
    } catch (error) {
      alert("Sync failed.");
    }
    setShowBookingModal(false);
    setShowDetailModal(false);
  };

  const handleExpenseSubmit = async (expense: Expense) => {
    try {
      const { error } = await supabase.from('tl_expenses').upsert({
        id: expense.id,
        category: expense.category,
        amount: expense.amount,
        description: expense.description,
        date: expense.date,
        recorded_by: expense.recordedBy,
        agent_code: expense.agentCode,
        tour_name: expense.tourName
      });
      if (error) throw error;
      fetchData();
    } catch (error) {
      alert("Expense sync failed.");
    }
  };

  const handleDeleteExpense = async (id: string) => {
    if (!confirm("Delete this expense permanently?")) return;
    try {
      await supabase.from('tl_expenses').delete().eq('id', id);
      fetchData();
    } catch (error) {
      alert("Delete failed.");
    }
  };

  const confirmDeselect = async () => {
    if (seatToDeselect) {
      const bus = buses.find(b => b.busId === seatToDeselect.busId);
      const seat = bus?.seats.find(s => s.id === seatToDeselect.seatId);
      if (seat?.bookingInfo) {
        try {
          await supabase.from('tl_bookings').delete().eq('id', seat.bookingInfo.id);
          fetchData();
        } catch (error) {
          alert("Cancel failed.");
        }
      }
    }
    setShowConfirmDeselect(false);
  };

  const syncAdminTours = async (newTours: Tour[]) => {
    await supabase.from('tl_tours').delete().neq('name', '___'); 
    if (newTours.length > 0) await supabase.from('tl_tours').insert(newTours);
    fetchData();
  };

  const syncAdminAgents = async (newAgents: Booker[]) => {
    await supabase.from('tl_agents').delete().neq('code', '___');
    if (newAgents.length > 0) await supabase.from('tl_agents').insert(newAgents);
    fetchData();
  };

  const syncAdminTypes = async (newTypes: CustomerType[]) => {
    await supabase.from('tl_customer_types').delete().neq('type', '___');
    if (newTypes.length > 0) await supabase.from('tl_customer_types').insert(newTypes);
    fetchData();
  };

  const handleTourDeleteCascading = async (tourName: string) => {
    if (!confirm(`Warning: Deleting "${tourName}" will permanently remove all associated bookings and expenses. Proceed?`)) return;
    setIsLoading(true);
    try {
      await Promise.all([
        supabase.from('tl_tours').delete().eq('name', tourName),
        supabase.from('tl_bookings').delete().eq('bus_no', tourName),
        supabase.from('tl_expenses').delete().eq('tour_name', tourName)
      ]);
      await fetchData();
    } catch (error) {
      alert("Cascading delete failed.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleMasterReset = async () => {
    if (!confirm("CRITICAL WARNING: Irreversible delete of ALL data. Proceed?")) return;
    setIsLoading(true);
    try {
      await Promise.all([
        supabase.from('tl_bookings').delete().neq('id', '___'),
        supabase.from('tl_expenses').delete().neq('id', '___'),
        supabase.from('tl_tours').delete().neq('name', '___'),
        supabase.from('tl_agents').delete().neq('code', '___'),
        supabase.from('tl_customer_types').delete().neq('type', '___')
      ]);
      await fetchData();
      alert("All data wiped.");
    } catch (error) {
      alert("Master reset failed.");
    } finally {
      setIsLoading(false);
    }
  };

  const seedDatabase = async () => {
    if (confirm("Seed database?")) {
      setIsLoading(true);
      await Promise.all([
        supabase.from('tl_tours').insert(TOURS),
        supabase.from('tl_agents').insert(BOOKERS),
        supabase.from('tl_customer_types').insert(CUSTOMER_TYPES)
      ]);
      await fetchData();
      setIsLoading(false);
    }
  };

  const handleSeatClick = (seatId: string) => {
    const bus = buses[selectedBusIndex];
    if (!bus) return;
    const seat = bus.seats.find(s => s.id === seatId);
    setSelectedSeatId(seatId);
    if (seat?.isBooked && seat.bookingInfo) {
      setEditingInfo(seat.bookingInfo);
      setShowDetailModal(true);
    } else {
      setShowBookingModal(true);
    }
  };

  const handleEditSeatRequest = (info: BookingInfo) => {
    setShowDetailModal(false);
    if (isAdminAuthenticated) {
      setEditingInfo(info);
      setSelectedSeatId(info.seatNo);
      setShowBookingModal(true);
    } else {
      setSecurityModal({ isOpen: true, targetInfo: info, action: 'edit' });
    }
  };

  const triggerCancelBooking = (busId: string, seatId: string) => {
    const bus = buses.find(b => b.busId === busId);
    const seat = bus?.seats.find(s => s.id === seatId);
    if (seat?.bookingInfo) {
      setShowDetailModal(false);
      if (isAdminAuthenticated) {
        setSeatToDeselect({ busId, seatId });
        setShowConfirmDeselect(true);
      } else {
        setSecurityModal({ isOpen: true, targetInfo: seat.bookingInfo, action: 'delete' });
      }
    }
  };

  const handleSecurityVerify = (code: string) => {
    if (!securityModal) return;
    if (code.toUpperCase() === securityModal.targetInfo.bookerCode.toUpperCase()) {
      const { action, targetInfo } = securityModal;
      setSecurityModal(null);
      if (action === 'edit') {
        setEditingInfo(targetInfo);
        setSelectedSeatId(targetInfo.seatNo);
        setShowBookingModal(true);
      } else if (action === 'delete') {
        setSeatToDeselect({ busId: targetInfo.busNo, seatId: targetInfo.seatNo });
        setShowConfirmDeselect(true);
      }
    } else {
      alert("Invalid Code!");
    }
  };

  const handleEntryLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (entryCodeInput === "@Rana&01625@") {
      setIsAdminAuthenticated(true);
      sessionStorage.setItem('tl_auth_admin', 'true');
      const adminAgent: Booker = { code: 'ADMIN', name: 'System Administrator' };
      setAuthenticatedAgent(adminAgent);
      sessionStorage.setItem('tl_auth_agent', JSON.stringify(adminAgent));
      setEntryCodeInput('');
      return;
    }
    const agent = bookers.find(b => b.code.toUpperCase() === entryCodeInput.toUpperCase());
    if (agent) {
      setAuthenticatedAgent(agent);
      sessionStorage.setItem('tl_auth_agent', JSON.stringify(agent));
      setIsAdminAuthenticated(false);
      sessionStorage.removeItem('tl_auth_admin');
      setEntryCodeInput('');
    } else {
      alert("Invalid Booker Code.");
    }
  };

  const handleAdminAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPasswordInput === "@Rana&01625@") {
      setIsAdminAuthenticated(true);
      sessionStorage.setItem('tl_auth_admin', 'true');
      setShowAdminLogin(false);
      setAdminPasswordInput('');
      setActiveTab('admin');
    } else {
      alert("Incorrect Password.");
    }
  };

  const handleLogout = () => {
    if (confirm("Sign out from session?")) {
      setAuthenticatedAgent(null);
      sessionStorage.removeItem('tl_auth_agent');
      setIsAdminAuthenticated(false);
      sessionStorage.removeItem('tl_auth_admin');
      setActiveTab('booking');
      setEntryCodeInput('');
      setAdminPasswordInput('');
    }
  };

  if (isLoading) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-[#001D4A] text-white">
        <img src={BUSINESS_INFO.logo} className="w-24 animate-pulse mb-8" />
        <div className="flex gap-2"><div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce"></div><div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div><div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div></div>
      </div>
    );
  }

  if (!authenticatedAgent) {
    return (
      <div className="min-h-screen w-full flex items-center justify-center bg-[#001D4A] p-6">
        <div className="w-full max-w-sm z-10 animate-in fade-in zoom-in duration-500">
           <div className="bg-white/5 backdrop-blur-3xl p-8 rounded-[40px] border border-white/10 shadow-2xl">
              <div className="flex flex-col items-center mb-10">
                <div className="bg-white p-5 rounded-3xl shadow-xl mb-6"><img src={BUSINESS_INFO.logo} alt="Logo" className="w-16" /></div>
                <h1 className="text-2xl font-black text-white tracking-tighter text-center uppercase">{BUSINESS_INFO.name}</h1>
                <p className="text-white/40 text-[9px] font-black uppercase tracking-[0.3em] mt-2">Booker Portal</p>
              </div>
              <form onSubmit={handleEntryLogin} className="space-y-4">
                 <input autoFocus type="password" placeholder="CODE" value={entryCodeInput} onChange={(e) => setEntryCodeInput(e.target.value)} className="w-full bg-white/10 border border-white/10 px-6 py-5 rounded-2xl text-white font-black text-xl tracking-widest uppercase placeholder:text-white/20 focus:outline-none focus:ring-2 focus:ring-orange-500 text-center" />
