        <button onClick={handleAdminClick} className={`flex-1 flex flex-col items-center justify-center gap-1 py-2 rounded-2xl mx-0.5 ${activeTab === 'admin' ? 'bg-orange-500 text-white shadow-lg' : 'text-white/30'}`}><i className="fas fa-user-shield text-lg"></i><span className="text-[7px] font-black uppercase tracking-tight">Admin</span></button>
