        </div>
      )}

      {activeSubTab === 'system' && (
        <div className="space-y-8 animate-in fade-in duration-300">
           <div className="bg-red-50 border-2 border-red-100 p-8 md:p-12 rounded-[48px] shadow-sm flex flex-col items-center text-center">
