const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'booking' | 'dashboard' | 'log' | 'edit' | 'admin' | 'expenses' | 'revenue'>('booking');
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(() => {
    return sessionStorage.getItem('tl_auth_admin') === 'true' || localStorage.getItem('tl_auth_admin') === 'true';
  });
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminPasswordInput, setAdminPasswordInput] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);

  const [authenticatedAgent, setAuthenticatedAgent] = useState<Booker | null>(() => {
    const savedSession = sessionStorage.getItem('tl_auth_agent');
    const savedLocal = localStorage.getItem('tl_auth_agent');
    const saved = savedSession || savedLocal;
    return saved ? JSON.parse(saved) : null;
  });
  const [entryCodeInput, setEntryCodeInput] = useState('');
  const [rememberMe, setRememberMe] = useState(false);

  const [selectedBusIndex, setSelectedBusIndex] = useState(0);
  const [selectedSeatId, setSelectedSeatId] = useState<string | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [showConfirmDeselect, setShowConfirmDeselect] = useState(false);
  const [editingInfo, setEditingInfo] = useState<BookingInfo | null>(null);
  const [seatToDeselect, setSeatToDeselect] = useState<{ busId: string, seatId: string } | null>(null);

  const [securityModal, setSecurityModal] = useState<{
    isOpen: boolean;
    targetInfo: BookingInfo;
    action: 'edit' | 'delete';
  } | null>(null);

  const [tours, setTours] = useState<Tour[]>([]);
  const [bookers, setBookers] = useState<Booker[]>([]);
  const [customerTypes, setCustomerTypes] = useState<CustomerType[]>([]);
  const [buses, setBuses] = useState<BusData[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);

  const fetchData = useCallback(async () => {
    try {
      const [toursRes, bookersRes, typesRes, bookingsRes, expensesRes] = await Promise.all([
        supabase.from('tl_tours').select('*').order('name'),
        supabase.from('tl_agents').select('*').order('name'),
        supabase.from('tl_customer_types').select('*').order('type'),
        supabase.from('tl_bookings').select('*'),
        supabase.from('tl_expenses').select('*').order('date', { ascending: false })
      ]);

      const fetchedTours = toursRes.data || [];
      const fetchedBookers = bookersRes.data || [];
      const fetchedTypes = typesRes.data || [];
      const fetchedBookings: any[] = bookingsRes.data || [];
      const fetchedExpenses: any[] = expensesRes.data || [];

      const mappedBookings: BookingInfo[] = fetchedBookings.map(b => ({
        id: b.id,
        name: b.name,
        mobile: b.mobile,
        address: b.address,
        gender: b.gender,
        religion: b.religion,
        tourName: b.tour_name,
        tourFees: b.tour_fees,
        customerType: b.customer_type,
        customerTypeFees: b.customer_type_fees,
        discountAmount: b.discount_amount,
        advanceAmount: b.advance_amount,
        dueAmount: b.due_amount,
        paymentStatus: b.payment_status,
        busNo: b.bus_no,
        seatNo: b.seat_no,
        bookedBy: b.booked_by,
        bookerCode: b.booker_code,
        bookingDate: b.booking_date
      }));

      setTours(fetchedTours);
      setBookers(fetchedBookers);
      setCustomerTypes(fetchedTypes);

      setExpenses(fetchedExpenses.map(e => ({
        id: e.id,
        category: e.category,
        amount: e.amount,
        description: e.description,
        date: e.date,
        recordedBy: e.recorded_by,
        agentCode: e.agent_code || 'ADMIN',
        tourName: e.tour_name
      })));

      const busLayouts = fetchedTours.map(t => {
        const seats = generateInitialSeats();
        mappedBookings.forEach(booking => {
          if (booking.busNo === t.name) {
            const seatIdx = seats.findIndex(s => s.id === booking.seatNo);
            if (seatIdx !== -1) {
              seats[seatIdx] = { ...seats[seatIdx], isBooked: true, bookingInfo: booking };
            }
          }
        });
        return { busId: t.name, seats };
      });
      setBuses(busLayouts);
    } catch (error) {
      console.error("Fetch Error:", error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
    const channel = supabase.channel('tl_realtime_v5')
      .on('postgres_changes', { event: '*', schema: 'public' }, () => {
        fetchData();
      })
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, [fetchData]);

  const handleBookingSubmit = async (info: BookingInfo) => {
    try {
      const { error } = await supabase.from('tl_bookings').upsert({
        id: info.id,
        name: info.name,
        mobile: info.mobile,
        address: info.address,
        gender: info.gender,
        religion: info.religion,
        tour_name: info.tourName,
        tour_fees: info.tourFees,
        customer_type: info.customerType,
        customer_type_fees: info.customerTypeFees,
        discount_amount: info.discountAmount,
        advance_amount: info.advanceAmount,
        due_amount: info.dueAmount,
        payment_status: info.paymentStatus,
        bus_no: info.busNo,
        seat_no: info.seatNo,
        booked_by: info.bookedBy,
        booker_code: info.bookerCode,
        booking_date: info.bookingDate
      });
      if (error) throw error;
      fetchData();
    } catch (error) {
      alert("Sync failed.");
    }
    setShowBookingModal(false);
    setShowDetailModal(false);
  };

  const handleExpenseSubmit = async (expense: Expense) => {
    try {
      const { error } = await supabase.from('tl_expenses').upsert({
        id: expense.id,
        category: expense.category,
        amount: expense.amount,
        description: expense.description,
        date: expense.date,
        recorded_by: expense.recordedBy,
        agent_code: expense.agentCode,
        tour_name: expense.tourName
      });
      if (error) throw error;
      fetchData();
    } catch (error) {
      alert("Expense sync failed.");
    }
  };

  const handleDeleteExpense = async (id: string) => {
    if (!confirm("Delete this expense permanently?")) return;
    try {
      await supabase.from('tl_expenses').delete().eq('id', id);
      fetchData();
    } catch (error) {
      alert("Delete failed.");
    }
  };

  const confirmDeselect = async () => {
    if (seatToDeselect) {
      const bus = buses.find(b => b.busId === seatToDeselect.busId);
      const seat = bus?.seats.find(s => s.id === seatToDeselect.seatId);
      if (seat?.bookingInfo) {
        try {
          await supabase.from('tl_bookings').delete().eq('id', seat.bookingInfo.id);
          fetchData();
        } catch (error) {
          alert("Cancel failed.");
        }
      }
    }
    setShowConfirmDeselect(false);
  };

  // Fix for: Cannot find name 'handleTourDeleteCascading'
  const handleTourDeleteCascading = async (tourName: string) => {
    if (!confirm(`Warning: This will delete tour "${tourName}" and all associated bookings and expenses. Continue?`)) return;
    try {
      await Promise.all([
        supabase.from('tl_bookings').delete().eq('tour_name', tourName),
        supabase.from('tl_expenses').delete().eq('tour_name', tourName),
        supabase.from('tl_tours').delete().eq('name', tourName)
      ]);
      fetchData();
    } catch (error) {
      console.error("Cascading delete error:", error);
      alert("Could not delete tour data.");
    }
  };

  // Fix for: Cannot find name 'handleMasterReset'
  const handleMasterReset = async () => {
    if (!confirm("DANGER: This will permanently wipe ALL business records. Are you absolutely sure?")) return;
    try {
      await Promise.all([
        supabase.from('tl_bookings').delete().neq('id', '_'),
        supabase.from('tl_expenses').delete().neq('id', '_'),
        supabase.from('tl_tours').delete().neq('name', '_'),
        supabase.from('tl_agents').delete().neq('code', '_'),
        supabase.from('tl_customer_types').delete().neq('type', '_')
      ]);
      fetchData();
      alert("System factory reset complete.");
    } catch (error) {
      console.error("Master reset error:", error);
      alert("Reset failed.");
    }
  };

  // Fix for: Cannot find name 'seedDatabase'
  const seedDatabase = async () => {
    if (!confirm("This will reset your tours and agents to default settings. Existing bookings might break. Continue?")) return;
    try {
      await Promise.all([
        supabase.from('tl_tours').delete().neq('name', '_'),
        supabase.from('tl_agents').delete().neq('code', '_'),
        supabase.from('tl_customer_types').delete().neq('type', '_')
      ]);
      await Promise.all([
        supabase.from('tl_tours').insert(TOURS),
        supabase.from('tl_agents').insert(BOOKERS),
        supabase.from('tl_customer_types').insert(CUSTOMER_TYPES)
      ]);
      fetchData();
      alert("Database seeded with defaults.");
    } catch (error) {
      console.error("Seeding error:", error);
      alert("Seeding failed.");
    }
  };

  const handleEntryLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (entryCodeInput === "@Rana&01625@") {
      setIsAdminAuthenticated(true);
      const adminAgent: Booker = { code: 'ADMIN', name: 'System Administrator' };
      setAuthenticatedAgent(adminAgent);

      const storage = rememberMe ? localStorage : sessionStorage;
      storage.setItem('tl_auth_admin', 'true');
      storage.setItem('tl_auth_agent', JSON.stringify(adminAgent));

      setEntryCodeInput('');
      return;
    }
    const agent = bookers.find(b => b.code.toUpperCase() === entryCodeInput.toUpperCase());
    if (agent) {
      setAuthenticatedAgent(agent);
      setIsAdminAuthenticated(false);

      const storage = rememberMe ? localStorage : sessionStorage;
      storage.setItem('tl_auth_agent', JSON.stringify(agent));

      setEntryCodeInput('');
    } else {
      alert("Invalid Booker Code.");
    }
  };

  const handleLogout = () => {
    setAuthenticatedAgent(null);
    sessionStorage.removeItem('tl_auth_agent');
    localStorage.removeItem('tl_auth_agent');
    setIsAdminAuthenticated(false);
    sessionStorage.removeItem('tl_auth_admin');
    localStorage.removeItem('tl_auth_admin');
    setActiveTab('booking');
    setEntryCodeInput('');
    setAdminPasswordInput('');
    setShowLogoutConfirm(false);
  };

  if (isLoading) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-[#001D4A] text-white">
        <img src={BUSINESS_INFO.logo} className="w-24 animate-pulse mb-8" />
        <div className="flex gap-2"><div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce"></div><div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div><div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div></div>
      </div>
    );
  }

  if (!authenticatedAgent) {
    return (
      <div className="min-h-screen w-full flex items-center justify-center bg-[#001D4A] p-6">
        <div className="w-full max-sm z-10 animate-in fade-in zoom-in duration-500">
           <div className="bg-white/5 backdrop-blur-3xl p-8 rounded-[40px] border border-white/10 shadow-2xl">
              <div className="flex flex-col items-center mb-10">
                <div className="bg-white p-5 rounded-3xl shadow-xl mb-6"><img src={BUSINESS_INFO.logo} alt="Logo" className="w-16" /></div>
                <h1 className="text-2xl font-black text-white tracking-tighter text-center uppercase">{BUSINESS_INFO.name}</h1>
                <p className="text-white/40 text-[9px] font-black uppercase tracking-[0.3em] mt-2 text-center">
                  {BUSINESS_INFO.address}
                </p>
              </div>
              <form onSubmit={handleEntryLogin} className="space-y-6">
                 <input autoFocus type="password" placeholder="CODE" value={entryCodeInput} onChange={(e) => setEntryCodeInput(e.target.value)} className="w-full bg-white/10 border border-white/10 px-6 py-5 rounded-2xl text-white font-black text-xl tracking-widest uppercase placeholder:text-white/20 focus:outline-none focus:ring-2 focus:ring-orange-500 text-center" />

                 <label className="flex items-center gap-3 cursor-pointer group px-4">
                    <input type="checkbox" checked={rememberMe} onChange={(e) => setRememberMe(e.target.checked)} className="w-5 h-5 rounded border-white/20 bg-white/10 text-orange-500 focus:ring-orange-500 cursor-pointer" />
                    <span className="text-[10px] font-black uppercase text-white/40 group-hover:text-white transition-colors">Remember Session</span>
                 </label>

                 <button type="submit" className="w-full py-5 bg-orange-500 text-white rounded-2xl font-black text-lg shadow-xl active:scale-95 transition-all">Unlock System</button>
              </form>
           </div>
        </div>
      </div>
    );
  }

  const navItems = [
    { id: 'dashboard', icon: 'fa-chart-line', label: 'Stats' },
    { id: 'booking', icon: 'fa-bus', label: 'Seats' },
    { id: 'revenue', icon: 'fa-sack-dollar', label: 'Cash' },
    { id: 'expenses', icon: 'fa-file-invoice-dollar', label: 'Cost' },
    { id: 'log', icon: 'fa-clipboard-list', label: 'Log' },
    { id: 'edit', icon: 'fa-user-pen', label: 'Edit' }
  ];

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row">
      <nav className="hidden md:flex fixed top-0 left-0 bottom-0 w-24 bg-[#001D4A] flex-col items-center justify-between py-8 shadow-2xl z-50">
        <div className="flex flex-col items-center w-full">
          <img src={BUSINESS_INFO.logo} alt="Logo" className="w-14 mb-12" />
          {navItems.map(item => (
            <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`w-full py-5 flex flex-col items-center transition-all ${activeTab === item.id ? 'bg-orange-500 text-white shadow-lg' : 'text-white/40 hover:text-white'}`}>
              <i className={`fas ${item.icon} text-xl mb-1`}></i>
              <span className="text-[9px] font-black uppercase">{item.label}</span>
            </button>
          ))}
        </div>
        <div className="flex flex-col items-center gap-6">
          <button onClick={() => isAdminAuthenticated ? setActiveTab('admin') : setShowAdminLogin(true)} className={`w-14 h-14 flex items-center justify-center rounded-2xl transition-all ${activeTab === 'admin' ? 'bg-orange-500 text-white' : 'bg-white/5 text-white/40'}`}><i className="fas fa-user-shield text-xl"></i></button>
          <button onClick={() => setShowLogoutConfirm(true)} className="w-14 h-14 flex items-center justify-center rounded-2xl bg-red-500/10 text-red-500"><i className="fas fa-power-off text-xl"></i></button>
        </div>
      </nav>

      <nav className="md:hidden fixed bottom-0 left-0 right-0 h-[75px] bg-[#001D4A]/95 backdrop-blur-md flex items-center justify-around z-[100] border-t border-white/10 shadow-[0_-10px_30px_rgba(0,0,0,0.3)] px-1 pb-safe">
        {navItems.map(item => (
          <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`flex-1 flex flex-col items-center justify-center gap-1 transition-all py-2 rounded-2xl mx-0.5 ${activeTab === item.id ? 'bg-orange-500 text-white shadow-lg' : 'text-white/30'}`}>
            <i className={`fas ${item.icon} text-lg`}></i>
            <span className="text-[7px] font-black uppercase tracking-tight">{item.label}</span>
          </button>
        ))}
        <button onClick={() => isAdminAuthenticated ? setActiveTab('admin') : setShowAdminLogin(true)} className={`flex-1 flex flex-col items-center justify-center gap-1 py-2 rounded-2xl mx-0.5 ${activeTab === 'admin' ? 'bg-orange-500 text-white shadow-lg' : 'text-white/30'}`}><i className="fas fa-user-shield text-lg"></i><span className="text-[7px] font-black uppercase tracking-tight">Admin</span></button>
      </nav>

      <main className="flex-grow md:ml-24 p-4 md:p-10 pb-24 md:pb-10">
        <header className="flex justify-between items-center mb-6 md:mb-10">
            <div className="flex items-center gap-3">
               <div className="md:hidden w-10 h-10 bg-white p-2 rounded-xl shadow-sm"><img src={BUSINESS_INFO.logo} className="w-full" /></div>
               <div>
                  <h2 className="text-xl md:text-3xl font-black text-[#001D4A] uppercase tracking-tighter leading-none">{activeTab === 'booking' ? 'Seat Plan' : activeTab.charAt(0).toUpperCase() + activeTab.slice(1)}</h2>
                  <div className="flex items-center gap-2 mt-1">
                    <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></div>
                    <p className="text-[8px] md:text-[10px] font-black text-gray-400 uppercase tracking-widest">Agent Active: {authenticatedAgent.name}</p>
                  </div>
               </div>
            </div>
            <button onClick={() => setShowLogoutConfirm(true)} className="md:hidden w-10 h-10 rounded-xl bg-red-50 text-red-500 flex items-center justify-center"><i className="fas fa-power-off"></i></button>
        </header>

        <div className="max-w-7xl mx-auto">
          {activeTab === 'booking' && (
            <div className="animate-in fade-in duration-500 space-y-6">
               {buses.length > 0 && (
                  <div className="bg-white p-4 rounded-3xl shadow-sm border border-gray-100 flex items-center gap-3 sticky top-0 z-40">
                    <i className="fas fa-route text-orange-500 ml-2"></i>
                    <select value={selectedBusIndex} onChange={(e) => setSelectedBusIndex(Number(e.target.value))} className="bg-transparent font-black text-[#001D4A] outline-none w-full text-xs uppercase tracking-widest cursor-pointer appearance-none">
                      {buses.map((bus, idx) => <option key={bus.busId} value={idx}>{bus.busId}</option>)}
                    </select>
                    <i className="fas fa-chevron-down text-[10px] text-gray-300 mr-2"></i>
                  </div>
               )}
               {buses.length > 0 ? (
                 <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
                    <div className="lg:col-span-7 flex justify-center w-full">
                       <BusLayout seats={buses[selectedBusIndex]?.seats || []} onSeatClick={(sid) => { setSelectedSeatId(sid); const s = buses[selectedBusIndex].seats.find(st => st.id === sid); if(s?.isBooked) { setEditingInfo(s.bookingInfo!); setShowDetailModal(true); } else setShowBookingModal(true); }} />
                    </div>
                    <div className="hidden lg:block lg:col-span-5 space-y-6">
                       <div className="bg-white rounded-[40px] p-8 shadow-sm border border-gray-100">
                         <h3 className="font-black text-[#001D4A] uppercase text-xs tracking-widest mb-6 border-b pb-4">Legend</h3>
                         <div className="space-y-4">
                           {[{c:'bg-green-500',l:'Vacant'}, {c:'bg-red-500',l:'Male (Muslim)'}, {c:'bg-pink-500',l:'Female (Muslim)'}, {c:'bg-blue-500',l:'Male (Others)'}, {c:'bg-yellow-500',l:'Female (Others)'}].map((item,i)=>(
                             <div key={i} className="flex items-center gap-4">
                               <div className={`${item.c} w-10 h-10 rounded-xl`}></div>
                               <p className="text-[10px] font-black text-gray-800 uppercase tracking-widest">{item.l}</p>
                             </div>
                           ))}
                         </div>
                       </div>
                    </div>
                 </div>
               ) : <div className="text-center py-20 bg-white rounded-[40px] border border-dashed border-gray-200"><p className="text-gray-400 font-black uppercase text-xs tracking-widest">No Active Routes</p></div>}
            </div>
          )}
          {activeTab === 'dashboard' && <Dashboard buses={buses} expenses={expenses} />}
          {activeTab === 'log' && <BookingLog buses={buses} bookers={bookers} />}
          {activeTab === 'expenses' && <ExpenseTracker expenses={expenses} onSubmit={handleExpenseSubmit} onDelete={handleDeleteExpense} bookers={bookers} initialAgentCode={authenticatedAgent?.code} tours={tours} />}
          {activeTab === 'revenue' && <RevenueReport buses={buses} expenses={expenses} tours={tours} />}
          {activeTab === 'edit' && <EditData buses={buses} onUpdate={handleBookingSubmit} onDelete={(bid, sid) => { setSeatToDeselect({busId:bid, seatId:sid}); setShowConfirmDeselect(true); }} onEdit={(info) => { setEditingInfo(info); setSelectedSeatId(info.seatNo); setShowBookingModal(true); }} bookers={bookers} />}
          {activeTab === 'admin' && isAdminAuthenticated && <AdminPanel tours={tours} setTours={async (t) => { await supabase.from('tl_tours').delete().neq('name','___'); if(t.length) await supabase.from('tl_tours').insert(t); fetchData(); }} agents={bookers} setAgents={async (a) => { await supabase.from('tl_agents').delete().neq('code','___'); if(a.length) await supabase.from('tl_agents').insert(a); fetchData(); }} customerTypes={customerTypes} setCustomerTypes={async (ct) => { await supabase.from('tl_customer_types').delete().neq('type','___'); if(ct.length) await supabase.from('tl_customer_types').insert(ct); fetchData(); }} buses={buses} onSeed={seedDatabase} onDeleteTourCascading={handleTourDeleteCascading} onMasterReset={handleMasterReset} />}
        </div>
      </main>

      {showLogoutConfirm && <ConfirmationDialog message="Are you sure you want to end your session?" onConfirm={handleLogout} onCancel={() => setShowLogoutConfirm(false)} />}
      {showConfirmDeselect && <ConfirmationDialog message="Confirm permanent cancellation?" onConfirm={confirmDeselect} onCancel={() => setShowConfirmDeselect(false)} />}

      {showAdminLogin && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 bg-[#001D4A]/90 backdrop-blur-xl">
           <div className="bg-white w-full max-w-sm rounded-[40px] p-8 animate-in zoom-in duration-300 shadow-2xl">
              <h3 className="text-xl font-black text-[#001D4A] mb-8 text-center uppercase tracking-widest">Master Auth</h3>
              <form onSubmit={(e) => { e.preventDefault(); if(adminPasswordInput === "@Rana&01625@") { setIsAdminAuthenticated(true); sessionStorage.setItem('tl_auth_admin','true'); setShowAdminLogin(false); setActiveTab('admin'); } else alert("Wrong Pass"); }} className="space-y-4">
                <input autoFocus type="password" placeholder="PASS" value={adminPasswordInput} onChange={(e) => setAdminPasswordInput(e.target.value)} className="w-full px-6 py-5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-500 text-center font-black text-xl tracking-widest outline-none" />
                <div className="flex gap-4">
                  <button type="button" onClick={() => setShowAdminLogin(false)} className="flex-1 py-4 text-gray-400 font-black text-xs uppercase tracking-widest">Close</button>
                  <button type="submit" className="flex-1 py-4 bg-orange-500 text-white rounded-2xl font-black shadow-lg uppercase tracking-widest">Unlock</button>
                </div>
              </form>
           </div>
        </div>
      )}

      {securityModal?.isOpen && <SecurityModal info={securityModal.targetInfo} action={securityModal.action} onClose={() => setSecurityModal(null)} onVerify={(c) => { if(c.toUpperCase() === securityModal.targetInfo.bookerCode.toUpperCase()) { if(securityModal.action === 'edit') { setEditingInfo(securityModal.targetInfo); setSelectedSeatId(securityModal.targetInfo.seatNo); setShowBookingModal(true); } else { setSeatToDeselect({busId:securityModal.targetInfo.busNo, seatId:securityModal.targetInfo.seatNo}); setShowConfirmDeselect(true); } setSecurityModal(null); } else alert("Invalid Code"); }} />}
      {showBookingModal && <BookingModal seatId={selectedSeatId!} busNo={editingInfo ? editingInfo.busNo : (buses[selectedBusIndex]?.busId || '')} onClose={() => { setShowBookingModal(false); setEditingInfo(null); }} onSubmit={handleBookingSubmit} tours={tours} bookers={bookers} customerTypes={customerTypes} existingData={editingInfo || undefined} />}
      {showDetailModal && editingInfo && <SeatDetailModal info={editingInfo} onClose={() => { setShowDetailModal(false); setEditingInfo(null); }} onEdit={() => { setShowDetailModal(false); setEditingInfo(editingInfo); setShowBookingModal(true); }} onCancel={() => { setShowDetailModal(false); setSeatToDeselect({busId:editingInfo.busNo, seatId:editingInfo.seatNo}); setShowConfirmDeselect(true); }} onUpdate={handleBookingSubmit} isAdmin={isAdminAuthenticated} />}
    </div>
  );
};

export default App;

export enum Gender {
  MALE = 'Male',
  FEMALE = 'Female',
  OTHERS = 'Others'
}

export enum Religion {
  MUSLIM = 'Muslim',
  HINDUISM = 'Hinduism',
  BUDDHISM = 'Buddhism',
  CHRISTIANITY = 'Christianity',
  OTHERS = 'Others'
}

export interface BookingInfo {
  id: string;
  name: string;
  mobile: string;
  address: string;
  gender: Gender;
  religion: Religion;
  tourName: string;
  tourFees: number;
  customerType?: string;
  customerTypeFees: number;
  discountAmount: number;
  advanceAmount: number;
  dueAmount: number;
  paymentStatus: 'Paid' | 'Partial' | 'Due';
  busNo: string;
  seatNo: string;
  bookedBy: string;
  bookerCode: string;
  bookingDate: string;
}

export interface SeatLock {
  id: string;
  bus_no: string;
  seat_no: string;
  agent_code: string;
  agent_name: string;
  expires_at: string;
}

export interface Expense {
  id: string;
  category: string;
  amount: number;
  description: string;
  date: string;
  recordedBy: string;
  agentCode: string;
  tourName?: string;
}

export interface SeatData {
  id: string;
  isBooked: boolean;
  bookingInfo?: BookingInfo;
  lockInfo?: SeatLock; // New: tracks if someone is currently filling the form
}

export interface BusData {
  busId: string;
  seats: SeatData[];
}

export interface Tour {
  name: string;
  fee: number;
}

export interface Booker {
  code: string;
  name: string;
  lastActive?: string;
}

export interface CustomerType {
  type: string;
  fee: number;
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { BUSINESS_INFO, generateInitialSeats, TOURS, BOOKERS, CUSTOMER_TYPES } from './constants';
import { BusData, BookingInfo, Tour, Booker, CustomerType, Expense, SeatLock } from './types';
import BusLayout from './components/BusLayout';
import BookingModal from './components/BookingModal';
import ConfirmationDialog from './components/ConfirmationDialog';
import Dashboard from './components/Dashboard';
import BookingLog from './components/BookingLog';
import EditData from './components/EditData';
import AdminPanel from './components/AdminPanel';
import SeatDetailModal from './components/SeatDetailModal';
import SecurityModal from './components/SecurityModal';
import ExpenseTracker from './components/ExpenseTracker';
import RevenueReport from './components/RevenueReport';
import { supabase } from './supabase';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'booking' | 'dashboard' | 'log' | 'edit' | 'admin' | 'expenses' | 'revenue'>('booking');
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(() => {
    return sessionStorage.getItem('tl_auth_admin') === 'true' || localStorage.getItem('tl_auth_admin') === 'true';
  });
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminPasswordInput, setAdminPasswordInput] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);

  const [authenticatedAgent, setAuthenticatedAgent] = useState<Booker | null>(() => {
    const savedSession = sessionStorage.getItem('tl_auth_agent');
    const savedLocal = localStorage.getItem('tl_auth_agent');
    const saved = savedSession || savedLocal;
    return saved ? JSON.parse(saved) : null;
  });
  const [entryCodeInput, setEntryCodeInput] = useState('');
  const [rememberMe, setRememberMe] = useState(false);

  const [selectedBusIndex, setSelectedBusIndex] = useState(0);
  const [selectedSeatId, setSelectedSeatId] = useState<string | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [showConfirmDeselect, setShowConfirmDeselect] = useState(false);
  const [editingInfo, setEditingInfo] = useState<BookingInfo | null>(null);
  const [seatToDeselect, setSeatToDeselect] = useState<{ busId: string, seatId: string } | null>(null);

  const [tours, setTours] = useState<Tour[]>([]);
  const [bookers, setBookers] = useState<Booker[]>([]);
  const [customerTypes, setCustomerTypes] = useState<CustomerType[]>([]);
  const [buses, setBuses] = useState<BusData[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [activeLocks, setActiveLocks] = useState<SeatLock[]>([]);
  const [onlineAgents, setOnlineAgents] = useState<Booker[]>([]);

  const fetchData = useCallback(async () => {
    try {
      const [toursRes, bookersRes, typesRes, bookingsRes, expensesRes, locksRes] = await Promise.all([
        supabase.from('tl_tours').select('*').order('name'),
        supabase.from('tl_agents').select('*').order('name'),
        supabase.from('tl_customer_types').select('*').order('type'),
        supabase.from('tl_bookings').select('*'),
        supabase.from('tl_expenses').select('*').order('date', { ascending: false }),
        supabase.from('tl_locks').select('*')
      ]);

      const fetchedTours = toursRes.data || [];
      const fetchedBookers = bookersRes.data || [];
      const fetchedTypes = typesRes.data || [];
      const fetchedBookings: any[] = bookingsRes.data || [];
      const fetchedExpenses: any[] = expensesRes.data || [];
      const fetchedLocks: any[] = locksRes.data || [];

      // Filter expired locks (Older than 5 mins)
      const now = new Date();
      const validLocks = fetchedLocks.filter(lock => new Date(lock.expires_at) > now);
      setActiveLocks(validLocks);

      // Heartbeat: Check online agents (Active in last 2 mins)
      const onlineCutoff = new Date(Date.now() - 2 * 60 * 1000);
      const activeAgents = fetchedBookers.filter(b => b.last_active && new Date(b.last_active) > onlineCutoff);
      setOnlineAgents(activeAgents);

      const mappedBookings: BookingInfo[] = fetchedBookings.map(b => ({
        id: b.id, name: b.name, mobile: b.mobile, address: b.address,
        gender: b.gender, religion: b.religion, tourName: b.tour_name,
        tourFees: b.tour_fees, customerType: b.customer_type,
        customerTypeFees: b.customer_type_fees, discountAmount: b.discount_amount,
        advanceAmount: b.advance_amount, dueAmount: b.due_amount,
        paymentStatus: b.payment_status, busNo: b.bus_no, seatNo: b.seat_no,
        bookedBy: b.booked_by, bookerCode: b.booker_code, bookingDate: b.booking_date
      }));

      setTours(fetchedTours);
      setBookers(fetchedBookers);
      setCustomerTypes(fetchedTypes);
      setExpenses(fetchedExpenses.map(e => ({
        id: e.id, category: e.category, amount: e.amount, description: e.description,
        date: e.date, recordedBy: e.recorded_by, agentCode: e.agent_code || 'ADMIN', tourName: e.tour_name
      })));

      const busLayouts = fetchedTours.map(t => {
        const seats = generateInitialSeats();
        mappedBookings.forEach(booking => {
          if (booking.busNo === t.name) {
            const seatIdx = seats.findIndex(s => s.id === booking.seatNo);
            if (seatIdx !== -1) seats[seatIdx] = { ...seats[seatIdx], isBooked: true, bookingInfo: booking };
          }
        });
        // Apply Locks
        validLocks.forEach(lock => {
          if (lock.bus_no === t.name) {
            const seatIdx = seats.findIndex(s => s.id === lock.seat_no);
            if (seatIdx !== -1 && !seats[seatIdx].isBooked) {
              seats[seatIdx] = { ...seats[seatIdx], lockInfo: lock };
            }
          }
        });
        return { busId: t.name, seats };
      });
      setBuses(busLayouts);
    } catch (error) {
      console.error("Fetch Error:", error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  // Sync effect
  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 10000); // 10s refresh for locks/presence
    const channel = supabase.channel('tl_realtime_v6')
      .on('postgres_changes', { event: '*', schema: 'public' }, () => fetchData())
      .subscribe();
    return () => { 
      clearInterval(interval);
      supabase.removeChannel(channel); 
    };
  }, [fetchData]);

  // Heartbeat for online status
  useEffect(() => {
    if (!authenticatedAgent) return;
    const heartbeat = setInterval(async () => {
      await supabase.from('tl_agents').update({ last_active: new Date().toISOString() }).eq('code', authenticatedAgent.code);
    }, 30000); // Every 30s
    return () => clearInterval(heartbeat);
  }, [authenticatedAgent]);

  const handleSeatClick = async (sid: string) => {
    const currentBus = buses[selectedBusIndex];
    const seat = currentBus.seats.find(s => s.id === sid);

    if (seat?.isBooked) {
      setEditingInfo(seat.bookingInfo!);
      setShowDetailModal(true);
      return;
    }

    if (seat?.lockInfo) {
      if (seat.lockInfo.agent_code === authenticatedAgent?.code) {
        setSelectedSeatId(sid);
        setShowBookingModal(true);
      } else {
        alert(`This seat is currently being held by ${seat.lockInfo.agent_name}. Please wait 5 minutes.`);
      }
      return;
    }

    // Try to lock
    const expiresAt = new Date(Date.now() + 5 * 60 * 1000).toISOString();
    try {
      const { error } = await supabase.from('tl_locks').insert({
        bus_no: currentBus.busId,
        seat_no: sid,
        agent_code: authenticatedAgent?.code,
        agent_name: authenticatedAgent?.name,
        expires_at: expiresAt
      });

      if (error) {
        alert("Someone else just clicked this seat! Refreshing...");
        fetchData();
        return;
      }

      setSelectedSeatId(sid);
      setShowBookingModal(true);
    } catch (e) {
      alert("Lock failed.");
    }
  };

  const releaseLock = async (busNo: string, seatId: string) => {
    await supabase.from('tl_locks').delete().eq('bus_no', busNo).eq('seat_no', seatId).eq('agent_code', authenticatedAgent?.code);
    fetchData();
  };

  const handleBookingSubmit = async (info: BookingInfo) => {
    try {
      const { error } = await supabase.from('tl_bookings').upsert({
        id: info.id, name: info.name, mobile: info.mobile, address: info.address,
        gender: info.gender, religion: info.religion, tour_name: info.tourName,
        tour_fees: info.tourFees, customer_type: info.customerType,
        customer_type_fees: info.customerTypeFees, discount_amount: info.discountAmount,
        advance_amount: info.advanceAmount, due_amount: info.dueAmount,
        payment_status: info.paymentStatus, bus_no: info.busNo, seat_no: info.seatNo,
        booked_by: info.bookedBy, booker_code: info.bookerCode, booking_date: info.bookingDate
      });
      if (error) throw error;
      // Clear lock on success
      await releaseLock(info.busNo, info.seatNo);
      fetchData();
    } catch (error) {
      alert("Sync failed.");
    }
    setShowBookingModal(false);
    setShowDetailModal(false);
  };

  const handleEntryLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (entryCodeInput === "@Rana&01625@") {
      const adminAgent: Booker = { code: 'ADMIN', name: 'System Administrator' };
      setAuthenticatedAgent(adminAgent);
      setIsAdminAuthenticated(true);
      const storage = rememberMe ? localStorage : sessionStorage;
      storage.setItem('tl_auth_admin', 'true');
      storage.setItem('tl_auth_agent', JSON.stringify(adminAgent));
      setEntryCodeInput('');
      return;
    }
    const agent = bookers.find(b => b.code.toUpperCase() === entryCodeInput.toUpperCase());
    if (agent) {
      setAuthenticatedAgent(agent);
      setIsAdminAuthenticated(false);
      const storage = rememberMe ? localStorage : sessionStorage;
      storage.setItem('tl_auth_agent', JSON.stringify(agent));
      setEntryCodeInput('');
    } else {
      alert("Invalid Booker Code.");
    }
  };

  if (isLoading) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-[#001D4A] text-white">
        <img src={BUSINESS_INFO.logo} className="w-24 animate-pulse mb-8" />
        <div className="flex gap-2"><div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce"></div><div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div><div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div></div>
      </div>
    );
  }

  if (!authenticatedAgent) {
    return (
      <div className="min-h-screen w-full flex items-center justify-center bg-[#001D4A] p-6">
        <div className="w-full max-sm z-10 animate-in fade-in zoom-in duration-500">
           <div className="bg-white/5 backdrop-blur-3xl p-8 rounded-[40px] border border-white/10 shadow-2xl">
              <div className="flex flex-col items-center mb-10">
                <div className="bg-white p-5 rounded-3xl shadow-xl mb-6"><img src={BUSINESS_INFO.logo} alt="Logo" className="w-16" /></div>
                <h1 className="text-2xl font-black text-white tracking-tighter text-center uppercase">{BUSINESS_INFO.name}</h1>
                <p className="text-white/40 text-[9px] font-black uppercase tracking-[0.3em] mt-2 text-center">{BUSINESS_INFO.address}</p>
              </div>
              <form onSubmit={handleEntryLogin} className="space-y-6">
                 <input autoFocus type="password" placeholder="CODE" value={entryCodeInput} onChange={(e) => setEntryCodeInput(e.target.value)} className="w-full bg-white/10 border border-white/10 px-6 py-5 rounded-2xl text-white font-black text-xl tracking-widest uppercase placeholder:text-white/20 focus:outline-none focus:ring-2 focus:ring-orange-500 text-center" />
                 <label className="flex items-center gap-3 cursor-pointer group px-4">
                    <input type="checkbox" checked={rememberMe} onChange={(e) => setRememberMe(e.target.checked)} className="w-5 h-5 rounded border-white/20 bg-white/10 text-orange-500 focus:ring-orange-500 cursor-pointer" />
                    <span className="text-[10px] font-black uppercase text-white/40 group-hover:text-white transition-colors">Remember Session</span>
                 </label>
                 <button type="submit" className="w-full py-5 bg-orange-500 text-white rounded-2xl font-black text-lg shadow-xl active:scale-95 transition-all">Unlock System</button>
              </form>
           </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row">
      {/* Sidebar - same as before */}
      <nav className="hidden md:flex fixed top-0 left-0 bottom-0 w-24 bg-[#001D4A] flex-col items-center justify-between py-8 shadow-2xl z-50">
        <div className="flex flex-col items-center w-full">
          <img src={BUSINESS_INFO.logo} alt="Logo" className="w-14 mb-12" />
          {[
            { id: 'dashboard', icon: 'fa-chart-line', label: 'Stats' },
            { id: 'booking', icon: 'fa-bus', label: 'Seats' },
            { id: 'revenue', icon: 'fa-sack-dollar', label: 'Cash' },
            { id: 'expenses', icon: 'fa-file-invoice-dollar', label: 'Cost' },
            { id: 'log', icon: 'fa-clipboard-list', label: 'Log' },
            { id: 'edit', icon: 'fa-user-pen', label: 'Edit' }
          ].map(item => (
            <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`w-full py-5 flex flex-col items-center transition-all ${activeTab === item.id ? 'bg-orange-500 text-white shadow-lg' : 'text-white/40 hover:text-white'}`}>
              <i className={`fas ${item.icon} text-xl mb-1`}></i>
              <span className="text-[9px] font-black uppercase">{item.label}</span>
            </button>
          ))}
        </div>
        <div className="flex flex-col items-center gap-6">
          <button onClick={() => isAdminAuthenticated ? setActiveTab('admin') : setShowAdminLogin(true)} className={`w-14 h-14 flex items-center justify-center rounded-2xl transition-all ${activeTab === 'admin' ? 'bg-orange-500 text-white' : 'bg-white/5 text-white/40'}`}><i className="fas fa-user-shield text-xl"></i></button>
          <button onClick={() => setShowLogoutConfirm(true)} className="w-14 h-14 flex items-center justify-center rounded-2xl bg-red-500/10 text-red-500"><i className="fas fa-power-off text-xl"></i></button>
        </div>
      </nav>

      {/* Mobile Nav - same as before */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 h-[75px] bg-[#001D4A]/95 backdrop-blur-md flex items-center justify-around z-[100] border-t border-white/10 shadow-[0_-10px_30px_rgba(0,0,0,0.3)] px-1 pb-safe">
        {[
          { id: 'dashboard', icon: 'fa-chart-line', label: 'Stats' },
          { id: 'booking', icon: 'fa-bus', label: 'Seats' },
          { id: 'revenue', icon: 'fa-sack-dollar', label: 'Cash' },
          { id: 'expenses', icon: 'fa-file-invoice-dollar', label: 'Cost' },
          { id: 'log', icon: 'fa-clipboard-list', label: 'Log' },
          { id: 'edit', icon: 'fa-user-pen', label: 'Edit' }
        ].map(item => (
          <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`flex-1 flex flex-col items-center justify-center gap-1 transition-all py-2 rounded-2xl mx-0.5 ${activeTab === item.id ? 'bg-orange-500 text-white shadow-lg' : 'text-white/30'}`}>
            <i className={`fas ${item.icon} text-lg`}></i>
            <span className="text-[7px] font-black uppercase tracking-tight">{item.label}</span>
          </button>
        ))}
        <button onClick={() => isAdminAuthenticated ? setActiveTab('admin') : setShowAdminLogin(true)} className={`flex-1 flex flex-col items-center justify-center gap-1 py-2 rounded-2xl mx-0.5 ${activeTab === 'admin' ? 'bg-orange-500 text-white shadow-lg' : 'text-white/30'}`}><i className="fas fa-user-shield text-lg"></i><span className="text-[7px] font-black uppercase tracking-tight">Admin</span></button>
      </nav>

      <main className="flex-grow md:ml-24 p-4 md:p-10 pb-24 md:pb-10">
        <header className="flex justify-between items-center mb-6 md:mb-10">
            <div className="flex items-center gap-3">
               <div className="md:hidden w-10 h-10 bg-white p-2 rounded-xl shadow-sm"><img src={BUSINESS_INFO.logo} className="w-full" /></div>
               <div>
                  <h2 className="text-xl md:text-3xl font-black text-[#001D4A] uppercase tracking-tighter leading-none">{activeTab === 'booking' ? 'Seat Plan' : activeTab.charAt(0).toUpperCase() + activeTab.slice(1)}</h2>
                  <div className="flex items-center gap-2 mt-1">
                    <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></div>
                    <p className="text-[8px] md:text-[10px] font-black text-gray-400 uppercase tracking-widest">Active Now: {onlineAgents.length} Agent(s)</p>
                  </div>
               </div>
            </div>
            <button onClick={() => setShowLogoutConfirm(true)} className="md:hidden w-10 h-10 rounded-xl bg-red-50 text-red-500 flex items-center justify-center"><i className="fas fa-power-off"></i></button>
        </header>

        <div className="max-w-7xl mx-auto">
          {activeTab === 'booking' && (
            <div className="animate-in fade-in duration-500 space-y-6">
               <div className="bg-white p-4 rounded-3xl shadow-sm border border-gray-100 flex items-center gap-3 sticky top-0 z-40 overflow-x-auto no-scrollbar">
                  <div className="flex items-center gap-1.5 shrink-0 px-2 border-r">
                    <span className="text-[9px] font-black text-gray-400 uppercase tracking-widest mr-2">Online:</span>
                    {onlineAgents.map(a => (
                      <div key={a.code} className="bg-green-50 text-green-700 text-[8px] font-black px-2 py-1 rounded-lg uppercase whitespace-nowrap">{a.name.split(' ')[0]}</div>
                    ))}
                  </div>
                  <select value={selectedBusIndex} onChange={(e) => setSelectedBusIndex(Number(e.target.value))} className="bg-transparent font-black text-[#001D4A] outline-none text-xs uppercase tracking-widest cursor-pointer appearance-none px-4">
                    {buses.map((bus, idx) => <option key={bus.busId} value={idx}>{bus.busId}</option>)}
                  </select>
               </div>
               {buses.length > 0 ? (
                 <div className="flex justify-center w-full">
                    <BusLayout seats={buses[selectedBusIndex]?.seats || []} onSeatClick={handleSeatClick} />
                 </div>
               ) : <div className="text-center py-20 bg-white rounded-[40px] border border-dashed border-gray-200"><p className="text-gray-400 font-black uppercase text-xs tracking-widest">No Active Routes</p></div>}
            </div>
          )}
          {activeTab === 'dashboard' && <Dashboard buses={buses} expenses={expenses} />}
          {activeTab === 'log' && <BookingLog buses={buses} bookers={bookers} />}
          {activeTab === 'expenses' && <ExpenseTracker expenses={expenses} onSubmit={(ex) => { fetchData(); }} onDelete={(id) => { fetchData(); }} bookers={bookers} initialAgentCode={authenticatedAgent?.code} tours={tours} />}
          {activeTab === 'revenue' && <RevenueReport buses={buses} expenses={expenses} tours={tours} />}
          {activeTab === 'edit' && <EditData buses={buses} onUpdate={handleBookingSubmit} onDelete={() => {}} onEdit={(info) => { setEditingInfo(info); setSelectedSeatId(info.seatNo); setShowBookingModal(true); }} bookers={bookers} />}
          {activeTab === 'admin' && isAdminAuthenticated && <AdminPanel tours={tours} setTours={() => {}} agents={bookers} setAgents={() => {}} customerTypes={customerTypes} setCustomerTypes={() => {}} buses={buses} onDeleteTourCascading={() => {}} onMasterReset={() => {}} />}
        </div>
      </main>

      {showLogoutConfirm && <ConfirmationDialog message="Are you sure you want to end your session?" onConfirm={() => { setAuthenticatedAgent(null); setShowLogoutConfirm(false); }} onCancel={() => setShowLogoutConfirm(false)} />}
      {showBookingModal && <BookingModal seatId={selectedSeatId!} busNo={editingInfo ? editingInfo.busNo : (buses[selectedBusIndex]?.busId || '')} onClose={() => { releaseLock(buses[selectedBusIndex].busId, selectedSeatId!); setShowBookingModal(false); setEditingInfo(null); }} onSubmit={handleBookingSubmit} tours={tours} bookers={bookers} customerTypes={customerTypes} existingData={editingInfo || undefined} />}
      {showDetailModal && editingInfo && <SeatDetailModal info={editingInfo} onClose={() => { setShowDetailModal(false); setEditingInfo(null); }} onEdit={() => { setShowDetailModal(false); setShowBookingModal(true); }} onCancel={() => { setShowDetailModal(false); setShowConfirmDeselect(true); }} isAdmin={isAdminAuthenticated} />}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { SeatData, Gender, Religion } from '../types';

interface SeatProps {
  data: SeatData;
  onClick: () => void;
}

const Seat: React.FC<SeatProps> = ({ data, onClick }) => {
  const [isHovered, setIsHovered] = useState(false);

  const getSeatColor = () => {
    if (data.lockInfo) return 'bg-gray-400 hover:bg-gray-500 shadow-gray-200 animate-pulse'; // Pending Gray
    if (!data.isBooked) return 'bg-green-500 hover:bg-green-600 shadow-green-200';

    const info = data.bookingInfo!;
    const isFemale = info.gender === Gender.FEMALE;
    const isMuslim = info.religion === Religion.MUSLIM;

    if (isFemale && !isMuslim) return 'bg-yellow-500 hover:bg-yellow-600 shadow-yellow-200';
    if (isFemale) return 'bg-pink-500 hover:bg-pink-600 shadow-pink-200';
    if (!isMuslim) return 'bg-blue-500 hover:bg-blue-600 shadow-blue-200';

    return 'bg-red-500 hover:bg-red-600 shadow-red-200';
  };

  const info = data.bookingInfo;
  const lock = data.lockInfo;

  return (
    <div 
      className="relative"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      onTouchStart={() => setIsHovered(true)}
      onTouchEnd={() => setTimeout(() => setIsHovered(false), 3000)}
    >
      <button
        onClick={(e) => { e.stopPropagation(); onClick(); }}
        className={`${getSeatColor()} w-11 h-11 md:w-14 md:h-14 rounded-[12px] md:rounded-2xl flex items-center justify-center text-white text-[11px] md:text-[13px] font-black transition-all shadow-md md:shadow-lg transform active:scale-90`}
      >
        {data.id}
      </button>

      {/* Held by Tooltip for Pending Seats */}
      {isHovered && lock && !data.isBooked && (
        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 z-[200] w-32 bg-gray-900 text-white p-3 rounded-xl text-center shadow-xl animate-in zoom-in duration-200">
          <p className="text-[8px] font-black uppercase text-gray-400 tracking-widest mb-1">Held By</p>
          <p className="text-[10px] font-black truncate">{lock.agent_name}</p>
          <div className="w-full bg-gray-700 h-1 rounded-full mt-2 overflow-hidden">
             <div className="bg-orange-500 h-full animate-[progress_300s_linear]" style={{width: '100%'}}></div>
          </div>
        </div>
      )}

      {/* Booking Tooltip - same as before */}
      {isHovered && data.isBooked && info && (
        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-4 z-[150] w-64 md:w-72 bg-white text-gray-800 p-0 rounded-2xl md:rounded-[28px] shadow-2xl border border-gray-100 animate-in fade-in slide-in-from-bottom-2 duration-200 overflow-hidden pointer-events-none">
          <div className="bg-[#001D4A] p-3 md:p-4 flex justify-between items-center">
             <div className="flex flex-col">
               <span className="text-white font-black text-[10px] md:text-xs">Seat {data.id}</span>
               <span className="text-orange-400 text-[8px] font-bold uppercase tracking-tighter">{info.tourName}</span>
             </div>
             <span className={`px-2 py-0.5 rounded-full text-[8px] md:text-[9px] font-black uppercase ${info.paymentStatus === 'Paid' ? 'bg-green-500 text-white' : 'bg-orange-500 text-white'}`}>
              {info.paymentStatus}
            </span>
          </div>
          <div className="p-4 md:p-5 space-y-3">
            <p className="text-sm font-black text-[#001D4A] leading-tight">{info.name}</p>
            <div className="bg-red-50 p-2 rounded-xl flex justify-between items-center border border-red-100">
               <span className="text-[9px] font-black text-red-400 uppercase">Due</span>
               <span className="text-base font-black text-red-600">৳{info.dueAmount.toLocaleString()}</span>
            </div>
            <div className="flex justify-between items-center pt-2 border-t border-gray-50">
              <span className="text-[9px] text-indigo-600 font-black uppercase truncate max-w-[120px]">{info.bookedBy}</span>
              <span className="text-[8px] font-black text-white bg-indigo-500 px-2 py-0.5 rounded uppercase tracking-tighter">ID: {info.bookerCode}</span>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Seat;

export enum Gender {
  MALE = 'Male',
  FEMALE = 'Female',
  OTHERS = 'Others'
}

export enum Religion {
  MUSLIM = 'Muslim',
  HINDUISM = 'Hinduism',
  BUDDHISM = 'Buddhism',
  CHRISTIANITY = 'Christianity',
  OTHERS = 'Others'
}

export interface BookingInfo {
  id: string;
  name: string;
  mobile: string;
  address: string;
  gender: Gender;
  religion: Religion;
  tourName: string;
  tourFees: number;
  customerType?: string;
  customerTypeFees: number;
  discountAmount: number;
  advanceAmount: number;
  dueAmount: number;
  paymentStatus: 'Paid' | 'Partial' | 'Due';
  busNo: string;
  seatNo: string;
  bookedBy: string;
  bookerCode: string;
  bookingDate: string;
}

export interface SeatLock {
  id?: string;
  bus_no: string;
  seat_no: string;
  agent_code: string;
  agent_name: string;
  expires_at: string;
}

export interface Expense {
  id: string;
  category: string;
  amount: number;
  description: string;
  date: string;
  recordedBy: string;
  agentCode: string;
  tourName?: string;
}

export interface SeatData {
  id: string;
  isBooked: boolean;
  bookingInfo?: BookingInfo;
  lockInfo?: SeatLock;
}

export interface BusData {
  busId: string;
  seats: SeatData[];
}

export interface Tour {
  name: string;
  fee: number;
}

export interface Booker {
  code: string;
  name: string;
  last_active?: string;
}

export interface CustomerType {
  type: string;
  fee: number;
}

import React, { useState, useEffect, useCallback } from 'react';
import { BUSINESS_INFO, generateInitialSeats, TOURS, BOOKERS, CUSTOMER_TYPES } from './constants';
import { BusData, BookingInfo, Tour, Booker, CustomerType, Expense, SeatLock } from './types';
import BusLayout from './components/BusLayout';
import BookingModal from './components/BookingModal';
import ConfirmationDialog from './components/ConfirmationDialog';
import Dashboard from './components/Dashboard';
import BookingLog from './components/BookingLog';
import EditData from './components/EditData';
import AdminPanel from './components/AdminPanel';
import SeatDetailModal from './components/SeatDetailModal';
import SecurityModal from './components/SecurityModal';
import ExpenseTracker from './components/ExpenseTracker';
import RevenueReport from './components/RevenueReport';
import { supabase } from './supabase';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'booking' | 'dashboard' | 'log' | 'edit' | 'admin' | 'expenses' | 'revenue'>('booking');
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(() => {
    return sessionStorage.getItem('tl_auth_admin') === 'true' || localStorage.getItem('tl_auth_admin') === 'true';
  });
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminPasswordInput, setAdminPasswordInput] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);

  const [authenticatedAgent, setAuthenticatedAgent] = useState<Booker | null>(() => {
    const savedSession = sessionStorage.getItem('tl_auth_agent');
    const savedLocal = localStorage.getItem('tl_auth_agent');
    const saved = savedSession || savedLocal;
    return saved ? JSON.parse(saved) : null;
  });
  const [entryCodeInput, setEntryCodeInput] = useState('');
  const [rememberMe, setRememberMe] = useState(false);

  const [selectedBusIndex, setSelectedBusIndex] = useState(0);
  const [selectedSeatId, setSelectedSeatId] = useState<string | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [showConfirmDeselect, setShowConfirmDeselect] = useState(false);
  const [editingInfo, setEditingInfo] = useState<BookingInfo | null>(null);
  const [seatToDeselect, setSeatToDeselect] = useState<{ busId: string, seatId: string } | null>(null);

  const [tours, setTours] = useState<Tour[]>([]);
  const [bookers, setBookers] = useState<Booker[]>([]);
  const [customerTypes, setCustomerTypes] = useState<CustomerType[]>([]);
  const [buses, setBuses] = useState<BusData[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [onlineAgents, setOnlineAgents] = useState<Booker[]>([]);

  const fetchData = useCallback(async () => {
    try {
      const [toursRes, bookersRes, typesRes, bookingsRes, expensesRes, locksRes] = await Promise.all([
        supabase.from('tl_tours').select('*').order('name'),
        supabase.from('tl_agents').select('*').order('name'),
        supabase.from('tl_customer_types').select('*').order('type'),
        supabase.from('tl_bookings').select('*'),
        supabase.from('tl_expenses').select('*').order('date', { ascending: false }),
        supabase.from('tl_locks').select('*')
      ]);

      const fetchedTours = toursRes.data || [];
      const fetchedBookers = bookersRes.data || [];
      const fetchedTypes = typesRes.data || [];
      const fetchedBookings: any[] = bookingsRes.data || [];
      const fetchedLocks: any[] = locksRes.data || [];

      // Filter expired locks (Older than 5 mins)
      const now = new Date();
      const validLocks: SeatLock[] = fetchedLocks.filter(lock => new Date(lock.expires_at) > now);

      // online cut-off (2 mins)
      const onlineCutoff = new Date(Date.now() - 2 * 60 * 1000);
      const activeAgents = fetchedBookers.filter(b => b.last_active && new Date(b.last_active) > onlineCutoff);
      setOnlineAgents(activeAgents);

      const mappedBookings: BookingInfo[] = fetchedBookings.map(b => ({
        id: b.id, name: b.name, mobile: b.mobile, address: b.address,
        gender: b.gender, religion: b.religion, tourName: b.tour_name,
        tourFees: b.tour_fees, customerType: b.customer_type,
        customerTypeFees: b.customer_type_fees, discountAmount: b.discount_amount,
        advanceAmount: b.advance_amount, dueAmount: b.due_amount,
        paymentStatus: b.payment_status, busNo: b.bus_no, seat_no: b.seat_no,
        bookedBy: b.booked_by, bookerCode: b.booker_code, bookingDate: b.booking_date
      }));

      setTours(fetchedTours);
      setBookers(fetchedBookers);
      setCustomerTypes(fetchedTypes);

      const busLayouts = fetchedTours.map(t => {
        const seats = generateInitialSeats();
        mappedBookings.forEach(booking => {
          if (booking.busNo === t.name) {
            const seatIdx = seats.findIndex(s => s.id === booking.seatNo);
            if (seatIdx !== -1) seats[seatIdx] = { ...seats[seatIdx], isBooked: true, bookingInfo: booking };
          }
        });
        // Apply Locks
        validLocks.forEach(lock => {
          if (lock.bus_no === t.name) {
            const seatIdx = seats.findIndex(s => s.id === lock.seat_no);
            if (seatIdx !== -1 && !seats[seatIdx].isBooked) {
              seats[seatIdx] = { ...seats[seatIdx], lockInfo: lock };
            }
          }
        });
        return { busId: t.name, seats };
      });
      setBuses(busLayouts);
    } catch (error) {
      console.error("Fetch Error:", error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 10000); // 10s auto-refresh for locks
    const channel = supabase.channel('tl_realtime_v7')
      .on('postgres_changes', { event: '*', schema: 'public' }, () => fetchData())
      .subscribe();
    return () => { 
      clearInterval(interval);
      supabase.removeChannel(channel); 
    };
  }, [fetchData]);

  // Heartbeat to signal we are online
  useEffect(() => {
    if (!authenticatedAgent) return;
    const updatePresence = async () => {
      await supabase.from('tl_agents').update({ last_active: new Date().toISOString() }).eq('code', authenticatedAgent.code);
    };
    updatePresence();
    const heartbeat = setInterval(updatePresence, 30000);
    return () => clearInterval(heartbeat);
  }, [authenticatedAgent]);

  const handleSeatClick = async (sid: string) => {
    const currentBus = buses[selectedBusIndex];
    const seat = currentBus.seats.find(s => s.id === sid);

    if (seat?.isBooked) {
      setEditingInfo(seat.bookingInfo!);
      setShowDetailModal(true);
      return;
    }

    if (seat?.lockInfo) {
      if (seat.lockInfo.agent_code === authenticatedAgent?.code) {
        setSelectedSeatId(sid);
        setShowBookingModal(true);
      } else {
        alert(`Hold by ${seat.lockInfo.agent_name}. Try again later.`);
      }
      return;
    }

    // Attempt to lock
    const expiresAt = new Date(Date.now() + 5 * 60 * 1000).toISOString();
    try {
      const { error } = await supabase.from('tl_locks').insert({
        bus_no: currentBus.busId,
        seat_no: sid,
        agent_code: authenticatedAgent?.code,
        agent_name: authenticatedAgent?.name,
        expires_at: expiresAt
      });

      if (error) {
        alert("Seat just taken! Refreshing...");
        fetchData();
        return;
      }

      setSelectedSeatId(sid);
      setShowBookingModal(true);
    } catch (e) {
      alert("Failed to lock seat.");
    }
  };

  const releaseLock = async (busNo: string, seatId: string) => {
    if (!authenticatedAgent) return;
    await supabase.from('tl_locks').delete().eq('bus_no', busNo).eq('seat_no', seatId).eq('agent_code', authenticatedAgent.code);
    fetchData();
  };

  const handleBookingSubmit = async (info: BookingInfo) => {
    try {
      const { error } = await supabase.from('tl_bookings').upsert({
        id: info.id, name: info.name, mobile: info.mobile, address: info.address,
        gender: info.gender, religion: info.religion, tour_name: info.tourName,
        tour_fees: info.tourFees, customer_type: info.customerType,
        customer_type_fees: info.customerTypeFees, discount_amount: info.discountAmount,
        advance_amount: info.advanceAmount, due_amount: info.dueAmount,
        payment_status: info.paymentStatus, bus_no: info.busNo, seat_no: info.seatNo,
        booked_by: info.bookedBy, booker_code: info.bookerCode, booking_date: info.bookingDate
      });
      if (error) throw error;
      await releaseLock(info.busNo, info.seatNo);
      fetchData();
    } catch (error) {
      alert("Sync failed.");
    }
    setShowBookingModal(false);
    setShowDetailModal(false);
  };

  const handleEntryLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (entryCodeInput === "@Rana&01625@") {
      const adminAgent: Booker = { code: 'ADMIN', name: 'System Administrator' };
      setAuthenticatedAgent(adminAgent);
      setIsAdminAuthenticated(true);
      const storage = rememberMe ? localStorage : sessionStorage;
      storage.setItem('tl_auth_admin', 'true');
      storage.setItem('tl_auth_agent', JSON.stringify(adminAgent));
      setEntryCodeInput('');
      return;
    }
    const agent = bookers.find(b => b.code.toUpperCase() === entryCodeInput.toUpperCase());
    if (agent) {
      setAuthenticatedAgent(agent);
      setIsAdminAuthenticated(false);
      const storage = rememberMe ? localStorage : sessionStorage;
      storage.setItem('tl_auth_agent', JSON.stringify(agent));
      setEntryCodeInput('');
    } else {
      alert("Invalid Code.");
    }
  };

  if (isLoading) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-[#001D4A] text-white">
        <img src={BUSINESS_INFO.logo} className="w-24 animate-pulse mb-8" />
        <div className="flex gap-2"><div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce"></div><div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div><div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div></div>
      </div>
    );
  }

  if (!authenticatedAgent) {
    return (
      <div className="min-h-screen w-full flex items-center justify-center bg-[#001D4A] p-6">
        <div className="w-full max-sm z-10 animate-in fade-in zoom-in duration-500">
           <div className="bg-white/5 backdrop-blur-3xl p-8 rounded-[40px] border border-white/10 shadow-2xl">
              <div className="flex flex-col items-center mb-10">
                <div className="bg-white p-5 rounded-3xl shadow-xl mb-6"><img src={BUSINESS_INFO.logo} alt="Logo" className="w-16" /></div>
                <h1 className="text-2xl font-black text-white tracking-tighter text-center uppercase">{BUSINESS_INFO.name}</h1>
                <p className="text-white/40 text-[9px] font-black uppercase tracking-[0.3em] mt-2 text-center">{BUSINESS_INFO.address}</p>
              </div>
              <form onSubmit={handleEntryLogin} className="space-y-6">
                 <input autoFocus type="password" placeholder="CODE" value={entryCodeInput} onChange={(e) => setEntryCodeInput(e.target.value)} className="w-full bg-white/10 border border-white/10 px-6 py-5 rounded-2xl text-white font-black text-xl tracking-widest uppercase placeholder:text-white/20 focus:outline-none focus:ring-2 focus:ring-orange-500 text-center" />
                 <label className="flex items-center gap-3 cursor-pointer group px-4">
                    <input type="checkbox" checked={rememberMe} onChange={(e) => setRememberMe(e.target.checked)} className="w-5 h-5 rounded border-white/20 bg-white/10 text-orange-500 focus:ring-orange-500 cursor-pointer" />
                    <span className="text-[10px] font-black uppercase text-white/40 group-hover:text-white transition-colors">Remember Session</span>
                 </label>
                 <button type="submit" className="w-full py-5 bg-orange-500 text-white rounded-2xl font-black text-lg shadow-xl active:scale-95 transition-all">Unlock System</button>
              </form>
           </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row">
      <nav className="hidden md:flex fixed top-0 left-0 bottom-0 w-24 bg-[#001D4A] flex-col items-center justify-between py-8 shadow-2xl z-50">
        <div className="flex flex-col items-center w-full">
          <img src={BUSINESS_INFO.logo} alt="Logo" className="w-14 mb-12" />
          {[
            { id: 'dashboard', icon: 'fa-chart-line', label: 'Stats' },
            { id: 'booking', icon: 'fa-bus', label: 'Seats' },
            { id: 'revenue', icon: 'fa-sack-dollar', label: 'Cash' },
            { id: 'expenses', icon: 'fa-file-invoice-dollar', label: 'Cost' },
            { id: 'log', icon: 'fa-clipboard-list', label: 'Log' },
            { id: 'edit', icon: 'fa-user-pen', label: 'Edit' }
          ].map(item => (
            <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`w-full py-5 flex flex-col items-center transition-all ${activeTab === item.id ? 'bg-orange-500 text-white shadow-lg' : 'text-white/40 hover:text-white'}`}>
              <i className={`fas ${item.icon} text-xl mb-1`}></i>
              <span className="text-[9px] font-black uppercase">{item.label}</span>
            </button>
          ))}
        </div>
        <div className="flex flex-col items-center gap-6">
          <button onClick={() => isAdminAuthenticated ? setActiveTab('admin') : setShowAdminLogin(true)} className={`w-14 h-14 flex items-center justify-center rounded-2xl transition-all ${activeTab === 'admin' ? 'bg-orange-500 text-white' : 'bg-white/5 text-white/40'}`}><i className="fas fa-user-shield text-xl"></i></button>
          <button onClick={() => setShowLogoutConfirm(true)} className="w-14 h-14 flex items-center justify-center rounded-2xl bg-red-500/10 text-red-500"><i className="fas fa-power-off text-xl"></i></button>
        </div>
      </nav>

      <nav className="md:hidden fixed bottom-0 left-0 right-0 h-[75px] bg-[#001D4A]/95 backdrop-blur-md flex items-center justify-around z-[100] border-t border-white/10 shadow-[0_-10px_30px_rgba(0,0,0,0.3)] px-1 pb-safe">
        {[
          { id: 'dashboard', icon: 'fa-chart-line', label: 'Stats' },
          { id: 'booking', icon: 'fa-bus', label: 'Seats' },
          { id: 'revenue', icon: 'fa-sack-dollar', label: 'Cash' },
          { id: 'expenses', icon: 'fa-file-invoice-dollar', label: 'Cost' },
          { id: 'log', icon: 'fa-clipboard-list', label: 'Log' },
          { id: 'edit', icon: 'fa-user-pen', label: 'Edit' }
        ].map(item => (
          <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`flex-1 flex flex-col items-center justify-center gap-1 transition-all py-2 rounded-2xl mx-0.5 ${activeTab === item.id ? 'bg-orange-500 text-white shadow-lg' : 'text-white/30'}`}>
            <i className={`fas ${item.icon} text-lg`}></i>
            <span className="text-[7px] font-black uppercase tracking-tight">{item.label}</span>
          </button>
        ))}
        <button onClick={() => isAdminAuthenticated ? setActiveTab('admin') : setShowAdminLogin(true)} className={`flex-1 flex flex-col items-center justify-center gap-1 py-2 rounded-2xl mx-0.5 ${activeTab === 'admin' ? 'bg-orange-500 text-white shadow-lg' : 'text-white/30'}`}><i className="fas fa-user-shield text-lg"></i><span className="text-[7px] font-black uppercase tracking-tight">Admin</span></button>
      </nav>

      <main className="flex-grow md:ml-24 p-4 md:p-10 pb-24 md:pb-10">
        <header className="flex justify-between items-center mb-6 md:mb-10">
            <div className="flex items-center gap-3">
               <div className="md:hidden w-10 h-10 bg-white p-2 rounded-xl shadow-sm"><img src={BUSINESS_INFO.logo} className="w-full" /></div>
               <div>
                  <h2 className="text-xl md:text-3xl font-black text-[#001D4A] uppercase tracking-tighter leading-none">{activeTab === 'booking' ? 'Seat Plan' : activeTab.charAt(0).toUpperCase() + activeTab.slice(1)}</h2>
                  <div className="flex items-center gap-2 mt-1">
                    <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></div>
                    <p className="text-[8px] md:text-[10px] font-black text-gray-400 uppercase tracking-widest">Live Agents Online: {onlineAgents.map(a => a.name).join(', ') || 'None'}</p>
                  </div>
               </div>
            </div>
            <button onClick={() => setShowLogoutConfirm(true)} className="md:hidden w-10 h-10 rounded-xl bg-red-50 text-red-500 flex items-center justify-center"><i className="fas fa-power-off"></i></button>
        </header>

        <div className="max-w-7xl mx-auto">
          {activeTab === 'booking' && (
            <div className="animate-in fade-in duration-500 space-y-6">
               <div className="bg-white p-4 rounded-3xl shadow-sm border border-gray-100 flex items-center gap-3 sticky top-0 z-40 overflow-x-auto no-scrollbar">
                  <div className="flex items-center gap-1.5 shrink-0 px-2 border-r">
                    <span className="text-[9px] font-black text-gray-400 uppercase tracking-widest mr-2">Online:</span>
                    {onlineAgents.map(a => (
                      <div key={a.code} className="bg-green-50 text-green-700 text-[8px] font-black px-2 py-1 rounded-lg uppercase whitespace-nowrap animate-pulse">{a.name.split(' ')[0]}</div>
                    ))}
                  </div>
                  <select value={selectedBusIndex} onChange={(e) => setSelectedBusIndex(Number(e.target.value))} className="bg-transparent font-black text-[#001D4A] outline-none text-xs uppercase tracking-widest cursor-pointer appearance-none px-4">
                    {buses.map((bus, idx) => <option key={bus.busId} value={idx}>{bus.busId}</option>)}
                  </select>
               </div>
               {buses.length > 0 ? (
                 <div className="flex justify-center w-full">
                    <BusLayout seats={buses[selectedBusIndex]?.seats || []} onSeatClick={handleSeatClick} />
                 </div>
               ) : <div className="text-center py-20 bg-white rounded-[40px] border border-dashed border-gray-200"><p className="text-gray-400 font-black uppercase text-xs tracking-widest">No Active Routes</p></div>}
            </div>
          )}
          {activeTab === 'dashboard' && <Dashboard buses={buses} expenses={expenses} />}
          {activeTab === 'log' && <BookingLog buses={buses} bookers={bookers} />}
          {activeTab === 'expenses' && <ExpenseTracker expenses={expenses} onSubmit={() => fetchData()} onDelete={() => fetchData()} bookers={bookers} initialAgentCode={authenticatedAgent?.code} tours={tours} />}
          {activeTab === 'revenue' && <RevenueReport buses={buses} expenses={expenses} tours={tours} />}
          {activeTab === 'edit' && <EditData buses={buses} onUpdate={handleBookingSubmit} onDelete={() => {}} onEdit={(info) => { setEditingInfo(info); setSelectedSeatId(info.seatNo); setShowBookingModal(true); }} bookers={bookers} />}
          {activeTab === 'admin' && isAdminAuthenticated && <AdminPanel tours={tours} setTours={() => {}} agents={bookers} setAgents={() => {}} customerTypes={customerTypes} setCustomerTypes={() => {}} buses={buses} onDeleteTourCascading={() => {}} onMasterReset={() => {}} />}
        </div>
      </main>

      {showLogoutConfirm && <ConfirmationDialog message="Are you sure you want to end your session?" onConfirm={() => { setAuthenticatedAgent(null); setShowLogoutConfirm(false); localStorage.removeItem('tl_auth_agent'); sessionStorage.removeItem('tl_auth_agent'); }} onCancel={() => setShowLogoutConfirm(false)} />}
      {showBookingModal && <BookingModal seatId={selectedSeatId!} busNo={editingInfo ? editingInfo.busNo : (buses[selectedBusIndex]?.busId || '')} onClose={() => { releaseLock(buses[selectedBusIndex].busId, selectedSeatId!); setShowBookingModal(false); setEditingInfo(null); }} onSubmit={handleBookingSubmit} tours={tours} bookers={bookers} customerTypes={customerTypes} existingData={editingInfo || undefined} />}
      {showDetailModal && editingInfo && <SeatDetailModal info={editingInfo} onClose={() => { setShowDetailModal(false); setEditingInfo(null); }} onEdit={() => { setShowDetailModal(false); setShowBookingModal(true); }} onCancel={() => { setShowDetailModal(false); setShowConfirmDeselect(true); }} isAdmin={isAdminAuthenticated} />}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { SeatData, Gender, Religion } from '../types';

interface SeatProps {
  data: SeatData;
  onClick: () => void;
}

const Seat: React.FC<SeatProps> = ({ data, onClick }) => {
  const [isHovered, setIsHovered] = useState(false);

  const getSeatColor = () => {
    if (data.lockInfo) return 'bg-gray-400 hover:bg-gray-500 shadow-gray-200 animate-pulse cursor-not-allowed'; // Pending Gray
    if (!data.isBooked) return 'bg-green-500 hover:bg-green-600 shadow-green-200';

    const info = data.bookingInfo!;
    const isFemale = info.gender === Gender.FEMALE;
    const isMuslim = info.religion === Religion.MUSLIM;

    if (isFemale && !isMuslim) return 'bg-yellow-500 hover:bg-yellow-600 shadow-yellow-200';
    if (isFemale) return 'bg-pink-500 hover:bg-pink-600 shadow-pink-200';
    if (!isMuslim) return 'bg-blue-500 hover:bg-blue-600 shadow-blue-200';

    return 'bg-red-500 hover:bg-red-600 shadow-red-200';
  };

  const info = data.bookingInfo;
  const lock = data.lockInfo;

  return (
    <div 
      className="relative"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      onTouchStart={() => setIsHovered(true)}
      onTouchEnd={() => setTimeout(() => setIsHovered(false), 3000)}
    >
      <button
        onClick={(e) => { e.stopPropagation(); onClick(); }}
        className={`${getSeatColor()} w-11 h-11 md:w-14 md:h-14 rounded-[12px] md:rounded-2xl flex items-center justify-center text-white text-[11px] md:text-[13px] font-black transition-all shadow-md md:shadow-lg transform active:scale-90`}
      >
        {data.id}
      </button>

      {/* Held by Tooltip for Pending Seats */}
      {isHovered && lock && !data.isBooked && (
        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 z-[200] w-32 bg-gray-900 text-white p-3 rounded-xl text-center shadow-xl animate-in zoom-in duration-200">
          <p className="text-[8px] font-black uppercase text-gray-400 tracking-widest mb-1">Held By</p>
          <p className="text-[10px] font-black truncate">{lock.agent_name}</p>
          <div className="w-full bg-gray-700 h-1 rounded-full mt-2 overflow-hidden">
             <div className="bg-orange-500 h-full animate-[progress_300s_linear]" style={{width: '100%'}}></div>
          </div>
        </div>
      )}

      {/* Booking Tooltip */}
      {isHovered && data.isBooked && info && (
        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-4 z-[150] w-64 md:w-72 bg-white text-gray-800 p-0 rounded-2xl md:rounded-[28px] shadow-2xl border border-gray-100 animate-in fade-in slide-in-from-bottom-2 duration-200 overflow-hidden pointer-events-none">
          <div className="bg-[#001D4A] p-3 md:p-4 flex justify-between items-center">
             <div className="flex flex-col">
               <span className="text-white font-black text-[10px] md:text-xs">Seat {data.id}</span>
               <span className="text-orange-400 text-[8px] font-bold uppercase tracking-tighter">{info.tourName}</span>
             </div>
             <span className={`px-2 py-0.5 rounded-full text-[8px] md:text-[9px] font-black uppercase ${info.paymentStatus === 'Paid' ? 'bg-green-500 text-white' : 'bg-orange-500 text-white'}`}>
              {info.paymentStatus}
            </span>
          </div>
          <div className="p-4 md:p-5 space-y-3">
            <p className="text-sm font-black text-[#001D4A] leading-tight">{info.name}</p>
            <div className="bg-red-50 p-2 rounded-xl flex justify-between items-center border border-red-100">
               <span className="text-[9px] font-black text-red-400 uppercase">Due</span>
               <span className="text-base font-black text-red-600">৳{info.dueAmount.toLocaleString()}</span>
            </div>
            <div className="flex justify-between items-center pt-2 border-t border-gray-50">
              <span className="text-[9px] text-indigo-600 font-black uppercase truncate max-w-[120px]">{info.bookedBy}</span>
              <span className="text-[8px] font-black text-white bg-indigo-500 px-2 py-0.5 rounded uppercase tracking-tighter">ID: {info.bookerCode}</span>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Seat;

export enum Gender {
  MALE = 'Male',
  FEMALE = 'Female',
  OTHERS = 'Others'
}

export enum Religion {
  MUSLIM = 'Muslim',
  HINDUISM = 'Hinduism',
  BUDDHISM = 'Buddhism',
  CHRISTIANITY = 'Christianity',
  OTHERS = 'Others'
}

export interface BookingInfo {
  id: string;
  name: string;
  mobile: string;
  address: string;
  gender: Gender;
  religion: Religion;
  tourName: string;
  tourFees: number;
  customerType?: string;
  customerTypeFees: number;
  discountAmount: number;
  advanceAmount: number;
  dueAmount: number;
  paymentStatus: 'Paid' | 'Partial' | 'Due';
  busNo: string;
  seatNo: string;
  bookedBy: string;
  bookerCode: string;
  bookingDate: string;
}

export interface SeatLock {
  id?: string;
  bus_no: string;
  seat_no: string;
  agent_code: string;
  agent_name: string;
  expires_at: string;
}

export interface Expense {
  id: string;
  category: string;
  amount: number;
  description: string;
  date: string;
  recordedBy: string;
  agentCode: string;
  tourName?: string;
}

export interface SeatData {
  id: string;
  isBooked: boolean;
  bookingInfo?: BookingInfo;
  lockInfo?: SeatLock;
}

export interface BusData {
  busId: string;
  seats: SeatData[];
}

export interface Tour {
  name: string;
  fee: number;
}

export interface Booker {
  code: string;
  name: string;
  last_active?: string;
}

export interface CustomerType {
  type: string;
  fee: number;
}

import React, { useState, useEffect, useCallback } from 'react';
import { BUSINESS_INFO, generateInitialSeats } from './constants';
import { BusData, BookingInfo, Tour, Booker, CustomerType, Expense, SeatLock } from './types';
import BusLayout from './components/BusLayout';
import BookingModal from './components/BookingModal';
import ConfirmationDialog from './components/ConfirmationDialog';
import Dashboard from './components/Dashboard';
import BookingLog from './components/BookingLog';
import EditData from './components/EditData';
import AdminPanel from './components/AdminPanel';
import SeatDetailModal from './components/SeatDetailModal';
import ExpenseTracker from './components/ExpenseTracker';
import RevenueReport from './components/RevenueReport';
import { supabase } from './supabase';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'booking' | 'dashboard' | 'log' | 'edit' | 'admin' | 'expenses' | 'revenue'>('booking');
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(() => {
    return sessionStorage.getItem('tl_auth_admin') === 'true' || localStorage.getItem('tl_auth_admin') === 'true';
  });
  const [isLoading, setIsLoading] = useState(true);
  const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);

  const [authenticatedAgent, setAuthenticatedAgent] = useState<Booker | null>(() => {
    const savedSession = sessionStorage.getItem('tl_auth_agent');
    const savedLocal = localStorage.getItem('tl_auth_agent');
    const saved = savedSession || savedLocal;
    return saved ? JSON.parse(saved) : null;
  });
  const [entryCodeInput, setEntryCodeInput] = useState('');
  const [rememberMe, setRememberMe] = useState(false);

  const [selectedBusIndex, setSelectedBusIndex] = useState(0);
  const [selectedSeatId, setSelectedSeatId] = useState<string | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [editingInfo, setEditingInfo] = useState<BookingInfo | null>(null);

  const [tours, setTours] = useState<Tour[]>([]);
  const [bookers, setBookers] = useState<Booker[]>([]);
  const [customerTypes, setCustomerTypes] = useState<CustomerType[]>([]);
  const [buses, setBuses] = useState<BusData[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [onlineAgents, setOnlineAgents] = useState<Booker[]>([]);

  const fetchData = useCallback(async () => {
    try {
      const [toursRes, bookersRes, typesRes, bookingsRes, expensesRes, locksRes] = await Promise.all([
        supabase.from('tl_tours').select('*').order('name'),
        supabase.from('tl_agents').select('*').order('name'),
        supabase.from('tl_customer_types').select('*').order('type'),
        supabase.from('tl_bookings').select('*'),
        supabase.from('tl_expenses').select('*').order('date', { ascending: false }),
        supabase.from('tl_locks').select('*')
      ]);

      const fetchedTours = toursRes.data || [];
      const fetchedBookers = bookersRes.data || [];
      const fetchedTypes = typesRes.data || [];
      const fetchedBookings: any[] = bookingsRes.data || [];
      const fetchedLocks: any[] = locksRes.data || [];

      // Filter expired locks (Older than 5 mins)
      const now = new Date();
      const validLocks: SeatLock[] = fetchedLocks.filter(lock => new Date(lock.expires_at) > now);

      // Presence logic (Last active in 2 mins)
      const onlineCutoff = new Date(Date.now() - 2 * 60 * 1000);
      const activeAgents = fetchedBookers.filter(b => b.last_active && new Date(b.last_active) > onlineCutoff);
      setOnlineAgents(activeAgents);

      const mappedBookings: BookingInfo[] = fetchedBookings.map(b => ({
        id: b.id, name: b.name, mobile: b.mobile, address: b.address,
        gender: b.gender, religion: b.religion, tourName: b.tour_name,
        tourFees: b.tour_fees, customerType: b.customer_type,
        customerTypeFees: b.customer_type_fees, discountAmount: b.discount_amount,
        advanceAmount: b.advance_amount, dueAmount: b.due_amount,
        paymentStatus: b.payment_status, busNo: b.bus_no, seatNo: b.seat_no,
        bookedBy: b.booked_by, bookerCode: b.booker_code, bookingDate: b.booking_date
      }));

      setTours(fetchedTours);
      setBookers(fetchedBookers);
      setCustomerTypes(fetchedTypes);

      const busLayouts = fetchedTours.map(t => {
        const seats = generateInitialSeats();
        mappedBookings.forEach(booking => {
          if (booking.busNo === t.name) {
            const seatIdx = seats.findIndex(s => s.id === booking.seatNo);
            if (seatIdx !== -1) seats[seatIdx] = { ...seats[seatIdx], isBooked: true, bookingInfo: booking };
          }
        });
        validLocks.forEach(lock => {
          if (lock.bus_no === t.name) {
            const seatIdx = seats.findIndex(s => s.id === lock.seat_no);
            if (seatIdx !== -1 && !seats[seatIdx].isBooked) {
              seats[seatIdx] = { ...seats[seatIdx], lockInfo: lock };
            }
          }
        });
        return { busId: t.name, seats };
      });
      setBuses(busLayouts);
    } catch (error) {
      console.error("Fetch Error:", error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 10000); // 10s auto-refresh
    const channel = supabase.channel('tl_realtime')
      .on('postgres_changes', { event: '*', schema: 'public' }, () => fetchData())
      .subscribe();
    return () => { 
      clearInterval(interval);
      supabase.removeChannel(channel); 
    };
  }, [fetchData]);

  // Heartbeat Presence
  useEffect(() => {
    if (!authenticatedAgent) return;
    const heartbeat = setInterval(async () => {
      await supabase.from('tl_agents').update({ last_active: new Date().toISOString() }).eq('code', authenticatedAgent.code);
    }, 30000);
    return () => clearInterval(heartbeat);
  }, [authenticatedAgent]);

  const handleSeatClick = async (sid: string) => {
    const currentBus = buses[selectedBusIndex];
    const seat = currentBus.seats.find(s => s.id === sid);

    if (seat?.isBooked) {
      setEditingInfo(seat.bookingInfo!);
      setShowDetailModal(true);
      return;
    }

    if (seat?.lockInfo) {
      if (seat.lockInfo.agent_code === authenticatedAgent?.code) {
        setSelectedSeatId(sid);
        setShowBookingModal(true);
      } else {
        alert(`This seat is currently held by ${seat.lockInfo.agent_name}.`);
      }
      return;
    }

    // Try to lock seat
    const expiresAt = new Date(Date.now() + 5 * 60 * 1000).toISOString();
    try {
      const { error } = await supabase.from('tl_locks').insert({
        bus_no: currentBus.busId,
        seat_no: sid,
        agent_code: authenticatedAgent?.code || 'GUEST',
        agent_name: authenticatedAgent?.name || 'Guest',
        expires_at: expiresAt
      });

      if (error) {
        alert("Someone else just clicked this seat! Refreshing...");
        fetchData();
        return;
      }

      setSelectedSeatId(sid);
      setShowBookingModal(true);
    } catch (e) {
      alert("Failed to secure seat.");
    }
  };

  const releaseLock = async (busNo: string, seatId: string) => {
    if (!authenticatedAgent) return;
    await supabase.from('tl_locks').delete().eq('bus_no', busNo).eq('seat_no', seatId).eq('agent_code', authenticatedAgent.code);
    fetchData();
  };

  const handleBookingSubmit = async (info: BookingInfo) => {
    try {
      const { error } = await supabase.from('tl_bookings').upsert({
        id: info.id, name: info.name, mobile: info.mobile, address: info.address,
        gender: info.gender, religion: info.religion, tour_name: info.tourName,
        tour_fees: info.tourFees, customer_type: info.customerType,
        customer_type_fees: info.customerTypeFees, discount_amount: info.discountAmount,
        advance_amount: info.advanceAmount, due_amount: info.dueAmount,
        payment_status: info.paymentStatus, bus_no: info.busNo, seat_no: info.seatNo,
        booked_by: info.bookedBy, booker_code: info.bookerCode, booking_date: info.bookingDate
      });
      if (error) throw error;
      await releaseLock(info.busNo, info.seatNo);
      fetchData();
    } catch (error) {
      alert("Booking failed to sync.");
    }
    setShowBookingModal(false);
    setShowDetailModal(false);
  };

  const handleEntryLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (entryCodeInput === "@Rana&01625@") {
      const adminAgent: Booker = { code: 'ADMIN', name: 'System Administrator' };
      setAuthenticatedAgent(adminAgent);
      setIsAdminAuthenticated(true);
      const storage = rememberMe ? localStorage : sessionStorage;
      storage.setItem('tl_auth_admin', 'true');
      storage.setItem('tl_auth_agent', JSON.stringify(adminAgent));
      setEntryCodeInput('');
      return;
    }
    const agent = bookers.find(b => b.code.toUpperCase() === entryCodeInput.toUpperCase());
    if (agent) {
      setAuthenticatedAgent(agent);
      setIsAdminAuthenticated(false);
      const storage = rememberMe ? localStorage : sessionStorage;
      storage.setItem('tl_auth_agent', JSON.stringify(agent));
      setEntryCodeInput('');
    } else {
      alert("Invalid Code.");
    }
  };

  if (isLoading) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-[#001D4A] text-white">
        <img src={BUSINESS_INFO.logo} className="w-24 animate-pulse mb-8" />
        <div className="flex gap-2"><div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce"></div><div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div><div className="w-2 h-2 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div></div>
      </div>
    );
  }

  if (!authenticatedAgent) {
    return (
      <div className="min-h-screen w-full flex items-center justify-center bg-[#001D4A] p-6">
        <div className="w-full max-sm z-10 animate-in fade-in zoom-in duration-500">
           <div className="bg-white/5 backdrop-blur-3xl p-8 rounded-[40px] border border-white/10 shadow-2xl">
              <div className="flex flex-col items-center mb-10">
                <div className="bg-white p-5 rounded-3xl shadow-xl mb-6"><img src={BUSINESS_INFO.logo} alt="Logo" className="w-16" /></div>
                <h1 className="text-2xl font-black text-white tracking-tighter text-center uppercase">{BUSINESS_INFO.name}</h1>
                <p className="text-white/40 text-[9px] font-black uppercase tracking-[0.3em] mt-2 text-center">{BUSINESS_INFO.address}</p>
              </div>
              <form onSubmit={handleEntryLogin} className="space-y-6">
                 <input autoFocus type="password" placeholder="CODE" value={entryCodeInput} onChange={(e) => setEntryCodeInput(e.target.value)} className="w-full bg-white/10 border border-white/10 px-6 py-5 rounded-2xl text-white font-black text-xl tracking-widest uppercase placeholder:text-white/20 focus:outline-none focus:ring-2 focus:ring-orange-500 text-center" />
                 <label className="flex items-center gap-3 cursor-pointer group px-4">
                    <input type="checkbox" checked={rememberMe} onChange={(e) => setRememberMe(e.target.checked)} className="w-5 h-5 rounded border-white/20 bg-white/10 text-orange-500 focus:ring-orange-500 cursor-pointer" />
                    <span className="text-[10px] font-black uppercase text-white/40 group-hover:text-white transition-colors">Remember Session</span>
                 </label>
                 <button type="submit" className="w-full py-5 bg-orange-500 text-white rounded-2xl font-black text-lg shadow-xl active:scale-95 transition-all">Unlock System</button>
              </form>
           </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row">
      <nav className="hidden md:flex fixed top-0 left-0 bottom-0 w-24 bg-[#001D4A] flex-col items-center justify-between py-8 shadow-2xl z-50">
        <div className="flex flex-col items-center w-full">
          <img src={BUSINESS_INFO.logo} alt="Logo" className="w-14 mb-12" />
          {[
            { id: 'dashboard', icon: 'fa-chart-line', label: 'Stats' },
            { id: 'booking', icon: 'fa-bus', label: 'Seats' },
            { id: 'revenue', icon: 'fa-sack-dollar', label: 'Cash' },
            { id: 'expenses', icon: 'fa-file-invoice-dollar', label: 'Cost' },
            { id: 'log', icon: 'fa-clipboard-list', label: 'Log' },
            { id: 'edit', icon: 'fa-user-pen', label: 'Edit' }
          ].map(item => (
            <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`w-full py-5 flex flex-col items-center transition-all ${activeTab === item.id ? 'bg-orange-500 text-white shadow-lg' : 'text-white/40 hover:text-white'}`}>
              <i className={`fas ${item.icon} text-xl mb-1`}></i>
              <span className="text-[9px] font-black uppercase">{item.label}</span>
            </button>
          ))}
        </div>
        <div className="flex flex-col items-center gap-6">
          <button onClick={() => isAdminAuthenticated ? setActiveTab('admin') : setActiveTab('admin')} className={`w-14 h-14 flex items-center justify-center rounded-2xl transition-all ${activeTab === 'admin' ? 'bg-orange-500 text-white' : 'bg-white/5 text-white/40'}`}><i className="fas fa-user-shield text-xl"></i></button>
          <button onClick={() => setShowLogoutConfirm(true)} className="w-14 h-14 flex items-center justify-center rounded-2xl bg-red-500/10 text-red-500"><i className="fas fa-power-off text-xl"></i></button>
        </div>
      </nav>

      <nav className="md:hidden fixed bottom-0 left-0 right-0 h-[75px] bg-[#001D4A]/95 backdrop-blur-md flex items-center justify-around z-[100] border-t border-white/10 shadow-[0_-10px_30px_rgba(0,0,0,0.3)] px-1 pb-safe">
        {[
          { id: 'dashboard', icon: 'fa-chart-line', label: 'Stats' },
          { id: 'booking', icon: 'fa-bus', label: 'Seats' },
          { id: 'revenue', icon: 'fa-sack-dollar', label: 'Cash' },
          { id: 'expenses', icon: 'fa-file-invoice-dollar', label: 'Cost' },
          { id: 'log', icon: 'fa-clipboard-list', label: 'Log' },
          { id: 'edit', icon: 'fa-user-pen', label: 'Edit' }
        ].map(item => (
          <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`flex-1 flex flex-col items-center justify-center gap-1 transition-all py-2 rounded-2xl mx-0.5 ${activeTab === item.id ? 'bg-orange-500 text-white shadow-lg' : 'text-white/30'}`}>
            <i className={`fas ${item.icon} text-lg`}></i>
            <span className="text-[7px] font-black uppercase tracking-tight">{item.label}</span>
          </button>
        ))}
      </nav>

      <main className="flex-grow md:ml-24 p-4 md:p-10 pb-24 md:pb-10">
        <header className="flex justify-between items-center mb-6 md:mb-10">
            <div className="flex items-center gap-3">
               <div className="md:hidden w-10 h-10 bg-white p-2 rounded-xl shadow-sm"><img src={BUSINESS_INFO.logo} className="w-full" /></div>
               <div>
                  <h2 className="text-xl md:text-3xl font-black text-[#001D4A] uppercase tracking-tighter leading-none">{activeTab === 'booking' ? 'Seat Plan' : activeTab.charAt(0).toUpperCase() + activeTab.slice(1)}</h2>
                  <div className="flex items-center gap-2 mt-1">
                    <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></div>
                    <p className="text-[8px] md:text-[10px] font-black text-gray-400 uppercase tracking-widest">
                      Online Agents: {onlineAgents.map(a => a.name).join(', ') || 'None'}
                    </p>
                  </div>
               </div>
            </div>
            <button onClick={() => setShowLogoutConfirm(true)} className="md:hidden w-10 h-10 rounded-xl bg-red-50 text-red-500 flex items-center justify-center"><i className="fas fa-power-off"></i></button>
        </header>

        <div className="max-w-7xl mx-auto">
          {activeTab === 'booking' && (
            <div className="animate-in fade-in duration-500 space-y-6">
               <div className="bg-white p-4 rounded-3xl shadow-sm border border-gray-100 flex items-center gap-3 sticky top-0 z-40 overflow-x-auto no-scrollbar">
                  <select value={selectedBusIndex} onChange={(e) => setSelectedBusIndex(Number(e.target.value))} className="bg-transparent font-black text-[#001D4A] outline-none text-xs uppercase tracking-widest cursor-pointer appearance-none px-4">
                    {buses.map((bus, idx) => <option key={bus.busId} value={idx}>{bus.busId}</option>)}
                  </select>
                  <div className="h-4 w-[1px] bg-gray-200"></div>
                  <div className="flex items-center gap-2">
                    <div className="w-3 h-3 bg-gray-400 rounded-sm animate-pulse"></div>
                    <span className="text-[8px] font-black uppercase text-gray-400">Locked Seat</span>
                  </div>
               </div>
               {buses.length > 0 ? (
                 <div className="flex justify-center w-full">
                    <BusLayout seats={buses[selectedBusIndex]?.seats || []} onSeatClick={handleSeatClick} />
                 </div>
               ) : <div className="text-center py-20 bg-white rounded-[40px] border border-dashed border-gray-200"><p className="text-gray-400 font-black uppercase text-xs tracking-widest">No Active Routes</p></div>}
            </div>
          )}
          {activeTab === 'dashboard' && <Dashboard buses={buses} expenses={expenses} />}
          {activeTab === 'log' && <BookingLog buses={buses} bookers={bookers} />}
          {activeTab === 'expenses' && <ExpenseTracker expenses={expenses} onSubmit={() => fetchData()} onDelete={() => fetchData()} bookers={bookers} initialAgentCode={authenticatedAgent?.code} tours={tours} />}
          {activeTab === 'revenue' && <RevenueReport buses={buses} expenses={expenses} tours={tours} />}
          {activeTab === 'edit' && <EditData buses={buses} onUpdate={handleBookingSubmit} onDelete={() => {}} onEdit={(info) => { setEditingInfo(info); setSelectedSeatId(info.seatNo); setShowBookingModal(true); }} bookers={bookers} />}
          {activeTab === 'admin' && isAdminAuthenticated && <AdminPanel tours={tours} setTours={() => {}} agents={bookers} setAgents={() => {}} customerTypes={customerTypes} setCustomerTypes={() => {}} buses={buses} onDeleteTourCascading={() => {}} onMasterReset={() => {}} />}
        </div>
      </main>

      {showLogoutConfirm && <ConfirmationDialog message="Are you sure you want to end your session?" onConfirm={() => { setAuthenticatedAgent(null); setShowLogoutConfirm(false); localStorage.removeItem('tl_auth_agent'); sessionStorage.removeItem('tl_auth_agent'); }} onCancel={() => setShowLogoutConfirm(false)} />}
      {showBookingModal && <BookingModal seatId={selectedSeatId!} busNo={editingInfo ? editingInfo.busNo : (buses[selectedBusIndex]?.busId || '')} onClose={() => { releaseLock(buses[selectedBusIndex].busId, selectedSeatId!); setShowBookingModal(false); setEditingInfo(null); }} onSubmit={handleBookingSubmit} tours={tours} bookers={bookers} customerTypes={customerTypes} existingData={editingInfo || undefined} />}
      {showDetailModal && editingInfo && <SeatDetailModal info={editingInfo} onClose={() => { setShowDetailModal(false); setEditingInfo(null); }} onEdit={() => { setShowDetailModal(false); setShowBookingModal(true); }} onCancel={() => { setShowDetailModal(false); }} isAdmin={isAdminAuthenticated} />}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { SeatData, Gender, Religion } from '../types';

interface SeatProps {
  data: SeatData;
  onClick: () => void;
}

const Seat: React.FC<SeatProps> = ({ data, onClick }) => {
  const [isHovered, setIsHovered] = useState(false);

  const getSeatColor = () => {
    // Priority 1: Temporary Lock (Gray)
    if (data.lockInfo) return 'bg-gray-400 hover:bg-gray-500 shadow-gray-200 animate-pulse cursor-not-allowed';

    // Priority 2: Confirmed Booking
    if (data.isBooked && data.bookingInfo) {
      const info = data.bookingInfo;
      const isFemale = info.gender === Gender.FEMALE;
      const isMuslim = info.religion === Religion.MUSLIM;

      if (isFemale && !isMuslim) return 'bg-yellow-500 hover:bg-yellow-600 shadow-yellow-200';
      if (isFemale) return 'bg-pink-500 hover:bg-pink-600 shadow-pink-200';
      if (!isMuslim) return 'bg-blue-500 hover:bg-blue-600 shadow-blue-200';
      return 'bg-red-500 hover:bg-red-600 shadow-red-200';
    }

    // Priority 3: Available
    return 'bg-green-500 hover:bg-green-600 shadow-green-200';
  };

  const info = data.bookingInfo;
  const lock = data.lockInfo;

  return (
    <div 
      className="relative"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      onTouchStart={() => setIsHovered(true)}
      onTouchEnd={() => setTimeout(() => setIsHovered(false), 3000)}
    >
      <button
        onClick={(e) => { e.stopPropagation(); onClick(); }}
        className={`${getSeatColor()} w-11 h-11 md:w-14 md:h-14 rounded-[12px] md:rounded-2xl flex items-center justify-center text-white text-[11px] md:text-[13px] font-black transition-all shadow-md md:shadow-lg transform active:scale-90`}
      >
        {data.id}
      </button>

      {/* Hold Status Tooltip */}
      {isHovered && lock && !data.isBooked && (
        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 z-[200] w-32 bg-gray-900 text-white p-3 rounded-xl text-center shadow-xl animate-in zoom-in duration-200">
          <p className="text-[8px] font-black uppercase text-gray-400 tracking-widest mb-1">Held By</p>
          <p className="text-[10px] font-black truncate">{lock.agent_name}</p>
          <div className="w-full bg-gray-700 h-1 rounded-full mt-2 overflow-hidden">
             <div className="bg-orange-500 h-full animate-[progress_300s_linear]"></div>
          </div>
        </div>
      )}

      {/* Confirmed Booking Tooltip */}
      {isHovered && data.isBooked && info && (
        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-4 z-[150] w-64 md:w-72 bg-white text-gray-800 p-0 rounded-2xl md:rounded-[28px] shadow-2xl border border-gray-100 animate-in fade-in slide-in-from-bottom-2 duration-200 overflow-hidden pointer-events-none">
          <div className="bg-[#001D4A] p-3 md:p-4 flex justify-between items-center">
             <div className="flex flex-col">
               <span className="text-white font-black text-[10px] md:text-xs">Seat {data.id}</span>
               <span className="text-orange-400 text-[8px] font-bold uppercase tracking-tighter">{info.tourName}</span>
             </div>
             <span className={`px-2 py-0.5 rounded-full text-[8px] md:text-[9px] font-black uppercase ${info.paymentStatus === 'Paid' ? 'bg-green-500 text-white' : 'bg-orange-500 text-white'}`}>
              {info.paymentStatus}
            </span>
          </div>
          <div className="p-4 md:p-5 space-y-3">
            <p className="text-sm font-black text-[#001D4A] leading-tight">{info.name}</p>
            <div className="bg-red-50 p-2 rounded-xl flex justify-between items-center border border-red-100">
               <span className="text-[9px] font-black text-red-400 uppercase">Due</span>
               <span className="text-base font-black text-red-600">৳{info.dueAmount.toLocaleString()}</span>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Seat;

