              <button onClick={handlePrintFoodTokens} disabled={selectedForPrint.length === 0} className="w-full py-5 bg-orange-500 text-white rounded-2xl font-black shadow-lg uppercase text-xs tracking-widest active:scale-95 transition-all">Generate {selectedForPrint.length} Tokens</button>
           </div>

           <div className="space-y-3">
              <div className="flex gap-2 mb-4 px-1">
                 <select value={foodFilterTour} onChange={e => setFoodFilterTour(e.target.value)} className="flex-1 bg-white border border-gray-100 px-3 py-3 rounded-xl text-[10px] font-black uppercase text-indigo-600">
                    <option value="">All Tours</option>
                    {tours.map(t => <option key={t.name} value={t.name}>{t.name}</option>)}
                 </select>
                 <select value={foodFilterBooker} onChange={e => setFoodFilterBooker(e.target.value)} className="flex-1 bg-white border border-gray-100 px-3 py-3 rounded-xl text-[10px] font-black uppercase text-indigo-600">
                    <option value="">All Agents</option>
                    {agents.map(a => <option key={a.code} value={a.code}>{a.name}</option>)}
                 </select>
              </div>
              {filteredFoodBookings.map(b => (
                 <div key={b.id} onClick={() => setSelectedForPrint(prev => prev.includes(b.id) ? prev.filter(p => p !== b.id) : [...prev, b.id])} className={`bg-white p-5 rounded-[28px] border transition-all cursor-pointer flex items-center justify-between ${selectedForPrint.includes(b.id) ? 'border-orange-500 bg-orange-50 shadow-md' : 'border-gray-100 shadow-sm'}`}>
                    <div className="flex items-center gap-4">
                       <div className={`w-8 h-8 rounded-xl flex items-center justify-center border-2 transition-all ${selectedForPrint.includes(b.id) ? 'bg-orange-500 border-orange-500 text-white' : 'border-gray-200 text-transparent'}`}><i className="fas fa-check text-[10px]"></i></div>
                       <div>
                          <p className="font-black text-[#001D4A] text-sm uppercase leading-none">{b.name}</p>
                          <p className="text-[9px] font-black text-orange-500 uppercase tracking-tighter mt-1">Seat {b.seatNo}</p>
                       </div>
                    </div>
                 </div>
              ))}
           </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useCallback } from 'react';
import { BUSINESS_INFO, generateInitialSeats } from './constants';
import { BusData, BookingInfo, Tour, Booker, CustomerType, Expense, SeatLock } from './types';
import BusLayout from './components/BusLayout';
import BookingModal from './components/BookingModal';
import ConfirmationDialog from './components/ConfirmationDialog';
import Dashboard from './components/Dashboard';
import BookingLog from './components/BookingLog';
import EditData from './components/EditData';
import AdminPanel from './components/AdminPanel';
import SeatDetailModal from './components/SeatDetailModal';
import ExpenseTracker from './components/ExpenseTracker';
import RevenueReport from './components/RevenueReport';
import { supabase } from './supabase';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'booking' | 'dashboard' | 'log' | 'edit' | 'admin' | 'expenses' | 'revenue'>('booking');
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(() => {
    return sessionStorage.getItem('tl_auth_admin') === 'true' || localStorage.getItem('tl_auth_admin') === 'true';
  });
  const [isLoading, setIsLoading] = useState(true);
  const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);

  const [authenticatedAgent, setAuthenticatedAgent] = useState<Booker | null>(() => {
    const savedSession = sessionStorage.getItem('tl_auth_agent');
    const savedLocal = localStorage.getItem('tl_auth_agent');
    const saved = savedSession || savedLocal;
    return saved ? JSON.parse(saved) : null;
  });
  const [entryCodeInput, setEntryCodeInput] = useState('');
  const [rememberMe, setRememberMe] = useState(false);

  const [selectedBusIndex, setSelectedBusIndex] = useState(0);
  const [selectedSeatId, setSelectedSeatId] = useState<string | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [editingInfo, setEditingInfo] = useState<BookingInfo | null>(null);

  const [tours, setTours] = useState<Tour[]>([]);
  const [bookers, setBookers] = useState<Booker[]>([]);
  const [customerTypes, setCustomerTypes] = useState<CustomerType[]>([]);
  const [buses, setBuses] = useState<BusData[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [onlineAgents, setOnlineAgents] = useState<Booker[]>([]);

  const fetchData = useCallback(async () => {
    try {
      const [toursRes, bookersRes, typesRes, bookingsRes, expensesRes, locksRes] = await Promise.all([
        supabase.from('tl_tours').select('*').order('name'),
        supabase.from('tl_agents').select('*').order('name'),
        supabase.from('tl_customer_types').select('*').order('type'),
        supabase.from('tl_bookings').select('*'),
        supabase.from('tl_expenses').select('*').order('date', { ascending: false }),
        supabase.from('tl_locks').select('*')
      ]);

      const fetchedTours = toursRes.data || [];
      const fetchedBookers = bookersRes.data || [];
      const fetchedTypes = typesRes.data || [];
      const fetchedBookings: any[] = bookingsRes.data || [];
      const fetchedLocks: any[] = locksRes.data || [];

      const now = new Date();
      const validLocks: SeatLock[] = fetchedLocks.filter(lock => new Date(lock.expires_at) > now);

      const onlineCutoff = new Date(Date.now() - 2 * 60 * 1000);
      const activeAgents = fetchedBookers.filter(b => b.last_active && new Date(b.last_active) > onlineCutoff);
      setOnlineAgents(activeAgents);

      const mappedBookings: BookingInfo[] = fetchedBookings.map(b => ({
        id: b.id, name: b.name, mobile: b.mobile, address: b.address,
        gender: b.gender, religion: b.religion, tourName: b.tour_name,
        tourFees: b.tour_fees, customerType: b.customer_type,
        customerTypeFees: b.customer_type_fees, discountAmount: b.discount_amount,
        advanceAmount: b.advance_amount, dueAmount: b.due_amount,
        paymentStatus: b.payment_status, busNo: b.bus_no, seatNo: b.seat_no,
        bookedBy: b.booked_by, bookerCode: b.booker_code, bookingDate: b.booking_date
      }));

      setTours(fetchedTours);
      setBookers(fetchedBookers);
      setCustomerTypes(fetchedTypes);

      const busLayouts = fetchedTours.map(t => {
        const seats = generateInitialSeats();
        mappedBookings.forEach(booking => {
          if (booking.busNo === t.name) {
            const seatIdx = seats.findIndex(s => s.id === booking.seatNo);
            if (seatIdx !== -1) seats[seatIdx] = { ...seats[seatIdx], isBooked: true, bookingInfo: booking };
          }
        });
        validLocks.forEach(lock => {
          if (lock.bus_no === t.name) {
            const seatIdx = seats.findIndex(s => s.id === lock.seat_no);
            if (seatIdx !== -1 && !seats[seatIdx].isBooked) {
              seats[seatIdx] = { ...seats[seatIdx], lockInfo: lock };
            }
          }
        });
        return { busId: t.name, seats };
      });
      setBuses(busLayouts);
    } catch (error) {
      console.error("Fetch Error:", error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 10000);
    const channel = supabase.channel('tl_realtime')
      .on('postgres_changes', { event: '*', schema: 'public' }, () => fetchData())
      .subscribe();
    return () => { 
      clearInterval(interval);
      supabase.removeChannel(channel); 
    };
  }, [fetchData]);

  useEffect(() => {
    if (!authenticatedAgent || authenticatedAgent.code === 'ADMIN') return;
    const heartbeat = setInterval(async () => {
      await supabase.from('tl_agents').update({ last_active: new Date().toISOString() }).eq('code', authenticatedAgent.code);
    }, 30000);
    return () => clearInterval(heartbeat);
  }, [authenticatedAgent]);

  const handleSeatClick = async (sid: string) => {
    const currentBus = buses[selectedBusIndex];
    const seat = currentBus.seats.find(s => s.id === sid);

    if (seat?.isBooked) {
      setEditingInfo(seat.bookingInfo!);
      setShowDetailModal(true);
      return;
    }

    if (seat?.lockInfo) {
      if (seat.lockInfo.agent_code === authenticatedAgent?.code) {
        setSelectedSeatId(sid);
        setShowBookingModal(true);
      } else {
        alert(`This seat is currently being booked by ${seat.lockInfo.agent_name}.`);
      }
      return;
    }

    const expiresAt = new Date(Date.now() + 5 * 60 * 1000).toISOString();
    try {
      const { error } = await supabase.from('tl_locks').insert({
        bus_no: currentBus.busId,
        seat_no: sid,
        agent_code: authenticatedAgent?.code || 'GUEST',
        agent_name: authenticatedAgent?.name || 'Guest',
        expires_at: expiresAt
      });

      if (error) {
        alert("Seat just taken! Refreshing data...");
        fetchData();
        return;
      }

      setSelectedSeatId(sid);
      setShowBookingModal(true);
    } catch (e) {
      alert("System error securing seat.");
    }
  };

  const releaseLock = async (busNo: string, seatId: string) => {
    if (!authenticatedAgent) return;
    await supabase.from('tl_locks').delete().eq('bus_no', busNo).eq('seat_no', seatId).eq('agent_code', authenticatedAgent.code);
    fetchData();
  };

  const handleBookingSubmit = async (info: BookingInfo) => {
    try {
      const { error } = await supabase.from('tl_bookings').upsert({
        id: info.id, name: info.name, mobile: info.mobile, address: info.address,
        gender: info.gender, religion: info.religion, tour_name: info.tourName,
        tour_fees: info.tourFees, customer_type: info.customerType,
        customer_type_fees: info.customerTypeFees, discount_amount: info.discountAmount,
        advance_amount: info.advanceAmount, due_amount: info.dueAmount,
        payment_status: info.paymentStatus, bus_no: info.busNo, seat_no: info.seatNo,
        booked_by: info.bookedBy, booker_code: info.bookerCode, booking_date: info.bookingDate
      });
      if (error) throw error;

      await releaseLock(info.busNo, info.seatNo);
      fetchData();
    } catch (error) {
      alert("Booking failed to save.");
    }
    setShowBookingModal(false);
    setShowDetailModal(false);
  };

  const handleBookingDelete = async (busId: string, seatId: string) => {
    try {
      const { error } = await supabase.from('tl_bookings').delete().eq('bus_no', busId).eq('seat_no', seatId);
      if (error) throw error;
      fetchData();
    } catch (error) {
      alert("Delete failed.");
    }
  };

  const handleBulkDelete = async (ids: string[]) => {
    try {
      const { error } = await supabase.from('tl_bookings').delete().in('id', ids);
      if (error) throw error;
      fetchData();
    } catch (error) {
      alert("Bulk delete failed.");
    }
  };

  const handleEntryLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (entryCodeInput === "@Rana&01625@") {
      const adminAgent: Booker = { code: 'ADMIN', name: 'System Administrator' };
      setAuthenticatedAgent(adminAgent);
      setIsAdminAuthenticated(true);
      const storage = rememberMe ? localStorage : sessionStorage;
      storage.setItem('tl_auth_admin', 'true');
      storage.setItem('tl_auth_agent', JSON.stringify(adminAgent));
      setEntryCodeInput('');
      return;
    }
    const agent = bookers.find(b => b.code.toUpperCase() === entryCodeInput.toUpperCase());
    if (agent) {
      setAuthenticatedAgent(agent);
      setIsAdminAuthenticated(false);
      const storage = rememberMe ? localStorage : sessionStorage;
      storage.setItem('tl_auth_agent', JSON.stringify(agent));
      storage.setItem('tl_auth_admin', 'false');
      setEntryCodeInput('');
    } else {
      alert("Invalid Code.");
    }
  };

  const navItems = [
    { id: 'dashboard', icon: 'fa-chart-line', label: 'Stats' },
    { id: 'booking', icon: 'fa-bus', label: 'Seats' },
    { id: 'revenue', icon: 'fa-sack-dollar', label: 'Cash' },
    { id: 'expenses', icon: 'fa-file-invoice-dollar', label: 'Cost' },
    { id: 'log', icon: 'fa-clipboard-list', label: 'Log' },
    { id: 'edit', icon: 'fa-user-pen', label: 'Edit' }
  ];

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row">
      <nav className="hidden md:flex fixed top-0 left-0 bottom-0 w-24 bg-[#001D4A] flex-col items-center justify-between py-8 shadow-2xl z-50">
        <div className="flex flex-col items-center w-full">
          <img src={BUSINESS_INFO.logo} alt="Logo" className="w-14 mb-12" />
          {navItems.map(item => (
            <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`w-full py-5 flex flex-col items-center transition-all ${activeTab === item.id ? 'bg-orange-500 text-white shadow-lg' : 'text-white/40 hover:text-white'}`}>
              <i className={`fas ${item.icon} text-xl mb-1`}></i>
              <span className="text-[9px] font-black uppercase">{item.label}</span>
            </button>
          ))}
        </div>
        <div className="flex flex-col items-center gap-6">
          {isAdminAuthenticated && (
            <button onClick={() => setActiveTab('admin')} className={`w-14 h-14 flex items-center justify-center rounded-2xl transition-all ${activeTab === 'admin' ? 'bg-orange-500 text-white' : 'bg-white/5 text-white/40'}`}>
              <i className="fas fa-user-shield text-xl"></i>
            </button>
          )}
          <button onClick={() => setShowLogoutConfirm(true)} className="w-14 h-14 flex items-center justify-center rounded-2xl bg-red-500/10 text-red-500"><i className="fas fa-power-off text-xl"></i></button>
        </div>
      </nav>

      <nav className="md:hidden fixed bottom-0 left-0 right-0 h-[75px] bg-[#001D4A]/95 backdrop-blur-md flex items-center justify-around z-[100] border-t border-white/10 shadow-[0_-10px_30px_rgba(0,0,0,0.3)] px-1 pb-safe">
        {navItems.map(item => (
          <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`flex-1 flex flex-col items-center justify-center gap-1 transition-all py-2 rounded-2xl mx-0.5 ${activeTab === item.id ? 'bg-orange-500 text-white shadow-lg' : 'text-white/30'}`}>
            <i className={`fas ${item.icon} text-lg`}></i>
            <span className="text-[7px] font-black uppercase tracking-tight">{item.label}</span>
          </button>
        ))}
        {isAdminAuthenticated && (
          <button onClick={() => setActiveTab('admin')} className={`flex-1 flex flex-col items-center justify-center gap-1 transition-all py-2 rounded-2xl mx-0.5 ${activeTab === 'admin' ? 'bg-orange-500 text-white shadow-lg' : 'text-white/30'}`}>
            <i className="fas fa-user-shield text-lg"></i>
            <span className="text-[7px] font-black uppercase tracking-tight">Admin</span>
          </button>
        )}
      </nav>

      <main className="flex-grow md:ml-24 p-4 md:p-10 pb-24 md:pb-10">
        <header className="flex justify-between items-center mb-6 md:mb-10">
            <div className="flex items-center gap-3">
               <div className="md:hidden w-10 h-10 bg-white p-2 rounded-xl shadow-sm"><img src={BUSINESS_INFO.logo} className="w-full" /></div>
               <div>
                  <h2 className="text-xl md:text-3xl font-black text-[#001D4A] uppercase tracking-tighter leading-none">{activeTab === 'booking' ? 'Seat Plan' : activeTab.charAt(0).toUpperCase() + activeTab.slice(1)}</h2>
                  <div className="flex items-center gap-2 mt-1">
                    <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></div>
                    <p className="text-[8px] md:text-[10px] font-black text-gray-400 uppercase tracking-widest">
                      Online Now: {onlineAgents.map(a => a.name).join(', ') || 'No active agents'}
                    </p>
                  </div>
               </div>
            </div>
            <button onClick={() => setShowLogoutConfirm(true)} className="md:hidden w-10 h-10 rounded-xl bg-red-50 text-red-500 flex items-center justify-center"><i className="fas fa-power-off"></i></button>
        </header>

        <div className="max-w-7xl mx-auto">
          {activeTab === 'booking' && (
            <div className="animate-in fade-in duration-500 space-y-6">
               <div className="bg-white p-4 rounded-3xl shadow-sm border border-gray-100 flex items-center gap-3 sticky top-0 z-40 overflow-x-auto no-scrollbar">
                  <select value={selectedBusIndex} onChange={(e) => setSelectedBusIndex(Number(e.target.value))} className="bg-transparent font-black text-[#001D4A] outline-none text-xs uppercase tracking-widest cursor-pointer appearance-none px-4">
                    {buses.map((bus, idx) => <option key={bus.busId} value={idx}>{bus.busId}</option>)}
                  </select>
                  <div className="h-4 w-[1px] bg-gray-200"></div>
                  <div className="flex items-center gap-2">
                    <div className="w-3 h-3 bg-gray-400 rounded-sm animate-pulse"></div>
                    <span className="text-[8px] font-black uppercase text-gray-400">Reserved (Hold)</span>
                  </div>
               </div>
               {buses.length > 0 ? (
                 <div className="flex justify-center w-full">
                    <BusLayout seats={buses[selectedBusIndex]?.seats || []} onSeatClick={handleSeatClick} />
                 </div>
               ) : <div className="text-center py-20 bg-white rounded-[40px] border border-dashed border-gray-200"><p className="text-gray-400 font-black uppercase text-xs tracking-widest">No Active Routes</p></div>}
            </div>
          )}
          {activeTab === 'dashboard' && <Dashboard buses={buses} expenses={expenses} />}
          {activeTab === 'log' && <BookingLog buses={buses} bookers={bookers} />}
          {activeTab === 'expenses' && <ExpenseTracker expenses={expenses} onSubmit={() => fetchData()} onDelete={() => fetchData()} bookers={bookers} initialAgentCode={authenticatedAgent?.code} tours={tours} />}
          {activeTab === 'revenue' && <RevenueReport buses={buses} expenses={expenses} tours={tours} />}
          {activeTab === 'edit' && <EditData buses={buses} onUpdate={handleBookingSubmit} onDelete={handleBookingDelete} onBulkDelete={handleBulkDelete} onEdit={(info) => { setEditingInfo(info); setSelectedSeatId(info.seatNo); setShowBookingModal(true); }} bookers={bookers} isAdmin={isAdminAuthenticated} />}
          {activeTab === 'admin' && isAdminAuthenticated && <AdminPanel tours={tours} setTours={() => {}} agents={bookers} setAgents={() => {}} customerTypes={customerTypes} setCustomerTypes={() => {}} buses={buses} onDeleteTourCascading={() => {}} onMasterReset={() => {}} />}
        </div>
      </main>

      {showLogoutConfirm && <ConfirmationDialog message="Are you sure you want to end your session?" onConfirm={() => { setAuthenticatedAgent(null); setIsAdminAuthenticated(false); setShowLogoutConfirm(false); localStorage.removeItem('tl_auth_agent'); sessionStorage.removeItem('tl_auth_agent'); localStorage.removeItem('tl_auth_admin'); sessionStorage.removeItem('tl_auth_admin'); }} onCancel={() => setShowLogoutConfirm(false)} />}
      {showBookingModal && <BookingModal seatId={selectedSeatId!} busNo={editingInfo ? editingInfo.busNo : (buses[selectedBusIndex]?.busId || '')} onClose={() => { releaseLock(buses[selectedBusIndex].busId, selectedSeatId!); setShowBookingModal(false); setEditingInfo(null); }} onSubmit={handleBookingSubmit} tours={tours} bookers={bookers} customerTypes={customerTypes} existingData={editingInfo || undefined} isAdmin={isAdminAuthenticated} />}
      {showDetailModal && editingInfo && <SeatDetailModal info={editingInfo} onClose={() => { setShowDetailModal(false); setEditingInfo(null); }} onEdit={() => { setShowDetailModal(false); setShowBookingModal(true); }} onCancel={() => { handleBookingDelete(editingInfo.busNo, editingInfo.seatNo); setShowDetailModal(false); }} onUpdate={handleBookingSubmit} isAdmin={isAdminAuthenticated} />}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { BusData, BookingInfo, Booker } from '../types';

interface EditDataProps {
  buses: BusData[];
  onUpdate: (info: BookingInfo) => void;
  onDelete: (busId: string, seatId: string) => void;
  onBulkDelete?: (ids: string[]) => void;
  onEdit: (info: BookingInfo) => void;
  bookers: Booker[];
  isAdmin?: boolean;
}

const EditData: React.FC<EditDataProps> = ({ buses, onDelete, onBulkDelete, onEdit, bookers, isAdmin }) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [filterTour, setFilterTour] = useState('');
  const [filterBooker, setFilterBooker] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const allBookings: BookingInfo[] = useMemo(() => 
    buses.flatMap(b => b.seats.filter(s => s.isBooked).map(s => s.bookingInfo!)),
    [buses]
  );

  const filtered = useMemo(() => {
    return allBookings.filter(b => {
      const q = searchQuery.toLowerCase();
      const matchesSearch = searchQuery === '' || 
        b.name.toLowerCase().includes(q) || 
        b.mobile.includes(searchQuery) ||
        b.seatNo.toLowerCase().includes(q) ||
        b.bookerCode.toLowerCase().includes(q);

      const matchesTour = filterTour === '' || b.busNo === filterTour;
      const matchesBooker = filterBooker === '' || b.bookerCode === filterBooker;

      return matchesSearch && matchesTour && matchesBooker;
    });
  }, [allBookings, searchQuery, filterTour, filterBooker]);

  const uniqueTours = useMemo(() => Array.from(new Set(allBookings.map(b => b.busNo))), [allBookings]);

  const handleSelectAll = () => {
    if (selectedIds.length === filtered.length && filtered.length > 0) {
      setSelectedIds([]);
    } else {
      setSelectedIds(filtered.map(b => b.id));
    }
  };

  const toggleSelection = (id: string) => {
    setSelectedIds(prev => prev.includes(id) ? prev.filter(item => item !== id) : [...prev, id]);
  };

  const handleDeleteSelected = () => {
    if (selectedIds.length === 0) return;
    if (window.confirm(`Delete ${selectedIds.length} selected bookings permanently?`)) {
      onBulkDelete?.(selectedIds);
      setSelectedIds([]);
    }
  };

  const handleDeleteSingle = (booking: BookingInfo) => {
    if (isAdmin || window.confirm(`Delete booking for ${booking.name}?`)) {
      onDelete(booking.busNo, booking.seatNo);
    }
  };

  return (
    <div className="animate-in fade-in duration-500 max-w-6xl mx-auto md:pl-12 space-y-6">
       <div className="bg-white rounded-[32px] shadow-sm p-6 md:p-8 border border-gray-100 sticky top-0 md:relative z-30">
          <div className="relative group mb-6">
            <i className="fas fa-search absolute left-5 top-1/2 -translate-y-1/2 text-gray-300"></i>
            <input 
              className="w-full pl-14 pr-6 py-4 bg-gray-50 border-none rounded-2xl text-sm font-bold outline-none shadow-inner" 
              placeholder="Search Passenger, Seat or Mobile..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
             <select 
               value={filterTour}
               onChange={(e) => setFilterTour(e.target.value)}
               className="w-full px-4 py-3 bg-indigo-50 border-none rounded-xl font-black text-indigo-600 text-[10px] uppercase outline-none"
             >
               <option value="">All Tours</option>
               {uniqueTours.map(t => <option key={t} value={t}>{t}</option>)}
             </select>
             <select 
               value={filterBooker}
               onChange={(e) => setFilterBooker(e.target.value)}
               className="w-full px-4 py-3 bg-indigo-50 border-none rounded-xl font-black text-indigo-600 text-[10px] uppercase outline-none"
             >
               <option value="">All Agents</option>
               {bookers.map(agent => <option key={agent.code} value={agent.code}>{agent.name}</option>)}
             </select>

             {isAdmin && (
               <div className="flex gap-2">
                 <button 
                   onClick={handleSelectAll}
                   className="flex-1 px-4 py-3 bg-[#001D4A] text-white rounded-xl font-black text-[10px] uppercase"
                 >
                   {selectedIds.length === filtered.length && filtered.length > 0 ? 'Deselect All' : 'Select All'}
                 </button>
                 <button 
                   onClick={handleDeleteSelected}
                   disabled={selectedIds.length === 0}
                   className="flex-1 px-4 py-3 bg-red-600 text-white rounded-xl font-black text-[10px] uppercase disabled:opacity-50"
                 >
                   Delete ({selectedIds.length})
                 </button>
               </div>
             )}
          </div>
       </div>

       <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {filtered.length === 0 ? (
            <div className="col-span-full py-20 text-center bg-white rounded-[32px] border-2 border-dashed border-gray-100">
              <i className="fas fa-search text-gray-200 text-4xl mb-4"></i>
              <p className="text-gray-400 font-black uppercase text-[10px] tracking-widest">No matching records</p>
            </div>
          ) : (
            filtered.map(booking => (
              <div 
                key={booking.id} 
                className={`bg-white p-5 rounded-[32px] shadow-sm border transition-all flex flex-col justify-between group relative ${selectedIds.includes(booking.id) ? 'border-indigo-600 ring-2 ring-indigo-50' : 'border-gray-100'}`}
              >
                 {isAdmin && (
                   <div className="absolute top-4 right-4 z-10">
                      <input 
                        type="checkbox" 
                        checked={selectedIds.includes(booking.id)}
                        onChange={() => toggleSelection(booking.id)}
                        className="w-6 h-6 rounded-lg border-gray-200 text-indigo-600 focus:ring-indigo-500 cursor-pointer"
                      />
                   </div>
                 )}

                 <div className="flex justify-between items-start mb-4">
                    <div className="flex-1 min-w-0">
                       <div className="flex items-center gap-2 mb-2">
                          <span className="text-[8px] font-black text-white bg-[#001D4A] px-2 py-1 rounded-lg uppercase">{booking.busNo}</span>
                          <span className="text-[8px] font-black text-indigo-600 bg-indigo-50 px-2 py-1 rounded-lg uppercase">Seat {booking.seatNo}</span>
                       </div>
                       <h4 className="font-black text-[#001D4A] text-lg leading-tight truncate pr-8">{booking.name}</h4>
                       <p className="text-[10px] font-bold text-gray-400 mt-1 uppercase tracking-tighter">+880{booking.mobile}</p>
                    </div>
                    {!isAdmin && (
                      <div className="flex flex-col gap-2">
                         <button onClick={() => onEdit(booking)} className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center active:scale-90 transition-all shadow-sm"><i className="fas fa-edit"></i></button>
                         <button onClick={() => handleDeleteSingle(booking)} className="w-10 h-10 bg-red-50 text-red-500 rounded-xl flex items-center justify-center active:scale-90 transition-all shadow-sm"><i className="fas fa-trash-alt"></i></button>
                      </div>
                    )}
                 </div>

                 <div className="grid grid-cols-2 gap-3 pt-4 border-t border-gray-50">
                    <div className="bg-green-50 p-3 rounded-2xl">
                       <span className="text-[8px] font-black text-green-400 uppercase tracking-widest block mb-0.5">Paid</span>
                       <span className="text-sm font-black text-green-700">৳{booking.advanceAmount.toLocaleString()}</span>
                    </div>
                    <div className="bg-red-50 p-3 rounded-2xl">
                       <span className="text-[8px] font-black text-red-400 uppercase tracking-widest block mb-0.5">Due</span>
                       <span className="text-sm font-black text-red-700">৳{booking.dueAmount.toLocaleString()}</span>
                    </div>
                 </div>

                 {isAdmin && (
                   <div className="flex gap-2 mt-4 pt-4 border-t border-gray-50">
                     <button 
                       onClick={() => onEdit(booking)}
                       className="flex-1 py-3 bg-indigo-50 text-indigo-600 rounded-xl font-black text-[10px] uppercase flex items-center justify-center gap-2"
                     >
                       <i className="fas fa-edit"></i> Edit
                     </button>
                     <button 
                       onClick={() => handleDeleteSingle(booking)}
                       className="flex-1 py-3 bg-red-50 text-red-500 rounded-xl font-black text-[10px] uppercase flex items-center justify-center gap-2"
                     >
                       <i className="fas fa-trash-alt"></i> Delete
                     </button>
                   </div>
                 )}

                 <div className="mt-4 flex justify-between items-center text-[8px] font-black text-gray-400 uppercase tracking-widest border-t border-gray-50 pt-3">
                    <span className="truncate max-w-[100px]">{booking.bookedBy}</span>
                    <span>{new Date(booking.bookingDate).toLocaleDateString()}</span>
                 </div>
              </div>
            ))
          )}
       </div>
    </div>
  );
};

export default EditData;

import React, { useState, useMemo } from 'react';
import { Tour, Booker, CustomerType, BusData, BookingInfo } from '../types';
import { BUSINESS_INFO } from '../constants';

interface AdminPanelProps {
  tours: Tour[];
  setTours: (tours: Tour[]) => void;
  agents: Booker[];
  setAgents: (agents: Booker[]) => void;
  customerTypes: CustomerType[];
  setCustomerTypes: (types: CustomerType[]) => void;
  buses: BusData[];
  onDeleteTourCascading: (name: string) => void;
  onMasterReset: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  tours, setTours, 
  agents, setAgents, 
  customerTypes, setCustomerTypes,
  buses,
  onDeleteTourCascading,
  onMasterReset
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'tours' | 'agents' | 'types' | 'print' | 'food'>('tours');

  const [newTour, setNewTour] = useState({ name: '', fee: 0 });
  const [newAgent, setNewAgent] = useState({ code: '', name: '' });
  const [newType, setNewType] = useState({ type: '', fee: 0 });

  const [editTourIndex, setEditTourIndex] = useState<number | null>(null);
  const [editTourData, setEditTourData] = useState<Tour | null>(null);

  const [editAgentIndex, setEditAgentIndex] = useState<number | null>(null);
  const [editAgentData, setEditAgentData] = useState<Booker | null>(null);

  const [editTypeIndex, setEditTypeIndex] = useState<number | null>(null);
  const [editTypeData, setEditTypeData] = useState<CustomerType | null>(null);

  const [selectedForPrint, setSelectedForPrint] = useState<string[]>([]);

  const [foodType, setFoodType] = useState<'Breakfast' | 'Lunch' | 'Dinner' | 'Special Item' | 'Snacks' | 'Refreshment'>('Breakfast');
  const [foodTime, setFoodTime] = useState('08:30 AM');
  const [foodFilterTour, setFoodFilterTour] = useState('');
  const [foodFilterBooker, setFoodFilterBooker] = useState('');

  const allBookings: BookingInfo[] = useMemo(() => 
    buses.flatMap(b => b.seats.filter(s => s.isBooked).map(s => s.bookingInfo!)),
    [buses]
  );

  const filteredFoodBookings = useMemo(() => {
    return allBookings.filter(b => {
      const matchTour = foodFilterTour === '' || b.tourName === foodFilterTour;
      const matchBooker = foodFilterBooker === '' || b.bookerCode === foodFilterBooker;
      return matchTour && matchBooker;
    });
  }, [allBookings, foodFilterTour, foodFilterBooker]);

  const addTour = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTour.name.trim()) return;
    const updated = [...tours, { name: newTour.name.trim(), fee: newTour.fee }];
    setTours(updated);
    setNewTour({ name: '', fee: 0 });
  };

  const saveTourEdit = () => {
    if (editTourIndex !== null && editTourData) {
      const updated = [...tours];
      updated[editTourIndex] = editTourData;
      setTours(updated);
      setEditTourIndex(null);
    }
  };

  const addAgent = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAgent.code.trim() || !newAgent.name.trim()) return;
    const updated = [...agents, { code: newAgent.code.trim().toUpperCase(), name: newAgent.name.trim() }];
    setAgents(updated);
    setNewAgent({ code: '', name: '' });
  };

  const saveAgentEdit = () => {
    if (editAgentIndex !== null && editAgentData) {
      const updated = [...agents];
      updated[editAgentIndex] = editAgentData;
      setAgents(updated);
      setEditAgentIndex(null);
    }
  };

  const removeAgent = (code: string) => {
    if (confirm(`Remove agent ${code}?`)) {
      setAgents(agents.filter(a => a.code !== code));
    }
  };

  const addType = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newType.type.trim()) return;
    const updated = [...customerTypes, { type: newType.type.trim(), fee: newType.fee }];
    setCustomerTypes(updated);
    setNewType({ type: '', fee: 0 });
  };

  const saveTypeEdit = () => {
    if (editTypeIndex !== null && editTypeData) {
      const updated = [...customerTypes];
      updated[editTypeIndex] = editTypeData;
      setCustomerTypes(updated);
      setEditTypeIndex(null);
    }
  };

  const removeType = (index: number) => {
    if (confirm("Remove this category?")) {
      setCustomerTypes(customerTypes.filter((_, idx) => idx !== index));
    }
  };

